    def _on_research_content_configure(self, _event=None):
        if hasattr(self, "research_canvas") and self.research_canvas.winfo_exists():
            self.research_canvas.configure(scrollregion=self.research_canvas.bbox("all"))

    def _on_research_canvas_configure(self, event=None):
        if hasattr(self, "research_canvas_window"):
            width = event.width if event else self.research_canvas.winfo_width()
            self.research_canvas.itemconfigure(self.research_canvas_window, width=width)

    def _populate_researcher_fields(self):
        for child in self.research_content.winfo_children():
            child.destroy()
        self.research_widgets = {}
        self.research_sections = {}

        self.research_tabs = ttk.Notebook(self.research_content)
        self.research_tabs.pack(fill="both", expand=True, padx=20, pady=12)
        self.research_tabs.bind("<<NotebookTabChanged>>", lambda _event: self._on_research_content_configure())

        for code, title, cls, _filename in RESEARCH_CONFIG_SPECS:
            tab = tk.Frame(self.research_tabs, bg=BG_COLOR)
            self.research_tabs.add(tab, text=f"Тест {code}")
            tab.grid_columnconfigure(0, weight=1)

            intro = tk.Label(
                tab,
                text=title,
                bg=BG_COLOR,
                fg=TITLE_COLOR,
                anchor="w",
                justify="left",
            )
            intro.grid(row=0, column=0, sticky="ew", padx=4, pady=(0, 10))

            sections_wrap = tk.Frame(tab, bg=BG_COLOR)
            sections_wrap.grid(row=1, column=0, sticky="nsew")
            sections_wrap.grid_columnconfigure(0, weight=1)
            sections_wrap.grid_columnconfigure(1, weight=1)
            tab.grid_rowconfigure(1, weight=1)

            cfg = cls()
            widgets = {}
            section_frames: list[tk.LabelFrame] = []
            section_groups = _get_research_section_groups(code, cls)

            for group_index, (section_title, field_names) in enumerate(section_groups):
                section = tk.LabelFrame(
                    sections_wrap,
                    text=section_title,
                    bg=PANEL_COLOR,
                    fg=TITLE_COLOR,
                    bd=2,
                    relief="groove",
                    padx=8,
                    pady=6,
                )
                section.grid(
                    row=group_index // 2,
                    column=group_index % 2,
                    sticky="nsew",
                    padx=8,
                    pady=8,
                )
                section.grid_columnconfigure(0, weight=0, minsize=280)
                section.grid_columnconfigure(1, weight=1)
                sections_wrap.grid_rowconfigure(group_index // 2, weight=1)
                section_frames.append(section)

                row = 0
                for field_name in field_names:
                    fld = next((item for item in fields(cls) if item.name == field_name), None)
                    if fld is None:
                        continue
                    default_value = getattr(cfg, fld.name)
                    meta = _get_research_field_meta(code, fld.name)

                    label_box = tk.Frame(section, bg=PANEL_COLOR)
                    label_box.grid(row=row, column=0, sticky="nsew", padx=14, pady=8)

                    label = tk.Label(
                        label_box,
                        text=meta.get("label", fld.name),
                        bg=PANEL_COLOR,
                        fg=TITLE_COLOR,
                        anchor="w",
                        justify="left",
                        font=("Segoe UI", 10, "bold"),
                        wraplength=250,
                    )
                    label.pack(anchor="w")

                    help_text = meta.get("help", "")
                    if help_text:
                        help_label = tk.Label(
                            label_box,
                            text=help_text,
                            bg=PANEL_COLOR,
                            fg="#5a5a5a",
                            anchor="w",
                            justify="left",
                            wraplength=250,
                        )
                        help_label.pack(anchor="w", pady=(2, 0))

                    serialized = _serialize_config_value(default_value)
                    is_multiline = isinstance(default_value, (list, dict, tuple)) or len(serialized) > 48
                    widget_box = tk.Frame(section, bg=PANEL_COLOR)
                    widget_box.grid(row=row, column=1, sticky="ew", padx=(0, 14), pady=8)
                    widget_box.grid_columnconfigure(0, weight=1)

                    if is_multiline:
                        widget = tk.Text(
                            widget_box,
                            height=max(3, min(6, serialized.count("\n") + 2)),
                            wrap="word",
                            bg=FIELD_BG,
                            relief="sunken",
                            bd=1,
                        )
                        widget.insert("1.0", serialized)
                        widget.grid(row=0, column=0, sticky="ew")
                    else:
                        widget = tk.Entry(widget_box, bg=FIELD_BG)
                        widget.insert(0, serialized)
                        widget.grid(row=0, column=0, sticky="ew", ipady=4)

                    default_hint = tk.Label(
                        widget_box,
                        text=f"По умолчанию: {serialized}",
                        bg=PANEL_COLOR,
                        fg="#6b7280",
                        anchor="w",
                        justify="left",
                        wraplength=520,
                    )
                    default_hint.grid(row=1, column=0, sticky="w", pady=(3, 0))

                    widgets[fld.name] = {"widget": widget, "template": default_value, "is_multiline": is_multiline}
                    row += 1

            self.research_widgets[code] = widgets
            self.research_sections[code] = section_frames

        self._on_research_content_configure()

    def _research_widget_get(self, widget_info: dict[str, object]) -> str:
        widget = widget_info["widget"]
        if widget_info.get("is_multiline"):
            return widget.get("1.0", "end").strip()
        return widget.get().strip()

    def _research_widget_set(self, widget_info: dict[str, object], value):
        serialized = _serialize_config_value(value)
        widget = widget_info["widget"]
        if widget_info.get("is_multiline"):
            widget.delete("1.0", "end")
            widget.insert("1.0", serialized)
        else:
            widget.delete(0, "end")
            widget.insert(0, serialized)

    def reset_researcher_defaults(self):
        for _code, _title, cls, _filename in RESEARCH_CONFIG_SPECS:
            cfg = cls()
            for fld in fields(cls):
                self._research_widget_set(self.research_widgets[_code][fld.name], getattr(cfg, fld.name))
        self.research_status_var.set("Поля возвращены к значениям по умолчанию.")

    def collect_researcher_configs(self):
        collected = []
        for code, title, cls, filename in RESEARCH_CONFIG_SPECS:
            kwargs = {}
            for fld in fields(cls):
                info = self.research_widgets[code][fld.name]
                raw = self._research_widget_get(info)
                try:
                    kwargs[fld.name] = _parse_config_value(raw, info["template"])
                except Exception as exc:
                    raise ValueError(f"{title}: поле '{fld.name}' заполнено некорректно ({exc}).")
            try:
                cfg = cls(**kwargs)
            except Exception as exc:
                raise ValueError(f"{title}: не удалось собрать конфигурацию ({exc}).")
            collected.append((filename, cfg))
        return collected

    def apply_researcher_and_open_login(self):
        try:
            configs = self.collect_researcher_configs()
            for filename, cfg in configs:
                save_config_dataclass(self.base_dir, filename, cfg)
        except ValueError as exc:
            self.research_status_var.set(str(exc))
            messagebox.showerror("Некорректные параметры", str(exc))
            return

        self.research_status_var.set("Параметры сохранены. Открывается регистрационная форма.")
        self.build_start_ui()

    def handle_enter(self):
        if self.view_mode == "researcher":
            return
        if self.view_mode == "menu":
            self.continue_next_test()
        else:
            self.submit_form()

    def make_session(self, profile: UserProfile) -> SessionInfo:
        now = datetime.now()
        return SessionInfo(
            session_id=now.strftime("%Y%m%d_%H%M%S_%f"),
            name=profile.name,
            age=profile.age,
            gender=profile.gender,
            started_at=now,
        )

    def load_images(self):
        for name in ("circle.png", "cockpit.png"):
            path = self.assets_dir / name
            if path.exists():
                self.original_images[name] = Image.open(path)

    def open_fullscreen(self):
        try:
            self.root.attributes("-fullscreen", True)
        except tk.TclError:
            try:
                self.root.state("zoomed")
            except tk.TclError:
                w = self.root.winfo_screenwidth()
                h = self.root.winfo_screenheight()
                self.root.geometry(f"{w}x{h}+0+0")

    def exit_fullscreen(self):
        try:
            self.root.attributes("-fullscreen", False)
        except tk.TclError:
            pass
        try:
            self.root.state("zoomed")
        except tk.TclError:
            pass

    def toggle_fullscreen(self):
        try:
            is_fullscreen = bool(self.root.attributes("-fullscreen"))
            self.root.attributes("-fullscreen", not is_fullscreen)
        except tk.TclError:
            pass

