    def on_configure(self, _event=None):
        if self._resize_after_id is not None:
            self.root.after_cancel(self._resize_after_id)
        self._resize_after_id = self.root.after(60, self.apply_current_layout)

    def apply_current_layout(self):
        self._resize_after_id = None
        if not hasattr(self, "main"):
            return
        if self.view_mode == "researcher":
            self.apply_researcher_layout()
        elif self.view_mode == "menu":
            self.apply_menu_layout()
        else:
            self.apply_start_layout()

    def apply_researcher_layout(self):
        width = max(self.root.winfo_width(), 1100)
        height = max(self.root.winfo_height(), 760)
        scale = min(width / BASE_W, height / BASE_H)
        scale = max(0.72, min(scale, 1.6))

        pad_x = int(22 * scale)
        pad_y = int(16 * scale)
        self.main.pack_configure(padx=pad_x, pady=pad_y)
        self.research_header.pack_configure(pady=(0, int(10 * scale)))
        self.research_actions_top.pack_configure(pady=(0, int(10 * scale)))
        self.research_status.pack_configure(pady=(0, int(10 * scale)))

        title_size = max(24, int(40 * scale))
        text_size = max(11, int(16 * scale))
        section_label_size = max(11, int(15 * scale))
        button_size = max(11, int(16 * scale))

        self.research_title.configure(font=("Times New Roman", title_size, "bold"))
        self.research_subtitle.configure(font=("Arial", text_size, "bold"), wraplength=int(width * 0.82))
        self.research_status.configure(font=("Arial", text_size, "bold"), wraplength=int(width * 0.82))
        for btn in (self.research_default_btn, self.research_next_btn, self.research_exit_btn):
            btn.configure(font=("Arial", button_size, "bold"))
        self.research_default_btn.pack_configure(padx=(0, int(12 * scale)))
        self.research_exit_btn.pack_configure(padx=(int(12 * scale), 0))
        self.research_next_btn.pack_configure(padx=(int(12 * scale), 0))

        section_title_wrap = int(width * 0.18)
        field_help_wrap = int(width * 0.18)
        default_wrap = int(width * 0.28)
        for code, section_list in self.research_sections.items():
            for section in section_list:
                try:
                    section.configure(font=("Arial", section_label_size, "bold"))
                except tk.TclError:
                    pass
                section.grid_columnconfigure(0, minsize=int(width * 0.18))
                for child in section.winfo_children():
                    if isinstance(child, tk.Frame):
                        for nested in child.winfo_children():
                            if isinstance(nested, tk.Label):
                                current_fg = str(nested.cget("fg"))
                                is_primary = current_fg in {TITLE_COLOR, "#000000", "black"}
                                nested.configure(
                                    font=("Arial", text_size, "bold" if is_primary else "normal"),
                                    wraplength=section_title_wrap if is_primary else field_help_wrap,
                                )
                            elif isinstance(nested, tk.Entry):
                                nested.configure(font=("Consolas", text_size))
                            elif isinstance(nested, tk.Text):
                                nested.configure(font=("Consolas", max(10, text_size - 1)))
                    elif isinstance(child, tk.Label):
                        child.configure(font=("Arial", text_size), wraplength=default_wrap)
                    elif isinstance(child, tk.Entry):
                        child.configure(font=("Consolas", text_size))
                    elif isinstance(child, tk.Text):
                        child.configure(font=("Consolas", max(10, text_size - 1)))

        self._on_research_canvas_configure()
        self._on_research_content_configure()

    def _apply_common_shell_layout(self, width: int, height: int, scale: float):
        pad_x = int(24 * scale)
        pad_y = int(18 * scale)
        left_right_gap = int(24 * scale)
        image_gap = int(18 * scale)

        self.main.pack_configure(padx=pad_x, pady=pad_y)
        self.left.grid_configure(padx=(0, left_right_gap))
        self.title_small.grid_configure(pady=(0, int(8 * scale)))
        self.title_big.grid_configure(pady=(0, int(8 * scale)))
        self.body.grid_configure(pady=(int(16 * scale), int(16 * scale)))
        self.image_gap.configure(height=image_gap)

        title_small_size = max(24, int(42 * scale))
        title_big_size = max(28, int(46 * scale))
        body_size = max(13, int(21 * scale))
        self.title_small.configure(font=("Times New Roman", title_small_size, "bold"))
        self.title_big.configure(font=("Times New Roman", title_big_size, "bold"))
        self.body.configure(font=("Times New Roman", body_size, "bold"), wraplength=int(width * 0.54))

        left_width = int(width * 0.29)
        img_size = min(left_width, int(height * 0.40))
        img_size = max(220, img_size)
        self.set_image(self.circle_label, "circle.png", img_size)
        self.set_image(self.cockpit_label, "cockpit.png", img_size)

