        width = max(self.root.winfo_width(), 1100)
        height = max(self.root.winfo_height(), 760)
        scale = min(width / BASE_W, height / BASE_H)
        scale = max(0.72, min(scale, 1.9))
        self._apply_common_shell_layout(width, height, scale)

