        self.btn_frame.grid_configure(pady=(0, int(8 * scale)))
        self.next_btn.pack_configure(padx=(0, 0))
        self.exit_btn.pack_configure(padx=(0, button_gap))

        form_title_size = max(14, int(22 * scale))
        form_text_size = max(12, int(18 * scale))
        status_size = max(11, int(15 * scale))
        button_font_size = max(14, int(24 * scale))

        self.form_title.configure(font=("Arial", form_title_size, "bold"))
        for widget in (self.name_label, self.age_label, self.gender_label, self.gender_male, self.gender_female):
            widget.configure(font=("Arial", form_text_size, "bold"))
        self.name_entry.configure(font=("Arial", form_text_size))
        self.age_entry.configure(font=("Arial", form_text_size))
        self.status_label.configure(font=("Arial", status_size, "bold"), wraplength=int(width * 0.48))

        self.form_frame.grid_columnconfigure(0, minsize=int(240 * scale))

