def _get_research_section_groups(code: str, cls) -> list[tuple[str, list[str]]]:
    declared = [fld.name for fld in fields(cls)]
    remaining = declared.copy()
    result: list[tuple[str, list[str]]] = []
    for title, field_names in RESEARCH_SECTION_META.get(code, []):
        filtered = [name for name in field_names if name in declared]
        if not filtered:
            continue
        result.append((title, filtered))
        for name in filtered:
            if name in remaining:
                remaining.remove(name)
    if remaining:
        result.append(("Прочие параметры", remaining))
    return result


def _serialize_config_value(value):
    if isinstance(value, (list, dict, tuple)):
        return json.dumps(value, ensure_ascii=False)
    if isinstance(value, bool):
        return "true" if value else "false"
    return str(value)


def _parse_config_value(raw: str, template):
    raw = raw.strip()
    if isinstance(template, bool):
        lowered = raw.lower()
        if lowered in {"1", "true", "yes", "y", "да"}:
            return True
        if lowered in {"0", "false", "no", "n", "нет"}:
            return False
        raise ValueError("нужно указать true/false")
    if isinstance(template, int) and not isinstance(template, bool):
        return int(raw.replace(",", "."))
    if isinstance(template, float):
        return float(raw.replace(",", "."))
    if isinstance(template, (list, dict, tuple)):
        parsed = json.loads(raw)
        if isinstance(template, tuple):
            return tuple(parsed)
        return parsed
    return raw


def save_config_dataclass(base_dir: Path, filename: str, obj):
    path = base_dir / filename
    path.write_text(json.dumps(asdict(obj), ensure_ascii=False, indent=2), encoding='utf-8')


def _load_json_dataclass(path: Path, cls):
    if path.exists():
        try:
            return cls(**json.loads(path.read_text(encoding='utf-8')))
        except Exception:
            return cls()
    return cls()


def load_method_b_config(base_dir: Path) -> MethodBConfig:
    return _load_json_dataclass(base_dir / 'method_b_config.json', MethodBConfig)


def load_method_c_config(base_dir: Path) -> MethodCConfig:
    return _load_json_dataclass(base_dir / 'method_c_config.json', MethodCConfig)


def load_method_d_config(base_dir: Path) -> MethodDConfig:
    return _load_json_dataclass(base_dir / 'method_d_config.json', MethodDConfig)


def _results_dir(base_dir: Path) -> Path:
    p = base_dir / 'data' / 'results'
    p.mkdir(parents=True, exist_ok=True)
    return p


def save_method_payload(base_dir: Path, code: str, session_id: str, payload: dict) -> str:
    ts = datetime.now().strftime('%Y%m%d_%H%M%S')
    p = _results_dir(base_dir) / f'method_{code.lower()}_{session_id}_{ts}.json'
    p.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding='utf-8')
    return str(p)


def _fmt_sec(sec: float) -> str:
    sec = max(0, int(round(sec)))
    return f"{sec // 60:02d}:{sec % 60:02d}"


def _safe_ratio(num: float, den: float, default: float = 0.0) -> float:
    if not den:
        return default
    try:
        return float(num) / float(den)
    except Exception:
        return default


def _round2(x):
    try:
        return round(float(x), 2)
    except Exception:
        return 0.0


BASIC_SYMBOLS = [
    'circle', 'square', 'triangle', 'diamond', 'star', 'plus', 'cross', 'ring',
    'arrow', 'hex', 'bars', 'moon', 'kite', 'double', 'target', 'wave'
]


def _rotate_points(points, angle_deg, cx, cy):
    if not angle_deg:
        return points
    ang = math.radians(angle_deg)
    ca, sa = math.cos(ang), math.sin(ang)
    out = []
    for x, y in points:
        dx, dy = x - cx, y - cy
        out.append((cx + dx * ca - dy * sa, cy + dx * sa + dy * ca))
    return out


def draw_basic_symbol(canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, symbol_id: int, outline: str = '#1b2b40', fill: str = '#1b2b40', rotation: float = 0.0, fill_mode: int = 1, count: int = 1, tag: str | None = None):
    tag = tag or 'symbol'
    cx = (x1 + x2) / 2
    cy = (y1 + y2) / 2
    w = x2 - x1
    h = y2 - y1
    size = min(w, h) * 0.28
    count = max(1, int(count))
    positions = [(0, 0)]
    if count == 2:
        positions = [(-size * 0.9, 0), (size * 0.9, 0)]
    elif count == 3:
        positions = [(-size * 1.0, size * 0.4), (size * 1.0, size * 0.4), (0, -size * 0.9)]
    elif count >= 4:
        positions = [(-size * 1.0, -size * 0.8), (size * 1.0, -size * 0.8), (-size * 1.0, size * 0.8), (size * 1.0, size * 0.8)]
    fill_color = fill if fill_mode == 1 else ('#79b8ff' if fill_mode == 2 else '#ffffff')
    for ox, oy in positions:
        ccx, ccy = cx + ox, cy + oy
        sid = symbol_id % len(BASIC_SYMBOLS)
        if sid == 0:
            canvas.create_oval(ccx - size, ccy - size, ccx + size, ccy + size, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 1:
            pts = [(ccx - size, ccy - size), (ccx + size, ccy - size), (ccx + size, ccy + size), (ccx - size, ccy + size)]
            canvas.create_polygon(_rotate_points(pts, rotation, ccx, ccy), outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 2:
            pts = [(ccx, ccy - size * 1.2), (ccx + size * 1.1, ccy + size), (ccx - size * 1.1, ccy + size)]
            canvas.create_polygon(_rotate_points(pts, rotation, ccx, ccy), outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 3:
            pts = [(ccx, ccy - size * 1.2), (ccx + size * 1.2, ccy), (ccx, ccy + size * 1.2), (ccx - size * 1.2, ccy)]
            canvas.create_polygon(_rotate_points(pts, rotation, ccx, ccy), outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 4:
            pts = []
            for k in range(10):
                rr = size * (1.2 if k % 2 == 0 else 0.5)
                ang = math.radians(rotation - 90 + k * 36)
                pts.append((ccx + rr * math.cos(ang), ccy + rr * math.sin(ang)))
            canvas.create_polygon(pts, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 5:
            canvas.create_rectangle(ccx - size * 0.28, ccy - size * 1.15, ccx + size * 0.28, ccy + size * 1.15, outline=outline, fill=fill_color, width=2, tags=tag)
            canvas.create_rectangle(ccx - size * 1.15, ccy - size * 0.28, ccx + size * 1.15, ccy + size * 0.28, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 6:
            canvas.create_line(ccx - size, ccy - size, ccx + size, ccy + size, fill=outline, width=4, tags=tag)
            canvas.create_line(ccx - size, ccy + size, ccx + size, ccy - size, fill=outline, width=4, tags=tag)
        elif sid == 7:
            canvas.create_oval(ccx - size, ccy - size, ccx + size, ccy + size, outline=outline, width=4, tags=tag)
        elif sid == 8:
            pts = [(ccx - size, ccy - size * 0.65), (ccx + size * 0.25, ccy - size * 0.65), (ccx + size * 0.25, ccy - size), (ccx + size, ccy), (ccx + size * 0.25, ccy + size), (ccx + size * 0.25, ccy + size * 0.65), (ccx - size, ccy + size * 0.65)]
            canvas.create_polygon(_rotate_points(pts, rotation, ccx, ccy), outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 9:
            pts = []
            for k in range(6):
                ang = math.radians(rotation + 30 + k * 60)
                pts.append((ccx + size * 1.15 * math.cos(ang), ccy + size * 1.15 * math.sin(ang)))
            canvas.create_polygon(pts, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 10:
            for dy in (-size * 0.7, 0, size * 0.7):
                canvas.create_rectangle(ccx - size * 1.1, ccy + dy - size * 0.18, ccx + size * 1.1, ccy + dy + size * 0.18, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 11:
            canvas.create_oval(ccx - size, ccy - size, ccx + size, ccy + size, outline=outline, fill=fill_color, width=2, tags=tag)
            canvas.create_oval(ccx - size * 0.25, ccy - size * 1.05, ccx + size * 0.95, ccy + size * 1.05, outline='', fill='#ffffff', tags=tag)
        elif sid == 12:
            pts = [(ccx, ccy - size * 1.2), (ccx + size, ccy), (ccx, ccy + size * 1.2), (ccx - size, ccy)]
            canvas.create_polygon(_rotate_points(pts, rotation, ccx, ccy), outline=outline, fill=fill_color, width=2, tags=tag)
            canvas.create_line(ccx, ccy - size * 1.2, ccx, ccy + size * 1.2, fill=outline, width=2, tags=tag)
        elif sid == 13:
            canvas.create_oval(ccx - size * 1.1, ccy - size, ccx - size * 0.1, ccy + size, outline=outline, fill=fill_color, width=2, tags=tag)
            canvas.create_oval(ccx + size * 0.1, ccy - size, ccx + size * 1.1, ccy + size, outline=outline, fill=fill_color, width=2, tags=tag)
        elif sid == 14:
            canvas.create_oval(ccx - size * 1.15, ccy - size * 1.15, ccx + size * 1.15, ccy + size * 1.15, outline=outline, width=3, tags=tag)
            canvas.create_oval(ccx - size * 0.45, ccy - size * 0.45, ccx + size * 0.45, ccy + size * 0.45, outline=outline, fill=fill_color, width=2, tags=tag)
        else:
            pts = []
            for dx in (-1.0, -0.3, 0.3, 1.0):
                pts.extend([ccx + dx * size, ccy + math.sin(dx * math.pi + math.radians(rotation)) * size * 0.8])
            canvas.create_line(*pts, fill=outline, width=4, smooth=True, tags=tag)


class MethodBWindow:
    def __init__(self, parent: tk.Tk, session: SessionInfo, logger: ParticipantsLogger, base_dir: Path, config: MethodBConfig):
        self.parent = parent
        self.session = session
        self.logger = logger
        self.base_dir = base_dir
        self.cfg = config
        self.result = {'completed': False, 'cycles': [], 'summary': {}}
        self.win = None
        self.after_ids = []
        self.total_start = 0.0
        self.cycle_started_at = 0.0
        self.phase = 'idle'
        self.current_n = 1
        self.current_positions = []
        self.current_shapes = []
        self.placements = {}
        self.available_shapes = []
        self.selected_shape = None
        self.reproduction_deadline = 0.0
        self.pending_message = ''
        self.exposure_adjust_s = 0.0
        self.reproduction_adjust_s = 0.0
        self.grid_cells = []
        self.tray_cells = []
        self.info_var = tk.StringVar(value='')
        self.message_var = tk.StringVar(value='')
        self.selection_var = tk.StringVar(value='Выберите фигуру и укажите её место в матрице.')

    def run(self) -> dict:
        self._build_ui()
        self.total_start = time.perf_counter()
        self.logger.log_event(self.session, event_type='method_session', screen='method_b', test_name='method_b', action='started', note='Запущена методика B: Memory 4x4')
        self._start_cycle()
        self.parent.wait_window(self.win)
        return self.result

    def _track_after(self, after_id):
        if after_id:
            self.after_ids.append(after_id)

    def _cancel_afters(self):
        if not self.win:
            return
        for after_id in self.after_ids:
            try:
                self.win.after_cancel(after_id)
            except Exception:
                pass
        self.after_ids.clear()

    def _build_ui(self):
        self.win = tk.Toplevel(self.parent)
        self.win.title('СПР - Тест B')
        self.win.configure(bg='#ffefd5')
        self.win.transient(self.parent)
        self.win.grab_set()
        try:
            self.win.attributes('-fullscreen', True)
        except tk.TclError:
            self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
        self.win.bind('<Escape>', lambda _e: self._abort())
        self.win.protocol('WM_DELETE_WINDOW', self._abort)
        try:
            self.win.lift()
            self.win.focus_force()
        except Exception:
            pass
        self.win.grid_columnconfigure(0, weight=1)
        self.win.grid_rowconfigure(1, weight=1)

        header = tk.Frame(self.win, bg='#ffefd5')
        header.grid(row=0, column=0, sticky='ew')
        tk.Label(header, text='Тест B · Запоминание фигур в матрице', bg='#ffefd5', fg='#400000', font=('Arial', 24, 'bold')).pack(side='left', padx=24, pady=14)
        tk.Label(header, textvariable=self.info_var, bg='#ffefd5', fg='#6b4a3d', font=('Arial', 14, 'bold')).pack(side='right', padx=24)

        body = tk.Frame(self.win, bg='#ffefd5')
        body.grid(row=1, column=0, sticky='nsew')
        body.grid_columnconfigure(0, weight=1)
        body.grid_rowconfigure(1, weight=1)

        top_text = tk.Frame(body, bg='#ffefd5')
        top_text.grid(row=0, column=0, sticky='ew', padx=18, pady=(14, 8))
        tk.Label(top_text, textvariable=self.message_var, bg='#ffefd5', fg='#6c0000', font=('Arial', 16, 'bold')).pack()
        tk.Label(top_text, textvariable=self.selection_var, bg='#ffefd5', fg='#6b4a3d', font=('Arial', 12)).pack(pady=(6, 0))

        center = tk.Frame(body, bg='#ffefd5')
        center.grid(row=1, column=0, sticky='nsew', padx=18, pady=8)
        center.grid_columnconfigure(0, weight=0)
        center.grid_columnconfigure(1, weight=1)
        center.grid_rowconfigure(0, weight=1)

        tray_panel = tk.Frame(center, bg='#f6e4bf', bd=1, relief='solid', highlightthickness=0)
        tray_panel.grid(row=0, column=0, sticky='nsw', padx=(0, 18), pady=4)
        tk.Label(tray_panel, text='Касса фигур', bg='#f6e4bf', fg='#6c0000', font=('Arial', 16, 'bold')).pack(anchor='n', pady=(14, 4), padx=14)
        tk.Label(
            tray_panel,
            text='Выберите фигуру в кассе слева\nи поместите её в нужную ячейку.',
            bg='#f6e4bf',
            fg='#6b4a3d',
            font=('Arial', 11),
            justify='center'
        ).pack(anchor='n', padx=14, pady=(0, 8))
        self.tray_frame = tk.Frame(tray_panel, bg='#f6e4bf')
        self.tray_frame.pack(padx=12, pady=(0, 10))
        controls = tk.Frame(tray_panel, bg='#f6e4bf')
        controls.pack(side='bottom', pady=(4, 14), padx=12)
        tk.Button(controls, text='Очистить', command=self._clear_placements, bg='#efe1c6', activebackground='#e5d2ae', fg='#5e372c', font=('Arial', 12, 'bold'), width=12).pack(pady=5)
        tk.Button(controls, text='Готово', command=self._submit_cycle, bg='#e8d9bb', activebackground='#dcc6a3', fg='#5e372c', font=('Arial', 12, 'bold'), width=12).pack(pady=5)
        tk.Button(controls, text='Выход', command=self._abort, bg='#b84a4a', activebackground='#9f3f3f', fg='white', font=('Arial', 12, 'bold'), width=12).pack(pady=5)

        matrix_wrap = tk.Frame(center, bg='#ffefd5')
        matrix_wrap.grid(row=0, column=1, sticky='nsew')
        matrix_wrap.grid_columnconfigure(0, weight=1)
        matrix_wrap.grid_rowconfigure(0, weight=1)

        self.matrix_frame = tk.Frame(matrix_wrap, bg='#ffefd5', bd=0, relief='flat')
        self.matrix_frame.grid(row=0, column=0)
        cell_size = 148
        for r in range(4):
            self.matrix_frame.grid_rowconfigure(r, weight=1)
            self.matrix_frame.grid_columnconfigure(r, weight=1)
        for idx in range(16):
            c = tk.Canvas(self.matrix_frame, width=cell_size, height=cell_size, bg='white', highlightthickness=1, highlightbackground='#e3d8c7')
            c.grid(row=idx // 4, column=idx % 4, padx=4, pady=4)
            c.bind('<Button-1>', lambda e, i=idx: self._on_matrix_cell(i))
            self.grid_cells.append(c)

    def _elapsed_total(self) -> float:
        return time.perf_counter() - self.total_start

    def _time_left_total(self) -> float:
        return max(0.0, self.cfg.total_test_s - self._elapsed_total())

    def _update_info_label(self):
        self.info_var.set(f'Осталось времени: {_fmt_sec(self._time_left_total())}    Фигур в цикле: {self.current_n}')
        if self.phase in ('memorize', 'reproduce') and self.win and self.win.winfo_exists():
            self._track_after(self.win.after(250, self._update_info_label))

    def _start_cycle(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        if self._time_left_total() <= 1.0:
            self._finish()
            return
        n = max(1, min(self.cfg.max_items, int(self.current_n)))
        all_cells = list(range(self.cfg.grid_size ** 2))
        all_shapes = list(range(self.cfg.max_items))
        random.shuffle(all_cells)
        random.shuffle(all_shapes)
        self.current_positions = sorted(all_cells[:n])
        self.current_shapes = all_shapes[:n]
        self.placements = {}
        self.available_shapes = list(self.current_shapes)
        self.selected_shape = None
        self.phase = 'memorize'
        self.cycle_started_at = time.perf_counter()
        self.message_var.set('Запомните расположение фигур в матрице.')
        self.selection_var.set('После показа восстановите рисунок расположения фигур.')
        self._draw_memory_matrix()
        self._draw_tray(show=False)
        exposure = min(self.cfg.start_exposure_s + self.cfg.step_time_s * (n - 1), max(1.0, self._time_left_total()))
        self._update_info_label()
        self._track_after(self.win.after(int(exposure * 1000), self._start_reproduction_phase))

    def _draw_memory_matrix(self):
        for idx, cell in enumerate(self.grid_cells):
            cell.delete('all')
            cell.create_rectangle(8, 8, 140, 140, outline='#d9ccb3', width=2)
            if idx in self.current_positions:
                shape = self.current_shapes[self.current_positions.index(idx)]
                draw_basic_symbol(cell, 14, 14, 134, 134, shape, fill='#400000', outline='#400000')

    def _draw_reproduction_matrix(self):
        for idx, cell in enumerate(self.grid_cells):
            cell.delete('all')
            border = '#b79e80' if idx in self.placements else '#e3d8c7'
            cell.create_rectangle(8, 8, 140, 140, outline=border, width=2)
            if idx in self.placements:
                shape = self.placements[idx]
                draw_basic_symbol(cell, 14, 14, 134, 134, shape, fill='#400000', outline='#400000')

    def _draw_tray(self, show=True):
        for child in self.tray_frame.winfo_children():
            child.destroy()
        self.tray_cells.clear()
        if not show:
            return
        items = list(self.available_shapes)
        items.sort()
        columns = 2 if len(items) > 4 else 1
        for pos, shape in enumerate(items):
            wrap = tk.Frame(self.tray_frame, bg='#f6e4bf')
            row, col = divmod(pos, columns)
            wrap.grid(row=row, column=col, padx=8, pady=8)
            c = tk.Canvas(wrap, width=104, height=104, bg='white', highlightthickness=1, highlightbackground='#c9aa77')
            c.pack()
            draw_basic_symbol(c, 12, 12, 92, 92, shape, fill='#400000', outline='#400000')
            c.bind('<Button-1>', lambda e, s=shape: self._select_shape(s))
            self.tray_cells.append(c)
        if self.selected_shape is not None and self.selected_shape in self.available_shapes:
            self.selection_var.set('Фигура выбрана. Укажите нужную ячейку матрицы справа.')
        elif self.available_shapes:
            self.selection_var.set('Выберите следующую фигуру в кассе слева и щёлкните по нужной ячейке.')
        else:
            self.selection_var.set('Все фигуры размещены. Нажмите «Готово».')

    def _start_reproduction_phase(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.phase = 'reproduce'
        n = len(self.current_positions)
        repr_time = min(self.cfg.start_reproduction_s + self.cfg.step_time_s * (n - 1), max(1.0, self._time_left_total()))
        self.reproduction_deadline = time.perf_counter() + repr_time
        self.message_var.set('Восстановите расположение фигур в матрице.')
        self._draw_reproduction_matrix()
        self._draw_tray(show=True)
        self._tick_reproduction_timeout()

    def _tick_reproduction_timeout(self):
        if self.phase != 'reproduce' or not self.win or not self.win.winfo_exists():
            return
        remaining = self.reproduction_deadline - time.perf_counter()
        self.info_var.set(f'Осталось времени: {_fmt_sec(self._time_left_total())}    На воспроизведение: {max(0, math.ceil(remaining))} c    Фигур: {self.current_n}')
        if remaining <= 0:
            self._finalize_cycle(success=False, reason='timeout')
            return
        self._track_after(self.win.after(100, self._tick_reproduction_timeout))

    def _select_shape(self, shape_id: int):
        if self.phase != 'reproduce' or shape_id not in self.available_shapes:
            return
        self.selected_shape = shape_id
        self._draw_tray(show=True)

    def _on_matrix_cell(self, idx: int):
        if self.phase != 'reproduce' or self.selected_shape is None:
            return
        if idx in self.placements:
            returned = self.placements[idx]
            if returned not in self.available_shapes:
                self.available_shapes.append(returned)
        self.placements[idx] = self.selected_shape
        if self.selected_shape in self.available_shapes:
            self.available_shapes.remove(self.selected_shape)
        self.selected_shape = None
        self._draw_reproduction_matrix()
        self._draw_tray(show=True)

    def _clear_placements(self):
        if self.phase != 'reproduce':
            return
        self.placements = {}
        self.available_shapes = list(self.current_shapes)
        self.selected_shape = None
        self._draw_reproduction_matrix()
        self._draw_tray(show=True)

    def _submit_cycle(self):
        if self.phase != 'reproduce':
            return
        self._finalize_cycle(success=None, reason='submitted')

    def _evaluate_cycle(self):
        expected = {cell: shape for cell, shape in zip(self.current_positions, self.current_shapes)}
        correct = sum(1 for cell, shape in expected.items() if self.placements.get(cell) == shape)
        success = len(self.placements) == len(expected) and correct == len(expected)
        return success, correct, expected

    def _finalize_cycle(self, success: bool | None, reason: str):
        if self.phase != 'reproduce':
            return
        self._cancel_afters()
        success_eval, correct, expected = self._evaluate_cycle()
        if success is None:
            success = success_eval
        elapsed = time.perf_counter() - self.cycle_started_at
        n = len(expected)
        cycle_info = {
            'n': n,
            'success': bool(success),
            'correct_count': int(correct),
            'elapsed_s': _round2(elapsed),
            'reason': reason,
            'positions': list(self.current_positions),
            'shapes': list(self.current_shapes),
        }
        self.result['cycles'].append(cycle_info)
        self.logger.log_event(
            self.session,
            event_type='method_cycle',
            screen='method_b',
            test_name='method_b',
            stage=f'n={n}',
            action='success' if success else 'error',
            elapsed_ms=int(elapsed * 1000),
            value=correct,
            note=f'reason={reason}; placed={len(self.placements)}',
        )
        if success:
            self.message_var.set(f'Успешно: воспроизведено {n} фигур. Следующий цикл будет сложнее.')
            self.current_n = min(self.cfg.max_items, self.current_n + 1)
        else:
            self.message_var.set(f'Ошибка: правильно размещено {correct} из {n}. Следующий цикл будет проще.')
            self.current_n = max(1, self.current_n - 1)
        self.phase = 'message'
        self._track_after(self.win.after(1000, self._start_cycle))

    def _compute_summary(self) -> dict:
        cycles = self.result.get('cycles', [])
        grouped_total = {n: 0 for n in range(1, self.cfg.max_items + 1)}
        grouped_success = {n: 0 for n in range(1, self.cfg.max_items + 1)}
        cycle_times = {n: [] for n in range(1, self.cfg.max_items + 1)}
        for cyc in cycles:
            n = int(cyc.get('n', 0))
            if 1 <= n <= self.cfg.max_items:
                grouped_total[n] += 1
                cycle_times[n].append(float(cyc.get('elapsed_s', 0.0)))
                if cyc.get('success'):
                    grouped_success[n] += 1
        t_values = {}
        by_n = {}
        for n in range(1, self.cfg.max_items + 1):
            n_total = int(grouped_total[n])
            if n_total <= 0:
                continue
            t_avg = sum(cycle_times[n]) / max(1, len(cycle_times[n]))
            k_usp = int(grouped_success[n])
            k_obsh = n_total
            gamma_n = _safe_ratio(k_usp, k_obsh, 0.0)
            t_norm = float(self.cfg.normative_times[n - 1]) if (n - 1) < len(self.cfg.normative_times) else float(self.cfg.normative_times[-1])
            t_n_zap = (float(t_avg) * float(k_usp)) / max(0.0001, float(t_norm) * float(k_obsh))
            t_values[str(n)] = _round2(t_n_zap)
            by_n[str(n)] = {
                'k_usp': k_usp,
                'k_obsh': k_obsh,
                'gamma_n': _round2(gamma_n),
                't_avg_s': _round2(t_avg),
                't_norm_s': _round2(t_norm),
                't_n_zap': _round2(t_n_zap),
            }
        max_correct = 0
        if cycles:
            max_correct = max(int(c.get('correct_count', 0)) for c in cycles)
        success_count = sum(1 for c in cycles if c.get('success'))
        summary = {
            'cycles_total': len(cycles),
            'successful_cycles': success_count,
            'accuracy_pct': _round2(100.0 * success_count / max(1, len(cycles))),
            'max_correct_count': max_correct,
            'calculation_version': 'method_b_docx_tn_avg_gamma_v1',
            't_values': t_values,
            'by_n': by_n,
            'tmin_b': t_values.get('1', 0.0),
            'tmedio_b': t_values.get('4', 0.0),
            'tmax_b': t_values.get('7', 0.0),
        }
        return summary

    def _finish(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.result['completed'] = True
        self.result['summary'] = self._compute_summary()
        self.logger.log_event(self.session, event_type='method_session', screen='method_b', test_name='method_b', action='finished', value=self.result['summary'].get('successful_cycles', 0), note='Методика B завершена по таймеру')
        self.win.destroy()

    def _abort(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.result['completed'] = False
        self.result['summary'] = self._compute_summary()
        self.logger.log_event(self.session, event_type='method_session', screen='method_b', test_name='method_b', action='aborted', value=len(self.result.get('cycles', [])), note='Пользователь прервал методику B')
        self.win.destroy()


class MethodCWindow:
    def __init__(self, parent: tk.Tk, session: SessionInfo, logger: ParticipantsLogger, base_dir: Path, config: MethodCConfig):
        self.parent = parent
        self.session = session
        self.logger = logger
        self.base_dir = base_dir
        self.cfg = config
        self.result = {'completed': False, 'stages': {}, 'summary': {}}
        self.win = None
        self.after_ids = []
        self.stage_index = 0
        self.stage_start_at = 0.0
        self.current_value = 0
        self.current_op = '+'
        self.current_operand = 0
        self.current_correct = 0
        self.current_cycle_started_at = 0.0
        self.exp_s = 1.0
        self.input_s = 3.0
        self.input_deadline = 0.0
        self.phase = 'idle'
        self.info_var = tk.StringVar(value='')
        self.prompt_var = tk.StringVar(value='')
        self.big_var = tk.StringVar(value='')
        self.entry_var = tk.StringVar(value='')
        self.stage_records = {}

    def run(self) -> dict:
        self._build_ui()
        self.logger.log_event(self.session, event_type='method_session', screen='method_c', test_name='method_c', action='started', note='Запущена методика C: счет в заданном темпе')
        self._start_stage(1)
        self.parent.wait_window(self.win)
        return self.result

    def _track_after(self, after_id):
        if after_id:
            self.after_ids.append(after_id)

    def _cancel_afters(self):
        if not self.win:
            return
        for after_id in self.after_ids:
            try:
                self.win.after_cancel(after_id)
            except Exception:
                pass
        self.after_ids.clear()

    def _build_ui(self):
        self.win = tk.Toplevel(self.parent)
        self.win.title('СПР - Тест C')
        self.win.configure(bg='#f5f7fb')
        self.win.transient(self.parent)
        self.win.grab_set()
        try:
            self.win.attributes('-fullscreen', True)
        except tk.TclError:
            self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
        self.win.bind('<Escape>', lambda _e: self._abort())
        self.win.protocol('WM_DELETE_WINDOW', self._abort)
        try:
            self.win.lift()
            self.win.focus_force()
        except Exception:
            pass

        frame = tk.Frame(self.win, bg='#f5f7fb')
        frame.pack(fill='both', expand=True)
        tk.Label(frame, text='Тест C · Счёт в заданном темпе', bg='#f5f7fb', fg='#102744', font=('Arial', 28, 'bold')).pack(pady=(28, 8))
        tk.Label(frame, text='Правило показа: зелёное число нужно прибавить, красное число нужно вычесть.', bg='#f5f7fb', fg='#2b4668', font=('Arial', 14, 'bold')).pack(pady=(0, 6))
        tk.Label(frame, textvariable=self.info_var, bg='#f5f7fb', fg='#41536c', font=('Arial', 15, 'bold')).pack(pady=(0, 20))
        tk.Label(frame, textvariable=self.prompt_var, bg='#f5f7fb', fg='#102744', font=('Arial', 18, 'bold')).pack(pady=(6, 18))
        self.big_label = tk.Label(frame, textvariable=self.big_var, bg='#f5f7fb', fg='#228b22', font=('Arial', 90, 'bold'))
        self.big_label.pack(pady=(10, 18))
        entry_wrap = tk.Frame(frame, bg='#f5f7fb')
        entry_wrap.pack(pady=10)
        tk.Label(entry_wrap, text='Введите новый результат:', bg='#f5f7fb', fg='#102744', font=('Arial', 16, 'bold')).pack(pady=(0, 8))
        self.entry = tk.Entry(entry_wrap, textvariable=self.entry_var, font=('Arial', 26), justify='center', width=10)
        self.entry.pack()
        self.entry.bind('<Return>', lambda _e: self._submit_answer())
        btns = tk.Frame(frame, bg='#f5f7fb')
        btns.pack(pady=(18, 0))
        tk.Button(btns, text='Ответ', command=self._submit_answer, bg='#42d95b', activebackground='#35b74a', font=('Arial', 14, 'bold'), width=10).pack(side='left', padx=8)
        tk.Button(btns, text='Выход', command=self._abort, bg='#d64a4a', activebackground='#b93c3c', fg='white', font=('Arial', 14, 'bold'), width=10).pack(side='left', padx=8)

    def _stage_digits(self, stage_index: int) -> int:
        return stage_index

    def _stage_limits(self, stage_index: int) -> tuple[int, int]:
        digits = self._stage_digits(stage_index)
        if digits == 1:
            return 0, 9
        return 10 ** (digits - 1), (10 ** digits) - 1

    def _generate_operand(self, current: int, stage_index: int):
        lo, hi = self._stage_limits(stage_index)
        choices = []
        max_add = hi - current
        if max_add >= lo:
            choices.append('+')
        max_sub = current - lo
        if max_sub >= lo:
            choices.append('-')
        if not choices:
            return '+', lo, current
        op = random.choice(choices)
        if op == '+':
            operand = random.randint(lo, max_add)
            correct = current + operand
        else:
            operand = random.randint(lo, max_sub)
            correct = current - operand
        return op, operand, correct

    def _start_stage(self, stage_index: int):
        self._cancel_afters()
        self.stage_index = stage_index
        if stage_index > 3:
            self._finish()
            return
        lo, hi = self._stage_limits(stage_index)
        self.exp_s = float(self.cfg.exposure_start_s[stage_index - 1])
        self.input_s = float(self.cfg.input_start_s[stage_index - 1])
        self.current_value = random.randint(lo, hi)
        self.stage_start_at = time.perf_counter()
        self.stage_records[stage_index] = {'cycles': [], 'Gq': 0, 'Fq': 0}
        self.prompt_var.set(f'Этап {stage_index}. Запомните стартовое число.')
        self.big_var.set(str(self.current_value))
        self.big_label.configure(fg='#163d7a')
        self.entry_var.set('')
        self.entry.configure(state='disabled')
        self._tick_stage_clock()
        self._track_after(self.win.after(int(self.exp_s * 1000), self._start_operation_cycle))

    def _stage_time_left(self) -> float:
        total = float(self.cfg.stage_time_s[self.stage_index - 1])
        return max(0.0, total - (time.perf_counter() - self.stage_start_at))

    def _tick_stage_clock(self):
        if not self.win or not self.win.winfo_exists() or self.phase == 'finished':
            return
        self.info_var.set(
            f'Этап {self.stage_index} из 3    Цифр в числе: {self.stage_index}    '
            f'Осталось в этапе: {_fmt_sec(self._stage_time_left())}    '
            f'Экспозиция: {self.exp_s:.0f} с    Ввод: {self.input_s:.0f} с'
        )
        self._track_after(self.win.after(200, self._tick_stage_clock))

    def _start_operation_cycle(self):
        self._cancel_afters()
        if self._stage_time_left() <= 0.2:
            self.prompt_var.set(f'Этап {self.stage_index} завершён. Переход к следующему.')
            self.big_var.set('')
            self.entry.configure(state='disabled')
            self._tick_stage_clock()
            self._track_after(self.win.after(1000, lambda: self._start_stage(self.stage_index + 1)))
            return
        self.phase = 'show_operand'
        self.current_op, self.current_operand, self.current_correct = self._generate_operand(self.current_value, self.stage_index)
        self.current_cycle_started_at = time.perf_counter()
        color = '#2a972f' if self.current_op == '+' else '#b62828'
        action = 'прибавьте' if self.current_op == '+' else 'вычтите'
        self.prompt_var.set(
            f'Используйте текущее число {self.current_value} как исходный результат. '
            f'{action.capitalize()} показанное число.'
        )
        self.big_var.set(str(self.current_operand))
        self.big_label.configure(fg=color)
        self.entry_var.set('')
        self.entry.configure(state='disabled')
        self._tick_stage_clock()
        self._track_after(self.win.after(int(self.exp_s * 1000), self._begin_input_phase))

    def _begin_input_phase(self):
        self.phase = 'input'
        self.prompt_var.set('Введите новый результат вычисления.')
        self.big_var.set('?')
        self.big_label.configure(fg='#163d7a')
        self.entry.configure(state='normal')
        self.entry.focus_set()
        self.entry.selection_range(0, tk.END)
        self.input_deadline = time.perf_counter() + self.input_s
        self._tick_input_timeout()

    def _tick_input_timeout(self):
        if self.phase != 'input':
            return
        remaining = self.input_deadline - time.perf_counter()
        if remaining <= 0:
            self._resolve_cycle(success=False, timeout=True)
            return
        self.prompt_var.set(f'Введите новый результат вычисления. Осталось {max(0, math.ceil(remaining))} с.')
        self._track_after(self.win.after(100, self._tick_input_timeout))

    def _submit_answer(self):
        if self.phase != 'input':
            return
        text = self.entry_var.get().strip().replace('−', '-')
        try:
            value = int(text)
        except Exception:
            return
        self._resolve_cycle(success=(value == self.current_correct), timeout=False, given=value)

    def _resolve_cycle(self, success: bool, timeout: bool, given: int | None = None):
        if self.phase not in ('input', 'show_operand'):
            return
        self._cancel_afters()
        stage = self.stage_records[self.stage_index]
        elapsed = time.perf_counter() - self.current_cycle_started_at
        stage['Gq'] += 1
        cycle_item = {
            'operand': self.current_operand,
            'op': self.current_op,
            'start_value': self.current_value,
            'correct_value': self.current_correct,
            'given_value': given,
            'success': bool(success),
            'elapsed_s': _round2(elapsed),
            'exp_s': _round2(self.exp_s),
            'input_s': _round2(self.input_s),
            'timeout': bool(timeout),
        }
        if success:
            stage['Fq'] += 1
        stage['cycles'].append(cycle_item)
        self.logger.log_event(
            self.session,
            event_type='method_cycle',
            screen='method_c',
            test_name='method_c',
            stage=f'stage_{self.stage_index}',
            action='success' if success else 'error',
            elapsed_ms=int(elapsed * 1000),
            value=self.current_correct,
            note=f'given={given}; timeout={int(timeout)}; op={self.current_op}{self.current_operand}',
        )
        step = float(self.cfg.time_step_s[self.stage_index - 1])
        base_exp = float(self.cfg.exposure_start_s[self.stage_index - 1])
        base_input = float(self.cfg.input_start_s[self.stage_index - 1])
        self.current_value = self.current_correct
        if success:
            self.exp_s = max(base_exp, self.exp_s - step)
            self.input_s = max(base_input, self.input_s - step)
            self.prompt_var.set('Верно. Продолжаем.')
        else:
            self.exp_s += step
            self.input_s += step
            self.prompt_var.set(f'Ошибка, правильный результат {self.current_correct}. Продолжаем.')
        self.big_var.set(str(self.current_correct))
        self.big_label.configure(fg='#163d7a')
        self.entry_var.set('')
        self.entry.configure(state='disabled')
        self.phase = 'feedback'
        self._tick_stage_clock()
        self._track_after(self.win.after(900, self._start_operation_cycle))

    def _compute_summary(self) -> dict:

        stage_payload = {}
        for stage_index in range(1, 4):
            rec = self.stage_records.get(stage_index, {'cycles': [], 'Gq': 0, 'Fq': 0})
            cycle_times = [float(c['elapsed_s']) for c in rec['cycles']]
            t_avg = sum(cycle_times) / len(cycle_times) if cycle_times else 0.0
            gq = int(rec.get('Gq', 0) or 0)
            fq = int(rec.get('Fq', 0) or 0)
            # Test C document formula:
            # t_count_L = (t_avg_L * k_success_L) / (t_norm_L * k_total_L)
            t_norm = max(0.0001, float(self.cfg.normative_cycle_times[stage_index - 1]))
            t_value = _round2((t_avg * fq) / (t_norm * gq)) if gq > 0 else 0.0
            h = _safe_ratio(fq, gq, 0.0)
            stage_payload[str(stage_index)] = {
                'digits': stage_index,
                'Gq': gq,
                'Fq': fq,
                'Hq': _round2(h),
                'avg_cycle_time_s': _round2(t_avg),
                't_value': t_value,
                'cycles': rec['cycles'],
            }
        summary = {
            'stages': stage_payload,
            'tmin_c': stage_payload['1']['t_value'],
            'tmedio_c': stage_payload['2']['t_value'],
            'tmax_c': stage_payload['3']['t_value'],
            'total_cycles': sum(stage_payload[s]['Gq'] for s in ('1', '2', '3')),
            'successful_cycles': sum(stage_payload[s]['Fq'] for s in ('1', '2', '3')),
        }
        return summary

    def _finish(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.phase = 'finished'
        self.result['completed'] = True
        self.result['summary'] = self._compute_summary()
        self.result['stages'] = self.result['summary'].get('stages', {})
        self.logger.log_event(self.session, event_type='method_session', screen='method_c', test_name='method_c', action='finished', value=self.result['summary'].get('successful_cycles', 0), note='Методика C завершена')
        self.win.destroy()

    def _abort(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.phase = 'finished'
        self.result['completed'] = False
        self.result['summary'] = self._compute_summary()
        self.result['stages'] = self.result['summary'].get('stages', {})
        self.logger.log_event(self.session, event_type='method_session', screen='method_c', test_name='method_c', action='aborted', value=self.result['summary'].get('successful_cycles', 0), note='Пользователь прервал методику C')
        self.win.destroy()


def _logic_spec_key(spec: dict) -> tuple:
    return (spec['shape'], spec['count'], spec['fill'], spec['rotation'])


LOGIC_DISTINCT_SHAPES = [0, 2, 4, 5, 8, 10, 12, 14]
LOGIC_FILL_MODES = [0, 1, 2]


def _make_options(correct: dict, rng: random.Random, count: int = 6) -> list[dict]:
    variants = {_logic_spec_key(correct): dict(correct)}
    attempts = 0
    shape_pool = [s for s in LOGIC_DISTINCT_SHAPES if s != correct['shape']]
    while len(variants) < count and attempts < 1000:
        attempts += 1
        cand = dict(correct)
        tweak = rng.choice(['shape', 'count', 'fill', 'shape_count', 'shape_fill'])
        if tweak == 'shape':
            cand['shape'] = rng.choice(shape_pool)
        elif tweak == 'count':
            cand['count'] = rng.choice([x for x in [1, 2, 3] if x != correct['count']])
        elif tweak == 'fill':
            cand['fill'] = rng.choice([x for x in LOGIC_FILL_MODES if x != correct['fill']])
        elif tweak == 'shape_count':
            cand['shape'] = rng.choice(shape_pool)
            cand['count'] = rng.choice([x for x in [1, 2, 3] if x != correct['count']])
        else:
            cand['shape'] = rng.choice(shape_pool)
            cand['fill'] = rng.choice([x for x in LOGIC_FILL_MODES if x != correct['fill']])
        cand['rotation'] = 0
        variants[_logic_spec_key(cand)] = cand
    out = list(variants.values())
    rng.shuffle(out)
    if not any(_logic_spec_key(item) == _logic_spec_key(correct) for item in out):
        out = out[:count - 1] + [dict(correct)]
    rng.shuffle(out)
    return out[:count]


def _make_min_task(rng: random.Random) -> dict:
    shape_seq = rng.sample(LOGIC_DISTINCT_SHAPES, 3)
    fill = rng.choice(LOGIC_FILL_MODES)
    count = rng.choice([1, 2, 3])
    matrix = []
    for r in range(3):
        for c in range(3):
            matrix.append({'shape': shape_seq[c], 'count': count, 'fill': fill, 'rotation': 0})
    correct = dict(matrix[-1])
    matrix[-1] = None
    return {'difficulty': 'min', 'matrix': matrix, 'correct': correct, 'options': _make_options(correct, rng)}


def _make_medio_task(rng: random.Random) -> dict:
    shape_seq = rng.sample(LOGIC_DISTINCT_SHAPES, 3)
    count_seq = rng.sample([1, 2, 3], 3)
    fill = rng.choice(LOGIC_FILL_MODES)
    matrix = []
    for r in range(3):
        for c in range(3):
            matrix.append({'shape': shape_seq[c], 'count': count_seq[r], 'fill': fill, 'rotation': 0})
    correct = dict(matrix[-1])
    matrix[-1] = None
    return {'difficulty': 'medio', 'matrix': matrix, 'correct': correct, 'options': _make_options(correct, rng)}


def _make_max_task(rng: random.Random) -> dict:
    shape_seq = rng.sample(LOGIC_DISTINCT_SHAPES, 3)
    count_seq = rng.sample([1, 2, 3], 3)
    fill_seq = rng.sample(LOGIC_FILL_MODES, 3)
    matrix = []
    for r in range(3):
        for c in range(3):
            matrix.append({
                'shape': shape_seq[c],
                'count': count_seq[r],
                'fill': fill_seq[(r + c) % 3],
                'rotation': 0,
            })
    correct = dict(matrix[-1])
    matrix[-1] = None
    return {'difficulty': 'max', 'matrix': matrix, 'correct': correct, 'options': _make_options(correct, rng)}


def generate_d_block(block_index: int) -> list[dict]:
    rng = random.Random(1000 + block_index)
    tasks = []
    for _ in range(2):
        tasks.append(_make_min_task(rng))
    for _ in range(4):
        tasks.append(_make_medio_task(rng))
    for _ in range(4):
        tasks.append(_make_max_task(rng))
    rng.shuffle(tasks)
    return tasks


class MethodDWindow:
    def __init__(self, parent: tk.Tk, session: SessionInfo, logger: ParticipantsLogger, base_dir: Path, config: MethodDConfig):
        self.parent = parent
        self.session = session
        self.logger = logger
        self.base_dir = base_dir
        self.cfg = config
        self.result = {'completed': False, 'tasks': [], 'summary': {}}
        self.win = None
        self.after_ids = []
        self.info_var = tk.StringVar(value='')
        self.prompt_var = tk.StringVar(value='Выберите фрагмент, который логически завершает матрицу.')
        self.feedback_var = tk.StringVar(value='')
        self.block_index = random.choice([1, 2, 3])
        self.tasks = generate_d_block(self.block_index)
        self.current_task_index = -1
        self.current_task_started_at = 0.0
        self.total_started_at = 0.0
        self.option_canvases = []
        self.matrix_canvas = None
        self.current_task = None
        self.phase = 'idle'
        self.next_btn = None
        self.current_task_deadline = 0.0
        base_times = getattr(self.cfg, 'answer_time_s', {}) or {}
        self.answer_limits = {
            'min': float(base_times.get('min', 25.0)),
            'medio': float(base_times.get('medio', 35.0)),
            'max': float(base_times.get('max', 45.0)),
        }

    def run(self) -> dict:
        self._build_ui()
        self.total_started_at = time.perf_counter()
        self.logger.log_event(self.session, event_type='method_session', screen='method_d', test_name='method_d', action='started', note=f'Запущен блок D{self.block_index}')
        self._start_next_task()
        self.parent.wait_window(self.win)
        return self.result

    def _track_after(self, after_id):
        if after_id:
            self.after_ids.append(after_id)

    def _cancel_afters(self):
        if not self.win:
            return
        for after_id in self.after_ids:
            try:
                self.win.after_cancel(after_id)
            except Exception:
                pass
        self.after_ids.clear()

    def _build_ui(self):
        self.win = tk.Toplevel(self.parent)
        self.win.title('СПР - Тест D')
        self.win.configure(bg='#f4f6fa')
        self.win.transient(self.parent)
        self.win.grab_set()
        try:
            self.win.attributes('-fullscreen', True)
        except tk.TclError:
            self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
        self.win.bind('<Escape>', lambda _e: self._abort())
        self.win.protocol('WM_DELETE_WINDOW', self._abort)
        try:
            self.win.lift()
            self.win.focus_force()
        except Exception:
            pass

        root = tk.Frame(self.win, bg='#f4f6fa')
        root.pack(fill='both', expand=True)
        tk.Label(root, text='Методика D · Сложная логическая деятельность', bg='#f4f6fa', fg='#102744', font=('Arial', 28, 'bold')).pack(pady=(24, 8))
        tk.Label(root, textvariable=self.info_var, bg='#f4f6fa', fg='#41536c', font=('Arial', 15, 'bold')).pack(pady=(0, 8))
        tk.Label(root, textvariable=self.prompt_var, bg='#f4f6fa', fg='#102744', font=('Arial', 16, 'bold')).pack(pady=(0, 10))
        tk.Label(root, textvariable=self.feedback_var, bg='#f4f6fa', fg='#4a5e7d', font=('Arial', 13, 'bold')).pack(pady=(0, 10))

        self.matrix_canvas = tk.Canvas(root, width=650, height=420, bg='white', highlightthickness=1, highlightbackground='#c7d3e1')
        self.matrix_canvas.pack(pady=(6, 14))

        options = tk.Frame(root, bg='#f4f6fa')
        options.pack(pady=8)
        for i in range(6):
            cv = tk.Canvas(options, width=170, height=140, bg='white', highlightthickness=3, highlightbackground='#afbdd1', cursor='hand2')
            cv.grid(row=i // 3, column=i % 3, padx=14, pady=14)
            cv.bind('<Button-1>', lambda e, idx=i: self._answer(idx))
            self.option_canvases.append(cv)

        btns = tk.Frame(root, bg='#f4f6fa')
        btns.pack(pady=(10, 0))
        self.next_btn = tk.Button(btns, text='Следующее задание', command=self._start_next_task, state=tk.DISABLED, bg='#4f78ff', activebackground='#4269e0', fg='white', font=('Arial', 14, 'bold'), width=18)
        self.next_btn.pack(side='left', padx=(0, 12))
        tk.Button(btns, text='Выход', command=self._abort, bg='#d64a4a', activebackground='#b93c3c', fg='white', font=('Arial', 14, 'bold'), width=10).pack(side='left')

    def _time_left(self) -> float:
        return max(0.0, self.cfg.total_test_s - (time.perf_counter() - self.total_started_at))

    def _tick_clock(self):
        if not self.win or not self.win.winfo_exists() or self.phase == 'finished':
            return
        self.info_var.set(f'Блок D{self.block_index}    Задание {max(1, self.current_task_index + 1)} из {len(self.tasks)}    Осталось времени: {_fmt_sec(self._time_left())}')
        self._track_after(self.win.after(250, self._tick_clock))

    def _render_logic_cell(self, canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, spec: dict | None):
        canvas.create_rectangle(x1, y1, x2, y2, outline='#d5deea', width=2, fill='#fbfdff')
        if spec:
            draw_basic_symbol(canvas, x1 + 12, y1 + 12, x2 - 12, y2 - 12, spec['shape'], outline='#1b2b40', fill='#1b2b40', rotation=spec['rotation'], fill_mode=spec['fill'], count=spec['count'])
        else:
            canvas.create_text((x1 + x2) / 2, (y1 + y2) / 2, text='?', fill='#6d7f98', font=('Arial', 48, 'bold'))

    def _draw_task(self):
        task = self.current_task
        self.matrix_canvas.delete('all')
        x0, y0 = 40, 30
        cell = 110
        gap = 12
        for idx, spec in enumerate(task['matrix']):
            r, c = divmod(idx, 3)
            x1 = x0 + c * (cell + gap)
            y1 = y0 + r * (cell + gap)
            self._render_logic_cell(self.matrix_canvas, x1, y1, x1 + cell, y1 + cell, spec)
        self.matrix_canvas.create_text(430, 200, text='→', fill='#7385a2', font=('Arial', 42, 'bold'))
        for i, cv in enumerate(self.option_canvases):
            cv.delete('all')
            cv.configure(highlightbackground='#afbdd1', highlightthickness=3)
            cv.create_text(18, 16, text=str(i + 1), fill='#7c8ea8', font=('Arial', 10, 'bold'))
            self._render_logic_cell(cv, 22, 18, 148, 122, task['options'][i])
        diff_name = {'min': 'минимальная', 'medio': 'средняя', 'max': 'максимальная'}[task['difficulty']]
        self.prompt_var.set(f'Выберите фрагмент, который завершает матрицу. Трудоёмкость: {diff_name}.')
        self.feedback_var.set('После ответа можно спокойно перейти к следующему заданию.')
        self.phase = 'task'
        if self.next_btn:
            self.next_btn.configure(state=tk.DISABLED, text='Следующее задание')

    def _start_next_task(self):
        self._cancel_afters()
        if self._time_left() <= 1.0 or self.current_task_index + 1 >= len(self.tasks):
            self._finish()
            return
        self.current_task_index += 1
        self.current_task = self.tasks[self.current_task_index]
        self.current_task_started_at = time.perf_counter()
        self._draw_task()
        self._tick_clock()

    def _answer(self, option_index: int):
        if not self.current_task or self.phase != 'task':
            return
        self.phase = 'feedback'
        chosen = self.current_task['options'][option_index]
        correct_index = next((i for i, item in enumerate(self.current_task['options']) if _logic_spec_key(item) == _logic_spec_key(self.current_task['correct'])), 0)
        correct = _logic_spec_key(chosen) == _logic_spec_key(self.current_task['correct'])
        elapsed = time.perf_counter() - self.current_task_started_at
        item = {
            'task_no': self.current_task_index + 1,
            'difficulty': self.current_task['difficulty'],
            'correct': bool(correct),
            'elapsed_s': _round2(elapsed),
            'option_index': option_index,
            'correct_option_index': correct_index,
        }
        self.result['tasks'].append(item)
        self.logger.log_event(
            self.session,
            event_type='method_task',
            screen='method_d',
            test_name='method_d',
            stage=self.current_task['difficulty'],
            action='success' if correct else 'error',
            elapsed_ms=int(elapsed * 1000),
            value=option_index + 1,
            note=f'task={self.current_task_index + 1}; block=D{self.block_index}; correct={correct_index + 1}',
        )
        for i, cv in enumerate(self.option_canvases):
            if i == correct_index:
                cv.configure(highlightbackground='#33b864', highlightthickness=4)
            elif i == option_index and not correct:
                cv.configure(highlightbackground='#e26565', highlightthickness=4)
            else:
                cv.configure(highlightbackground='#afbdd1', highlightthickness=3)
        if correct:
            self.prompt_var.set('Верно. Можно переходить к следующему заданию.')
            self.feedback_var.set(f'Выбран вариант №{option_index + 1}. Время ответа: {_round2(elapsed)} с.')
        else:
            self.prompt_var.set(f'Неверно. Правильный вариант: №{correct_index + 1}.')
            self.feedback_var.set('Следующее задание не запускается автоматически. Сначала можно посмотреть правильный ответ.')
        if self.next_btn:
            last_or_timeout = (self.current_task_index + 1 >= len(self.tasks)) or (self._time_left() <= 1.0)
            self.next_btn.configure(state=tk.NORMAL, text='Завершить блок' if last_or_timeout else 'Следующее задание')

    def _compute_summary(self) -> dict:
        groups = {'min': [], 'medio': [], 'max': []}
        for item in self.result.get('tasks', []):
            groups[item['difficulty']].append(item)
        out = {}
        for key in ('min', 'medio', 'max'):
            items = groups[key]
            correct_items = [x for x in items if x.get('correct')]
            avg_time = sum(float(x['elapsed_s']) for x in correct_items) / len(correct_items) if correct_items else 0.0
            gd = len(correct_items)
            td = _round2(avg_time)
            out[key] = {
                'correct_count': gd,
                'avg_time_s': td,
                't_value': _round2((td * gd) / max(0.0001, float(self.cfg.normative_times[key]) * float(self.cfg.normative_correct[key]))) if gd else 0.0,
            }
        summary = {
            'block_index': self.block_index,
            'groups': out,
            'tmin_d': out['min']['t_value'],
            'tmedio_d': out['medio']['t_value'],
            'tmax_d': out['max']['t_value'],
            'tasks_total': len(self.result.get('tasks', [])),
            'tasks_correct': sum(1 for x in self.result.get('tasks', []) if x.get('correct')),
        }
        return summary

    def _finish(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.phase = 'finished'
        self.result['completed'] = True
        self.result['summary'] = self._compute_summary()
        self.logger.log_event(self.session, event_type='method_session', screen='method_d', test_name='method_d', action='finished', value=self.result['summary'].get('tasks_correct', 0), note=f'Методика D завершена, блок D{self.block_index}')
        self.win.destroy()

    def _abort(self):
        if not self.win or not self.win.winfo_exists():
            return
        self._cancel_afters()
        self.phase = 'finished'
        self.result['completed'] = False
        self.result['summary'] = self._compute_summary()
        self.logger.log_event(self.session, event_type='method_session', screen='method_d', test_name='method_d', action='aborted', value=self.result['summary'].get('tasks_correct', 0), note='Пользователь прервал методику D')
        self.win.destroy()


# ====== Патчи StartPageApp ======

def _build_method_b_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = {
        'test_code': 'B',
        'test_label': TEST_LABELS['B'],
        'completed_at': datetime.now().isoformat(timespec='seconds'),
        'session_id': session.session_id,
        'participant': {'name': session.name, 'age': session.age, 'gender': session.gender},
        'cycles': result.get('cycles', []),
        'summary': result.get('summary', {}),
    }
    payload['result_path'] = save_method_payload(self.base_dir, 'B', session.session_id, payload)
    return payload


