def _run_modal_method(self, window_factory):
    self.set_enabled(False)
    self.root.update_idletasks()
    # Важно: для Toplevel-окон B/C/D нельзя прятать root через withdraw().
    # На части систем вместе с родителем исчезает и дочернее окно,
    # поэтому пользователь видит "всё пропало".
    try:
        result = window_factory()
    finally:
        try:
            self.root.deiconify()
        except Exception:
            pass
        self.open_fullscreen()
        self.root.update_idletasks()
        try:
            self.root.lift()
            self.root.focus_force()
        except Exception:
            pass
        try:
            self.refresh_menu_state()
        except Exception:
            pass
        self.set_enabled(True)
    return result


def _run_method_b(self, session: SessionInfo) -> dict:
    cfg = load_method_b_config(self.base_dir)
    result = _run_modal_method(self, lambda: MethodBWindow(self.root, session, self.logger, self.base_dir, cfg).run())
    if result.get('completed'):
        payload = _build_method_b_payload(self, session, result)
        self.progress_store.save_test_result(self.current_profile, 'B', payload)
        self.logger.log_event(session, event_type='summary', screen='test_menu', test_name='method_b', action='session_finished', value=payload['summary'].get('successful_cycles', 0), note='Методика B завершена и сохранена')
        self.menu_status_var.set('Тест B завершён. Следующим по порядку открыт Тест C.')
        messagebox.showinfo('Готово', 'Тест B завершён. Следующим по порядку открыт Тест C.')
    else:
        self.menu_status_var.set('Тест B был прерван. Уже записанные данные сохранены, прогресс не засчитан.')
        messagebox.showwarning('Остановлено', 'Тест B был прерван. Уже записанные данные сохранены, прогресс не засчитан.')
    return result


