def _draw_summary_cards(parent: tk.Widget, cards: list[tuple[str, str, str, str]]):
    grid = tk.Frame(parent, bg=parent['bg'])
    for i, (title, value, subtitle, accent) in enumerate(cards):
        card = tk.Frame(grid, bg='white', bd=0, highlightbackground='#d8e1ec', highlightthickness=1)
        card.grid(row=0, column=i, padx=10, pady=10, sticky='nsew')
        tk.Frame(card, bg=accent, height=6).pack(fill='x')
        tk.Label(card, text=title, bg='white', fg='#425065', font=('Arial', 11, 'bold')).pack(anchor='w', padx=14, pady=(12, 4))
        tk.Label(card, text=value, bg='white', fg='#102744', font=('Arial', 22, 'bold')).pack(anchor='w', padx=14)
        tk.Label(card, text=subtitle, bg='white', fg='#657385', font=('Arial', 10), wraplength=200, justify='left').pack(anchor='w', padx=14, pady=(2, 12))
    return grid


def _open_results_top(self, title: str):
    top = tk.Toplevel(self.root)
    top.title(title)
    top.configure(bg='#eef3f8')
    top.transient(self.root)
    top.grab_set()
    try:
        top.attributes('-fullscreen', True)
    except tk.TclError:
        top.geometry(f"{self.root.winfo_screenwidth()}x{self.root.winfo_screenheight()}+0+0")
    top.bind('<Escape>', lambda _e: top.destroy())

    shell = tk.Frame(top, bg='#eef3f8')
    shell.pack(fill='both', expand=True)

    toolbar = tk.Frame(shell, bg='#eef3f8')
    toolbar.pack(fill='x', side='top')
    tk.Button(
        toolbar,
        text='Закрыть',
        command=top.destroy,
        bg=NEXT_BG,
        activebackground=NEXT_ACTIVE,
        relief='raised',
        bd=3,
        cursor='hand2',
        font=('Arial', 12, 'bold'),
        width=12,
    ).pack(side='right', padx=24, pady=(16, 4))

    content = tk.Frame(shell, bg='#eef3f8')
    content.pack(fill='both', expand=True)

    canvas = tk.Canvas(content, bg='#eef3f8', highlightthickness=0)
    scrollbar = tk.Scrollbar(content, orient='vertical', command=canvas.yview)
    canvas.configure(yscrollcommand=scrollbar.set)
    scrollbar.pack(side='right', fill='y')
    canvas.pack(side='left', fill='both', expand=True)

    body = tk.Frame(canvas, bg='#eef3f8')
    window_id = canvas.create_window((0, 0), window=body, anchor='nw')

    def _sync(_event=None):
        canvas.configure(scrollregion=canvas.bbox('all'))
        canvas.itemconfigure(window_id, width=canvas.winfo_width())

    def _on_mousewheel(event):
        delta = 0
        if getattr(event, 'delta', 0):
            delta = -int(event.delta / 120)
        elif getattr(event, 'num', None) == 4:
            delta = -1
        elif getattr(event, 'num', None) == 5:
            delta = 1
        if delta:
            canvas.yview_scroll(delta, 'units')
            return 'break'
        return None

    def _bind_mousewheel(_event=None):
        canvas.bind_all('<MouseWheel>', _on_mousewheel)
        canvas.bind_all('<Button-4>', _on_mousewheel)
        canvas.bind_all('<Button-5>', _on_mousewheel)

    def _unbind_mousewheel(_event=None):
        canvas.unbind_all('<MouseWheel>')
        canvas.unbind_all('<Button-4>')
        canvas.unbind_all('<Button-5>')

    body.bind('<Configure>', _sync)
    canvas.bind('<Configure>', _sync)
    top.bind('<Enter>', _bind_mousewheel)
    top.bind('<Leave>', _unbind_mousewheel)
    top.protocol('WM_DELETE_WINDOW', top.destroy)
    top.bind('<Destroy>', lambda _e: _unbind_mousewheel())
    return top, body


def _add_info_box(parent: tk.Widget, title: str, text: str, accent: str = '#6b7dff'):
    box = tk.Frame(parent, bg='white', highlightthickness=1, highlightbackground='#d8e1ec')
    tk.Frame(box, bg=accent, height=6).pack(fill='x')
    tk.Label(box, text=title, bg='white', fg='#102744', font=('Arial', 13, 'bold')).pack(anchor='w', padx=16, pady=(12, 4))
    tk.Label(box, text=text, bg='white', fg='#33455c', font=('Arial', 11), justify='left', wraplength=1080).pack(anchor='w', padx=16, pady=(0, 14))
    return box


def _draw_stage_time_chart(parent: tk.Widget, title: str, cycles: list[dict]):
    canvas = tk.Canvas(parent, width=1020, height=190, bg='white', highlightthickness=1, highlightbackground='#d8e1ec')
    canvas.create_text(510, 20, text=title, fill='#102744', font=('Arial', 14, 'bold'))
    if not cycles:
        canvas.create_text(510, 95, text='Для этого этапа пока нет ответов.', fill='#61748c', font=('Arial', 12))
        return canvas

    x1, y1, x2, y2 = 70, 155, 970, 48
    totals = [max(0.0, float(c.get('exp_s', 0.0)) + float(c.get('input_s', 0.0))) for c in cycles]
    max_y = max(1.0, max(totals) * 1.15)
    n = len(cycles)

    canvas.create_line(x1, y1, x2, y1, fill='#9aa9bb', width=2)
    canvas.create_line(x1, y1, x1, y2, fill='#9aa9bb', width=2)
    canvas.create_text(18, y2 - 6, text='сек', fill='#5c6c80', font=('Arial', 9, 'bold'))
    canvas.create_text((x1 + x2) / 2, 178, text='Номер ответа', fill='#5c6c80', font=('Arial', 10, 'bold'))

    for j in range(5):
        yy = y1 - (y1 - y2) * j / 4
        val = max_y * j / 4
        canvas.create_line(x1 - 5, yy, x1, yy, fill='#9aa9bb')
        canvas.create_text(x1 - 10, yy, text=f'{val:.1f}', anchor='e', fill='#5c6c80', font=('Arial', 9, 'bold'))

    pts = []
    for idx, cyc in enumerate(cycles, start=1):
        xx = (x1 + x2) / 2 if n == 1 else x1 + (x2 - x1) * (idx - 1) / (n - 1)
        total_t = max(0.0, float(cyc.get('exp_s', 0.0)) + float(cyc.get('input_s', 0.0)))
        yy = y1 - (y1 - y2) * total_t / max_y
        pts.extend([xx, yy])
        color = '#36a257' if cyc.get('success') else '#d15a5a'
        canvas.create_oval(xx - 4, yy - 4, xx + 4, yy + 4, fill=color, outline='')
        if n <= 16 or idx in (1, n) or idx % 3 == 0:
            canvas.create_text(xx, y1 + 16, text=str(idx), fill='#4d5c70', font=('Arial', 9, 'bold'))
        if idx <= 12 or idx == n:
            canvas.create_text(xx, yy - 12, text=f'{total_t:.1f}', fill=color, font=('Arial', 8, 'bold'))
    if len(pts) >= 4:
        canvas.create_line(*pts, fill='#3b78d8', width=2, smooth=True)
    return canvas


def _interpret_method_a(summary: dict, reports: list[dict]) -> str:
    total_time = float(summary.get('total_time_s', 0.0))
    stability = float(summary.get('avg_stability_pct', 0.0))
    mean_xy = float(summary.get('avg_mean_xy_cm', 0.0))
    crashes = int(summary.get('total_crashes', 0))
    best_stage = summary.get('best_stage')

    if not reports:
        if total_time <= 0:
            return 'Пока нет данных для расшифровки этого теста.'
        parts = [
            f'Тест длился {total_time:.1f} с.',
            f'В среднем объект удерживался в зелёной зоне {stability:.0f}% времени.',
            f'Среднее отклонение от центра составило {mean_xy:.2f} см.',
        ]
        if crashes:
            parts.append(f'За весь тест было {crashes} выходов из зоны.')
        if best_stage:
            parts.append(f'Самым ровным получился этап {best_stage}.')
        return ' '.join(parts)

    stage_names = {1: 'по оси X', 2: 'по осям X и Y', 3: 'по осям X, Y и крену'}
    best_report = None
    if best_stage:
        for rep in reports:
            if int(rep.get('stage_no', 0)) == int(best_stage):
                best_report = rep
                break
    if best_report is None and reports:
        best_report = max(
            reports,
            key=lambda r: (
                float(r.get('stability_pct', 0.0)),
                -int(r.get('crashes', 0)),
                -float(r.get('mean_abs_xy_cm', 999.0)),
            ),
        )
        best_stage = int(best_report.get('stage_no', 0) or 0) or None

    worst_report = min(
        reports,
        key=lambda r: (
            float(r.get('stability_pct', 0.0)),
            int(r.get('crashes', 0)),
            float(r.get('mean_abs_xy_cm', 0.0)),
        ),
    )
    worst_stage = int(worst_report.get('stage_no', 0) or 0) or None

    if stability >= 65 and mean_xy <= 4.5 and crashes <= 1:
        overall = 'Контроль движения выглядит устойчивым: объект в целом удерживался близко к центру цели.'
    elif stability >= 35 and mean_xy <= 8.5 and crashes <= 4:
        overall = 'Контроль движения сохранён, но тест требовал заметной коррекции и постоянного подруливания.'
    else:
        overall = 'Тест шёл напряжённо: объект часто уходил от центра, а удержание в целевой зоне давалось трудно.'

    details = [
        f'За три этапа тест занял {total_time:.1f} с.',
        f'В среднем объект удерживался в зелёной зоне {stability:.0f}% времени, среднее отклонение от центра составило {mean_xy:.2f} см.',
        overall,
    ]

    if best_stage:
        details.append(
            f'Наиболее ровно прошёл этап {best_stage} ({stage_names.get(int(best_stage), "без уточнения осей")}).'
        )
    if worst_stage and worst_stage != best_stage:
        details.append(
            f'Больше всего трудностей было на этапе {worst_stage} ({stage_names.get(int(worst_stage), "без уточнения осей")}).'
        )

    if any(int(r.get('stage_no', 0)) == 3 for r in reports):
        roll = next((float(r.get('mean_abs_roll_deg', 0.0)) for r in reports if int(r.get('stage_no', 0)) == 3), 0.0)
        details.append(f'На третьем этапе дополнительно оценивался крен; среднее отклонение по крену составило {roll:.1f}°.')

    details.append('Ниже показаны отдельные карточки по этапам, где можно сравнить удержание в зоне, выходы из неё и величину отклонений.')
    return ' '.join(details)


def _interpret_method_b(summary: dict) -> str:
    total = int(summary.get('cycles_total', 0))
    success = int(summary.get('successful_cycles', 0))
    accuracy = float(summary.get('accuracy_pct', 0.0))
    max_correct = int(summary.get('max_correct_count', 0))
    if total == 0:
        return 'Тест был открыт, но завершённых циклов пока нет.'
    tone = 'Работа шла уверенно.' if accuracy >= 75 else ('Работа шла ровно, но с заметными потерями точности.' if accuracy >= 45 else 'Воспроизведение давалось трудно и требовало заметного напряжения.')
    return (
        f'За тест выполнено {total} циклов, из них полностью успешных {success}. '
        f'Максимум, который удалось правильно воспроизвести в одном цикле, составляет {max_correct} фигур. '
        f'Итоговая точность по циклам {accuracy:.1f}%. {tone} '
        'График ниже показывает расчётный показатель темпа для разного количества фигур: он объединяет время успешного воспроизведения и точность.'
    )


def _interpret_method_c(summary: dict) -> str:
    stages = summary.get('stages', {})
    if not stages:
        return 'Пока нет данных для расшифровки этого теста.'
    readable = {'1': 'однозначные числа', '2': 'двузначные числа', '3': 'трёхзначные числа'}
    items = []
    for key in ('1', '2', '3'):
        item = stages.get(key, {})
        total = int(item.get('Gq', 0))
        correct = int(item.get('Fq', 0))
        pct = 100.0 * correct / max(1, total)
        items.append((key, pct, float(item.get('avg_cycle_time_s', 0.0))))
    best = max(items, key=lambda t: (t[1], -t[2]))
    hardest = min(items, key=lambda t: (t[1], -t[2]))
    return (
        f'Лучше всего шёл этап, где использовались {readable[best[0]]}: там была самая высокая доля правильных ответов. '
        f'Наиболее трудным оказался этап с {readable[hardest[0]]}. '
        'В таблице ниже показано, сколько всего примеров было предъявлено, сколько ответов были правильными, '
        'какая получилась точность и сколько в среднем занимал успешный цикл. '
        'Три графика ниже показывают, как менялось суммарное доступное время на каждый ответ: время показа примера плюс время на ввод ответа.'
    )


def _interpret_method_d(summary: dict) -> str:
    groups = summary.get('groups', {})
    if not groups:
        return 'Пока нет данных для расшифровки этого теста.'
    names = {'min': 'низкая сложность', 'medio': 'средняя сложность', 'max': 'высокая сложность'}
    scored = []
    for key in ('min', 'medio', 'max'):
        g = groups.get(key, {})
        scored.append((key, int(g.get('correct_count', 0)), float(g.get('avg_time_s', 0.0))))
    best = max(scored, key=lambda t: (t[1], -t[2]))
    weakest = min(scored, key=lambda t: (t[1], -t[2]))
    return (
        f'Лучше всего решались задания уровня «{names[best[0]]}». '
        f'Больше всего затруднений вызвали задания уровня «{names[weakest[0]]}». '
        'Показатель темпа в этом тесте объединяет среднее время верных ответов и количество правильно решённых задач внутри каждой группы сложности.'
    )


def _show_method_b_results(self, payload: dict):
    top, outer = _open_results_top(self, 'Результаты - Тест B. Запоминание фигур в матрице')
    summary = payload.get('summary', {})
    tk.Label(outer, text='Тест B · Запоминание фигур в матрице', bg='#eef3f8', fg='#102744', font=('Arial', 26, 'bold')).pack(pady=(24, 8))
    cards = [
        ('Всего попыток', str(summary.get('cycles_total', 0)), 'Сколько циклов воспроизведения было выполнено за тест', '#67a9ff'),
        ('Полностью верных циклов', str(summary.get('successful_cycles', 0)), 'Циклы без ошибок и в пределах времени', '#53c26b'),
        ('Лучший результат за цикл', str(summary.get('max_correct_count', 0)), 'Максимум фигур, правильно воспроизведённых за одну попытку', '#ffb35c'),
        ('Общая точность', f"{summary.get('accuracy_pct', 0)}%", 'Доля полностью верных циклов от общего числа попыток', '#c98cff'),
    ]
    _draw_summary_cards(outer, cards).pack(anchor='center')
    _add_info_box(outer, 'Как читать результат', _interpret_method_b(summary), '#6b7dff').pack(anchor='center', padx=28, pady=(4, 10), fill='x')

    chart = tk.Canvas(outer, width=1000, height=440, bg='white', highlightthickness=1, highlightbackground='#d8e1ec')
    chart.pack(anchor='center', padx=24, pady=16)
    chart.create_text(500, 30, text='Расчётный показатель темпа по числу правильно воспроизведённых фигур', fill='#102744', font=('Arial', 16, 'bold'))
    chart.create_text(500, 54, text='Чем правее точка, тем больше фигур было в цикле. Подпись над точкой показывает расчётный показатель.', fill='#5d6d80', font=('Arial', 10))
    tvals = payload.get('summary', {}).get('t_values', {})
    xs = sorted((int(k), float(v)) for k, v in tvals.items() if str(k).isdigit())
    x1, y1, x2, y2 = 80, 390, 930, 96
    chart.create_line(x1, y1, x2, y1, fill='#95a5bb', width=2)
    chart.create_line(x1, y1, x1, y2, fill='#95a5bb', width=2)
    chart.create_text((x1 + x2) / 2, 416, text='Количество фигур в цикле', fill='#4d5c70', font=('Arial', 10, 'bold'))
    chart.create_text(18, 86, text='показатель', fill='#4d5c70', font=('Arial', 9, 'bold'))
    for i in range(1, 17):
        xx = x1 + (x2 - x1) * (i - 1) / 15
        chart.create_line(xx, y1, xx, y1 + 6, fill='#95a5bb')
        chart.create_text(xx, y1 + 18, text=str(i), fill='#4d5c70', font=('Arial', 10, 'bold'))
    for j in range(6):
        yy = y1 - (y1 - y2) * j / 5
        label = f'{j * 0.5:.1f}'
        chart.create_line(x1 - 6, yy, x1, yy, fill='#95a5bb')
        chart.create_text(x1 - 24, yy, text=label, fill='#4d5c70', font=('Arial', 10, 'bold'))
    pts = []
    for i, val in xs:
        xx = x1 + (x2 - x1) * (i - 1) / 15
        yy = y1 - (y1 - y2) * min(2.5, val) / 2.5
        pts.extend([xx, yy])
        chart.create_oval(xx - 5, yy - 5, xx + 5, yy + 5, fill='#397de0', outline='')
        chart.create_text(xx, yy - 14, text=f'{val:.2f}', fill='#397de0', font=('Arial', 9, 'bold'))
    if len(pts) >= 4:
        chart.create_line(*pts, fill='#397de0', width=3, smooth=True)


