    tk.Label(outer, text=note, bg='#eef3f8', fg='#5d6d80', font=('Arial', 10), wraplength=1080, justify='center').pack(padx=24, pady=(0, 4))
    for key, title in [('1', 'Этап 1 · Однозначные числа'), ('2', 'Этап 2 · Двузначные числа'), ('3', 'Этап 3 · Трёхзначные числа')]:
        chart = _draw_stage_time_chart(outer, title, stages.get(key, {}).get('cycles', []))
