def _collect_integral_values(self, profile: UserProfile | None = None) -> dict:
    profile = profile or self.current_profile
    if not profile:
        return {}
    results = {}
    for code in TEST_ORDER:
        payload = self.progress_store.get_test_result(profile, code)
        if payload:
            results[code] = payload
    values = {
        'A': [0.0, 0.0, 0.0],
        'B': [0.0, 0.0, 0.0],
        'C': [0.0, 0.0, 0.0],
        'D': [0.0, 0.0, 0.0],
    }
    if 'A' in results:
        s = results['A'].get('summary', {})
        values['A'] = [float(s.get('tmin_a', s.get('tmin_A', s.get('t_values', {}).get('min', 0.0) if isinstance(s.get('t_values', {}), dict) else 0.0)) or 0.0), float(s.get('tmedio_a', s.get('tmedio_A', s.get('t_values', {}).get('medio', 0.0) if isinstance(s.get('t_values', {}), dict) else 0.0)) or 0.0), float(s.get('tmax_a', s.get('tmax_A', s.get('t_values', {}).get('max', 0.0) if isinstance(s.get('t_values', {}), dict) else 0.0)) or 0.0)]
        if values['A'] == [0.0, 0.0, 0.0]:
            reports = results['A'].get('reports', [])
            if reports:
                values['A'] = [
                    _round2(float(reports[0].get('stability_pct', 0)) / 100.0),
                    _round2(float(reports[1].get('stability_pct', 0)) / 100.0 if len(reports) > 1 else 0.0),
                    _round2(float(reports[2].get('stability_pct', 0)) / 100.0 if len(reports) > 2 else 0.0),
                ]
    if 'B' in results:
        s = results['B'].get('summary', {})
        values['B'] = [float(s.get('tmin_b', 0.0) or 0.0), float(s.get('tmedio_b', 0.0) or 0.0), float(s.get('tmax_b', 0.0) or 0.0)]
    if 'C' in results:
        s = results['C'].get('summary', {})
        values['C'] = [float(s.get('tmin_c', 0.0) or 0.0), float(s.get('tmedio_c', 0.0) or 0.0), float(s.get('tmax_c', 0.0) or 0.0)]
    if 'D' in results:
        s = results['D'].get('summary', {})
        values['D'] = [float(s.get('tmin_d', 0.0) or 0.0), float(s.get('tmedio_d', 0.0) or 0.0), float(s.get('tmax_d', 0.0) or 0.0)]
    return values


def _show_integral_results(self):
    if not self.current_profile:
        return
    values = _collect_integral_values(self, self.current_profile)
    if not values:
        messagebox.showinfo('Интегральный результат', 'Пока нет сохранённых результатов для построения поверхности.')
        return

    def _normalize_surface(raw: dict[str, list[float]]) -> dict[str, list[float]]:
        flat = [float(v) for arr in raw.values() for v in arr if float(v) > 0]
        if not flat:
            return {k: [0.0, 0.0, 0.0] for k in raw}
        vmin = min(flat)
        vmax = max(flat)
        out: dict[str, list[float]] = {}
        for key, arr in raw.items():
            normed: list[float] = []
            for v in arr:
                fv = float(v or 0.0)
                if fv <= 0:
                    normed.append(0.10)
                elif abs(vmax - vmin) < 1e-9:
                    normed.append(0.72)
                else:
                    normed.append(0.18 + 0.78 * (fv - vmin) / (vmax - vmin))
            out[key] = normed
        return out

    norm = _normalize_surface(values)
    top, outer = _open_results_top(self, 'Интегральный результат')
    bg = '#f0efe7'
    outer.configure(bg=bg)

    tk.Label(
        outer,
        text='Интегральный профиль психической работоспособности',
        bg=bg,
        fg='#111111',
        font=('Arial', 24, 'bold'),
    ).pack(pady=(18, 4))
    participant = f'{self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}'
    tk.Label(
        outer,
        text=participant,
        bg=bg,
        fg='#4b4b4b',
        font=('Arial', 13, 'bold'),
    ).pack(pady=(0, 8))

    screen_w = max(1024, int(top.winfo_screenwidth() or 1366))
    screen_h = max(768, int(top.winfo_screenheight() or 768))
    canvas_w = min(max(screen_w - 90, 980), 1280)
    canvas_h = min(max(screen_h - 290, 560), 740)

    canvas = tk.Canvas(outer, width=canvas_w, height=canvas_h, bg=bg, highlightthickness=0)
    canvas.pack(fill='both', expand=True, padx=18, pady=(4, 8))

    methods = [
        ('A', 'СЛЕЖЕНИЕ', ['X', 'X+Y', 'X+Y+крен']),
        ('B', 'ПАМЯТЬ', ['4', '5', '6']),
        ('C', 'СЧЁТ', ['однозначные', 'двузначные', 'трёхзначные']),
        ('D', 'РАВЕН', ['1 логика', '2 логики', '3 логики']),
    ]
    tempo_ticks = [0.25, 0.50, 0.75, 1.00]

    # Логическая 3D-сетка, которую потом масштабируем под реальный экран.
    step_x = (1.62, 0.00)
    step_depth = (-0.60, 0.45)
    z_scale = 2.10

    def proj_raw(ix: float, iy: float, iz: float) -> tuple[float, float]:
        return (
            ix * step_x[0] + iy * step_depth[0],
            ix * step_x[1] + iy * step_depth[1] - iz * z_scale,
        )

    raw_points: list[tuple[float, float]] = []
    raw_points.extend([
        proj_raw(0, 0, 0), proj_raw(3.95, 0, 0), proj_raw(0, 2.60, 0), proj_raw(0, 0, 1.18),
        proj_raw(3.60, 0, 0), proj_raw(0, 2.35, 0), proj_raw(0, 0, 1.0),
    ])
    for i in range(4):
        for j in range(3):
            raw_points.append(proj_raw(i, j, 0))
            raw_points.append(proj_raw(i, j, 1.0))
    for t in tempo_ticks:
        raw_points.append(proj_raw(0, 0, t))
        raw_points.append(proj_raw(3.25, 0, t))
        raw_points.append(proj_raw(0, 2.20, t))
    raw_points.append((proj_raw(3.75, 0, 0)[0] + 1.6, proj_raw(3.75, 0, 0)[1]))
    raw_points.append((proj_raw(0, 2.42, 0)[0] - 1.1, proj_raw(0, 2.42, 0)[1] + 1.5))

    min_x = min(x for x, _ in raw_points)
    max_x = max(x for x, _ in raw_points)
    min_y = min(y for _, y in raw_points)
    max_y = max(y for _, y in raw_points)

    margin_l, margin_t, margin_r, margin_b = 84, 54, 70, 82
    span_x = max(1e-6, max_x - min_x)
    span_y = max(1e-6, max_y - min_y)
    scale = min((canvas_w - margin_l - margin_r) / span_x, (canvas_h - margin_t - margin_b) / span_y)

    def map_xy(x: float, y: float) -> tuple[float, float]:
        return (
            margin_l + (x - min_x) * scale,
            margin_t + (y - min_y) * scale,
        )

    def proj(ix: float, iy: float, iz: float) -> tuple[float, float]:
        return map_xy(*proj_raw(ix, iy, iz))

    grid = '#1f1f1f'
    soft_grid = '#6c6c6c'
    post_color = '#6c5a4b'
    fill_color = '#ead9ca'
    wire_color = '#ef2e24'
    font_axis = ('Arial', 16, 'bold')
    font_method = ('Arial', 14, 'bold')
    font_level = ('Arial', 10, 'bold')
    font_tick = ('Arial', 10, 'bold')

    # Оси
    canvas.create_line(*proj(0, 0, 0), *proj(3.9, 0, 0), fill=grid, width=4)
    canvas.create_line(*proj(0, 0, 0), *proj(0, 2.55, 0), fill=grid, width=4)
    canvas.create_line(*proj(0, 0, 0), *proj(0, 0, 1.14), fill=grid, width=4)

    # Пространственная сетка
    for t in tempo_ticks:
        canvas.create_line(*proj(0, 0, t), *proj(3.25, 0, t), fill=soft_grid, width=1)
        canvas.create_line(*proj(0, 0, t), *proj(0, 2.2, t), fill=soft_grid, width=1)
    for i in range(4):
        canvas.create_line(*proj(i, 0, 0), *proj(i, 0, 1.02), fill=soft_grid, width=1)
        canvas.create_line(*proj(i, 0, 0), *proj(i, 2.1, 0), fill=soft_grid, width=1)
        for t in tempo_ticks:
            canvas.create_line(*proj(i, 0, t), *proj(i, 2.0, t), fill='#2f2f2f', width=1)
    for j in range(3):
        canvas.create_line(*proj(0, j, 0), *proj(3.15, j, 0), fill=soft_grid, width=1)
        canvas.create_line(*proj(0, j, 0), *proj(0, j, 1.0), fill=soft_grid, width=1)

    # Подписи осей
    tx, ty = proj(0, 0, 1.16)
    canvas.create_text(tx, ty - 10, text='ТЕМП', anchor='s', fill='black', font=font_axis)
    mx, my = proj(3.75, 0, 0)
    canvas.create_text(min(canvas_w - 10, mx + 96), my - 4, text='МЕТОДИКА', anchor='w', fill='black', font=font_axis)
    canvas.create_text(18, canvas_h - 10, text='КОЛИЧЕСТВО\nЭЛЕМЕНТОВ\nЗАДАНИЯ', anchor='sw', fill='black', font=('Arial', 14, 'bold'))

    for t in tempo_ticks:
        px, py = proj(0, 0, t)
        canvas.create_text(px - 18, py, text=f'{int(t * 100)}', anchor='e', fill='#202020', font=font_tick)

    pts: dict[tuple[int, int], tuple[float, float]] = {}
    ground_pts: dict[tuple[int, int], tuple[float, float]] = {}
    for i, (code, title, lvl_labels) in enumerate(methods):
        title_x, title_y = proj(i + 0.16, 0.05, 0)
        canvas.create_text(title_x, title_y - 16, text=title, anchor='s', fill='black', font=font_method)
        for j, lvl in enumerate(lvl_labels):
            gx, gy = proj(i, j, 0)
            ground_pts[(i, j)] = (gx, gy)
            px, py = proj(i, j, norm[code][j])
            pts[(i, j)] = (px, py)
            canvas.create_line(gx, gy, px, py, fill=post_color, width=4)
            canvas.create_oval(px - 3, py - 3, px + 3, py + 3, fill='black', outline=wire_color, width=1)
            label_dx = -8 if j < 2 else 0
            label_dy = 18 if j < 2 else 22
            canvas.create_text(gx + label_dx, gy + label_dy, text=lvl, anchor='n', fill='black', font=font_level)

    # Полупрозрачные секции поверхности
    for i in range(3):
        for j in range(2):
            poly = [
                *pts[(i, j)],
                *pts[(i + 1, j)],
                *pts[(i + 1, j + 1)],
                *pts[(i, j + 1)],
            ]
            canvas.create_polygon(poly, fill=fill_color, outline='', stipple='gray50')

    # Красный каркас поверхности
    for i in range(4):
        row_pts = [pts[(i, j)] for j in range(3)]
        canvas.create_line(*sum(row_pts, ()), fill=wire_color, width=2)
    for j in range(3):
        col_pts = [pts[(i, j)] for i in range(4)]
        canvas.create_line(*sum(col_pts, ()), fill=wire_color, width=2)

    front = [ground_pts[(i, 2)] for i in range(4)]
    canvas.create_line(*sum(front, ()), fill=wire_color, width=2)
    side = [ground_pts[(0, j)] for j in range(3)]
    canvas.create_line(*sum(side, ()), fill=wire_color, width=2)

    flat_values = [(code, idx, float(values[code][idx] or 0.0)) for code, _, _ in methods for idx in range(3)]
    nonzero = [v for _, _, v in flat_values if v > 0]
    avg = sum(nonzero) / len(nonzero) if nonzero else 0.0
    weakest = min(flat_values, key=lambda t: (t[2] if t[2] > 0 else 9999)) if flat_values else ('-', 0, 0.0)
    weakest_names = {
        ('A', 0): 'Слежение · X', ('A', 1): 'Слежение · X+Y', ('A', 2): 'Слежение · X+Y+крен',
        ('B', 0): 'Память · 4 фигуры', ('B', 1): 'Память · 5 фигур', ('B', 2): 'Память · 6 фигур',
        ('C', 0): 'Счёт · однозначные', ('C', 1): 'Счёт · двузначные', ('C', 2): 'Счёт · трёхзначные',
        ('D', 0): 'Равен · 1 логика', ('D', 1): 'Равен · 2 логики', ('D', 2): 'Равен · 3 логики',
    }
    note = (
        'Красная поверхность показывает индивидуальный профиль темпа: чем выше точка, тем лучше результат на соответствующем уровне. '
        f'Среднее по заполненным точкам: {avg:.2f}. Наиболее слабая зона: {weakest_names.get((weakest[0], weakest[1]), "-")} ({weakest[2]:.2f}).'
    )
    tk.Label(
        outer,
        text=note,
        bg=bg,
        fg='#2c2c2c',
        justify='left',
        wraplength=canvas_w - 32,
        font=('Arial', 12),
    ).pack(padx=22, pady=(0, 18), anchor='w')

def _view_results(self, code: str):
    if not self.current_profile:
        return
    payload = self.progress_store.get_test_result(self.current_profile, code)
    if not payload:
        messagebox.showinfo('Результаты', f'Для {TEST_LABELS[code]} пока нет сохранённых результатов.')
        return
    if code == 'A':
        self.show_method_a_results(payload)
    elif code == 'B':
        _show_method_b_results(self, payload)
    elif code == 'C':
        _show_method_c_results(self, payload)
    elif code == 'D':
        _show_method_d_results(self, payload)


def _continue_next_test(self):
    if not self.current_profile:
        return
    next_code = self.progress_store.next_test_code(self.current_profile)
    if not next_code:
        _show_integral_results(self)
        return
    self.launch_test(next_code)


def _refresh_menu_state(self):
    if not self.current_profile:
        return
    progress = self.progress_store.ensure_user(self.current_profile)
    completed = progress.get('completed_tests', [])
    next_code = self.progress_store.next_test_code(self.current_profile)
    completed_text = ', '.join(TEST_LABELS[c] for c in completed) if completed else 'пока нет'
    if next_code:
        next_text = f'Следующий доступный тест: {TEST_LABELS[next_code]}'
    else:
        next_text = 'Все тесты пройдены. Ниже можно открыть результаты каждой методики и общий профиль СПР.'
    self.menu_intro_var.set(
        f'Пользователь: {self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}.\n\n'
        'Тесты можно проходить не за один раз. Уже пройденные кнопки блокируются, '
        'а доступной остаётся только следующая методика по порядку.'
    )
    self.menu_status_var.set(f'Пройдено: {completed_text}.\n{next_text}')
    for code, btn in self.menu_buttons.items():
        if code in completed:
            btn.configure(state=tk.DISABLED, text=menu_card_text(code, "done"), bg='#bfc7ba', activebackground='#bfc7ba', disabledforeground='#4a5b47', relief='sunken')
        elif code == next_code:
            btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg='#111111', relief='raised')
        else:
            btn.configure(state=tk.DISABLED, text=menu_card_text(code, "locked"), bg=MENU_DISABLED, activebackground=MENU_DISABLED, disabledforeground='#6d6955', relief='ridge')
    for code, btn in getattr(self, 'menu_result_buttons', {}).items():
        has_payload = bool(self.progress_store.get_test_result(self.current_profile, code))
        if has_payload:
            btn.configure(state=tk.NORMAL, text='ПОКАЗАТЬ\nРЕЗУЛЬТАТЫ', bg='#6b7dff', activebackground='#5b6de8', fg='white', relief='raised')
        else:
            btn.configure(state=tk.DISABLED, text='РЕЗУЛЬТАТОВ\nПОКА НЕТ', bg='#d6dbe5', activebackground='#d6dbe5', disabledforeground='#7f8897', relief='flat')
    if next_code:
        self.continue_btn.configure(state=tk.NORMAL, text='ПРОДОЛЖИТЬ', bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg='#111111', width=14, relief='raised')
    else:
        self.continue_btn.configure(state=tk.NORMAL, text='ОБЩИЙ\nПРОФИЛЬ СПР', bg='#4f78ff', activebackground='#4269e0', fg='white', width=16, relief='raised')


def _show_test_completed_dialog(self, code: str):

    dialog = tk.Toplevel(self.root)
    dialog.title(f'{TEST_LABELS[code]} завершён')
    dialog.configure(bg=BG_COLOR)
    dialog.transient(self.root)
    dialog.grab_set()
    dialog.resizable(False, False)
    frame = tk.Frame(dialog, bg=PANEL_COLOR, bd=2, relief='groove')
    frame.pack(fill='both', expand=True, padx=18, pady=18)
    tk.Label(frame, text=f'{TEST_LABELS[code]} завершён', bg=PANEL_COLOR, fg=TITLE_COLOR, font=('Arial', 20, 'bold')).pack(pady=(12, 10))
    all_done = self.current_profile and self.progress_store.next_test_code(self.current_profile) is None
    descr = 'Можно сразу открыть наглядный экран с результатами или вернуться в меню.' if not all_done else 'Все методики завершены. Можно открыть общий профиль СПР или вернуться в меню.'
    tk.Label(frame, text=descr, bg=PANEL_COLOR, fg=TEXT_COLOR, justify='center', font=('Arial', 12, 'bold'), wraplength=440).pack(padx=18, pady=(0, 16))
    btns = tk.Frame(frame, bg=PANEL_COLOR)
    btns.pack(pady=(0, 14))
    primary_text = 'ОБЩИЙ\nПРОФИЛЬ СПР' if all_done else 'ПОСМОТРЕТЬ\nСВОИ РЕЗУЛЬТАТЫ'
    primary_cmd = (lambda: (dialog.destroy(), _show_integral_results(self))) if all_done else (lambda: (dialog.destroy(), self.view_results(code)))
    tk.Button(btns, text=primary_text, command=primary_cmd, bg=RESULT_BG, activebackground=RESULT_ACTIVE, relief='raised', bd=3, cursor='hand2', font=('Arial', 12, 'bold'), width=18, height=2).pack(side='left', padx=(0, 12))
    tk.Button(btns, text='В МЕНЮ', command=dialog.destroy, bg=NEXT_BG, activebackground=NEXT_ACTIVE, relief='raised', bd=3, cursor='hand2', font=('Arial', 12, 'bold'), width=12, height=2).pack(side='left')
    dialog.update_idletasks()
    width = dialog.winfo_width()
    height = dialog.winfo_height()
    x = self.root.winfo_rootx() + max(20, (self.root.winfo_width() - width) // 2)
    y = self.root.winfo_rooty() + max(20, (self.root.winfo_height() - height) // 2)
    dialog.geometry(f'{width}x{height}+{x}+{y}')
    self.root.wait_window(dialog)


def _launch_test(self, code: str):
    if not self.current_profile or not self.current_session:
        return
    next_code = self.progress_store.next_test_code(self.current_profile)
    completed = self.progress_store.get_progress(self.current_profile).get('completed_tests', [])
    if code in completed:
        messagebox.showinfo('Уже пройдено', f'{TEST_LABELS[code]} уже отмечен как пройденный.')
        return
    if code != next_code:
        messagebox.showwarning('Порядок тестов', f'Сейчас доступен только {TEST_LABELS[next_code]}.')
        return
    self.logger.log_event(self.current_session, event_type='menu_event', screen='test_menu', test_name=f'test_{code.lower()}', action='launch_requested', note=TEST_DESCRIPTIONS[code])
    if code == 'A':
        result = self.run_method_a(self.current_session)
    elif code == 'B':
        result = _run_method_b(self, self.current_session)
    elif code == 'C':
        result = _run_method_c(self, self.current_session)
    elif code == 'D':
        result = _run_method_d(self, self.current_session)
    else:
        return
    if result.get('completed'):
        self.progress_store.mark_completed(self.current_profile, code)
        self.logger.log_event(self.current_session, event_type='menu_event', screen='test_menu', test_name=f'test_{code.lower()}', action='marked_completed', note=f'{TEST_LABELS[code]} завершён и заблокирован как пройденный.')
        self.refresh_menu_state()
        self.show_test_completed_dialog(code)
    else:
        self.refresh_menu_state()


