def _open_result_for_profile(self, profile: UserProfile, code: str | None = None):
    previous = self.current_profile
    try:
        self.current_profile = profile
        if code is None:
            self.show_integral_results()
        else:
            self.view_results(code)
    finally:
        self.current_profile = previous


def _show_all_results_browser(self):
    top = tk.Toplevel(self.root)
    top.title('Все результаты')
    top.configure(bg='#eef3f8')
    top.geometry('1180x760')
    try:
        top.state('zoomed')
    except tk.TclError:
        pass

    tk.Label(top, text='Все сохранённые результаты', bg='#eef3f8', fg='#102744', font=('Arial', 24, 'bold')).pack(anchor='w', padx=18, pady=(18, 4))
    tk.Label(top, text='Здесь можно открыть результаты любого пользователя по каждому тесту и общий профиль СПР.', bg='#eef3f8', fg='#51627a', font=('Arial', 12, 'bold')).pack(anchor='w', padx=18, pady=(0, 8))

    canvas = tk.Canvas(top, bg='#eef3f8', highlightthickness=0)
    scroll = tk.Scrollbar(top, orient='vertical', command=canvas.yview)
    canvas.configure(yscrollcommand=scroll.set)
    scroll.pack(side='right', fill='y')
    canvas.pack(side='left', fill='both', expand=True)
    inner = tk.Frame(canvas, bg='#eef3f8')
    canvas_window = canvas.create_window((0, 0), window=inner, anchor='nw')
    inner.bind('<Configure>', lambda _e: canvas.configure(scrollregion=canvas.bbox('all')))
    canvas.bind('<Configure>', lambda e: canvas.itemconfigure(canvas_window, width=e.width))
    _bind_mousewheel_to_canvas(canvas, inner)

    records = self.progress_store.all_user_records()
    if not records:
        tk.Label(inner, text='Сохранённых результатов пока нет.', bg='#eef3f8', fg='#5b6c83', font=('Arial', 14, 'bold')).pack(anchor='w', padx=18, pady=18)
        return

    for profile, record in records:
        card = tk.Frame(inner, bg='white', bd=1, relief='solid', highlightthickness=1, highlightbackground='#d8e1ec')
        card.pack(fill='x', padx=18, pady=10)
        head = tk.Frame(card, bg='white')
        head.pack(fill='x', padx=14, pady=(12, 6))
        tk.Label(head, text=f'{profile.name}, {profile.age} лет, {profile.gender}', bg='white', fg='#102744', font=('Arial', 15, 'bold')).pack(side='left', anchor='w')
        updated_at = str(record.get('updated_at', ''))
        if updated_at:
            tk.Label(head, text=f'Обновлено: {updated_at}', bg='white', fg='#6b7280', font=('Arial', 10, 'bold')).pack(side='right', anchor='e')

        completed = record.get('completed_tests', []) if isinstance(record.get('completed_tests', []), list) else []
        completed_text = ', '.join(TEST_LABELS[c] for c in completed if c in TEST_LABELS) or 'пока нет'
        tk.Label(card, text=f'Пройдено: {completed_text}', bg='white', fg='#42546c', font=('Arial', 11, 'bold')).pack(anchor='w', padx=14)

        btn_row = tk.Frame(card, bg='white')
        btn_row.pack(fill='x', padx=14, pady=(10, 12))
        results = record.get('results', {}) if isinstance(record.get('results', {}), dict) else {}
        any_results = False
        for code in TEST_ORDER:
            payload = results.get(code)
            if isinstance(payload, dict):
                any_results = True
                tk.Button(
                    btn_row,
                    text=f'{TEST_LABELS[code]}\n{TEST_DESCRIPTIONS[code]}',
                    command=lambda p=profile, c=code: _open_result_for_profile(self, p, c),
                    bg='#6b7dff',
                    activebackground='#5b6de8',
                    fg='white',
                    relief='raised',
                    bd=2,
                    cursor='hand2',
                    font=('Arial', 11, 'bold'),
                    width=18,
                    height=2,
                    wraplength=170,
                ).pack(side='left', padx=(0, 10))
        if any_results:
            tk.Button(
                btn_row,
                text='ОБЩИЙ\nПРОФИЛЬ СПР',
                command=lambda p=profile: _open_result_for_profile(self, p, None),
                bg='#4f78ff',
                activebackground='#4269e0',
                fg='white',
                relief='raised',
                bd=2,
                cursor='hand2',
                font=('Arial', 11, 'bold'),
                width=16,
                height=2,
            ).pack(side='left')
        else:
            tk.Label(btn_row, text='Отдельных результатов пока нет.', bg='white', fg='#7a8799', font=('Arial', 11, 'bold')).pack(side='left')


_original_refresh_menu_state = StartPageApp.refresh_menu_state

def _patched_refresh_menu_state(self):
    if not self.current_profile:
        return
    if not getattr(self, 'researcher_mode_enabled', False):
        return _original_refresh_menu_state(self)

    progress = self.progress_store.ensure_user(self.current_profile)
    completed = progress.get('completed_tests', [])
    next_code = self.progress_store.next_test_code(self.current_profile)
    completed_text = ', '.join(TEST_LABELS[c] for c in completed) if completed else 'пока нет'
    self.menu_intro_var.set(
        f'Пользователь: {self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}.\n\n'
        'Исследовательский вариант: доступны все тесты сразу. Уже пройденные методики можно запускать повторно, '
        'а результаты по каждому тесту и общий профиль СПР можно открыть в любой момент.'
    )
    self.menu_status_var.set(f'Пройдено: {completed_text}.\nСледующий неполный тест: {TEST_LABELS[next_code] if next_code else "все методики уже завершены"}.')

    for code, btn in self.menu_buttons.items():
        if code in completed:
            text = f"{TEST_LABELS[code]}\n{TEST_DESCRIPTIONS[code]}\n(можно запустить снова)"
            btn.configure(state=tk.NORMAL, text=text, bg='#d8f0d7', activebackground='#c7e7c6', fg='#102744', relief='raised')
        else:
            btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG if code == next_code else MENU_BG, activebackground=NEXT_ACTIVE if code == next_code else MENU_ACTIVE, fg='#111111', relief='raised')
    for code, btn in getattr(self, 'menu_result_buttons', {}).items():
        has_payload = bool(self.progress_store.get_test_result(self.current_profile, code))
        if has_payload:
            btn.configure(state=tk.NORMAL, text='ПОКАЗАТЬ\nРЕЗУЛЬТАТЫ', bg='#6b7dff', activebackground='#5b6de8', fg='white', relief='raised')
        else:
            btn.configure(state=tk.DISABLED, text='РЕЗУЛЬТАТОВ\nПОКА НЕТ', bg='#d6dbe5', activebackground='#d6dbe5', disabledforeground='#7f8897', relief='flat')
    if next_code:
        self.continue_btn.configure(state=tk.NORMAL, text='НЕПРОЙДЕННЫЙ\nДАЛЕЕ', bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg='#111111', width=16, relief='raised')
    else:
        self.continue_btn.configure(state=tk.NORMAL, text='ОБЩИЙ\nПРОФИЛЬ СПР', bg='#4f78ff', activebackground='#4269e0', fg='white', width=16, relief='raised')
    if getattr(self, 'all_results_btn', None) is not None:
        self.all_results_btn.configure(state=tk.NORMAL)


_original_launch_test = StartPageApp.launch_test

def _patched_launch_test(self, code: str):
    if not self.current_profile or not self.current_session:
        return
    if not getattr(self, 'researcher_mode_enabled', False):
        return _original_launch_test(self, code)

    self.logger.log_event(self.current_session, event_type='menu_event', screen='test_menu', test_name=f'test_{code.lower()}', action='launch_requested', note=TEST_DESCRIPTIONS[code])
    if code == 'A':
        result = self.run_method_a(self.current_session)
    elif code == 'B':
        result = _run_method_b(self, self.current_session)
    elif code == 'C':
        result = _run_method_c(self, self.current_session)
    elif code == 'D':
        result = _run_method_d(self, self.current_session)
    else:
        return
    if result.get('completed'):
        self.progress_store.mark_completed(self.current_profile, code)
        self.logger.log_event(self.current_session, event_type='menu_event', screen='test_menu', test_name=f'test_{code.lower()}', action='marked_completed', note=f'{TEST_LABELS[code]} завершён и сохранён.')
        self.refresh_menu_state()
        self.show_test_completed_dialog(code)
    else:
        self.refresh_menu_state()


def _patched_method_b_start_cycle(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    if self._time_left_total() <= 1.0:
        self._finish()
        return
    n = max(1, min(self.cfg.max_items, int(self.current_n)))
    all_cells = list(range(self.cfg.grid_size ** 2))
    all_shapes = list(range(self.cfg.max_items))
    random.shuffle(all_cells)
    random.shuffle(all_shapes)
    self.current_positions = sorted(all_cells[:n])
    self.current_shapes = all_shapes[:n]
    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    self.phase = 'memorize'
    self.cycle_started_at = time.perf_counter()
    self.message_var.set('Запомните расположение фигур в матрице.')
    self.selection_var.set('После показа восстановите рисунок расположения фигур.')
    self._draw_memory_matrix()
    self._draw_tray(show=False)
    base_exposure = float(self.cfg.start_exposure_s + self.cfg.step_time_s * (n - 1))
    exposure = max(0.7, base_exposure + float(getattr(self, 'exposure_adjust_s', 0.0)))
    exposure = min(exposure, max(1.0, self._time_left_total()))
    self._update_info_label()
    self._track_after(self.win.after(int(exposure * 1000), self._start_reproduction_phase))


def _patched_method_b_start_reproduction_phase(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    self.phase = 'reproduce'
    n = len(self.current_positions)
    base_repr = float(self.cfg.start_reproduction_s + self.cfg.step_time_s * (n - 1))
    repr_time = max(1.2, base_repr + float(getattr(self, 'reproduction_adjust_s', 0.0)))
    repr_time = min(repr_time, max(1.0, self._time_left_total()))
    self.reproduction_deadline = time.perf_counter() + repr_time
    self.message_var.set('Восстановите расположение фигур в матрице.')
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)
    self._tick_reproduction_timeout()


def _patched_method_b_finalize_cycle(self, success: bool | None, reason: str):
    if self.phase != 'reproduce':
        return
    self._cancel_afters()
    success_eval, correct, expected = self._evaluate_cycle()
    if success is None:
        success = success_eval
    elapsed = time.perf_counter() - self.cycle_started_at
    n = len(expected)
    cycle_info = {
        'n': n,
        'success': bool(success),
        'correct_count': int(correct),
        'elapsed_s': _round2(elapsed),
        'reason': reason,
        'positions': list(self.current_positions),
        'shapes': list(self.current_shapes),
    }
    self.result['cycles'].append(cycle_info)
    self.logger.log_event(
        self.session,
        event_type='method_cycle',
        screen='method_b',
        test_name='method_b',
        stage=f'n={n}',
        action='success' if success else 'error',
        elapsed_ms=int(elapsed * 1000),
        value=correct,
        note=f'reason={reason}; placed={len(self.placements)}',
    )
    adaptive_step = float(getattr(self.cfg, 'adaptive_time_step_s', 0.5) or 0.5)
    max_expand = max(6.0, adaptive_step * 8)
    self.exposure_adjust_s = max(-(float(self.cfg.start_exposure_s) - 0.7), min(max_expand, float(getattr(self, 'exposure_adjust_s', 0.0)) + (-adaptive_step if success else adaptive_step)))
    self.reproduction_adjust_s = max(-(float(self.cfg.start_reproduction_s) - 1.0), min(max_expand * 1.5, float(getattr(self, 'reproduction_adjust_s', 0.0)) + (-adaptive_step if success else adaptive_step)))
    if success:
        self.message_var.set(f'Успешно: воспроизведено {n} фигур. Следующий цикл будет сложнее и чуть быстрее.')
        self.current_n = min(self.cfg.max_items, self.current_n + 1)
    else:
        self.message_var.set(f'Ошибка: правильно размещено {correct} из {n}. Следующий цикл будет чуть медленнее.')
        self.current_n = max(1, self.current_n - 1)
    self.phase = 'message'
    self._track_after(self.win.after(1000, self._start_cycle))


def _patched_method_d_tick_clock(self):
    if not self.win or not self.win.winfo_exists() or self.phase == 'finished':
        return
    extra = ''
    if self.phase == 'task' and self.current_task is not None:
        remaining_task = self.current_task_deadline - time.perf_counter()
        if remaining_task <= 0:
            self._timeout_current_task()
            return
        extra = f'    На ответ: {max(0, math.ceil(remaining_task))} с'
    self.info_var.set(
        f'Блок D{self.block_index}    Задание {max(1, self.current_task_index + 1)} из {len(self.tasks)}    '
        f'Осталось общего времени: {_fmt_sec(self._time_left())}{extra}'
    )
    self._track_after(self.win.after(200, self._tick_clock))


def _method_d_apply_time_adaptation(self, difficulty: str, correct: bool):
    step_map = getattr(self.cfg, 'adaptive_time_step_s', {}) or {}
    step = float(step_map.get(difficulty, 2.0))
    base_map = getattr(self.cfg, 'answer_time_s', {}) or {}
    base_value = float(base_map.get(difficulty, 20.0))
    current = float(self.answer_limits.get(difficulty, base_value))
    if correct:
        current = max(5.0, current - step)
    else:
        current = min(max(base_value * 2.0, base_value + step * 5.0), current + step)
    self.answer_limits[difficulty] = current


def _method_d_register_answer(self, option_index: int | None, timeout: bool = False):
    if not self.current_task or self.phase != 'task':
        return
    self.phase = 'feedback'
    correct_index = next((i for i, item in enumerate(self.current_task['options']) if _logic_spec_key(item) == _logic_spec_key(self.current_task['correct'])), 0)
    chosen = self.current_task['options'][option_index] if option_index is not None and 0 <= option_index < len(self.current_task['options']) else None
    correct = bool(chosen is not None and _logic_spec_key(chosen) == _logic_spec_key(self.current_task['correct']))
    elapsed = time.perf_counter() - self.current_task_started_at
    difficulty = self.current_task['difficulty']
    current_limit = float(self.answer_limits.get(difficulty, getattr(self.cfg, 'answer_time_s', {}).get(difficulty, 0.0)))
    item = {
        'task_no': self.current_task_index + 1,
        'difficulty': difficulty,
        'correct': bool(correct),
        'elapsed_s': _round2(elapsed),
        'option_index': option_index,
        'correct_option_index': correct_index,
        'timeout': bool(timeout),
        'answer_time_limit_s': _round2(current_limit),
    }
    self.result['tasks'].append(item)
    self.logger.log_event(
        self.session,
        event_type='method_task',
        screen='method_d',
        test_name='method_d',
        stage=difficulty,
        action='timeout' if timeout else ('success' if correct else 'error'),
        elapsed_ms=int(elapsed * 1000),
        value=(option_index + 1) if option_index is not None else 0,
        note=f'task={self.current_task_index + 1}; block=D{self.block_index}; correct={correct_index + 1}; timeout={int(timeout)}',
    )
    self._method_d_apply_time_adaptation(difficulty, correct)
    for i, cv in enumerate(self.option_canvases):
        if i == correct_index:
            cv.configure(highlightbackground='#33b864', highlightthickness=4)
        elif option_index is not None and i == option_index and not correct:
            cv.configure(highlightbackground='#e26565', highlightthickness=4)
        else:
            cv.configure(highlightbackground='#afbdd1', highlightthickness=3)
    if correct:
        self.prompt_var.set('Верно. Можно переходить к следующему заданию.')
        self.feedback_var.set(f'Ответ дан за {_round2(elapsed)} с. Следующий похожий элемент будет чуть быстрее.')
    elif timeout:
        self.prompt_var.set(f'Время вышло. Правильный вариант: №{correct_index + 1}.')
        self.feedback_var.set('Следующее похожее задание получит больше времени. Можно посмотреть правильный ответ и перейти дальше.')
    else:
        self.prompt_var.set(f'Неверно. Правильный вариант: №{correct_index + 1}.')
        self.feedback_var.set('Следующее похожее задание получит больше времени. Автопереход не запускается.')
    if self.next_btn:
        last_or_timeout = (self.current_task_index + 1 >= len(self.tasks)) or (self._time_left() <= 1.0)
        self.next_btn.configure(state=tk.NORMAL, text='Завершить блок' if last_or_timeout else 'Следующее задание')


def _patched_method_d_start_next_task(self):
    self._cancel_afters()
    if self._time_left() <= 1.0 or self.current_task_index + 1 >= len(self.tasks):
        self._finish()
        return
    self.current_task_index += 1
    self.current_task = self.tasks[self.current_task_index]
    self.current_task_started_at = time.perf_counter()
    difficulty = self.current_task['difficulty']
    self.current_task_deadline = self.current_task_started_at + float(self.answer_limits.get(difficulty, getattr(self.cfg, 'answer_time_s', {}).get(difficulty, 25.0)))
    self._draw_task()
    self._tick_clock()


def _patched_method_d_answer(self, option_index: int):
    _method_d_register_answer(self, option_index=option_index, timeout=False)


def _method_d_timeout_current_task(self):
    _method_d_register_answer(self, option_index=None, timeout=True)


