# ====== FIXED24 menu action row + drag-and-drop tray for Method B ======

def _fixed24_scale(root: tk.Tk) -> float:
    width = max(root.winfo_width(), 1100)
    height = max(root.winfo_height(), 760)
    scale = min(width / BASE_W, height / BASE_H)
    return max(0.72, min(scale, 1.9))


def _fixed24_repack_menu_action_row(self):
    if not hasattr(self, 'menu_btn_frame') or self.menu_btn_frame is None:
        return
    scale = _fixed24_scale(self.root)
    gap = max(10, int(12 * scale))
    font_size = max(11, int(18 * scale))
    self.menu_btn_frame.grid_configure(sticky='ew', pady=(0, int(10 * scale)))
    try:
        self.right.grid_columnconfigure(0, weight=1)
    except Exception:
        pass

    ordered = [getattr(self, 'all_results_btn', None), getattr(self, 'continue_btn', None), getattr(self, 'restart_btn', None), getattr(self, 'exit_btn', None)]
    for btn in ordered:
        if btn is not None and btn.winfo_exists():
            try:
                btn.pack_forget()
            except Exception:
                pass

    if getattr(self, 'all_results_btn', None) is not None and self.all_results_btn.winfo_exists():
        self.all_results_btn.configure(
            text='ВСЕ\nРЕЗУЛЬТАТЫ',
            font=('Arial', max(10, font_size - 1), 'bold'),
            width=max(12, int(13 * scale)),
            height=2,
            justify='center',
            wraplength=int(150 * scale),
        )
        self.all_results_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'continue_btn', None) is not None and self.continue_btn.winfo_exists():
        self.continue_btn.configure(
            font=('Arial', font_size, 'bold'),
            width=max(16, int(18 * scale)),
            height=2,
            justify='center',
            wraplength=int(220 * scale),
        )
        self.continue_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'restart_btn', None) is not None and self.restart_btn.winfo_exists():
        self.restart_btn.configure(
            font=('Arial', font_size, 'bold'),
            width=max(18, int(20 * scale)),
            height=2,
            justify='center',
            wraplength=int(240 * scale),
        )
        self.restart_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'exit_btn', None) is not None and self.exit_btn.winfo_exists():
        self.exit_btn.configure(
            font=('Arial', font_size, 'bold'),
            width=max(12, int(14 * scale)),
            height=2,
            justify='center',
            wraplength=int(120 * scale),
        )
        self.exit_btn.pack(side='left')


