def _fixed24_patched_build_researcher_ui(self):
    _fixed24_original_build_researcher_ui(self)
    scale = _fixed24_scale(self.root)
    gap = max(10, int(12 * scale))
    buttons = [getattr(self, 'research_default_btn', None), getattr(self, 'research_all_results_btn', None), getattr(self, 'research_next_btn', None), getattr(self, 'research_exit_btn', None)]
    for btn in buttons:
        if btn is not None and btn.winfo_exists():
            try:
                btn.pack_forget()
            except Exception:
                pass
    if getattr(self, 'research_default_btn', None) is not None:
        self.research_default_btn.configure(width=max(18, int(22 * scale)), justify='center', wraplength=int(240 * scale))
        self.research_default_btn.pack(side='left', padx=(0, gap))
    if getattr(self, 'research_all_results_btn', None) is not None:
        self.research_all_results_btn.configure(width=max(14, int(16 * scale)), justify='center', wraplength=int(180 * scale))
        self.research_all_results_btn.pack(side='left', padx=(0, gap))
    if getattr(self, 'research_next_btn', None) is not None:
        self.research_next_btn.configure(width=max(16, int(20 * scale)), justify='center', wraplength=int(220 * scale))
        self.research_next_btn.pack(side='right', padx=(gap, 0))
    if getattr(self, 'research_exit_btn', None) is not None:
        self.research_exit_btn.configure(width=max(12, int(14 * scale)), justify='center', wraplength=int(120 * scale))
        self.research_exit_btn.pack(side='right')


_fixed24_original_method_b_build_ui = MethodBWindow._build_ui

def _fixed24_method_b_build_ui(self):
    _fixed24_original_method_b_build_ui(self)
    self.all_tray_shapes = list(range(len(BASIC_SYMBOLS)))
    self.drag_shape = None
    self.drag_preview = None
    self._drag_motion_bind = None
    self._drag_release_bind = None
    self.selection_var.set('Во время воспроизведения перетащите нужную фигуру из кассы слева в нужную ячейку.')



def _fixed24_method_b_used_shapes(self):
    return set(self.placements.values()) if isinstance(getattr(self, 'placements', {}), dict) else set()



def _fixed24_method_b_show_drag_preview(self, x_root: int, y_root: int, shape_id: int):
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.destroy()
        except Exception:
            pass
    preview = tk.Toplevel(self.win)
    preview.overrideredirect(True)
    preview.attributes('-topmost', True)
    preview.configure(bg='#ffefd5')
    canvas = tk.Canvas(preview, width=72, height=72, bg='#ffefd5', highlightthickness=0)
    canvas.pack()
    draw_basic_symbol(canvas, 8, 8, 64, 64, shape_id, fill='#400000', outline='#400000')
    preview.geometry(f'72x72+{int(x_root - 36)}+{int(y_root - 36)}')
    self.drag_preview = preview



def _fixed24_method_b_move_drag_preview(self, x_root: int, y_root: int):
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.geometry(f'+{int(x_root - 36)}+{int(y_root - 36)}')
        except Exception:
            pass



def _fixed24_method_b_end_drag(self):
    if getattr(self, '_drag_motion_bind', None):
        try:
            self.win.unbind('<B1-Motion>', self._drag_motion_bind)
        except Exception:
            pass
    if getattr(self, '_drag_release_bind', None):
        try:
            self.win.unbind('<ButtonRelease-1>', self._drag_release_bind)
        except Exception:
            pass
    self._drag_motion_bind = None
    self._drag_release_bind = None
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.destroy()
        except Exception:
            pass
    self.drag_preview = None
    self.drag_shape = None
    self.selected_shape = None



def _fixed24_method_b_find_cell(self, x_root: int, y_root: int):
    for idx, cell in enumerate(self.grid_cells):
        try:
            x1 = cell.winfo_rootx()
            y1 = cell.winfo_rooty()
            x2 = x1 + cell.winfo_width()
            y2 = y1 + cell.winfo_height()
        except Exception:
            continue
        if x1 <= x_root <= x2 and y1 <= y_root <= y2:
            return idx
    return None



def _fixed24_method_b_place_shape(self, idx: int, shape_id: int):
    if self.phase != 'reproduce':
        return
    used = _fixed24_method_b_used_shapes(self)
    existing_at_target = self.placements.get(idx)
    if shape_id in used and existing_at_target != shape_id:
        return
    self.placements[idx] = shape_id
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)



def _fixed24_method_b_on_drag_motion(self, event):
    if getattr(self, 'drag_shape', None) is None:
        return
    _fixed24_method_b_move_drag_preview(self, event.x_root, event.y_root)



def _fixed24_method_b_on_drag_release(self, event):
    if getattr(self, 'drag_shape', None) is None:
        return
    shape_id = self.drag_shape
    target_idx = _fixed24_method_b_find_cell(self, event.x_root, event.y_root)
    if target_idx is not None:
        _fixed24_method_b_place_shape(self, target_idx, shape_id)
        self.selection_var.set('Фигура помещена в ячейку. Можно перетащить следующую или нажать «Готово».')
    else:
        self.selection_var.set('Фигура не была помещена в ячейку. Перетащите её ещё раз.')
    _fixed24_method_b_end_drag(self)



def _fixed24_method_b_start_drag(self, event, shape_id: int):
    if self.phase != 'reproduce':
        return 'break'
    if shape_id in _fixed24_method_b_used_shapes(self):
        return 'break'
    self.drag_shape = shape_id
    self.selected_shape = shape_id
    self.selection_var.set('Перетащите выбранную фигуру в нужную ячейку матрицы справа.')
    _fixed24_method_b_show_drag_preview(self, event.x_root, event.y_root, shape_id)
    self._drag_motion_bind = self.win.bind('<B1-Motion>', _fixed24_method_b_on_drag_motion, add='+')
    self._drag_release_bind = self.win.bind('<ButtonRelease-1>', _fixed24_method_b_on_drag_release, add='+')
    return 'break'



def _fixed24_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return
    items = list(getattr(self, 'all_tray_shapes', list(range(len(BASIC_SYMBOLS)))))
    used = _fixed24_method_b_used_shapes(self)
    columns = 4 if len(items) >= 12 else 3 if len(items) >= 6 else 2
    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        wrap = tk.Frame(self.tray_frame, bg='#f6e4bf')
        wrap.grid(row=row, column=col, padx=6, pady=6)
        is_used = shape in used
        bg = '#efe3cc' if is_used else 'white'
        border = '#dcc8ab' if is_used else '#d7c0a0'
        canvas = tk.Canvas(wrap, width=86, height=86, bg=bg, highlightthickness=1, highlightbackground=border, cursor='hand2' if not is_used else 'arrow')
        canvas.pack()
        fill = '#b59d89' if is_used else '#5a2323'
        outline = '#b59d89' if is_used else '#5a2323'
        draw_basic_symbol(canvas, 10, 10, 76, 76, shape, fill=fill, outline=outline)
        if is_used:
            canvas.create_line(14, 14, 72, 72, fill='#d46a6a', width=3)
        else:
            canvas.bind('<ButtonPress-1>', lambda e, s=shape: _fixed24_method_b_start_drag(self, e, s))
        self.tray_cells.append(canvas)

    if len(used) == 0:
        self.selection_var.set('В кассе слева показаны все фигуры. Перетаскивайте нужные в ячейки матрицы справа.')
    elif len(used) < len(self.current_positions):
        self.selection_var.set('Продолжайте перетаскивать фигуры в нужные ячейки. Занятые фигуры помечены в кассе.')
    else:
        self.selection_var.set('Все фигуры для этого цикла размещены. Проверьте матрицу и нажмите «Готово».')



def _fixed24_method_b_on_matrix_cell(self, idx: int):
    if self.phase != 'reproduce':
        return
    if idx in self.placements:
        del self.placements[idx]
        self._draw_reproduction_matrix()
        self._draw_tray(show=True)
        self.selection_var.set('Фигура убрана из ячейки. Можно перетащить другую фигуру из кассы.')



def _fixed24_method_b_clear_placements(self):
    if self.phase != 'reproduce':
        return
    self.placements = {}
    self.selected_shape = None
    _fixed24_method_b_end_drag(self)
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)




