# ====== FIXED31 researcher buttons + Method A fit-to-screen ======

_FIXED31_ORIGINAL_METHOD_A_INIT = MethodAApp.__init__


def _fixed31_adjust_method_a_cfg_for_screen(cfg: MethodAConfig) -> MethodAConfig:
    """Поджимает Метод A под текущий экран.
    Сохраняет физические размеры зон в сантиметрах, но уменьшает пиксельный масштаб и
    чувствительность шага, чтобы методика помещалась и на менее крупных экранах."""
    if not bool(getattr(cfg, 'auto_fit_to_screen', True)):
        return cfg

    total_radius_cm = float(getattr(cfg, 'target_half_cm', 3.0)) + float(getattr(cfg, 'work_extension_cm', 15.0)) + float(getattr(cfg, 'crash_extension_cm', 1.0))
    if total_radius_cm <= 0:
        return cfg

    side_margin = max(40, int(getattr(cfg, 'screen_side_margin_px', 90) or 90))
    vertical_margin = max(40, int(getattr(cfg, 'screen_vertical_margin_px', 70) or 70))
    available_radius = min(
        max(120.0, (float(cfg.width) - side_margin * 2) / 2.0),
        max(120.0, (float(cfg.height) - vertical_margin * 2) / 2.0),
    )
    max_px_per_cm = available_radius / total_radius_cm

    original_px_per_cm = max(1e-6, float(getattr(cfg, 'px_per_cm', 38.0)))
    if max_px_per_cm < original_px_per_cm:
        scale = max(0.35, float(max_px_per_cm) / original_px_per_cm)
        cfg.px_per_cm = max(10.0, max_px_per_cm)
        cfg.mouse_gain_px = max(0.35, float(getattr(cfg, 'mouse_gain_px', 1.15)) * scale)
        cfg.roll_step_per_wheel_notch_deg = max(1.0, float(getattr(cfg, 'roll_step_per_wheel_notch_deg', 4.0)) * max(0.6, scale))
    return cfg


def _fixed31_method_a_init(self, cfg: MethodAConfig, session: SessionInfo, logger: ParticipantsLogger, base_dir: Path):
    cfg = _fixed31_adjust_method_a_cfg_for_screen(cfg)
    _FIXED31_ORIGINAL_METHOD_A_INIT(self, cfg, session, logger, base_dir)


MethodAApp.__init__ = _fixed31_method_a_init


def _fixed31_update_research_button_wrap(self, _event=None):
    frame = getattr(self, 'research_actions_top', None)
    if frame is None or not frame.winfo_exists():
        return
    width = max(frame.winfo_width(), 760)
    slots = 4
    gap = 14
    usable = max(120, int((width - gap * (slots - 1)) / slots) - 20)
    for btn in (
        getattr(self, 'research_default_btn', None),
        getattr(self, 'research_all_results_btn', None),
        getattr(self, 'research_next_btn', None),
        getattr(self, 'research_exit_btn', None),
    ):
        if btn is not None and btn.winfo_exists():
            try:
                btn.configure(wraplength=usable, justify='center')
            except Exception:
                pass


def _fixed31_repack_research_action_row(self):
    frame = getattr(self, 'research_actions_top', None)
    if frame is None or not frame.winfo_exists():
        return

    scale = _fixed24_scale(self.root) if '_fixed24_scale' in globals() else 1.0
    gap_x = max(10, int(14 * scale))
    gap_y = max(8, int(10 * scale))
    font_size = max(12, int(16 * scale))
    pad_x = max(12, int(16 * scale))
    pad_y = max(6, int(8 * scale))

    buttons = [
        (getattr(self, 'research_default_btn', None), 'СБРОС ПО УМОЛЧАНИЮ', BACK_BG, BACK_ACTIVE),
        (getattr(self, 'research_all_results_btn', None), 'ВСЕ РЕЗУЛЬТАТЫ', '#6b7dff', '#5b6de8'),
        (getattr(self, 'research_next_btn', None), 'ПРОДОЛЖИТЬ К ЛОГИНУ', NEXT_BG, NEXT_ACTIVE),
        (getattr(self, 'research_exit_btn', None), 'ВЫХОД', EXIT_BG, EXIT_ACTIVE),
    ]

    for child in frame.winfo_children():
        try:
            child.pack_forget()
        except Exception:
            pass
        try:
            child.grid_forget()
        except Exception:
            pass

    for col in range(4):
        frame.grid_columnconfigure(col, weight=1, uniform='research_buttons')

    for idx, (btn, text, bg, active_bg) in enumerate(buttons):
        if btn is None or not btn.winfo_exists():
            continue
        btn.configure(
            text=text,
            font=('Arial', font_size, 'bold'),
            bg=bg,
            activebackground=active_bg,
            fg='white' if idx == 1 else '#111111',
            relief='raised',
            bd=3,
            height=2,
            padx=pad_x,
            pady=pad_y,
            justify='center',
            anchor='center',
            width=1,
        )
        btn.grid(row=0, column=idx, sticky='ew', padx=(0 if idx == 0 else gap_x, 0), pady=(0, gap_y))

    if not getattr(self, '_fixed31_research_wrap_bound', False):
        try:
            frame.bind('<Configure>', lambda event, _self=self: _fixed31_update_research_button_wrap(_self, event), add='+')
            self._fixed31_research_wrap_bound = True
        except Exception:
            pass
    _fixed31_update_research_button_wrap(self)


def _fixed31_patched_build_researcher_ui(self):
    _fixed25_patched_build_researcher_ui(self)
    _fixed31_repack_research_action_row(self)


StartPageApp.build_researcher_ui = _fixed31_patched_build_researcher_ui

