# ====== FIXED35 compact researcher layout without left empty column ======

def _patched_populate_researcher_fields_fixed35(self):
    for child in self.research_content.winfo_children():
        child.destroy()
    self.research_widgets = {}
    self.research_sections = {}

    self.research_tabs = ttk.Notebook(self.research_content)
    self.research_tabs.pack(fill='both', expand=True, padx=14, pady=10)
    self.research_tabs.bind('<<NotebookTabChanged>>', lambda _event: self._on_research_content_configure())

    for code, title, cls, _filename in RESEARCH_CONFIG_SPECS:
        tab = tk.Frame(self.research_tabs, bg=BG_COLOR)
        self.research_tabs.add(tab, text=f'Тест {code}')

        intro = tk.Label(
            tab,
            text=title,
            bg=BG_COLOR,
            fg=TITLE_COLOR,
            anchor='w',
            justify='left',
        )
        intro.pack(fill='x', padx=10, pady=(4, 10))

        sections_wrap = tk.Frame(tab, bg=BG_COLOR)
        sections_wrap.pack(fill='both', expand=True, padx=6, pady=(0, 6))

        cfg = cls()
        widgets = {}
        section_frames = []
        section_groups = _get_research_section_groups(code, cls)

        for section_title, field_names in section_groups:
            section = tk.LabelFrame(
                sections_wrap,
                text=section_title,
                bg=PANEL_COLOR,
                fg=TITLE_COLOR,
                bd=2,
                relief='groove',
                padx=10,
                pady=8,
            )
            section.pack(fill='x', expand=True, padx=6, pady=7, anchor='n')
            section_frames.append(section)
            section.grid_columnconfigure(0, weight=1)
            section.grid_columnconfigure(1, weight=1)

            row = 0
            col = 0
            for field_name in field_names:
                fld = next((item for item in fields(cls) if item.name == field_name), None)
                if fld is None:
                    continue
                default_value = getattr(cfg, fld.name)
                meta = _get_research_field_meta(code, fld.name)
                serialized = _serialize_config_value(default_value)
                is_multiline = isinstance(default_value, (list, dict, tuple)) or len(serialized) > 60
                span_two = is_multiline or len(meta.get('help', '')) > 120 or len(meta.get('label', fld.name)) > 38

                field_box = tk.Frame(section, bg=PANEL_COLOR, bd=0, highlightthickness=0)
                if span_two:
                    if col != 0:
                        row += 1
                        col = 0
                    field_box.grid(row=row, column=0, columnspan=2, sticky='ew', padx=8, pady=6)
                else:
                    field_box.grid(row=row, column=col, sticky='nsew', padx=8, pady=6)
                    section.grid_columnconfigure(col, weight=1)

                label = tk.Label(
                    field_box,
                    text=meta.get('label', fld.name),
                    bg=PANEL_COLOR,
                    fg=TITLE_COLOR,
                    anchor='w',
                    justify='left',
                    font=('Segoe UI', 10, 'bold'),
                    wraplength=820 if span_two else 420,
                )
                label.pack(fill='x', anchor='w')

                help_text = meta.get('help', '')
                if help_text:
                    help_label = tk.Label(
                        field_box,
                        text=help_text,
                        bg=PANEL_COLOR,
                        fg='#5a5a5a',
                        anchor='w',
                        justify='left',
                        wraplength=820 if span_two else 420,
                    )
                    help_label.pack(fill='x', anchor='w', pady=(2, 0))

                widget_box = tk.Frame(field_box, bg=PANEL_COLOR)
                widget_box.pack(fill='x', pady=(6, 0))
                widget_box.grid_columnconfigure(0, weight=1)
                if is_multiline:
                    height = max(3, min(7, serialized.count('\n') + max(2, len(serialized) // 70 + 1)))
                    widget = tk.Text(
                        widget_box,
                        height=height,
                        wrap='word',
                        bg=FIELD_BG,
                        relief='sunken',
                        bd=1,
                    )
                    widget.insert('1.0', serialized)
                    widget.grid(row=0, column=0, sticky='ew')
                else:
                    widget = tk.Entry(widget_box, bg=FIELD_BG)
                    widget.insert(0, serialized)
                    widget.grid(row=0, column=0, sticky='ew', ipady=4)

                default_hint = tk.Label(
                    field_box,
                    text=f'По умолчанию: {serialized}',
                    bg=PANEL_COLOR,
                    fg='#6b7280',
                    anchor='w',
                    justify='left',
                    wraplength=860 if span_two else 420,
                )
                default_hint.pack(fill='x', anchor='w', pady=(4, 0))

                sep = tk.Frame(field_box, bg='#d7d1bf', height=1)
                sep.pack(fill='x', pady=(8, 0))

                widgets[fld.name] = {'widget': widget, 'template': default_value, 'is_multiline': is_multiline}

                if span_two:
                    row += 1
                    col = 0
                else:
                    col += 1
                    if col > 1:
                        row += 1
                        col = 0

        self.research_widgets[code] = widgets
        self.research_sections[code] = section_frames

    _bind_mousewheel_to_canvas(self.research_canvas, self.research_content, self.research_tabs)
    self._on_research_content_configure()


def _patched_apply_researcher_layout_fixed35(self):
    width = max(self.root.winfo_width(), 1100)
    height = max(self.root.winfo_height(), 760)
    scale = min(width / BASE_W, height / BASE_H)
    scale = max(0.72, min(scale, 1.6))

    pad_x = int(18 * scale)
    pad_y = int(14 * scale)
    self.main.pack_configure(padx=pad_x, pady=pad_y)
    self.research_header.pack_configure(pady=(0, int(8 * scale)))
    self.research_actions_top.pack_configure(pady=(0, int(8 * scale)))
    self.research_status.pack_configure(pady=(0, int(8 * scale)))

    title_size = max(24, int(38 * scale))
    text_size = max(11, int(15 * scale))
    section_label_size = max(11, int(14 * scale))
    button_size = max(11, int(15 * scale))

    self.research_title.configure(font=('Times New Roman', title_size, 'bold'))
    self.research_subtitle.configure(font=('Arial', text_size, 'bold'), wraplength=int(width * 0.9))
    self.research_status.configure(font=('Arial', text_size, 'bold'), wraplength=int(width * 0.9))
    for btn in (self.research_default_btn, self.research_next_btn, self.research_exit_btn, getattr(self, 'research_all_results_btn', None)):
        if btn is not None:
            btn.configure(font=('Arial', button_size, 'bold'))
    self.research_default_btn.pack_configure(padx=(0, int(10 * scale)))
    self.research_exit_btn.pack_configure(padx=(int(10 * scale), 0))
    self.research_next_btn.pack_configure(padx=(int(10 * scale), 0))
    if getattr(self, 'research_all_results_btn', None) is not None:
        self.research_all_results_btn.pack_configure(padx=(int(10 * scale), 0))

    title_wrap_one = int(width * 0.62)
    title_wrap_two = int(width * 0.30)
    help_wrap_one = int(width * 0.62)
    help_wrap_two = int(width * 0.30)
    default_wrap_one = int(width * 0.62)
    default_wrap_two = int(width * 0.30)
    for section_list in self.research_sections.values():
        for section in section_list:
            try:
                section.configure(font=('Arial', section_label_size, 'bold'))
            except tk.TclError:
                pass
            for child in section.winfo_children():
                if isinstance(child, tk.Frame):
                    child_width = max(child.winfo_width(), 200)
                    wide_box = child.grid_info().get('columnspan', 1) == 2
                    t_wrap = title_wrap_one if wide_box else max(260, min(title_wrap_two, child_width - 16))
                    h_wrap = help_wrap_one if wide_box else max(260, min(help_wrap_two, child_width - 16))
                    d_wrap = default_wrap_one if wide_box else max(260, min(default_wrap_two, child_width - 16))
                    for nested in child.winfo_children():
                        if isinstance(nested, tk.Label):
                            text = str(nested.cget('text'))
                            fg = str(nested.cget('fg'))
                            if text.startswith('По умолчанию:'):
                                nested.configure(font=('Arial', max(10, text_size - 1)), wraplength=d_wrap)
                            elif fg == TITLE_COLOR:
                                nested.configure(font=('Arial', text_size, 'bold'), wraplength=t_wrap)
                            else:
                                nested.configure(font=('Arial', max(10, text_size - 1)), wraplength=h_wrap)
                        elif isinstance(nested, tk.Entry):
                            nested.configure(font=('Consolas', text_size))
                        elif isinstance(nested, tk.Text):
                            nested.configure(font=('Consolas', max(10, text_size - 1)))
    self._on_research_canvas_configure()
    self._on_research_content_configure()


StartPageApp._populate_researcher_fields = _patched_populate_researcher_fields_fixed35
StartPageApp.apply_researcher_layout = _patched_apply_researcher_layout_fixed35


# ====== FIXED36 all-results aesthetics + full-window mouse wheel ======

def _bind_mousewheel_to_canvas(canvas: tk.Canvas, *widgets):
    def _wheel_delta(event):
        if getattr(event, 'delta', 0):
            return -1 * int(event.delta / 120) if event.delta else 0
        if getattr(event, 'num', None) == 4:
            return -1
        if getattr(event, 'num', None) == 5:
            return 1
        return 0

    def _iter_widgets(root):
        if root is None:
            return
        stack = [root]
        seen_local = set()
        while stack:
            item = stack.pop()
            if item is None or id(item) in seen_local:
                continue
            seen_local.add(id(item))
            yield item
            try:
                children = item.winfo_children()
            except Exception:
                children = []
            stack.extend(reversed(children))

    top = canvas.winfo_toplevel()

    def _on_mousewheel(event):
        try:
            if event.widget.winfo_toplevel() != top:
                return None
        except Exception:
            return None
        delta = _wheel_delta(event)
        if delta:
            try:
                canvas.yview_scroll(delta, 'units')
                return 'break'
            except Exception:
                return None
        return None

    seen = set()
    for root in (top, canvas, *widgets):
        for widget in _iter_widgets(root):
            if id(widget) in seen:
                continue
            seen.add(id(widget))
            try:
                widget.bind('<MouseWheel>', _on_mousewheel, add='+')
                widget.bind('<Button-4>', _on_mousewheel, add='+')
                widget.bind('<Button-5>', _on_mousewheel, add='+')
            except Exception:
                pass


def _show_all_results_browser_v2(self):
    top = tk.Toplevel(self.root)
    top.title('Все результаты')
