class _Fixed42HoverTip:
    def __init__(self, widget, text: str, bg: str = '#fff7d7'):
        self.widget = widget
        self.text = text
        self.bg = bg
        self.tip = None
        self.label = None
        widget.bind('<Enter>', self._show, add='+')
        widget.bind('<Leave>', self._hide, add='+')
        widget.bind('<Motion>', self._move, add='+')

    def _show(self, event=None):
        if self.tip is not None or not self.text:
            return
        top = tk.Toplevel(self.widget)
        top.overrideredirect(True)
        top.attributes('-topmost', True)
        top.configure(bg=self.bg)
        lbl = tk.Label(
            top,
            text=self.text,
            justify='left',
            wraplength=520,
            bg=self.bg,
            fg='#2b2b2b',
            font=('Arial', 12),
            bd=1,
            relief='solid',
            padx=14,
            pady=10,
        )
        lbl.pack()
        self.tip = top
        self.label = lbl
        self._move(event)

    def _move(self, event=None):
        if self.tip is None:
            return
        self.tip.update_idletasks()
        sw = self.widget.winfo_screenwidth()
        sh = self.widget.winfo_screenheight()
        tw = max(120, self.tip.winfo_reqwidth())
        th = max(40, self.tip.winfo_reqheight())
        px = event.x_root if event else (self.widget.winfo_rootx() + self.widget.winfo_width() // 2)
        py = event.y_root if event else (self.widget.winfo_rooty() + self.widget.winfo_height() // 2)
        x = px + 18
        y = py + 18
        if x + tw > sw - 12:
            x = px - tw - 18
        if x < 8:
            x = 8
        if y + th > sh - 12:
            y = py - th - 18
        if y < 8:
            y = 8
        self.tip.geometry(f'+{int(x)}+{int(y)}')

    def _hide(self, event=None):
        if self.tip is not None:
            try:
                self.tip.destroy()
            except Exception:
                pass
            self.tip = None
            self.label = None


def _fixed42_make_help_button(parent, instruction_text: str, bg: str = UNIFORM_TEST_BG):
    btn = tk.Label(
        parent,
        text='?',
        bg='#ffffff',
        fg=UNIFORM_TEST_FG,
        font=('Arial', 16, 'bold'),
        width=2,
        height=1,
        relief='solid',
        bd=1,
        cursor='question_arrow',
        padx=4,
        pady=1,
    )
    _Fixed42HoverTip(btn, instruction_text)
    return btn


def _fixed42_create_bar(parent, label_text: str, bg: str, width: int = 280):
    wrap = tk.Frame(parent, bg=bg)
    tk.Label(wrap, text=label_text, bg=bg, fg=UNIFORM_TEST_FG, font=('Arial', 11, 'bold')).pack(anchor='w')
    canvas = tk.Canvas(wrap, width=width, height=14, bg=bg, highlightthickness=0, bd=0)
    canvas.pack(anchor='w', pady=(4, 0))
    return wrap, canvas


def _fixed42_set_bar(canvas: tk.Canvas, ratio: float, fill: str):
    ratio = max(0.0, min(1.0, float(ratio)))
    try:
        width = max(40, int(canvas.winfo_width()))
        if width <= 1:
            width = int(canvas.cget('width'))
    except Exception:
        width = int(canvas.cget('width'))
    try:
        height = max(10, int(canvas.winfo_height()))
        if height <= 1:
            height = int(canvas.cget('height'))
    except Exception:
        height = int(canvas.cget('height'))
    canvas.delete('all')
    canvas.create_rectangle(1, 1, width - 1, height - 1, outline='#b8b09a', fill='#fbf8ee', width=1)
    fill_w = max(2, int((width - 2) * ratio)) if ratio > 0 else 0
    if fill_w > 0:
        canvas.create_rectangle(1, 1, min(width - 1, fill_w), height - 1, outline='', fill=fill)


def _fixed42_method_b_update_hud(self):
    if getattr(self, 'time_bar_canvas', None) is None or getattr(self, 'task_bar_canvas', None) is None:
        return
    total = max(1.0, float(self.cfg.total_test_s))
    time_ratio = min(1.0, self._elapsed_total() / total)
    if self.phase == 'reproduce' and self.current_positions:
        task_ratio = len(self.placements) / max(1, len(self.current_positions))
    else:
        task_ratio = max(1, min(self.cfg.max_items, int(self.current_n))) / max(1, self.cfg.max_items)
    _fixed42_set_bar(self.time_bar_canvas, time_ratio, '#68a8ff')
    _fixed42_set_bar(self.task_bar_canvas, task_ratio, '#67cb7b')


def _fixed42_method_b_update_info_label(self):
    self.info_var.set('')
    _fixed42_method_b_update_hud(self)
    if self.phase in ('memorize', 'reproduce', 'message') and self.win and self.win.winfo_exists():
        self._track_after(self.win.after(160, self._update_info_label))


def _fixed42_method_b_tick_reproduction_timeout(self):
    if self.phase != 'reproduce' or not self.win or not self.win.winfo_exists():
        return
    remaining = self.reproduction_deadline - time.perf_counter()
    _fixed42_method_b_update_hud(self)
    if remaining <= 0:
        self._finalize_cycle(success=False, reason='timeout')
        return
    self._track_after(self.win.after(100, self._tick_reproduction_timeout))


