def _fixed42_method_c_update_hud(self):
    if getattr(self, 'time_bar_canvas', None) is None or getattr(self, 'task_bar_canvas', None) is None:
        return
    stage_total = 1.0
    if 1 <= int(self.stage_index or 1) <= 3:
        stage_total = float(self.cfg.stage_time_s[max(0, self.stage_index - 1)])
    stage_left = self._stage_time_left() if getattr(self, 'stage_index', 0) else stage_total
    time_ratio = 1.0 - max(0.0, min(1.0, stage_left / max(1.0, stage_total)))
    local = max(0.0, min(1.0, time_ratio))
    task_ratio = ((max(1, self.stage_index) - 1) + local) / 3.0
    _fixed42_set_bar(self.time_bar_canvas, time_ratio, '#68a8ff')
    _fixed42_set_bar(self.task_bar_canvas, task_ratio, '#67cb7b')


def _fixed42_method_c_tick_stage_clock(self):
    if not self.win or not self.win.winfo_exists() or self.phase == 'finished':
        return
    self.info_var.set('')
    _fixed42_method_c_update_hud(self)
    self._track_after(self.win.after(150, self._tick_stage_clock))


