    if getattr(self, 'back_to_settings_btn', None) is not None and self.back_to_settings_btn.winfo_exists():
        self.back_to_settings_btn.configure(
            font=('Arial', button_font_size, 'bold'),
            width=max(button_width + 3, 14),
            height=max(1, int(1 * scale)),
            padx=max(14, int(16 * scale)),
            pady=max(8, int(10 * scale)),
            justify='center',
            anchor='center',
            wraplength=0,
            text='НАСТРОЙКИ',
        )
        try:
            self.back_to_settings_btn.pack_configure(padx=(0, button_gap))
        except Exception:
            pass
        try:
            self.exit_btn.configure(width=max(button_width - 1, 8), font=('Arial', button_font_size, 'bold'))
            self.next_btn.configure(width=max(button_width - 1, 8), font=('Arial', button_font_size, 'bold'))
            self.exit_btn.pack_configure(padx=(0, button_gap))
            self.next_btn.pack_configure(padx=(0, 0))
        except Exception:
            pass


