# ====== FIXED49: menu action row order and settings button size ======
def _fixed49_repack_menu_action_row(self):
    if not hasattr(self, 'menu_btn_frame') or self.menu_btn_frame is None:
        return
    scale = _fixed24_scale(self.root) if '_fixed24_scale' in globals() else 1.0
    gap = max(10, int(12 * scale))
    font_size = max(11, int(16 * scale))
    self.menu_btn_frame.grid_configure(sticky='ew', pady=(0, int(10 * scale)))
    try:
        self.right.grid_columnconfigure(0, weight=1)
    except Exception:
        pass

    buttons = [
        getattr(self, 'settings_btn', None),
        getattr(self, 'all_results_btn', None),
        getattr(self, 'continue_btn', None),
        getattr(self, 'restart_btn', None),
        getattr(self, 'exit_btn', None),
    ]
    for btn in buttons:
        if btn is not None and btn.winfo_exists():
            try:
                btn.pack_forget()
            except Exception:
                pass

    common = dict(font=('Arial', font_size, 'bold'), height=2, justify='center', wraplength=0)

    if getattr(self, 'settings_btn', None) is not None and self.settings_btn.winfo_exists():
        self.settings_btn.configure(text='НАСТРОЙКИ', width=max(14, int(16 * scale)), padx=max(10, int(12 * scale)), **common)
        self.settings_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'all_results_btn', None) is not None and self.all_results_btn.winfo_exists():
        self.all_results_btn.configure(text='ВСЕ РЕЗУЛЬТАТЫ', width=max(16, int(18 * scale)), padx=max(10, int(12 * scale)), **common)
        self.all_results_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'continue_btn', None) is not None and self.continue_btn.winfo_exists():
        self.continue_btn.configure(text='СЛЕДУЮЩИЙ ТЕСТ', width=max(16, int(18 * scale)), padx=max(10, int(12 * scale)), **common)
        self.continue_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'restart_btn', None) is not None and self.restart_btn.winfo_exists():
        self.restart_btn.configure(width=max(16, int(18 * scale)), padx=max(10, int(12 * scale)), **common)
        self.restart_btn.pack(side='left', padx=(0, gap))

    if getattr(self, 'exit_btn', None) is not None and self.exit_btn.winfo_exists():
        self.exit_btn.configure(width=max(8, int(9 * scale)), padx=max(10, int(12 * scale)), **common)
        self.exit_btn.pack(side='right')


def _fixed49_apply_menu_layout(self):
    _FIXED48_ORIGINAL_APPLY_MENU_LAYOUT(self)
    if getattr(self, 'view_mode', '') != 'menu':
        return
    _fixed49_repack_menu_action_row(self)


StartPageApp.apply_menu_layout = _fixed49_apply_menu_layout



# ====== FIXED50: normalize bottom action rows on start and menu screens ======
def _fixed50_relayout_start_action_row(self):
    if not hasattr(self, 'btn_frame') or self.btn_frame is None or not self.btn_frame.winfo_exists():
        return
    scale = _fixed24_scale(self.root) if '_fixed24_scale' in globals() else 1.0
    gap = max(8, int(10 * scale))
    frame = self.btn_frame
    try:
        frame.grid_configure(sticky='ew', pady=(0, int(8 * scale)))
    except Exception:
        pass
    try:
        self.right.grid_columnconfigure(0, weight=1)
    except Exception:
        pass

    buttons = [
        getattr(self, 'back_to_settings_btn', None),
        getattr(self, 'next_btn', None),
        getattr(self, 'exit_btn', None),
    ]
    for btn in buttons:
        if btn is not None and btn.winfo_exists():
            try:
                btn.pack_forget()
            except Exception:
                pass
            try:
                btn.grid_forget()
            except Exception:
                pass

    for col, weight in enumerate((1.3, 1.0, 0.75)):
        try:
            frame.grid_columnconfigure(col, weight=weight, uniform='start_actions')
        except Exception:
            pass

    width = max(self.root.winfo_width(), 1100)
    height = max(self.root.winfo_height(), 760)
    scale2 = min(width / BASE_W, height / BASE_H)
    scale2 = max(0.72, min(scale2, 1.25))
    font_size = max(12, int(18 * scale2))
    pad_x = max(10, int(12 * scale2))
    pad_y = max(8, int(10 * scale2))

    common = dict(font=('Arial', font_size, 'bold'), height=2, bd=3, relief='raised', justify='center', anchor='center')
    labels = [
        (getattr(self, 'back_to_settings_btn', None), 'НАСТРОЙКИ'),
        (getattr(self, 'next_btn', None), 'ДАЛЕЕ'),
        (getattr(self, 'exit_btn', None), 'ВЫХОД'),
    ]
    for col, (btn, label) in enumerate(labels):
        if btn is None or not btn.winfo_exists():
            continue
        try:
            btn.configure(text=label, wraplength=0, padx=pad_x, pady=pad_y, **common)
        except Exception:
            pass
        try:
            btn.grid(row=0, column=col, sticky='ew', padx=(0, gap) if col < 2 else (0, 0), pady=0)
        except Exception:
            pass


