# ====== FIXED54: menu text fit + Method A roll logic + save partial A results ======
def _fixed54_normalize_method_a_cfg(cfg: MethodAConfig) -> MethodAConfig:
    try:
        if float(getattr(cfg, 'target_roll_deg', 0.0)) <= 5.5 and float(getattr(cfg, 'work_roll_deg', 0.0)) >= 80.0:
            cfg.target_roll_deg = 12.0
            cfg.work_roll_deg = 12.0
        if float(getattr(cfg, 'start_speed_z_deg_s', 0.0)) >= 9.5:
            cfg.start_speed_z_deg_s = 3.0
        if float(getattr(cfg, 'step_speed_z_deg_s', 0.0)) >= 1.8:
            cfg.step_speed_z_deg_s = 1.0
        if float(getattr(cfg, 'roll_step_per_wheel_notch_deg', 0.0)) >= 3.5:
            cfg.roll_step_per_wheel_notch_deg = 2.0
    except Exception:
        pass
    return cfg

_FIXED54_PREV_LOAD_CONFIG = load_config
def load_config(path: str | Path = "method_a_config.json", screen_w: int | None = None, screen_h: int | None = None) -> MethodAConfig:
    cfg = _FIXED54_PREV_LOAD_CONFIG(path, screen_w, screen_h)
    return _fixed54_normalize_method_a_cfg(cfg)
globals()["load_config"] = load_config

def _fixed54_load_researcher_cfg(self, cls, filename):
    cfg = _load_json_dataclass(self.base_dir / filename, cls)
    if cls is MethodAConfig:
        cfg = _fixed54_normalize_method_a_cfg(cfg)
    return cfg
StartPageApp.load_researcher_cfg = _fixed54_load_researcher_cfg

def _fixed54_method_a_inside_target(self, state: DriftState, stage_no: int) -> bool:
    stage = self.stage_defs[stage_no]
    ok_x = (not stage["x"]) or abs(state.x_px) <= self.target_half_px
    ok_y = (not stage["y"]) or abs(state.y_px) <= self.target_half_px
    return ok_x and ok_y

def _fixed54_method_a_roll_limit_exceeded(self, state: DriftState, stage_no: int) -> bool:
    return bool(self.stage_defs[stage_no]["z"]) and abs(state.roll_deg) > max(1.0, float(self.cfg.work_roll_deg))

def _fixed54_method_a_in_crash_zone(self, state: DriftState, stage_no: int) -> bool:
    stage = self.stage_defs[stage_no]
    hit_x = stage["x"] and abs(state.x_px) > self.work_half_px
    hit_y = stage["y"] and abs(state.y_px) > self.work_half_px
    hit_z = bool(stage["z"]) and abs(state.roll_deg) > max(1.0, float(self.cfg.work_roll_deg))
    return hit_x or hit_y or hit_z

def _fixed54_method_a_draw_roll_limit_guides(self, state: DriftState, stage_no: int):
    if not self.stage_defs[stage_no]["z"]:
        return
    cx = int(self.center.x)
    cy = int(self.center.y)
    outer_radius = int(self.work_half_px)
    limit_deg = max(6.0, float(self.cfg.work_roll_deg))
    slope = math.tan(math.radians(limit_deg)) * 0.55
    color = self.cfg.crash_color if self.roll_limit_exceeded(state, stage_no) else self.cfg.grid_color
    overlay = pygame.Surface((self.cfg.width, self.cfg.height), pygame.SRCALPHA)
    alpha = 215 if self.roll_limit_exceeded(state, stage_no) else 125
    for sign in (-1, 1):
        pts = []
        x = cx - outer_radius
        while x <= cx + outer_radius:
            y = cy + sign * slope * (x - cx)
            if (x - cx) ** 2 + (y - cy) ** 2 <= outer_radius ** 2:
                pts.append((int(x), int(y)))
            x += 4
        if len(pts) >= 2:
            pygame.draw.aalines(overlay, (*color, alpha), False, pts)
    self.screen.blit(overlay, (0, 0))

MethodAApp.inside_target = _fixed54_method_a_inside_target
MethodAApp.roll_limit_exceeded = _fixed54_method_a_roll_limit_exceeded
MethodAApp.in_crash_zone = _fixed54_method_a_in_crash_zone
MethodAApp.draw_roll_limit_guides = _fixed54_method_a_draw_roll_limit_guides

def _fixed54_run_method_a(self, session: SessionInfo) -> dict:
    try:
        _ensure_pygame()
    except Exception as exc:
        messagebox.showerror(
            "Тест A недоступен",
            "Не удалось загрузить модуль pygame.\n"
            "Остальные экраны программы работают, но Тест A сейчас запустить нельзя.\n\n"
            f"Ошибка: {exc}"
        )
        return {'completed': False, 'reports': []}
    result = {'completed': False, 'reports': []}
    self.set_enabled(False)
    self.root.update_idletasks()
    self.root.withdraw()
    try:
        cfg = load_config(path=self.base_dir / "method_a_config.json", screen_w=self.root.winfo_screenwidth(), screen_h=self.root.winfo_screenheight())
        result = MethodAApp(cfg, session, self.logger, self.base_dir).run()
    finally:
        self.root.deiconify()
        self.open_fullscreen()
        self.root.update_idletasks()
        try:
            self.root.focus_force()
        except Exception:
            pass
    if result.get("reports"):
        payload = self.build_method_a_payload(session, result)
        payload["completed"] = bool(result.get("completed"))
        self.progress_store.save_test_result(self.current_profile, "A", payload)
    if result.get("completed"):
        self.logger.log_event(session, event_type="summary", screen="test_menu", test_name="method_a", action="session_finished", value=len(result.get("reports", [])), note="Методика А завершена, данные добавлены в participants.csv и user_progress.json")
        self.menu_status_var.set("Тест А завершён. Его результат можно открыть из меню.")
        messagebox.showinfo("Готово", f"Тест А завершён.\nОбщий файл: {self.logger.data_file}\nРезультат сохранён и доступен из меню.")
    else:
        self.menu_status_var.set("Тест А был прерван. Уже выполненные этапы сохранены и доступны в результатах.")
        if result.get("reports"):
            messagebox.showwarning("Остановлено", "Тест А был прерван.\nЧастично выполненные этапы сохранены и доступны в результатах.")
        else:
            messagebox.showwarning("Остановлено", "Тест А был прерван до появления данных.")
    self.set_enabled(True)
    self.refresh_menu_state()
    return result
StartPageApp.run_method_a = _fixed54_run_method_a

def _fixed54_refresh_menu_state(self):
    if not self.current_profile:
        return
    progress = self.progress_store.ensure_user(self.current_profile)
    completed = progress.get("completed_tests", [])
    next_code = self.progress_store.next_test_code(self.current_profile)
    completed_text = ", ".join(TEST_LABELS[c] for c in completed) if completed else "пока нет"
    if getattr(self, "researcher_mode_enabled", False):
        self.menu_intro_var.set(f"Пользователь: {self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}.")
        next_text = f"Следующий неполный тест: {TEST_LABELS[next_code]}." if next_code else "Все методики уже завершены."
        self.menu_status_var.set(f"Пройдено: {completed_text}.\n{next_text}")
        for code, btn in self.menu_buttons.items():
            if code in completed:
                text = f"{TEST_LABELS[code]}\n{TEST_DESCRIPTIONS[code]}\n(можно запустить снова)"
                btn.configure(state=tk.NORMAL, text=text, bg="#d8f0d7", activebackground="#c7e7c6", fg="#102744", relief="raised")
            else:
                btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG if code == next_code else MENU_BG, activebackground=NEXT_ACTIVE if code == next_code else MENU_ACTIVE, fg="#111111", relief="raised")
        for code, btn in getattr(self, "menu_result_buttons", {}).items():
            has_payload = bool(self.progress_store.get_test_result(self.current_profile, code))
            if has_payload:
                btn.configure(state=tk.NORMAL, text="ПОКАЗАТЬ\nРЕЗУЛЬТАТ", bg="#6b7dff", activebackground="#5b6de8", fg="white", relief="raised")
            else:
                btn.configure(state=tk.DISABLED, text="РЕЗУЛЬТАТОВ\nПОКА НЕТ", bg="#d6dbe5", activebackground="#d6dbe5", disabledforeground="#7f8897", relief="flat")
        if next_code:
            self.continue_btn.configure(state=tk.NORMAL, text="СЛЕДУЮЩИЙ ТЕСТ", bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg="#111111", relief="raised")
        else:
            self.continue_btn.configure(state=tk.NORMAL, text="ОБЩИЙ ПРОФИЛЬ СПР", bg="#4f78ff", activebackground="#4269e0", fg="white", relief="raised")
        if getattr(self, "all_results_btn", None) is not None:
            self.all_results_btn.configure(state=tk.NORMAL)
    else:
        self.menu_intro_var.set(f"Пользователь: {self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}.")
        next_text = f"Следующий тест: {TEST_LABELS[next_code]}." if next_code else "Все тесты пройдены."
        self.menu_status_var.set(f"Пройдено: {completed_text}.\n{next_text}")
        for code, btn in self.menu_buttons.items():
            if code in completed:
                btn.configure(state=tk.DISABLED, text=menu_card_text(code, "done"), bg="#bfc7ba", activebackground="#bfc7ba", disabledforeground="#4a5b47", relief="sunken")
            elif code == next_code:
                btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg="#111111", relief="raised")
            else:
                btn.configure(state=tk.DISABLED, text=menu_card_text(code, "locked"), bg=MENU_DISABLED, activebackground=MENU_DISABLED, disabledforeground="#6d6955", relief="ridge")
        for code, btn in getattr(self, "menu_result_buttons", {}).items():
            has_payload = bool(self.progress_store.get_test_result(self.current_profile, code))
            if has_payload:
                btn.configure(state=tk.NORMAL, text="ПОКАЗАТЬ\nРЕЗУЛЬТАТ", bg="#6b7dff", activebackground="#5b6de8", fg="white", relief="raised")
            else:
                btn.configure(state=tk.DISABLED, text="РЕЗУЛЬТАТОВ\nПОКА НЕТ", bg="#d6dbe5", activebackground="#d6dbe5", disabledforeground="#7f8897", relief="flat")
        if next_code:
            self.continue_btn.configure(state=tk.NORMAL, text="ПРОДОЛЖИТЬ", bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg="#111111", relief="raised")
        else:
            self.continue_btn.configure(state=tk.NORMAL, text="ОБЩИЙ ПРОФИЛЬ СПР", bg="#4f78ff", activebackground="#4269e0", fg="white", relief="raised")
StartPageApp.refresh_menu_state = _fixed54_refresh_menu_state

def _fixed54_apply_menu_layout(self):
    width = max(self.root.winfo_width(), 1100)
    height = max(self.root.winfo_height(), 760)
    scale = min(width / BASE_W, height / BASE_H)
    scale = max(0.72, min(scale, 1.12))
    try:
        self._apply_common_shell_layout(width, height, scale)
    except Exception:
        pass
    try:
        self.title_small.configure(font=("Times New Roman", max(16, int(20 * scale)), "bold"))
        self.title_big.configure(font=("Times New Roman", max(18, int(25 * scale)), "bold"))
        self.body.configure(font=("Arial", max(11, int(13 * scale)), "bold"), wraplength=int(width * 0.30), justify="left", anchor="nw")
        self.body.grid_configure(pady=(int(6 * scale), int(8 * scale)), sticky="ew")
        self.menu_status_label.configure(font=("Arial", max(11, int(13 * scale)), "bold"), wraplength=int(width * 0.40), justify="left")
    except Exception:
        pass
    try:
        self.menu_title.configure(font=("Arial", max(14, int(20 * scale)), "bold"))
    except Exception:
        pass
    for code, card in getattr(self, "menu_cards", {}).items():
        try:
            card.grid_configure(padx=8, pady=8)
        except Exception:
            pass
    for code, btn in getattr(self, "menu_buttons", {}).items():
        try:
            btn.configure(font=("Arial", max(12, int(16 * scale)), "bold"), wraplength=int(width * 0.16), padx=max(8, int(10 * scale)), pady=max(10, int(12 * scale)), height=3)
        except Exception:
            pass
    for code, btn in getattr(self, "menu_result_buttons", {}).items():
        try:
            btn.configure(font=("Arial", max(11, int(14 * scale)), "bold"), wraplength=int(width * 0.13), padx=max(8, int(10 * scale)), pady=max(8, int(10 * scale)), height=2)
        except Exception:
            pass
    try:
        _fixed50_relayout_menu_action_row(self)
    except Exception:
        try:
            _fixed49_repack_menu_action_row(self)
        except Exception:
            pass
StartPageApp.apply_menu_layout = _fixed54_apply_menu_layout


# ====== FIXED55: stable settings button on menu + grid-only action row ======
def _fixed55_open_settings_from_menu(self):
    try:
        _fixed46_open_researcher_settings(self)
    except Exception:
        try:
            self.show_researcher()
        except Exception:
            pass


def _fixed55_ensure_menu_settings_button(self):
    frame = getattr(self, 'menu_btn_frame', None)
    if frame is None or not frame.winfo_exists():
        return
    btn = getattr(self, 'settings_btn', None)
    if btn is not None and btn.winfo_exists():
        try:
            btn.configure(command=lambda: _fixed55_open_settings_from_menu(self))
        except Exception:
            pass
        return
    self.settings_btn = tk.Button(
        frame,
        text='НАСТРОЙКИ',
        bg=BACK_BG,
        activebackground=BACK_ACTIVE,
        relief='raised',
        bd=3,
        command=lambda: _fixed55_open_settings_from_menu(self),
        cursor='hand2',
        justify='center',
        anchor='center',
        wraplength=0,
    )


def _fixed55_relayout_menu_action_row(self):
    frame = getattr(self, 'menu_btn_frame', None)
    if frame is None or not frame.winfo_exists():
        return
    _fixed55_ensure_menu_settings_button(self)
    width = max(self.root.winfo_width(), 1180)
    height = max(self.root.winfo_height(), 760)
    scale = min(width / BASE_W, height / BASE_H)
    scale = max(0.72, min(scale, 1.18))
    gap = max(8, int(10 * scale))
    pad_x = max(10, int(12 * scale))
    pad_y = max(8, int(9 * scale))
    font_size = max(11, int(15 * scale))
    try:
        frame.grid_configure(sticky='ew', pady=(0, int(10 * scale)))
    except Exception:
        pass
    try:
        self.right.grid_columnconfigure(0, weight=1)
    except Exception:
        pass

    buttons = [
        getattr(self, 'settings_btn', None),
        getattr(self, 'all_results_btn', None),
        getattr(self, 'continue_btn', None),
        getattr(self, 'restart_btn', None),
        getattr(self, 'exit_btn', None),
    ]
    for btn in buttons:
        if btn is not None and btn.winfo_exists():
            for forget in ('pack_forget', 'grid_forget', 'place_forget'):
                try:
                    getattr(btn, forget)()
                except Exception:
                    pass

    for col in range(5):
        try:
            frame.grid_columnconfigure(col, weight=0, uniform='')
        except Exception:
            pass
    weights = (1.05, 1.1, 1.15, 1.2, 0.75)
    for col, weight in enumerate(weights):
        try:
            frame.grid_columnconfigure(col, weight=weight, uniform='menu_actions55')
        except Exception:
            pass

    common = dict(font=('Arial', font_size, 'bold'), height=2, bd=3, relief='raised', justify='center', anchor='center')
    order = [
        (getattr(self, 'settings_btn', None), 'НАСТРОЙКИ', max(14, int(15 * scale))),
        (getattr(self, 'all_results_btn', None), 'ВСЕ РЕЗУЛЬТАТЫ', max(16, int(17 * scale))),
        (getattr(self, 'continue_btn', None), None, max(16, int(17 * scale))),
        (getattr(self, 'restart_btn', None), 'НАЧАТЬ СНАЧАЛА', max(16, int(18 * scale))),
        (getattr(self, 'exit_btn', None), 'ВЫХОД', max(8, int(9 * scale))),
    ]

    for col, (btn, forced_text, width_units) in enumerate(order):
        if btn is None or not btn.winfo_exists():
            continue
        text = forced_text if forced_text is not None else btn.cget('text')
        wrap = 0
        if text == 'ВСЕ РЕЗУЛЬТАТЫ':
            wrap = max(150, int(width * 0.12))
        elif text in ('ОБЩИЙ ПРОФИЛЬ СПР', 'СЛЕДУЮЩИЙ ТЕСТ', 'НАЧАТЬ СНАЧАЛА'):
            wrap = max(160, int(width * 0.14))
        try:
            btn.configure(text=text, width=width_units, wraplength=wrap, padx=pad_x, pady=pad_y, **common)
        except Exception:
            pass
        try:
            btn.grid(row=0, column=col, sticky='ew', padx=(0, gap) if col < 4 else (0, 0), pady=0)
        except Exception:
            pass


_FIXED55_PREV_BUILD_MENU_UI = StartPageApp.build_menu_ui
_FIXED55_PREV_APPLY_MENU_LAYOUT = StartPageApp.apply_menu_layout
_FIXED55_PREV_REFRESH_MENU_STATE = StartPageApp.refresh_menu_state


