def _fixed57_apply_start_layout(self):
    width = max(self.root.winfo_width(), 1100)
    height = max(self.root.winfo_height(), 760)
    scale = min(width / BASE_W, height / BASE_H)
    scale = max(0.72, min(scale, 1.9))
    self._apply_common_shell_layout(width, height, scale)

    form_pad_x = int(18 * scale)
    form_pad_y = int(12 * scale)
    self.form_frame.grid_configure(pady=(0, int(16 * scale)))
    self.btn_frame.grid_configure(pady=(0, int(8 * scale)))

    form_title_size = max(14, int(22 * scale))
    form_text_size = max(12, int(18 * scale))
    status_size = max(11, int(15 * scale))
    button_font_size = max(14, int(22 * scale))

    self.body.configure(font=("Arial", max(12, int(18 * scale)), "bold"), wraplength=int(width * 0.50))
    self.form_title.configure(font=("Arial", form_title_size, "bold"))
    for widget in (self.name_label, self.age_label, self.gender_label, self.gender_male, self.gender_female):
        widget.configure(font=("Arial", form_text_size, "bold"))
    self.name_entry.configure(font=("Arial", form_text_size))
    self.age_entry.configure(font=("Arial", form_text_size))
    self.status_label.configure(font=("Arial", status_size, "bold"), wraplength=int(width * 0.50))

    self.form_frame.grid_columnconfigure(0, minsize=int(240 * scale))
    self.form_title.grid_configure(padx=form_pad_x, pady=(form_pad_y, int(6 * scale)))
    self.name_label.grid_configure(padx=form_pad_x, pady=int(6 * scale))
    self.name_entry.grid_configure(padx=(0, form_pad_x), pady=int(6 * scale), ipady=max(2, int(4 * scale)))
    self.age_label.grid_configure(padx=form_pad_x, pady=int(6 * scale))
    self.age_entry.grid_configure(padx=(0, form_pad_x), pady=int(6 * scale), ipady=max(2, int(4 * scale)))
    self.gender_label.grid_configure(padx=form_pad_x, pady=int(6 * scale))
    self.gender_frame.grid_configure(padx=(0, form_pad_x), pady=int(6 * scale))
    self.gender_male.pack_configure(padx=(0, int(16 * scale)))
    self.gender_female.pack_configure(padx=(0, int(6 * scale)))
    self.status_label.grid_configure(padx=form_pad_x, pady=(int(8 * scale), form_pad_y))

    gap = int(14 * scale)
    self.btn_frame.grid_columnconfigure(0, weight=1, uniform='start_buttons')
    self.btn_frame.grid_columnconfigure(1, weight=1, uniform='start_buttons')
    self.btn_frame.grid_columnconfigure(2, weight=1, uniform='start_buttons')
    common = dict(font=("Arial", button_font_size, "bold"), padx=max(10, int(14 * scale)), pady=max(8, int(10 * scale)), justify='center', anchor='center')
    self.back_to_settings_btn.configure(width=max(12, int(14 * scale)), **common)
    self.next_btn.configure(width=max(10, int(12 * scale)), **common)
    self.exit_btn.configure(width=max(10, int(12 * scale)), **common)
    self.back_to_settings_btn.grid_configure(padx=(0, gap), pady=(0, 0))
    self.next_btn.grid_configure(padx=(0, gap), pady=(0, 0))
    self.exit_btn.grid_configure(padx=(0, 0), pady=(0, 0))


