# === FIXED60: все наклонные линии краснеют, HUD опущен ниже ===
def _fixed60_draw_diagonal_family(self, color, alpha=170):
    cx = int(self.center.x)
    cy = int(self.center.y)
    outer_radius = int(self.work_half_px)
    step = max(16, int(outer_radius * 0.115))
    slope = 0.17
    xmin = cx - outer_radius
    xmax = cx + outer_radius
    overlay = pygame.Surface((self.cfg.width, self.cfg.height), pygame.SRCALPHA)

    for sign in (1, -1):
        for offset in range(-outer_radius - step, outer_radius + step * 2, step):
            pts = []
            x = xmin
            while x <= xmax:
                y = cy + sign * slope * (x - cx) + offset
                if (x - cx) ** 2 + (y - cy) ** 2 <= outer_radius ** 2:
                    pts.append((int(x), int(y)))
                elif len(pts) >= 2:
                    pygame.draw.aalines(overlay, (*color, alpha), False, pts)
                    pts = []
                else:
                    pts = []
                x += 6
            if len(pts) >= 2:
                pygame.draw.aalines(overlay, (*color, alpha), False, pts)
    self.screen.blit(overlay, (0, 0))


def _fixed60_method_a_draw_roll_limit_guides(self, state: DriftState, stage_no: int):
    if not self.stage_defs[stage_no].get('z'):
        return
    warning = _fixed58_roll_warning_exceeded(self, state, stage_no) if '_fixed58_roll_warning_exceeded' in globals() else self.roll_limit_exceeded(state, stage_no)
    if warning:
        _fixed60_draw_diagonal_family(self, self.cfg.crash_color, alpha=220)
    else:
        # В спокойном состоянии слегка усиливаем все наклонные линии тем же цветом,
        # что и сетка, чтобы границы крена были заметнее, но без красного сигнала.
        _fixed60_draw_diagonal_family(self, self.cfg.grid_color, alpha=95)


def _fixed60_method_a_draw_hud(self, stage_no: int, elapsed_s: float, stage_error: float, report: StageReport, state: DriftState):
    time_ratio = elapsed_s / self.cfg.stage_time_limit_s
    err_ratio = stage_error / self.stage_smax(stage_no)
    bar_w = 64
    bar_h = min(360, max(300, int(self.cfg.height * 0.43)))
    # Опускаем столбики примерно к середине экрана, чтобы они меньше спорили с полем.
    top = max(80, int((self.cfg.height - bar_h) * 0.5))
    left = 16
    right = self.cfg.width - bar_w - 16
    self.draw_bar(left, top, bar_w, bar_h, time_ratio, 'ВРЕМЯ', (60, 130, 255))
    self.draw_bar(right, top, bar_w, bar_h, err_ratio, 'ОШИБКА', (255, 118, 50))


MethodAApp.draw_roll_limit_guides = _fixed60_method_a_draw_roll_limit_guides
MethodAApp.draw_hud = _fixed60_method_a_draw_hud


# === FIXED61: столбики ближе к кругу, нижний край на середине экрана ===
def _fixed61_method_a_draw_hud(self, stage_no: int, elapsed_s: float, stage_error: float, report: StageReport, state: DriftState):
    time_ratio = elapsed_s / self.cfg.stage_time_limit_s
    err_ratio = stage_error / self.stage_smax(stage_no)

    bar_w = 64
    bar_h = min(340, max(250, int(self.cfg.height * 0.34)))

    # Пользователь просил, чтобы нижняя часть столбиков была примерно на середине экрана.
    mid_y = int(self.cfg.height * 0.50)
    top = max(24, mid_y - bar_h)

    cx = int(self.center.x)
    outer = int(self.work_half_px)
    gap = max(18, int(self.cfg.width * 0.012))

    left = max(12, cx - outer - gap - bar_w)
    right = min(self.cfg.width - bar_w - 12, cx + outer + gap)

    # Если экран слишком узкий, всё равно держим столбики симметрично и не даём им уползти за край.
    if right - left < bar_w * 2 + gap:
        left = 12
        right = self.cfg.width - bar_w - 12

    self.draw_bar(left, top, bar_w, bar_h, time_ratio, 'ВРЕМЯ', (60, 130, 255))
    self.draw_bar(right, top, bar_w, bar_h, err_ratio, 'ОШИБКА', (255, 118, 50))


MethodAApp.draw_hud = _fixed61_method_a_draw_hud



