def _fixed63_method_a_current_error_increment(self, state: DriftState, stage_no: int, dt: float) -> float:
    inc = _FIXED63_PREV_METHOD_A_CURRENT_ERROR_INCREMENT(self, state, stage_no, dt)
    self._current_stage_no = int(stage_no)
    self._error_bar_growing = bool(stage_no in (1, 2) and inc > 1e-9)
    return inc


MethodAApp.current_error_increment = _fixed63_method_a_current_error_increment



def _fixed63_method_a_draw_zones(self):
    stage_no = int(getattr(self, '_current_stage_no', 0) or 0)
    if stage_no not in (1, 2):
        return

    target_surface = self.screen
    c = self.center
    outer_radius = int(self.work_half_px)
    target_radius = int(self.target_half_px)
    normal = (20, 66, 96)
    alert = bool(getattr(self, '_error_bar_growing', False))
    color = self.cfg.crash_color if alert else normal
    width = 4 if alert else 2

    radii = [
        target_radius,
        int(target_radius + (outer_radius - target_radius) * 0.28),
        int(target_radius + (outer_radius - target_radius) * 0.56),
        int(target_radius + (outer_radius - target_radius) * 0.84),
    ]
    for radius in radii:
        pygame.draw.circle(target_surface, color, c, radius, width)


MethodAApp.draw_zones = _fixed63_method_a_draw_zones


