def _fixed63_hide_research_tab_tip(self):
    tip = getattr(self, '_research_tab_tip', None)
    if tip is not None:
        try:
            tip.destroy()
        except Exception:
            pass
    self._research_tab_tip = None
    self._research_tab_tip_label = None
    self._research_tab_tip_index = None



def _fixed63_show_research_tab_tip(self, text: str, x_root: int, y_root: int):
    tip = getattr(self, '_research_tab_tip', None)
    if tip is None or not tip.winfo_exists():
        tip = tk.Toplevel(self.root)
        tip.overrideredirect(True)
        try:
            tip.attributes('-topmost', True)
        except Exception:
            pass
        label = tk.Label(
            tip,
            text=text,
            bg='#fffbe8',
            fg='#213547',
            justify='left',
            anchor='w',
            relief='solid',
            bd=1,
            padx=10,
            pady=8,
            wraplength=420,
            font=('Segoe UI', 10),
        )
        label.pack(fill='both', expand=True)
        self._research_tab_tip = tip
        self._research_tab_tip_label = label
    else:
        label = self._research_tab_tip_label
        label.configure(text=text)

    tip.update_idletasks()
    sw = self.root.winfo_screenwidth()
    sh = self.root.winfo_screenheight()
    tw = tip.winfo_reqwidth()
    th = tip.winfo_reqheight()
    x = x_root + 16
    y = y_root + 20
    if x + tw > sw - 12:
        x = max(12, x_root - tw - 16)
    if y + th > sh - 12:
        y = max(12, y_root - th - 16)
    tip.geometry(f'+{int(x)}+{int(y)}')



def _fixed63_on_research_tab_motion(self, event):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None or event.widget is not tabs:
        return
    try:
        index = tabs.index(f'@{event.x},{event.y}')
        bx, by, bw, bh = tabs.bbox(index)
    except Exception:
        _fixed63_hide_research_tab_tip(self)
        return

    if not (bx <= event.x <= bx + bw and by <= event.y <= by + bh):
        _fixed63_hide_research_tab_tip(self)
        return

    text = getattr(self, '_research_tab_help_by_index', {}).get(index, '')
    if not text:
        _fixed63_hide_research_tab_tip(self)
        return

    self._research_tab_tip_index = index
    _fixed63_show_research_tab_tip(self, text, event.x_root, event.y_root)



def _fixed63_on_research_tab_leave(self, _event=None):
    _fixed63_hide_research_tab_tip(self)



def _fixed63_populate_researcher_fields(self):
    for child in self.research_content.winfo_children():
        child.destroy()
    self.research_widgets = {}
    self.research_sections = {}
    _fixed63_hide_research_tab_tip(self)

    self.research_tabs = ttk.Notebook(self.research_content)
    self.research_tabs.pack(fill='both', expand=True, padx=14, pady=10)
    self.research_tabs.bind('<<NotebookTabChanged>>', lambda _event: self._on_research_content_configure())
    self.research_tabs.bind('<Motion>', lambda event: _fixed63_on_research_tab_motion(self, event))
    self.research_tabs.bind('<Leave>', lambda event: _fixed63_on_research_tab_leave(self, event))
    self._research_tab_help_by_index = {}

    for tab_index, (code, _title, cls, filename) in enumerate(RESEARCH_CONFIG_SPECS):
        tab = tk.Frame(self.research_tabs, bg=BG_COLOR)
        self.research_tabs.add(tab, text=f'Тест {code}')
        self._research_tab_help_by_index[tab_index] = _FIXED63_TAB_DESCRIPTIONS.get(code, f'Тест {code}')
        tab.grid_columnconfigure(0, weight=1)

        sections_wrap = tk.Frame(tab, bg=BG_COLOR)
        sections_wrap.grid(row=0, column=0, sticky='nsew', padx=4, pady=(2, 6))
        sections_wrap.grid_columnconfigure(0, weight=1)
        tab.grid_rowconfigure(0, weight=1)

        cfg = _fixed46_load_researcher_cfg(self, cls, filename)
        default_cfg = cls()
        widgets = {}
        section_frames = []
        section_groups = _get_research_section_groups(code, cls)

        for group_index, (section_title, field_names) in enumerate(section_groups):
            section = tk.LabelFrame(
                sections_wrap,
                text=section_title,
                bg=PANEL_COLOR,
                fg=TITLE_COLOR,
                bd=2,
                relief='groove',
                padx=10,
                pady=8,
            )
            section.grid(row=group_index, column=0, sticky='ew', padx=6, pady=7)
            section.grid_columnconfigure(0, weight=1)
            sections_wrap.grid_rowconfigure(group_index, weight=0)
            section_frames.append(section)

            for row, field_name in enumerate(field_names):
                fld = next((item for item in fields(cls) if item.name == field_name), None)
                if fld is None:
                    continue
                current_value = getattr(cfg, fld.name)
                default_value = getattr(default_cfg, fld.name)
                meta = _get_research_field_meta(code, fld.name)

                field_box = tk.Frame(section, bg=PANEL_COLOR, bd=0, highlightthickness=0)
                field_box.grid(row=row, column=0, sticky='ew', padx=8, pady=6)
                field_box.grid_columnconfigure(0, weight=1)

                label = tk.Label(
                    field_box,
                    text=meta.get('label', fld.name),
                    bg=PANEL_COLOR,
                    fg=TITLE_COLOR,
                    anchor='w',
                    justify='left',
                    font=('Segoe UI', 10, 'bold'),
                    wraplength=980,
                )
                label.grid(row=0, column=0, sticky='ew')

                help_text = meta.get('help', '')
                if help_text:
                    help_label = tk.Label(
                        field_box,
                        text=help_text,
                        bg=PANEL_COLOR,
                        fg='#5a5a5a',
                        anchor='w',
                        justify='left',
                        wraplength=980,
                    )
                    help_label.grid(row=1, column=0, sticky='ew', pady=(2, 0))

                serialized_current = _serialize_config_value(current_value)
                serialized_default = _serialize_config_value(default_value)
                is_multiline = isinstance(current_value, (list, dict, tuple)) or len(serialized_current) > 72
                widget_box = tk.Frame(field_box, bg=PANEL_COLOR)
                widget_box.grid(row=2, column=0, sticky='ew', pady=(6, 0))
                widget_box.grid_columnconfigure(0, weight=1)

                if is_multiline:
                    height = max(3, min(7, serialized_current.count('\n') + max(2, len(serialized_current) // 90 + 1)))
                    widget = tk.Text(
                        widget_box,
                        height=height,
                        wrap='word',
                        bg=FIELD_BG,
                        relief='sunken',
                        bd=1,
                    )
                    widget.insert('1.0', serialized_current)
                    widget.grid(row=0, column=0, sticky='ew')
                else:
                    widget = tk.Entry(widget_box, bg=FIELD_BG)
                    widget.insert(0, serialized_current)
                    widget.grid(row=0, column=0, sticky='ew', ipady=4)

                default_hint = tk.Label(
                    field_box,
                    text=f'По умолчанию: {serialized_default}',
                    bg=PANEL_COLOR,
                    fg='#6b7280',
                    anchor='w',
                    justify='left',
                    wraplength=1080,
                )
                default_hint.grid(row=3, column=0, sticky='ew', pady=(4, 0))

                sep = tk.Frame(field_box, bg='#d7d1bf', height=1)
                sep.grid(row=4, column=0, sticky='ew', pady=(8, 0))

                widgets[fld.name] = {'widget': widget, 'template': default_value, 'is_multiline': is_multiline}

        self.research_widgets[code] = widgets
        self.research_sections[code] = section_frames

    _bind_mousewheel_to_canvas(self.research_canvas, self.research_content, self.research_tabs)
    self._on_research_content_configure()


StartPageApp._populate_researcher_fields = _fixed63_populate_researcher_fields

# ====== FIXED64: robust hover tooltips for notebook tabs ======

def _fixed64_stop_research_tab_tip_watcher(self):
    job = getattr(self, '_research_tab_tip_after', None)
    if job is not None:
        try:
            self.root.after_cancel(job)
        except Exception:
            pass
    self._research_tab_tip_after = None
    _fixed63_hide_research_tab_tip(self)


def _fixed64_poll_research_tab_tip(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        _fixed64_stop_research_tab_tip_watcher(self)
        return
    try:
        if not tabs.winfo_exists() or not tabs.winfo_ismapped():
            _fixed63_hide_research_tab_tip(self)
            self._research_tab_tip_after = self.root.after(180, lambda: _fixed64_poll_research_tab_tip(self))
            return
    except Exception:
        _fixed64_stop_research_tab_tip_watcher(self)
        return

    try:
        px, py = self.root.winfo_pointerxy()
        rx, ry = tabs.winfo_rootx(), tabs.winfo_rooty()
        rw, rh = tabs.winfo_width(), tabs.winfo_height()
    except Exception:
        _fixed63_hide_research_tab_tip(self)
        self._research_tab_tip_after = self.root.after(180, lambda: _fixed64_poll_research_tab_tip(self))
        return

    inside = (rx <= px <= rx + rw and ry <= py <= ry + max(36, min(rh, 48)))
    if not inside:
        _fixed63_hide_research_tab_tip(self)
        self._research_tab_tip_after = self.root.after(180, lambda: _fixed64_poll_research_tab_tip(self))
        return

    local_x = int(px - rx)
    local_y = int(py - ry)
    try:
        index = tabs.index(f'@{local_x},{local_y}')
        bx, by, bw, bh = tabs.bbox(index)
    except Exception:
        _fixed63_hide_research_tab_tip(self)
        self._research_tab_tip_after = self.root.after(180, lambda: _fixed64_poll_research_tab_tip(self))
        return

    if not (bx <= local_x <= bx + bw and by <= local_y <= by + bh):
        _fixed63_hide_research_tab_tip(self)
    else:
        text = getattr(self, '_research_tab_help_by_index', {}).get(index, '')
        if text:
            _fixed63_show_research_tab_tip(self, text, px, py)
        else:
            _fixed63_hide_research_tab_tip(self)

    self._research_tab_tip_after = self.root.after(180, lambda: _fixed64_poll_research_tab_tip(self))


def _fixed64_start_research_tab_tip_watcher(self):
    _fixed64_stop_research_tab_tip_watcher(self)
    self._research_tab_tip_after = self.root.after(250, lambda: _fixed64_poll_research_tab_tip(self))


_FIXED64_PREV_POPULATE_RESEARCHER_FIELDS = StartPageApp._populate_researcher_fields

def _fixed64_populate_researcher_fields(self):
    _FIXED64_PREV_POPULATE_RESEARCHER_FIELDS(self)
    tabs = getattr(self, 'research_tabs', None)
    if tabs is not None:
        try:
            tabs.unbind('<Motion>')
            tabs.unbind('<Leave>')
        except Exception:
            pass
        try:
            tabs.bind('<Destroy>', lambda _e: _fixed64_stop_research_tab_tip_watcher(self), add='+')
        except Exception:
            pass
    _fixed64_start_research_tab_tip_watcher(self)


StartPageApp._populate_researcher_fields = _fixed64_populate_researcher_fields



# ====== FIXED65: actually working hover descriptions for research tabs ======

def _fixed65_hide_research_tab_tip(self):
    tip = getattr(self, '_research_tab_tip', None)
    if tip is not None:
        try:
            tip.destroy()
        except Exception:
            pass
    self._research_tab_tip = None
    self._research_tab_tip_label = None
    self._research_tab_tip_index = None


def _fixed65_show_research_tab_tip(self, text: str, x_root: int, y_root: int):
    tip = getattr(self, '_research_tab_tip', None)
    if tip is None or not getattr(tip, 'winfo_exists', lambda: False)():
        tip = tk.Toplevel(self.root)
        tip.overrideredirect(True)
        try:
            tip.attributes('-topmost', True)
        except Exception:
            pass
        frame = tk.Frame(tip, bg='#fffbe8', bd=1, relief='solid')
        frame.pack(fill='both', expand=True)
        label = tk.Label(
            frame,
            text=text,
            bg='#fffbe8',
            fg='#213547',
            justify='left',
            anchor='w',
            padx=10,
            pady=8,
            wraplength=420,
            font=('Segoe UI', 10),
        )
        label.pack(fill='both', expand=True)
        self._research_tab_tip = tip
        self._research_tab_tip_label = label
    else:
        label = self._research_tab_tip_label
        if label is not None:
            label.configure(text=text)

    tip.update_idletasks()
    sw = self.root.winfo_screenwidth()
    sh = self.root.winfo_screenheight()
    tw = tip.winfo_reqwidth()
    th = tip.winfo_reqheight()
    x = x_root + 16
    y = y_root + 22
    if x + tw > sw - 12:
        x = max(12, x_root - tw - 16)
    if y + th > sh - 12:
        y = max(12, y_root - th - 16)
    tip.geometry(f'+{int(x)}+{int(y)}')


def _fixed65_tab_index_from_pointer(tabs, x_local: int, y_local: int):
    try:
        tab_count = tabs.index('end')
    except Exception:
        return None
    for idx in range(tab_count):
        try:
            bx, by, bw, bh = tabs.bbox(idx)
        except Exception:
            continue
        if bw <= 0 or bh <= 0:
            continue
        if bx <= x_local <= bx + bw and by <= y_local <= by + bh:
            return idx
    return None


def _fixed65_update_research_tab_tip(self, x_root=None, y_root=None):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        _fixed65_hide_research_tab_tip(self)
        return
    try:
        tabs.update_idletasks()
        if x_root is None or y_root is None:
            x_root, y_root = self.root.winfo_pointerxy()
        rx, ry = tabs.winfo_rootx(), tabs.winfo_rooty()
        local_x = int(x_root - rx)
        local_y = int(y_root - ry)
    except Exception:
        _fixed65_hide_research_tab_tip(self)
        return

    index = _fixed65_tab_index_from_pointer(tabs, local_x, local_y)
    if index is None:
        _fixed65_hide_research_tab_tip(self)
        return

    text = getattr(self, '_research_tab_help_by_index', {}).get(index, '')
    if not text:
        _fixed65_hide_research_tab_tip(self)
        return

    self._research_tab_tip_index = index
    _fixed65_show_research_tab_tip(self, text, x_root, y_root)


def _fixed65_on_research_tabs_motion(self, event=None):
    x_root = getattr(event, 'x_root', None)
    y_root = getattr(event, 'y_root', None)
    _fixed65_update_research_tab_tip(self, x_root, y_root)


def _fixed65_on_research_tabs_leave(self, _event=None):
    _fixed65_hide_research_tab_tip(self)


def _fixed65_install_research_tab_tooltips(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    try:
        tabs.unbind('<Motion>')
        tabs.unbind('<Leave>')
        tabs.unbind('<Enter>')
    except Exception:
        pass
    tabs.bind('<Enter>', lambda e: _fixed65_on_research_tabs_motion(self, e), add='+')
    tabs.bind('<Motion>', lambda e: _fixed65_on_research_tabs_motion(self, e), add='+')
    tabs.bind('<Leave>', lambda e: _fixed65_on_research_tabs_leave(self, e), add='+')
    tabs.bind('<ButtonPress-1>', lambda e: _fixed65_hide_research_tab_tip(self), add='+')
    tabs.bind('<<NotebookTabChanged>>', lambda e: _fixed65_hide_research_tab_tip(self), add='+')
    tabs.bind('<Destroy>', lambda e: _fixed65_hide_research_tab_tip(self), add='+')


_FIXED65_PREV_POPULATE_RESEARCHER_FIELDS = StartPageApp._populate_researcher_fields

def _fixed65_populate_researcher_fields(self):
    _FIXED65_PREV_POPULATE_RESEARCHER_FIELDS(self)
    _fixed65_install_research_tab_tooltips(self)
    _fixed65_hide_research_tab_tip(self)


StartPageApp._populate_researcher_fields = _fixed65_populate_researcher_fields



# ====== FIXED66: visible hover popup for research tabs via in-window overlay ======

def _fixed66_hide_research_tab_tip(self):
    tip = getattr(self, '_research_tab_tip_frame', None)
    if tip is not None:
        try:
            tip.place_forget()
        except Exception:
            pass
    self._research_tab_tip_visible = False
    self._research_tab_tip_index = None


def _fixed66_get_research_tab_tip(self):
    tip = getattr(self, '_research_tab_tip_frame', None)
    if tip is None or not getattr(tip, 'winfo_exists', lambda: False)():
        parent = getattr(self, 'research_top', None) or self.root
        tip = tk.Frame(parent, bg='#fff8dc', highlightthickness=1, highlightbackground='#b8a76a', bd=0)
        label = tk.Label(
            tip,
            text='',
            bg='#fff8dc',
            fg='#2b2b2b',
            font=('Arial', 11),
            justify='left',
            wraplength=520,
            padx=12,
            pady=8,
        )
        label.pack(fill='both', expand=True)
        self._research_tab_tip_frame = tip
        self._research_tab_tip_label = label
    return self._research_tab_tip_frame, self._research_tab_tip_label


def _fixed66_show_research_tab_tip(self, text: str, x_root: int, y_root: int):
    tip, label = _fixed66_get_research_tab_tip(self)
    label.configure(text=text)
    parent = getattr(self, 'research_top', None) or self.root
    try:
        parent.update_idletasks()
        tip.update_idletasks()
        pw, ph = parent.winfo_width(), parent.winfo_height()
        prx, pry = parent.winfo_rootx(), parent.winfo_rooty()
        tw, th = max(260, tip.winfo_reqwidth()), max(60, tip.winfo_reqheight())
        x = int(x_root - prx + 18)
        y = int(y_root - pry + 18)
        pad = 12
        if x + tw > pw - pad:
            x = max(pad, pw - tw - pad)
        if y + th > ph - pad:
            y = max(pad, y_root - pry - th - 16)
        if y < pad:
            y = pad
        tip.place(x=x, y=y)
        tip.lift()
        self._research_tab_tip_visible = True
    except Exception:
        _fixed66_hide_research_tab_tip(self)


def _fixed66_tab_index_from_pointer(tabs, x_local: int, y_local: int):
    try:
        tab_count = tabs.index('end')
    except Exception:
        return None
    for idx in range(tab_count):
        try:
            bx, by, bw, bh = tabs.bbox(idx)
        except Exception:
            continue
        if bw <= 0 or bh <= 0:
            continue
        if bx <= x_local <= bx + bw and by <= y_local <= by + bh:
            return idx
    return None


def _fixed66_update_research_tab_tip(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None or not getattr(tabs, 'winfo_exists', lambda: False)():
        _fixed66_hide_research_tab_tip(self)
        return
    try:
        px, py = self.root.winfo_pointerxy()
        rx, ry = tabs.winfo_rootx(), tabs.winfo_rooty()
        rw, rh = tabs.winfo_width(), tabs.winfo_height()
        lx, ly = int(px - rx), int(py - ry)
        # Only top strip where tab headers live. The content area should not trigger tip.
        if lx < 0 or ly < 0 or lx > rw or ly > max(36, min(70, rh)):
            _fixed66_hide_research_tab_tip(self)
            return
        idx = _fixed66_tab_index_from_pointer(tabs, lx, ly)
        if idx is None:
            _fixed66_hide_research_tab_tip(self)
            return
        text = getattr(self, '_research_tab_help_by_index', {}).get(idx, '')
        if not text:
            _fixed66_hide_research_tab_tip(self)
            return
        self._research_tab_tip_index = idx
        _fixed66_show_research_tab_tip(self, text, px, py)
    except Exception:
        _fixed66_hide_research_tab_tip(self)


def _fixed66_poll_research_tab_tip(self):
    try:
        _fixed66_update_research_tab_tip(self)
    finally:
        try:
            self._research_tab_tip_after = self.root.after(120, lambda: _fixed66_poll_research_tab_tip(self))
        except Exception:
            self._research_tab_tip_after = None


def _fixed66_start_research_tab_tip(self):
    job = getattr(self, '_research_tab_tip_after', None)
    if job is not None:
        try:
            self.root.after_cancel(job)
        except Exception:
            pass
    self._research_tab_tip_after = self.root.after(160, lambda: _fixed66_poll_research_tab_tip(self))


def _fixed66_stop_research_tab_tip(self):
    job = getattr(self, '_research_tab_tip_after', None)
    if job is not None:
        try:
            self.root.after_cancel(job)
        except Exception:
            pass
    self._research_tab_tip_after = None
    _fixed66_hide_research_tab_tip(self)


_FIXED66_PREV_POPULATE_RESEARCHER_FIELDS = StartPageApp._populate_researcher_fields

def _fixed66_populate_researcher_fields(self):
    _FIXED66_PREV_POPULATE_RESEARCHER_FIELDS(self)
    try:
        _fixed66_start_research_tab_tip(self)
        tabs = getattr(self, 'research_tabs', None)
        if tabs is not None:
            tabs.bind('<<NotebookTabChanged>>', lambda _e: _fixed66_hide_research_tab_tip(self), add='+')
            tabs.bind('<Destroy>', lambda _e: _fixed66_stop_research_tab_tip(self), add='+')
    except Exception:
        pass


StartPageApp._populate_researcher_fields = _fixed66_populate_researcher_fields

# Реальный запуск будет в самом конце файла, после всех поздних фиксов.


# ====== FIXED67: replace notebook tab strip with reliable custom tab buttons + hover descriptions ======

def _fixed67_hide_native_research_tabs(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    style = ttk.Style()
    try:
        style.layout('HiddenResearch.TNotebook.Tab', [])
    except Exception:
        pass
    try:
        style.layout('HiddenResearch.TNotebook', [('Notebook.client', {'sticky': 'nswe'})])
    except Exception:
        pass
    try:
        tabs.configure(style='HiddenResearch.TNotebook')
    except Exception:
        pass


def _fixed67_show_custom_research_tab(self, code: str):
    buttons = getattr(self, '_research_tab_buttons_by_code', {})
    code_to_index = getattr(self, '_research_tab_index_by_code', {})
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None or code not in code_to_index:
        return
    try:
        tabs.select(code_to_index[code])
    except Exception:
        pass
    for btn_code, btn in buttons.items():
        try:
            if btn_code == code:
                btn.configure(bg='#e9e2bd', fg=TITLE_COLOR, relief='solid', bd=1)
            else:
                btn.configure(bg=PANEL_COLOR, fg='#2b3d4f', relief='flat', bd=1)
        except Exception:
            pass
    try:
        self._on_research_content_configure()
    except Exception:
        pass


def _fixed67_on_custom_tab_enter(self, code: str, event=None):
    text = _FIXED63_TAB_DESCRIPTIONS.get(code, f'Тест {code}')
    if not text:
        return
    if event is not None:
        x_root = int(getattr(event, 'x_root', 0) or 0)
        y_root = int(getattr(event, 'y_root', 0) or 0)
    else:
        try:
            x_root, y_root = self.root.winfo_pointerxy()
        except Exception:
            return
    _fixed66_show_research_tab_tip(self, text, x_root, y_root)


def _fixed67_on_custom_tab_motion(self, code: str, event=None):
    _fixed67_on_custom_tab_enter(self, code, event)


def _fixed67_on_custom_tab_leave(self, _event=None):
    try:
        _fixed66_hide_research_tab_tip(self)
    except Exception:
        try:
            _fixed63_hide_research_tab_tip(self)
        except Exception:
            pass


def _fixed67_install_custom_research_tabs(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    try:
        old = getattr(self, '_research_custom_tab_bar', None)
        if old is not None and old.winfo_exists():
            old.destroy()
    except Exception:
        pass

    _fixed67_hide_native_research_tabs(self)

    bar = tk.Frame(self.research_content, bg=BG_COLOR)
    bar.pack(fill='x', padx=14, pady=(10, 0), before=tabs)
    self._research_custom_tab_bar = bar
    self._research_tab_buttons_by_code = {}
    self._research_tab_index_by_code = {}

    for col, (code, _title, _cls, _filename) in enumerate(RESEARCH_CONFIG_SPECS):
        bar.grid_columnconfigure(col, weight=1)
        btn = tk.Label(
            bar,
            text=f'Тест {code}',
            bg=PANEL_COLOR,
            fg='#2b3d4f',
            padx=18,
            pady=8,
            cursor='hand2',
            bd=1,
            relief='flat',
            font=('Segoe UI', 11, 'bold'),
        )
        btn.grid(row=0, column=col, sticky='ew', padx=(0 if col == 0 else 6, 0), pady=(0, 4))
        self._research_tab_buttons_by_code[code] = btn
        self._research_tab_index_by_code[code] = col
        btn.bind('<Button-1>', lambda e, c=code: _fixed67_show_custom_research_tab(self, c))
        btn.bind('<Enter>', lambda e, c=code: _fixed67_on_custom_tab_enter(self, c, e))
        btn.bind('<Motion>', lambda e, c=code: _fixed67_on_custom_tab_motion(self, c, e))
        btn.bind('<Leave>', lambda e: _fixed67_on_custom_tab_leave(self, e))

    try:
        tabs.bind('<<NotebookTabChanged>>', lambda _e: _fixed67_sync_custom_research_tabs(self), add='+')
    except Exception:
        pass
    _fixed67_show_custom_research_tab(self, RESEARCH_CONFIG_SPECS[0][0])


def _fixed67_sync_custom_research_tabs(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    try:
        current_index = tabs.index(tabs.select())
    except Exception:
        return
    for code, idx in getattr(self, '_research_tab_index_by_code', {}).items():
        if idx == current_index:
            _fixed67_show_custom_research_tab(self, code)
            break


