# ====== FIXED69: robust custom research tabs, hide native notebook strip completely ======

def _fixed69_ensure_native_tab_cover(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    parent = getattr(self, 'research_content', None) or tabs.master
    cover = getattr(self, '_research_native_tab_cover', None)
    if cover is None or not getattr(cover, 'winfo_exists', lambda: False)():
        cover = tk.Frame(parent, bg=BG_COLOR, bd=0, highlightthickness=0)
        self._research_native_tab_cover = cover
    try:
        cover.configure(bg=BG_COLOR)
    except Exception:
        pass
    try:
        parent.update_idletasks()
        tabs.update_idletasks()
        x = max(0, tabs.winfo_x() + 1)
        y = max(0, tabs.winfo_y() + 1)
        w = max(0, tabs.winfo_width() - 2)
        h = 34
        if w > 0:
            cover.place(x=x, y=y, width=w, height=h)
            cover.lift()
            bar = getattr(self, '_research_custom_tab_bar', None)
            if bar is not None and getattr(bar, 'winfo_exists', lambda: False)():
                bar.lift()
    except Exception:
        pass


def _fixed69_install_custom_research_tabs(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return

    old = getattr(self, '_research_custom_tab_bar', None)
    try:
        if old is not None and old.winfo_exists():
            old.destroy()
    except Exception:
        pass

    bar = tk.Frame(self.research_content, bg=BG_COLOR, bd=0, highlightthickness=0)
    bar.pack(fill='x', padx=14, pady=(10, 0), before=tabs)
    self._research_custom_tab_bar = bar
    self._research_tab_buttons_by_code = {}
    self._research_tab_index_by_code = {}

    for col, (code, _title, _cls, _filename) in enumerate(RESEARCH_CONFIG_SPECS):
        bar.grid_columnconfigure(col, weight=1, uniform='research_tabs')
        btn = tk.Label(
            bar,
            text=f'Тест {code}',
            bg=PANEL_COLOR,
            fg=TITLE_COLOR,
            padx=12,
            pady=6,
            cursor='hand2',
            bd=1,
            relief='solid',
            font=('Segoe UI', 11, 'bold'),
        )
        btn.grid(row=0, column=col, sticky='ew', padx=(0 if col == 0 else 6, 0), pady=(0, 6))
        self._research_tab_buttons_by_code[code] = btn
        self._research_tab_index_by_code[code] = col
        btn.bind('<Button-1>', lambda e, c=code: _fixed67_show_custom_research_tab(self, c))
        btn.bind('<Enter>', lambda e, c=code: _fixed67_on_custom_tab_enter(self, c, e))
        btn.bind('<Motion>', lambda e, c=code: _fixed67_on_custom_tab_motion(self, c, e))
        btn.bind('<Leave>', lambda e: _fixed67_on_custom_tab_leave(self, e))

    try:
        tabs.bind('<<NotebookTabChanged>>', lambda _e: (_fixed67_sync_custom_research_tabs(self), _fixed69_ensure_native_tab_cover(self)), add='+')
        tabs.bind('<Configure>', lambda _e: _fixed69_ensure_native_tab_cover(self), add='+')
    except Exception:
        pass
    try:
        self.research_content.bind('<Configure>', lambda _e: _fixed69_ensure_native_tab_cover(self), add='+')
    except Exception:
        pass
    try:
        self.root.bind('<Configure>', lambda _e: _fixed69_ensure_native_tab_cover(self), add='+')
    except Exception:
        pass

    _fixed67_show_custom_research_tab(self, RESEARCH_CONFIG_SPECS[0][0])
    try:
        self.root.after(50, lambda: _fixed69_ensure_native_tab_cover(self))
        self.root.after(250, lambda: _fixed69_ensure_native_tab_cover(self))
    except Exception:
        pass


def _fixed69_populate_researcher_fields(self):
    _FIXED67_PREV_POPULATE_RESEARCHER_FIELDS(self)
    _fixed69_install_custom_research_tabs(self)


StartPageApp._populate_researcher_fields = _fixed69_populate_researcher_fields




# ====== FIXED70: stable hover descriptions for custom research tabs without Toplevel issues ======

def _fixed70_hide_custom_research_tab_tip(self):
    tip = getattr(self, '_research_custom_tab_tip', None)
    if tip is not None:
        try:
            tip.place_forget()
        except Exception:
            pass
    self._research_custom_tab_tip_visible = False


def _fixed70_get_custom_research_tab_tip(self):
    tip = getattr(self, '_research_custom_tab_tip', None)
    label = getattr(self, '_research_custom_tab_tip_label', None)
    need_new = True
    try:
        need_new = tip is None or label is None or not tip.winfo_exists() or not label.winfo_exists()
    except Exception:
        need_new = True
    if need_new:
        parent = getattr(self, '_research_custom_tab_bar', None) or getattr(self, 'research_content', None) or self.root
        tip = tk.Frame(parent, bg='#fff8dc', highlightthickness=1, highlightbackground='#b8a76a', bd=0)
        label = tk.Label(
            tip,
            text='',
            bg='#fff8dc',
            fg='#2b2b2b',
            font=('Segoe UI', 10),
            justify='left',
            anchor='w',
            wraplength=760,
            padx=12,
            pady=8,
        )
        label.pack(fill='both', expand=True)
        self._research_custom_tab_tip = tip
        self._research_custom_tab_tip_label = label
    return tip, label


def _fixed70_show_custom_research_tab_tip(self, code: str):
    text = _FIXED63_TAB_DESCRIPTIONS.get(code, f'Тест {code}')
    if not text:
        _fixed70_hide_custom_research_tab_tip(self)
        return
    tip, label = _fixed70_get_custom_research_tab_tip(self)
    try:
        label.configure(text=text)
    except Exception:
        # recreate once if label was somehow lost
        self._research_custom_tab_tip = None
        self._research_custom_tab_tip_label = None
        tip, label = _fixed70_get_custom_research_tab_tip(self)
        label.configure(text=text)

    bar = getattr(self, '_research_custom_tab_bar', None)
    buttons = getattr(self, '_research_tab_buttons_by_code', {})
    btn = buttons.get(code)
    if bar is None or btn is None:
        _fixed70_hide_custom_research_tab_tip(self)
        return
    try:
        bar.update_idletasks()
        btn.update_idletasks()
        tip.update_idletasks()
        bar_w = max(200, bar.winfo_width())
        tip_w = min(max(260, tip.winfo_reqwidth()), max(320, bar_w - 20))
        label.configure(wraplength=max(240, tip_w - 24))
        tip.update_idletasks()
        tip_w = min(max(260, tip.winfo_reqwidth()), max(320, bar_w - 20))
        tip_h = max(48, tip.winfo_reqheight())
        x = int(btn.winfo_x())
        y = int(btn.winfo_y() + btn.winfo_height() + 6)
        pad = 6
        if x + tip_w > bar_w - pad:
            x = max(pad, bar_w - tip_w - pad)
        tip.place(x=x, y=y, width=tip_w, height=tip_h)
        tip.lift()
        self._research_custom_tab_tip_visible = True
    except Exception:
        _fixed70_hide_custom_research_tab_tip(self)


def _fixed70_on_custom_tab_enter(self, code: str, _event=None):
    _fixed70_show_custom_research_tab_tip(self, code)


def _fixed70_on_custom_tab_motion(self, code: str, _event=None):
    _fixed70_show_custom_research_tab_tip(self, code)


def _fixed70_on_custom_tab_leave(self, _event=None):
    _fixed70_hide_custom_research_tab_tip(self)


def _fixed70_install_custom_research_tabs(self):
    # start from the cleaned fixed69 version so native tabs stay hidden
    _fixed69_install_custom_research_tabs(self)
    # rebind hover handlers to the stable in-window tooltip implementation
    buttons = getattr(self, '_research_tab_buttons_by_code', {})
    for code, btn in buttons.items():
        try:
            btn.bind('<Enter>', lambda e, c=code: _fixed70_on_custom_tab_enter(self, c, e))
            btn.bind('<Motion>', lambda e, c=code: _fixed70_on_custom_tab_motion(self, c, e))
            btn.bind('<Leave>', lambda e: _fixed70_on_custom_tab_leave(self, e))
        except Exception:
            pass
    try:
        bar = getattr(self, '_research_custom_tab_bar', None)
        if bar is not None:
            bar.bind('<Leave>', lambda e: _fixed70_on_custom_tab_leave(self, e), add='+')
    except Exception:
        pass
    _fixed70_hide_custom_research_tab_tip(self)


def _fixed70_populate_researcher_fields(self):
    _FIXED67_PREV_POPULATE_RESEARCHER_FIELDS(self)
    _fixed70_install_custom_research_tabs(self)


StartPageApp._populate_researcher_fields = _fixed70_populate_researcher_fields



# ====== FIXED71 Method B: tray below, only current shapes, larger figures, simple→complex ======

_FIXED71_SHAPE_ORDER = list(range(len(BASIC_SYMBOLS)))


def _fixed71_draw_symbol(canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, shape_id: int,
                         fill: str = '#5a2323', outline: str = '#5a2323',
                         scale: float = 1.42, tag: str = 'symbol'):
    canvas.delete(tag)
    draw_basic_symbol(canvas, x1, y1, x2, y2, shape_id, fill=fill, outline=outline, tag=tag)
    cx = (x1 + x2) / 2
    cy = (y1 + y2) / 2
    try:
        canvas.scale(tag, cx, cy, scale, scale)
    except Exception:
        pass


