def _fixed71_method_b_start_cycle(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    if self._time_left_total() <= 1.0:
        self._finish()
        return
    n = max(1, min(self.cfg.max_items, int(self.current_n)))
    all_cells = list(range(self.cfg.grid_size ** 2))
    random.shuffle(all_cells)
    self.current_positions = sorted(all_cells[:n])

    ordered_shapes = [s for s in _FIXED71_SHAPE_ORDER if s < len(BASIC_SYMBOLS)]
    self.current_shapes = ordered_shapes[:n]
    self.all_tray_shapes = list(self.current_shapes)

    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    self.phase = 'memorize'
    self.cycle_started_at = time.perf_counter()
    self.message_var.set('')
    self.selection_var.set('')
    self._draw_memory_matrix()
    self._draw_tray(show=False)
    base_exposure = float(self.cfg.start_exposure_s + self.cfg.step_time_s * (n - 1))
    exposure = max(0.7, base_exposure + float(getattr(self, 'exposure_adjust_s', 0.0)))
    exposure = min(exposure, max(1.0, self._time_left_total()))
    self._update_info_label()
    self._track_after(self.win.after(int(exposure * 1000), self._start_reproduction_phase))


def _fixed71_method_b_start_reproduction_phase(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    self.phase = 'reproduce'
    n = len(self.current_positions)
    self.all_tray_shapes = list(self.current_shapes)
    base_repr = float(self.cfg.start_reproduction_s + self.cfg.step_time_s * (n - 1))
    repr_time = max(1.2, base_repr + float(getattr(self, 'reproduction_adjust_s', 0.0)))
    repr_time = min(repr_time, max(1.0, self._time_left_total()))
    self.reproduction_deadline = time.perf_counter() + repr_time
    self.message_var.set('')
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)
    self._tick_reproduction_timeout()


def _fixed71_method_b_draw_memory_matrix(self):
    pad = 8
    size = getattr(self, '_matrix_cell_size', 156)
    inner = size - pad
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
        cell.configure(bg=bg)
        cell.create_rectangle(pad, pad, inner, inner, outline='#d8ccb5', width=1, fill=bg)
        if idx in self.current_positions:
            shape = self.current_shapes[self.current_positions.index(idx)]
            _fixed71_draw_symbol(
                cell, 18, 18, size - 18, size - 18, shape,
                fill='#5a2323', outline='#5a2323',
                scale=getattr(self, '_matrix_symbol_scale', 1.46),
                tag='symbol'
            )


def _fixed71_method_b_draw_reproduction_matrix(self):
    pad = 8
    size = getattr(self, '_matrix_cell_size', 156)
    inner = size - pad
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
        cell.configure(bg=bg)
        border = '#b79e80' if idx in self.placements else '#d8ccb5'
        cell.create_rectangle(pad, pad, inner, inner, outline=border, width=1, fill=bg)
        if idx in self.placements:
            shape = self.placements[idx]
            _fixed71_draw_symbol(
                cell, 18, 18, size - 18, size - 18, shape,
                fill='#5a2323', outline='#5a2323',
                scale=getattr(self, '_matrix_symbol_scale', 1.46),
                tag='symbol'
            )


def _fixed71_method_b_show_drag_preview(self, x_root: int, y_root: int, shape_id: int):
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.destroy()
        except Exception:
            pass
    preview = tk.Toplevel(self.win)
    preview.overrideredirect(True)
    preview.attributes('-topmost', True)
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    preview.configure(bg=tray_bg)
    canvas = tk.Canvas(preview, width=108, height=108, bg=tray_bg, highlightthickness=0, bd=0)
    canvas.pack()
    _fixed71_draw_symbol(
        canvas, 14, 14, 94, 94, shape_id,
        fill='#5a2323', outline='#5a2323',
        scale=getattr(self, '_tray_symbol_scale', 1.38),
        tag='symbol'
    )
    preview.geometry(f'108x108+{int(x_root - 54)}+{int(y_root - 54)}')
    self.drag_preview = preview


def _fixed71_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return
    items = sorted(list(getattr(self, 'all_tray_shapes', []) or getattr(self, 'current_shapes', [])))
    used = _fixed24_method_b_used_shapes(self)
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    columns = max(1, len(items))
    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        wrap = tk.Frame(self.tray_frame, bg=tray_bg)
        wrap.grid(row=row, column=col, padx=8, pady=8)
        is_used = shape in used
        border = '#dcc8ab' if is_used else '#d7c0a0'
        canvas = tk.Canvas(
            wrap,
            width=118,
            height=118,
            bg=tray_bg,
            highlightthickness=1,
            highlightbackground=border,
            bd=0,
            cursor='hand2' if not is_used else 'arrow'
        )
        canvas.pack()
        fill = '#b59d89' if is_used else '#5a2323'
        outline = '#b59d89' if is_used else '#5a2323'
        _fixed71_draw_symbol(
            canvas, 16, 16, 102, 102, shape,
            fill=fill, outline=outline,
            scale=getattr(self, '_tray_symbol_scale', 1.38),
            tag='symbol'
        )
        if is_used:
            canvas.create_line(20, 20, 98, 98, fill='#d46a6a', width=4)
        else:
            canvas.bind('<ButtonPress-1>', lambda e, s=shape, _self=self: _fixed25_method_b_start_drag(_self, e, s))
        self.tray_cells.append(canvas)

    if len(used) == 0:
        self.selection_var.set('Внизу показаны фигуры этого этапа. Перетащите их в нужные ячейки.')
    elif len(used) < len(self.current_positions):
        self.selection_var.set('Продолжайте перетаскивать фигуры снизу в нужные ячейки матрицы.')
    else:
        self.selection_var.set('Все фигуры этапа размещены. Проверьте матрицу и нажмите «Готово».')


