# ====== FIXED73B: center titles in B/C, enlarge B figures to nearly cell size ======

def _fixed73b_build_centered_header(parent, title_text: str, tip_text: str, bg: str):
    header = tk.Frame(parent, bg=bg)
    header.grid_columnconfigure(0, weight=1)
    header.grid_columnconfigure(1, weight=0)
    header.grid_columnconfigure(2, weight=1)
    left_spacer = tk.Frame(header, bg=bg)
    left_spacer.grid(row=0, column=0, sticky='w')
    lbl = tk.Label(header, text=title_text, bg=bg, fg=UNIFORM_TEST_FG, font=('Arial', 24, 'bold'), justify='center', anchor='center')
    lbl.grid(row=0, column=1, padx=8, pady=0)
    help_btn = _fixed42_make_help_button(header, tip_text, bg)
    help_btn.grid(row=0, column=2, sticky='e', padx=(10, 0))
    return header


def _fixed73b_method_b_build_ui(self):
    self.win = tk.Toplevel(self.parent)
    self.win.title('СПР - Тест B')
    self.win.configure(bg=UNIFORM_TEST_BG)
    self.win.transient(self.parent)
    self.win.grab_set()
    try:
        self.win.attributes('-fullscreen', True)
    except tk.TclError:
        self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
    self.win.bind('<Escape>', lambda _e: self._abort())
    self.win.protocol('WM_DELETE_WINDOW', self._abort)
    try:
        self.win.lift()
        self.win.focus_force()
    except Exception:
        pass
    self.win.grid_columnconfigure(0, weight=1)
    self.win.grid_rowconfigure(2, weight=1)

    header_wrap = tk.Frame(self.win, bg=UNIFORM_TEST_BG)
    header_wrap.grid(row=0, column=0, sticky='ew', padx=24, pady=(16, 8))
    header_wrap.grid_columnconfigure(0, weight=1)
    header = _fixed73b_build_centered_header(header_wrap, 'Тест B · Запоминание фигур в матрице', TEST_INSTRUCTIONS['B'], UNIFORM_TEST_BG)
    header.grid(row=0, column=0, sticky='ew')

    hud = tk.Frame(self.win, bg=UNIFORM_TEST_BG)
    hud.grid(row=1, column=0, sticky='ew', padx=24, pady=(0, 10))
    hud.grid_columnconfigure(0, weight=1)
    hud.grid_columnconfigure(1, weight=1)
    time_wrap, self.time_bar_canvas = _fixed42_create_bar(hud, 'Время', UNIFORM_TEST_BG)
    time_wrap.grid(row=0, column=0, sticky='ew', padx=(0, 10))
    task_wrap, self.task_bar_canvas = _fixed42_create_bar(hud, 'Задание', UNIFORM_TEST_BG)
    task_wrap.grid(row=0, column=1, sticky='ew', padx=(10, 0))

    body = tk.Frame(self.win, bg=UNIFORM_TEST_BG)
    body.grid(row=2, column=0, sticky='nsew', padx=20, pady=(2, 16))
    body.grid_columnconfigure(0, weight=1)
    body.grid_rowconfigure(0, weight=1)
    body.grid_rowconfigure(1, weight=0)

    matrix_wrap = tk.Frame(body, bg=UNIFORM_TEST_BG)
    matrix_wrap.grid(row=0, column=0, sticky='n', pady=(6, 10))
    self.matrix_frame = tk.Frame(matrix_wrap, bg=UNIFORM_TEST_BG, bd=0)
    self.matrix_frame.pack()

    cell_size = 156
    self._matrix_cell_size = cell_size
    self._tray_cell_size = cell_size
    self._matrix_bg = UNIFORM_TEST_BG
    self._tray_bg = UNIFORM_TEST_PANEL_2
    self._matrix_symbol_scale = 1.62
    self._tray_symbol_scale = 1.62
    self._matrix_symbol_pad = 10
    self._tray_symbol_pad = 10

    self.grid_cells.clear()
    for r in range(4):
        self.matrix_frame.grid_rowconfigure(r, weight=1)
        self.matrix_frame.grid_columnconfigure(r, weight=1)
    for idx in range(16):
        c = tk.Canvas(
            self.matrix_frame,
            width=cell_size,
            height=cell_size,
            bg=self._matrix_bg,
            highlightthickness=1,
            highlightbackground='#d8ccb5',
            bd=0
        )
        c.grid(row=idx // 4, column=idx % 4, padx=4, pady=4)
        c.bind('<Button-1>', lambda e, i=idx: self._on_matrix_cell(i))
        self.grid_cells.append(c)

    tray_panel = tk.Frame(body, bg=UNIFORM_TEST_PANEL_2, bd=1, relief='solid')
    tray_panel.grid(row=1, column=0, sticky='ew', pady=(4, 0))
    tray_panel.grid_columnconfigure(0, weight=1)
    tray_panel.grid_columnconfigure(1, weight=0)

    top_row = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2)
    top_row.grid(row=0, column=0, columnspan=2, sticky='ew', padx=14, pady=(10, 6))
    top_row.grid_columnconfigure(0, weight=1)
    tk.Label(top_row, text='Касса фигур', bg=UNIFORM_TEST_PANEL_2, fg=UNIFORM_TEST_FG, font=('Arial', 16, 'bold')).grid(row=0, column=0, sticky='w')

    controls = tk.Frame(top_row, bg=UNIFORM_TEST_PANEL_2)
    controls.grid(row=0, column=1, sticky='e')
    tk.Button(controls, text='Очистить', command=self._clear_placements,
              bg='#eee4c8', activebackground='#e1d6b6', fg='#5e372c',
              font=('Arial', 12, 'bold'), width=12).pack(side='left', padx=(0, 8))
    tk.Button(controls, text='Готово', command=self._submit_cycle,
              bg='#d9f1d7', activebackground='#c6e7c2', fg='#214125',
              font=('Arial', 12, 'bold'), width=12).pack(side='left', padx=(0, 8))
    tk.Button(controls, text='Выход', command=self._abort,
              bg='#d95a5a', activebackground='#c44d4d', fg='white',
              font=('Arial', 12, 'bold'), width=12).pack(side='left')

    self.tray_frame = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2)
    self.tray_frame.grid(row=1, column=0, columnspan=2, sticky='n', padx=12, pady=(0, 12))

    self.all_tray_shapes = []
    self.drag_shape = None
    self.drag_preview = None
    self._drag_motion_bind = None
    self._drag_release_bind = None
    self.message_var.set('')
    self.selection_var.set('')
    _fixed42_method_b_update_hud(self)


def _fixed73b_method_b_draw_memory_matrix(self):
    pad = 8
    size = getattr(self, '_matrix_cell_size', 156)
    inner = size - pad
    symbol_pad = getattr(self, '_matrix_symbol_pad', 10)
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
        cell.configure(bg=bg)
        cell.create_rectangle(pad, pad, inner, inner, outline='#d8ccb5', width=1, fill=bg)
        if idx in self.current_positions:
            shape = self.current_shapes[self.current_positions.index(idx)]
            _fixed71_draw_symbol(
                cell, symbol_pad, symbol_pad, size - symbol_pad, size - symbol_pad, shape,
                fill='#5a2323', outline='#5a2323',
                scale=getattr(self, '_matrix_symbol_scale', 1.62),
                tag='symbol'
            )


def _fixed73b_method_b_draw_reproduction_matrix(self):
    pad = 8
    size = getattr(self, '_matrix_cell_size', 156)
    inner = size - pad
    symbol_pad = getattr(self, '_matrix_symbol_pad', 10)
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
        cell.configure(bg=bg)
        border = '#b79e80' if idx in self.placements else '#d8ccb5'
        cell.create_rectangle(pad, pad, inner, inner, outline=border, width=1, fill=bg)
        if idx in self.placements:
            shape = self.placements[idx]
            _fixed71_draw_symbol(
                cell, symbol_pad, symbol_pad, size - symbol_pad, size - symbol_pad, shape,
                fill='#5a2323', outline='#5a2323',
                scale=getattr(self, '_matrix_symbol_scale', 1.62),
                tag='symbol'
            )


def _fixed73b_method_b_show_drag_preview(self, x_root: int, y_root: int, shape_id: int):
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.destroy()
        except Exception:
            pass
    size = getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 156))
    preview = tk.Toplevel(self.win)
    preview.overrideredirect(True)
    preview.attributes('-topmost', True)
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    preview.configure(bg=tray_bg)
    canvas = tk.Canvas(preview, width=size, height=size, bg=tray_bg, highlightthickness=0, bd=0)
    canvas.pack()
    symbol_pad = getattr(self, '_tray_symbol_pad', 10)
    _fixed71_draw_symbol(
        canvas, symbol_pad, symbol_pad, size - symbol_pad, size - symbol_pad, shape_id,
        fill='#5a2323', outline='#5a2323',
        scale=getattr(self, '_tray_symbol_scale', 1.62),
        tag='symbol'
    )
    preview.geometry(f'{size}x{size}+{int(x_root - size/2)}+{int(y_root - size/2)}')
    self.drag_preview = preview


def _fixed73b_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return
    items = sorted(list(getattr(self, 'all_tray_shapes', []) or getattr(self, 'current_shapes', [])))
    used = _fixed24_method_b_used_shapes(self)
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    cell_size = getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 156))
    symbol_pad = getattr(self, '_tray_symbol_pad', 10)
    columns = max(1, len(items))
    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        wrap = tk.Frame(self.tray_frame, bg=tray_bg)
        wrap.grid(row=row, column=col, padx=8, pady=8)
        is_used = shape in used
        border = '#dcc8ab' if is_used else '#d7c0a0'
        canvas = tk.Canvas(
            wrap,
            width=cell_size,
            height=cell_size,
            bg=tray_bg,
            highlightthickness=1,
            highlightbackground=border,
            bd=0,
            cursor='hand2' if not is_used else 'arrow'
        )
        canvas.pack()
        fill = '#b59d89' if is_used else '#5a2323'
        outline = '#b59d89' if is_used else '#5a2323'
        _fixed71_draw_symbol(
            canvas, symbol_pad, symbol_pad, cell_size - symbol_pad, cell_size - symbol_pad, shape,
            fill=fill, outline=outline,
            scale=getattr(self, '_tray_symbol_scale', 1.62),
            tag='symbol'
        )
        if is_used:
            canvas.create_line(20, 20, cell_size - 20, cell_size - 20, fill='#d46a6a', width=4)
        else:
            canvas.bind('<ButtonPress-1>', lambda e, s=shape, _self=self: _fixed25_method_b_start_drag(_self, e, s))
        self.tray_cells.append(canvas)

    if len(used) == 0:
        self.selection_var.set('Внизу показаны фигуры этого этапа. Перетащите их в нужные ячейки.')
    elif len(used) < len(self.current_positions):
        self.selection_var.set('Продолжайте перетаскивать фигуры снизу в нужные ячейки матрицы.')
    else:
        self.selection_var.set('Все фигуры этапа размещены. Проверьте матрицу и нажмите «Готово».')


