    btns = tk.Frame(center, bg=UNIFORM_TEST_BG)
    btns.pack(pady=(0, 10))
    tk.Button(btns, text='Ответ', command=self._submit_answer, bg='#42d95b', activebackground='#35b74a', font=('Arial', 14, 'bold'), width=10).pack(side='left', padx=8)
    tk.Button(btns, text='Выход', command=self._abort, bg='#d95a5a', activebackground='#c44d4d', fg='white', font=('Arial', 14, 'bold'), width=10).pack(side='left', padx=8)
    _fixed42_method_c_update_hud(self)


