def _fixed73c_draw_symbol(canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, shape_id: int,
                          fill: str = '#5a2323', outline: str = '#5a2323',
                          scale: float = 1.0, tag: str = 'symbol'):
    canvas.delete(tag)
    draw_basic_symbol(canvas, x1, y1, x2, y2, shape_id, fill=fill, outline=outline, tag=tag)
    if abs(scale - 1.0) > 1e-6:
        cx = (x1 + x2) / 2
        cy = (y1 + y2) / 2
        try:
            canvas.scale(tag, cx, cy, scale, scale)
        except Exception:
            pass


def _fixed73c_method_b_build_ui(self):
    _fixed73b_method_b_build_ui(self)
    self._tray_cell_size = int(getattr(self, '_matrix_cell_size', 156))
    self._tray_symbol_scale = float(getattr(self, '_matrix_symbol_scale', 1.62))
    self._tray_symbol_margin = int(getattr(self, '_matrix_symbol_margin', 10))


def _fixed73c_method_b_draw_memory_matrix(self):
    size = int(getattr(self, '_matrix_cell_size', 156))
    pad = 8
    bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
    margin = int(getattr(self, '_matrix_symbol_margin', 10))
    scale = float(getattr(self, '_matrix_symbol_scale', 1.62))
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        cell.configure(bg=bg)
        cell.create_rectangle(pad, pad, size - pad, size - pad, outline='#d8ccb5', width=1, fill=bg)
        if idx in self.current_positions:
            shape = self.current_shapes[self.current_positions.index(idx)]
            _fixed73c_draw_symbol(cell, margin, margin, size - margin, size - margin, shape, fill='#5a2323', outline='#5a2323', scale=scale, tag='symbol')


def _fixed73c_method_b_draw_reproduction_matrix(self):
    size = int(getattr(self, '_matrix_cell_size', 156))
    pad = 8
    bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
    margin = int(getattr(self, '_matrix_symbol_margin', 10))
    scale = float(getattr(self, '_matrix_symbol_scale', 1.62))
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        cell.configure(bg=bg)
        border = '#b79e80' if idx in self.placements else '#d8ccb5'
        cell.create_rectangle(pad, pad, size - pad, size - pad, outline=border, width=1, fill=bg)
        if idx in self.placements:
            shape = self.placements[idx]
            _fixed73c_draw_symbol(cell, margin, margin, size - margin, size - margin, shape, fill='#5a2323', outline='#5a2323', scale=scale, tag='symbol')


def _fixed73c_method_b_show_drag_preview(self, x_root: int, y_root: int, shape_id: int):
    if getattr(self, 'drag_preview', None) is not None:
        try:
            self.drag_preview.destroy()
        except Exception:
            pass
    size = int(getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 156)))
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    margin = int(getattr(self, '_tray_symbol_margin', 10))
    scale = float(getattr(self, '_tray_symbol_scale', getattr(self, '_matrix_symbol_scale', 1.62)))
    preview = tk.Toplevel(self.win)
    preview.overrideredirect(True)
    preview.attributes('-topmost', True)
    preview.configure(bg=tray_bg)
    canvas = tk.Canvas(preview, width=size, height=size, bg=tray_bg, highlightthickness=0, bd=0)
    canvas.pack()
    _fixed73c_draw_symbol(canvas, margin, margin, size - margin, size - margin, shape_id, fill='#5a2323', outline='#5a2323', scale=scale, tag='symbol')
    half = size // 2
    preview.geometry(f'{size}x{size}+{int(x_root - half)}+{int(y_root - half)}')
    self.drag_preview = preview


def _fixed73c_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return
    items = sorted(list(getattr(self, 'all_tray_shapes', []) or getattr(self, 'current_shapes', [])))
    used = _fixed24_method_b_used_shapes(self)
    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    columns = max(1, len(items))
    size = int(getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 156)))
    margin = int(getattr(self, '_tray_symbol_margin', 10))
    scale = float(getattr(self, '_tray_symbol_scale', getattr(self, '_matrix_symbol_scale', 1.62)))
    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        wrap = tk.Frame(self.tray_frame, bg=tray_bg)
        wrap.grid(row=row, column=col, padx=4, pady=4)
        is_used = shape in used
        border = '#dcc8ab' if is_used else '#d7c0a0'
        canvas = tk.Canvas(wrap, width=size, height=size, bg=tray_bg, highlightthickness=1, highlightbackground=border, bd=0, cursor='hand2' if not is_used else 'arrow')
        canvas.pack()
        fill = '#b59d89' if is_used else '#5a2323'
        outline = '#b59d89' if is_used else '#5a2323'
        _fixed73c_draw_symbol(canvas, margin, margin, size - margin, size - margin, shape, fill=fill, outline=outline, scale=scale, tag='symbol')
        if is_used:
            canvas.create_line(20, 20, size - 20, size - 20, fill='#d46a6a', width=4)
        else:
            canvas.bind('<ButtonPress-1>', lambda e, s=shape, _self=self: _fixed25_method_b_start_drag(_self, e, s))
        self.tray_cells.append(canvas)
    if len(used) == 0:
        self.selection_var.set('Внизу показаны фигуры этого этапа. Перетащите их в нужные ячейки.')
    elif len(used) < len(self.current_positions):
        self.selection_var.set('Продолжайте перетаскивать фигуры снизу в нужные ячейки матрицы.')
    else:
        self.selection_var.set('Все фигуры этапа размещены. Проверьте матрицу и нажмите «Готово».')


def _fixed73c_sync_research_next_button(self):
    btn = getattr(self, 'research_next_btn', None)
    if btn is None or not btn.winfo_exists():
        return
    logged_in = getattr(self, 'current_profile', None) is not None and getattr(self, 'current_session', None) is not None
    if logged_in:
        btn.configure(text='ВЕРНУТЬСЯ В МЕНЮ')
        if getattr(self, 'research_status_var', None) is not None:
            self.research_status_var.set('Измените параметры и нажмите «ВЕРНУТЬСЯ В МЕНЮ». Текущий пользователь останется активным.')
    else:
        btn.configure(text='ПРОДОЛЖИТЬ К ЛОГИНУ')
        if getattr(self, 'research_status_var', None) is not None:
            self.research_status_var.set('Измените параметры при необходимости и нажмите «ПРОДОЛЖИТЬ К ЛОГИНУ».')


