def _fixed73d_populate_researcher_fields(self):
    for child in self.research_content.winfo_children():
        child.destroy()
    self.research_widgets = {}
    self.research_sections = {}

    self.research_content.grid_columnconfigure(0, weight=1)

    self.research_tabs = ttk.Notebook(self.research_content)
    self.research_tabs.grid(row=0, column=0, sticky='nsew', padx=10, pady=10)

    for code, title, cls, filename in RESEARCH_CONFIG_SPECS:
        tab = tk.Frame(self.research_tabs, bg=BG_COLOR)
        tab.grid_columnconfigure(0, weight=1)
        self.research_tabs.add(tab, text=f'Тест {code}')

        intro = tk.Label(
            tab,
            text=title,
            bg=BG_COLOR,
            fg=TITLE_COLOR,
            anchor='center',
            justify='center',
        )
        intro.grid(row=0, column=0, sticky='ew', padx=10, pady=(8, 10))

        cfg = _fixed73d_load_cfg(self, cls, filename)
        widgets = {}
        section_frames = []
        section_groups = _get_research_section_groups(code, cls)

        for section_index, (section_title, field_names) in enumerate(section_groups, start=1):
            section = tk.LabelFrame(
                tab,
                text=section_title,
                bg=PANEL_COLOR,
                fg=TITLE_COLOR,
                bd=2,
                relief='groove',
                padx=10,
                pady=8,
            )
            section.grid(row=section_index, column=0, sticky='ew', padx=10, pady=6)
            section.grid_columnconfigure(0, weight=0, minsize=300)
            section.grid_columnconfigure(1, weight=1)
            section_frames.append(section)

            row = 0
            for field_name in field_names:
                fld = next((item for item in fields(cls) if item.name == field_name), None)
                if fld is None:
                    continue
                meta = _get_research_field_meta(code, fld.name)
                default_value = getattr(cfg, fld.name)

                label_box = tk.Frame(section, bg=PANEL_COLOR)
                label_box.grid(row=row, column=0, sticky='nw', padx=(8, 16), pady=6)

                label = tk.Label(
                    label_box,
                    text=meta.get('label', fld.name),
                    bg=PANEL_COLOR,
                    fg=TITLE_COLOR,
                    anchor='w',
                    justify='left',
                    font=('Segoe UI', 10, 'bold'),
                    wraplength=280,
                )
                label.pack(anchor='w')

                help_text = meta.get('help', '')
                if help_text:
                    help_label = tk.Label(
                        label_box,
                        text=help_text,
                        bg=PANEL_COLOR,
                        fg='#5a5a5a',
                        anchor='w',
                        justify='left',
                        wraplength=280,
                    )
                    help_label.pack(anchor='w', pady=(2, 0))

                serialized = _serialize_config_value(default_value)
                is_multiline = isinstance(default_value, (list, dict, tuple)) or len(serialized) > 52

                widget_box = tk.Frame(section, bg=PANEL_COLOR)
                widget_box.grid(row=row, column=1, sticky='ew', padx=(0, 8), pady=6)
                widget_box.grid_columnconfigure(0, weight=1)

                if is_multiline:
                    widget = tk.Text(widget_box, height=max(3, min(6, serialized.count('\n') + 2)), wrap='word', bg=FIELD_BG, relief='sunken', bd=1)
                    widget.insert('1.0', serialized)
                    widget.grid(row=0, column=0, sticky='ew')
                else:
                    widget = tk.Entry(widget_box, bg=FIELD_BG)
                    widget.insert(0, serialized)
                    widget.grid(row=0, column=0, sticky='ew', ipady=4)

                default_hint = tk.Label(
                    widget_box,
                    text=f'По умолчанию: {serialized}',
                    bg=PANEL_COLOR,
                    fg='#6b7280',
                    anchor='w',
                    justify='left',
                    wraplength=620,
                )
                default_hint.grid(row=1, column=0, sticky='w', pady=(3, 0))

                widgets[fld.name] = {'widget': widget, 'template': getattr(cls(), fld.name), 'is_multiline': is_multiline}
                row += 1

        self.research_widgets[code] = widgets
        self.research_sections[code] = section_frames

    self._on_research_canvas_configure()
    self._on_research_content_configure()


def _fixed73d_apply_researcher_layout(self):
    width = max(self.root.winfo_width(), 1100)
    height = max(self.root.winfo_height(), 760)
    scale = max(0.75, min(min(width / BASE_W, height / BASE_H), 1.25))

    pad_x = int(18 * scale)
    pad_y = int(14 * scale)
    gap = int(10 * scale)

    try:
        self.main.pack_configure(padx=pad_x, pady=pad_y)
    except Exception:
        pass

    self.research_header.grid_configure(pady=(0, int(8 * scale)))
    self.research_subtitle.grid_configure(pady=(0, int(8 * scale)))
    self.research_actions_top.grid_configure(pady=(0, int(8 * scale)))
    self.research_status.grid_configure(pady=(0, int(8 * scale)))

    self.research_title.configure(font=('Times New Roman', max(22, int(34 * scale)), 'bold'))
    self.research_subtitle.configure(font=('Arial', max(11, int(14 * scale)), 'bold'), wraplength=int(width * 0.82))
    self.research_status.configure(font=('Arial', max(11, int(13 * scale)), 'bold'), wraplength=int(width * 0.82))

    btn_font = ('Arial', max(11, int(14 * scale)), 'bold')
    for col, btn in enumerate([self.research_default_btn, self.research_all_results_btn, self.research_next_btn, self.research_exit_btn]):
        btn.configure(font=btn_font)
        btn.grid_configure(padx=(0, gap) if col < 3 else (0, 0), pady=0)

    for code, section_list in self.research_sections.items():
        for section in section_list:
            try:
                section.configure(font=('Arial', max(11, int(14 * scale)), 'bold'))
            except Exception:
                pass
            section.grid_columnconfigure(0, minsize=int(width * 0.24))
            for child in section.winfo_children():
                if isinstance(child, tk.Frame):
                    for nested in child.winfo_children():
                        if isinstance(nested, tk.Label):
                            is_title = 'bold' in str(nested.cget('font')).lower() or str(nested.cget('fg')) == TITLE_COLOR
                            nested.configure(font=('Arial', max(10, int(12 * scale)), 'bold' if is_title else 'normal'))
                elif isinstance(child, tk.Entry):
                    child.configure(font=('Consolas', max(10, int(12 * scale))))
                elif isinstance(child, tk.Text):
                    child.configure(font=('Consolas', max(10, int(11 * scale))))
                elif isinstance(child, tk.Label):
                    child.configure(font=('Arial', max(9, int(11 * scale))), wraplength=int(width * 0.44))

    self._on_research_canvas_configure()
    self._on_research_content_configure()


