def _fixed73d_refresh_menu_state(self):
    if not self.current_profile:
        return
    progress = self.progress_store.ensure_user(self.current_profile)
    completed = progress.get('completed_tests', [])
    next_code = self.progress_store.next_test_code(self.current_profile)
    completed_text = ', '.join(TEST_LABELS[c] for c in completed) if completed else 'пока нет'
    researcher = bool(getattr(self, 'researcher_mode_enabled', False))

    self.menu_intro_var.set(f'Пользователь: {self.current_profile.name}, {self.current_profile.age} лет, {self.current_profile.gender}.')
    if researcher:
        next_text = f'Следующий неполный тест: {TEST_LABELS[next_code]}.' if next_code else 'Все методики уже завершены.'
    else:
        next_text = f'Следующий тест: {TEST_LABELS[next_code]}.' if next_code else 'Все тесты пройдены.'
    self.menu_status_var.set(f'Пройдено: {completed_text}.\n{next_text}')

    for code, btn in self.menu_buttons.items():
        has_result = bool(self.progress_store.get_test_result(self.current_profile, code))
        if researcher:
            if code in completed:
                btn.configure(state=tk.NORMAL, text=f"{TEST_LABELS[code]}\n{TEST_DESCRIPTIONS[code]}\n(можно запустить снова)", bg='#d8f0d7', activebackground='#c7e7c6', fg='#102744', relief='raised')
            else:
                btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG if code == next_code else MENU_BG, activebackground=NEXT_ACTIVE if code == next_code else MENU_ACTIVE, fg='#111111', relief='raised')
        else:
            if code in completed:
                btn.configure(state=tk.DISABLED, text=menu_card_text(code, 'done'), bg='#bfc7ba', activebackground='#bfc7ba', disabledforeground='#4a5b47', relief='sunken')
            elif code == next_code:
                btn.configure(state=tk.NORMAL, text=menu_card_text(code), bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg='#111111', relief='raised')
            else:
                btn.configure(state=tk.DISABLED, text=menu_card_text(code, 'locked'), bg=MENU_DISABLED, activebackground=MENU_DISABLED, disabledforeground='#6d6955', relief='ridge')

        result_btn = self.menu_result_buttons.get(code)
        if result_btn is not None:
            if has_result:
                result_btn.configure(state=tk.NORMAL, text='ПОКАЗАТЬ\nРЕЗУЛЬТАТ', bg='#6b7dff', activebackground='#5b6de8', fg='white', relief='raised')
            else:
                result_btn.configure(state=tk.DISABLED, text='РЕЗУЛЬТАТОВ\nПОКА НЕТ', bg='#d6dbe5', activebackground='#d6dbe5', disabledforeground='#7f8897', relief='flat')

    if next_code:
        self.continue_btn.configure(state=tk.NORMAL, text='СЛЕДУЮЩИЙ ТЕСТ', bg=NEXT_BG, activebackground=NEXT_ACTIVE, fg='#111111', relief='raised')
    else:
        self.continue_btn.configure(state=tk.NORMAL, text='ОБЩИЙ ПРОФИЛЬ СПР', bg='#4f78ff', activebackground='#4269e0', fg='white', relief='raised')

    if getattr(self, 'all_results_btn', None) is not None and self.all_results_btn.winfo_exists():
        self.all_results_btn.configure(state=tk.NORMAL)


StartPageApp.build_researcher_ui = _fixed73d_build_researcher_ui
StartPageApp._populate_researcher_fields = _fixed73d_populate_researcher_fields
StartPageApp.apply_researcher_layout = _fixed73d_apply_researcher_layout
StartPageApp.apply_researcher_and_open_login = _fixed73d_apply_researcher_and_open_login
StartPageApp.build_start_ui = _fixed73d_build_start_ui
StartPageApp.apply_start_layout = _fixed73d_apply_start_layout
StartPageApp.build_menu_ui = _fixed73d_build_menu_ui
StartPageApp.apply_menu_layout = _fixed73d_apply_menu_layout
StartPageApp.refresh_menu_state = _fixed73d_refresh_menu_state



# === FIXED73E: математика теста A по документу «Обработка данных в задаче Слежение» ===
import math as _fixed73e_math


def _fixed73e_clip(value, lo, hi):
    try:
        value = float(value)
    except Exception:
        value = lo
    return max(float(lo), min(float(hi), value))


def _fixed73e_stage_name(stage_no: int) -> str:
    return {1: 'X', 2: 'X+Y', 3: 'X+Y+крен'}.get(int(stage_no or 0), f'Этап {stage_no}')


def _fixed73e_stage_error_bounds(self, stage_no: int) -> tuple[float, float]:
    stage_no = int(stage_no)
    if stage_no == 3 and bool(self.stage_defs.get(stage_no, {}).get('z')):
        return 0.0, 1.0
    goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    crash = max(goal + 1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)) + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    return goal, crash


def _fixed73e_current_tracking_error(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[stage_no]
    x_cm = abs(float(getattr(state, 'x_px', 0.0))) / max(1e-6, float(self.cfg.px_per_cm)) if stage.get('x') else 0.0
    y_cm = abs(float(getattr(state, 'y_px', 0.0))) / max(1e-6, float(self.cfg.px_per_cm)) if stage.get('y') else 0.0
    xy_now = (x_cm * x_cm + y_cm * y_cm) ** 0.5

    if not stage.get('z'):
        return xy_now

    xy_goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    xy_crash = max(xy_goal + 1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)) + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    roll_goal = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 10.0)))
    roll_crash = max(roll_goal + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0)))

    xy_norm = _fixed73e_clip((xy_now - xy_goal) / max(1e-6, xy_crash - xy_goal), 0.0, 1.0)
    roll_now = abs(float(getattr(state, 'roll_deg', 0.0)))
    roll_norm = _fixed73e_clip((roll_now - roll_goal) / max(1e-6, roll_crash - roll_goal), 0.0, 1.0)
    return ((xy_norm * xy_norm + roll_norm * roll_norm) / 2.0) ** 0.5


def _fixed73e_current_speed_value(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[stage_no]
    active_xy_axes = int(bool(stage.get('x'))) + int(bool(stage.get('y')))
    xy_speed = abs(float(getattr(state, 'speed_xy_cm_s', 0.0))) * (_fixed73e_math.sqrt(active_xy_axes) if active_xy_axes else 0.0)

    if not stage.get('z'):
        return xy_speed

    xy_goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    xy_crash = max(xy_goal + 1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)) + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    roll_goal = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 10.0)))
    roll_crash = max(roll_goal + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0)))

    xy_norm_speed = xy_speed / max(1e-6, xy_crash - xy_goal)
    roll_norm_speed = abs(float(getattr(state, 'speed_z_deg_s', 0.0))) / max(1e-6, roll_crash - roll_goal)
    return ((xy_norm_speed * xy_norm_speed + roll_norm_speed * roll_norm_speed) / 2.0) ** 0.5


def _fixed73e_stage_report_to_dict(self) -> dict:
    data = asdict(self)
    for key, value in self.__dict__.items():
        if key not in data:
            data[key] = value
    return data


def _fixed73e_finalize_stage_report(self, report: StageReport, elapsed_s: float, xy_integral: float, roll_integral: float, tracking_error_integral: float = 0.0, speed_integral: float = 0.0) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    report.avg_tracking_error = float(tracking_error_integral) / total
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed73e_stage_error_bounds(self, int(report.stage_no))
    clamped_error = _fixed73e_clip(getattr(report, 'avg_tracking_error', 0.0), goal, crash)
    entropy_h = (clamped_error - goal) / max(1e-6, crash - goal)
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)

    report.entropy_h = entropy_h
    report.success_gamma = _fixed73e_clip(1.0 - entropy_h, 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = goal
    report.tracking_error_crash = crash
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    return report


def _fixed73e_log_stage_report(self, report: StageReport):
    self.logger.log_event(
        self.session,
        event_type='stage_report',
        screen='method_a',
        test_name='method_a_stage',
        stage=str(report.stage_no),
        action='stage_end',
        elapsed_ms=int(float(report.real_time_s) * 1000),
        x=round(float(getattr(report, 'v_avg', 0.0)), 4),
        y=round(float(getattr(report, 'avg_tracking_error', 0.0)), 4),
        angle=round(float(getattr(report, 'reduced_tempo_tr', 0.0)), 4),
        value=int(report.crashes),
        note=(
            f"axes={report.active_axes}; gamma={float(getattr(report, 'success_gamma', 0.0)):.4f}; "
            f"h={float(getattr(report, 'entropy_h', 0.0)):.4f}; tr={float(getattr(report, 'reduced_tempo_tr', 0.0)):.4f}"
        ),
    )


def _fixed73e_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    stage_error = 0.0
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        stage_error += self.current_error_increment(state, stage_no, dt)
        report.sum_error = stage_error
        self.maybe_register_return(state, stage_no, report)

        inside_now = self.inside_target(state, stage_no)
        if inside_now:
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        tracking_error_integral += _fixed73e_current_tracking_error(self, state, stage_no) * dt
        speed_integral += _fixed73e_current_speed_value(self, state, stage_no) * dt

        crashed = self.in_crash_zone(state, stage_no) or stage_error >= self.stage_smax(stage_no)
        if crashed:
            report.crashes += 1
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(state.x_px, 3),
                y=round(stage_error, 3),
                angle=round(state.roll_deg, 3),
                value=report.crashes,
                note=f"axes={report.active_axes}",
            )
            self.show_message('ОШИБКА', seconds=0.8)
            self.reset_after_crash(state)
            stage_error = 0.0
            report.sum_error = 0.0

            if report.crashes >= self.cfg.stage_crash_limit:
                return _fixed73e_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)

        if elapsed_s >= self.cfg.stage_time_limit_s:
            return _fixed73e_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)

        self.draw_background()
        self.draw_zones()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, stage_error, report, state)
        pygame.display.flip()


def _fixed73e_method_a_summary_from_reports(reports: list[dict]) -> dict:
    reports = [r for r in (reports or []) if isinstance(r, dict)]
    total_time_s = round(sum(float(r.get('real_time_s', 0.0) or 0.0) for r in reports), 2)
    total_crashes = int(sum(int(r.get('crashes', 0) or 0) for r in reports))
    avg_stability_pct = round(sum(float(r.get('stability_pct', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 1) if reports else 0.0
    avg_mean_xy_cm = round(sum(float(r.get('mean_abs_xy_cm', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 2) if reports else 0.0
    avg_v_avg = round(sum(float(r.get('v_avg', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_entropy_h = round(sum(float(r.get('entropy_h', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_success_gamma = round(sum(float(r.get('success_gamma', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_tracking_error = round(sum(float(r.get('avg_tracking_error', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_reduced_tempo_tr = round(sum(float(r.get('reduced_tempo_tr', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0

    by_stage = {int(r.get('stage_no', 0) or 0): r for r in reports}
    t_values = {
        'min': round(float(by_stage.get(1, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'medio': round(float(by_stage.get(2, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'max': round(float(by_stage.get(3, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
    }

    best_stage = None
    if reports:
        best = max(
            reports,
            key=lambda r: (
                float(r.get('reduced_tempo_tr', 0.0) or 0.0),
                float(r.get('success_gamma', 0.0) or 0.0),
                -int(r.get('crashes', 0) or 0),
                -float(r.get('avg_tracking_error', 0.0) or 0.0),
            ),
        )
        try:
            best_stage = int(best.get('stage_no', 0) or 0)
        except Exception:
            best_stage = None

    return {
        'total_time_s': total_time_s,
        'total_crashes': total_crashes,
        'avg_stability_pct': avg_stability_pct,
        'avg_mean_xy_cm': avg_mean_xy_cm,
        'avg_v_avg': avg_v_avg,
        'avg_entropy_h': avg_entropy_h,
        'avg_success_gamma': avg_success_gamma,
        'avg_tracking_error': avg_tracking_error,
        'avg_reduced_tempo_tr': avg_reduced_tempo_tr,
        'best_stage': best_stage,
        't_values': t_values,
        'tmin_a': t_values['min'],
        'tmedio_a': t_values['medio'],
        'tmax_a': t_values['max'],
    }


def _fixed73e_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    reports = [r for r in (result.get('reports', []) or []) if isinstance(r, dict)]
    summary = _fixed73e_method_a_summary_from_reports(reports)
    return {
        'test_code': 'A',
        'test_label': TEST_LABELS['A'],
        'completed_at': datetime.now().isoformat(timespec='seconds'),
        'session_id': session.session_id,
        'participant': {
            'name': session.name,
            'age': session.age,
            'gender': session.gender,
        },
        'result_path': result.get('result_path', ''),
        'reports': reports,
        'summary': summary,
    }


def _fixed73e_enrich_payload_for_storage(self, test_code: str, payload: dict) -> dict:
    normalized = dict(payload) if isinstance(payload, dict) else {}
    if test_code != 'A':
        return _FIXED73E_PREV_ENRICH_PAYLOAD(self, test_code, payload)

    reports = self._load_method_a_reports(normalized)
    normalized['reports'] = reports
    summary = normalized.get('summary', {})
    if not isinstance(summary, dict):
        summary = {}
    if reports:
        computed = _fixed73e_method_a_summary_from_reports(reports)
        for key, value in computed.items():
            if key == 't_values':
                if not isinstance(summary.get('t_values'), dict) or not summary.get('t_values'):
                    summary['t_values'] = value
                else:
                    merged = dict(value)
                    merged.update(summary.get('t_values', {}))
                    summary['t_values'] = merged
            elif key not in summary or summary.get(key) in (None, '', 0, 0.0):
                summary[key] = value
    normalized['summary'] = summary
    return normalized


def _fixed73e_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    stage_no = int(report.get('stage_no', 0) or 0)
    if stage_no == 3:
        v_label = 'Vср'
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} усл. ед./с"
        e_value = f"{float(report.get('avg_tracking_error', 0.0) or 0.0):.4f} норм. ед."
        bounds_value = 'цель = 0.0000, авария = 1.0000'
    else:
        v_label = 'Vср'
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} см/с"
        e_value = f"{float(report.get('avg_tracking_error', 0.0) or 0.0):.4f} см"
        bounds_value = (
            f"цель = {float(report.get('tracking_error_target', 0.0) or 0.0):.2f} см, "
            f"авария = {float(report.get('tracking_error_crash', 0.0) or 0.0):.2f} см"
        )

    rows = [
        ('Режим', _fixed73e_stage_name(stage_no)),
        ('Контролируемые оси', str(report.get('active_axes', ''))),
        ('Длительность', f"{float(report.get('real_time_s', 0.0) or 0.0):.1f} с"),
        ('Ошибки', f"{int(report.get('crashes', 0) or 0)} из 3"),
        (v_label, v_value),
        ('γ', f"{float(report.get('success_gamma', 0.0) or 0.0):.4f}"),
        ('Энтропия H', f"{float(report.get('entropy_h', 0.0) or 0.0):.4f}"),
        ('Yтек. ср.', e_value),
        ('tр = Vср × γ', f"{float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}"),
        ('Границы расчёта ошибки', bounds_value),
    ]
    if stage_no == 3:
        rows.append(('Средний крен', f"{float(report.get('mean_abs_roll_deg', 0.0) or 0.0):.2f}°"))
    else:
        rows.append(('Среднее отклонение X/Y', f"{float(report.get('mean_abs_xy_cm', 0.0) or 0.0):.2f} см"))
    return rows


def _fixed73e_show_method_a_results(self, payload: dict):
    top, outer = _open_results_top(self, 'Результаты - Тест А. Слежение за объектом')
    participant = payload.get('participant', {})
    reports = payload.get('reports', [])
    if not reports:
        result_path = payload.get('result_path', '')
        if result_path:
            try:
                rp = Path(result_path)
                if not rp.is_absolute():
                    rp = self.base_dir / rp
                if rp.exists():
                    loaded = json.loads(rp.read_text(encoding='utf-8'))
                    if isinstance(loaded, list):
                        reports = [item for item in loaded if isinstance(item, dict)]
            except Exception:
                reports = []
    summary = dict(payload.get('summary', {}) or {})
    if reports:
        computed = _fixed73e_method_a_summary_from_reports(reports)
        for key, value in computed.items():
            if key == 't_values':
                merged = dict(value)
                merged.update(summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {})
                summary['t_values'] = merged
            else:
                summary.setdefault(key, value)
    t_values = summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {}

    completed_at = payload.get('completed_at', '')
    dt_label = completed_at.replace('T', ' ')[:19] if completed_at else 'не указано'

    header = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
    header.pack(fill='x', padx=24, pady=(24, 12))
    tk.Frame(header, bg='#67a9ff', height=8).pack(fill='x')
    head_body = tk.Frame(header, bg='#ffffff')
    head_body.pack(fill='both', expand=True, padx=22, pady=18)
    tk.Label(head_body, text='Тест А · Слежение за объектом', bg='#ffffff', fg='#102744', font=('Arial', 28, 'bold')).pack(anchor='w')
    subtitle = f"{participant.get('name', '')}, {participant.get('age', '')} лет, {participant.get('gender', '')}. Последнее завершение: {dt_label}."
    tk.Label(head_body, text=subtitle, bg='#ffffff', fg='#5a6678', font=('Arial', 12, 'bold'), wraplength=1180, justify='left').pack(anchor='w', pady=(8, 0))

    summary_shell = tk.Frame(outer, bg='#eef3f8')
    summary_shell.pack(fill='x', padx=24, pady=(0, 12))
    summary_grid = tk.Frame(summary_shell, bg='#eef3f8')
    summary_grid.pack(fill='x')
    for col in range(6):
        summary_grid.grid_columnconfigure(col, weight=1, uniform='a_summary73e')

    summary_cards = [
        ('tр · X', f"{float(t_values.get('min', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по одной координате', '#67a9ff', 0, 0),
        ('tр · X+Y', f"{float(t_values.get('medio', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по двум координатам', '#53c26b', 0, 2),
        ('tр · X+Y+крен', f"{float(t_values.get('max', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по трём параметрам', '#c98cff', 0, 4),
        ('Средний γ', f"{float(summary.get('avg_success_gamma', 0.0) or 0.0):.4f}", 'Коэффициент успешности, равный негэнтропии управления', '#7bd0d5', 1, 0),
        ('Средняя энтропия H', f"{float(summary.get('avg_entropy_h', 0.0) or 0.0):.4f}", 'Чем меньше H, тем ближе средняя ошибка к целевой зоне', '#ffb35c', 1, 2),
        ('Ошибки за тест', f"{int(summary.get('total_crashes', 0) or 0)} из 9", 'Суммарное число ошибок на трёх этапах', '#e26565', 1, 4),
    ]
    for title, value, subtitle, accent, row, col in summary_cards:
        card = self.draw_result_card(summary_grid, title, value, subtitle, accent)
        card.grid(row=row, column=col, columnspan=2, sticky='nsew', padx=8, pady=8)

    info_text = (
        'Основной показатель этапа рассчитывается как tр = Vср × γ. '
        'Коэффициент успешности γ получен через энтропию управления H, которая определяется средней текущей ошибкой слежения между целевой и аварийной границами. '
        'Для этапа X+Y+крен скорость и ошибка приведены к единой нормированной шкале, чтобы получить один скалярный показатель tр.'
    )
    info_box = _add_info_box(outer, 'Как читать результат', info_text, '#6b7dff')
    info_box.pack(fill='x', padx=24, pady=(0, 14))

    stages_title = tk.Frame(outer, bg='#eef3f8')
    stages_title.pack(fill='x', padx=24, pady=(0, 8))
    tk.Label(stages_title, text='Показатели по этапам', bg='#eef3f8', fg='#102744', font=('Arial', 18, 'bold')).pack(anchor='w')
    tk.Label(stages_title, text='На каждом этапе показаны Vср, γ, энтропия H, средняя текущая ошибка и приведённый темп tр.', bg='#eef3f8', fg='#607187', font=('Arial', 11)).pack(anchor='w', pady=(2, 0))

    if not reports:
        empty = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        empty.pack(fill='x', padx=24, pady=(0, 14))
        tk.Label(empty, text='Подробные данные этапов не найдены.', bg='#ffffff', fg='#102744', font=('Arial', 16, 'bold')).pack(anchor='w', padx=18, pady=(16, 6))
        tk.Label(empty, text='Сводные карточки выше сохранены, но детальный список этапов для этого результата отсутствует.', bg='#ffffff', fg='#506176', font=('Arial', 11), wraplength=1120, justify='left').pack(anchor='w', padx=18, pady=(0, 18))
        return top

    ordered_reports = sorted(reports, key=lambda r: int(r.get('stage_no', 0) or 0))
    for report in ordered_reports:
        card = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        card.pack(fill='x', padx=24, pady=(0, 14))

        head = tk.Frame(card, bg='#ffffff')
        head.pack(fill='x', padx=18, pady=(16, 8))
        stage_no = int(report.get('stage_no', 0) or 0)
        tk.Label(head, text=f"Этап {stage_no} · {_fixed73e_stage_name(stage_no)}", bg='#ffffff', fg='#102744', font=('Arial', 20, 'bold')).pack(anchor='w')
        tk.Label(head, text=f"tр = {float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}", bg='#ffffff', fg='#4f78ff', font=('Arial', 12, 'bold')).pack(anchor='w', pady=(4, 0))

        grid = tk.Frame(card, bg='#ffffff')
        grid.pack(fill='x', padx=18, pady=(0, 16))
        rows = _fixed73e_method_a_stage_metric_rows(report)
        for idx, (label_text, value_text) in enumerate(rows):
            r = idx // 2
            c = (idx % 2) * 2
            tk.Label(grid, text=label_text, bg='#ffffff', fg='#617187', font=('Arial', 10, 'bold'), anchor='w').grid(row=r, column=c, sticky='w', padx=(0, 10), pady=4)
            tk.Label(grid, text=value_text, bg='#ffffff', fg='#102744', font=('Arial', 12, 'bold'), anchor='w').grid(row=r, column=c + 1, sticky='w', padx=(0, 26), pady=4)
        for col in range(4):
            grid.grid_columnconfigure(col, weight=1 if col % 2 else 0)

    return top


