# ====== FIXED73F: Method B single vertical time bar placed closer to matrix ======

def _fixed73f_draw_vertical_time_bar(canvas: tk.Canvas, ratio: float):
    ratio = max(0.0, min(1.0, float(ratio)))
    try:
        width = max(10, int(canvas.winfo_width()))
        if width <= 1:
            width = int(canvas.cget('width'))
    except Exception:
        width = int(canvas.cget('width'))
    try:
        height = max(10, int(canvas.winfo_height()))
        if height <= 1:
            height = int(canvas.cget('height'))
    except Exception:
        height = int(canvas.cget('height'))

    canvas.delete('all')
    title_y = 16
    bar_top = 40
    bar_bottom = height - 12
    bar_w = 26
    left = (width - bar_w) // 2
    right = left + bar_w

    canvas.create_text(width / 2, title_y, text='ВРЕМЯ', fill='#102744', font=('Arial', 10, 'bold'))
    canvas.create_rectangle(left, bar_top, right, bar_bottom, outline='#7a899d', fill='#e9eef6', width=2)

    inner_left = left + 2
    inner_right = right - 2
    inner_top = bar_top + 2
    inner_bottom = bar_bottom - 2
    inner_h = max(0, inner_bottom - inner_top)
    fill_h = int(inner_h * ratio)

    if fill_h > 0:
        canvas.create_rectangle(
            inner_left,
            max(inner_top, inner_bottom - fill_h),
            inner_right,
            inner_bottom,
            outline='',
            fill='#68a8ff',
        )


def _fixed73f_method_b_update_hud(self):
    if getattr(self, 'time_bar_canvas', None) is None:
        return
    total = max(1.0, float(self.cfg.total_test_s))
    time_ratio = min(1.0, self._elapsed_total() / total)
    _fixed73f_draw_vertical_time_bar(self.time_bar_canvas, time_ratio)


