def _fixed73f_method_b_draw_memory_matrix(self):
    size = int(getattr(self, '_matrix_cell_size', 156))
    pad = 8
    bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
    margin = int(getattr(self, '_matrix_symbol_margin', 10))
    scale = float(getattr(self, '_matrix_symbol_scale', 1.62))
    normal_border = '#8a775c'
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        cell.configure(bg=bg)
        cell.create_rectangle(pad, pad, size - pad, size - pad, outline=normal_border, width=2, fill=bg)
        if idx in self.current_positions:
            shape = self.current_shapes[self.current_positions.index(idx)]
            _fixed73c_draw_symbol(
                cell, margin, margin, size - margin, size - margin, shape,
                fill='#5a2323', outline='#5a2323', scale=scale, tag='symbol'
            )


def _fixed73f_method_b_draw_reproduction_matrix(self):
    size = int(getattr(self, '_matrix_cell_size', 156))
    pad = 8
    bg = getattr(self, '_matrix_bg', UNIFORM_TEST_BG)
    margin = int(getattr(self, '_matrix_symbol_margin', 10))
    scale = float(getattr(self, '_matrix_symbol_scale', 1.62))
    normal_border = '#8a775c'
    active_border = '#6f5535'
    for idx, cell in enumerate(self.grid_cells):
        cell.delete('all')
        cell.configure(bg=bg)
        border = active_border if idx in self.placements else normal_border
        cell.create_rectangle(pad, pad, size - pad, size - pad, outline=border, width=2, fill=bg)
        if idx in self.placements:
            shape = self.placements[idx]
            _fixed73c_draw_symbol(
                cell, margin, margin, size - margin, size - margin, shape,
                fill='#5a2323', outline='#5a2323', scale=scale, tag='symbol'
            )


