# ====== FIXED75: Method B difficulty must change clearly after every cycle ======

_FIXED75_B_EXPOSURE_PER_EXTRA_FIG = 0.35
_FIXED75_B_REPRO_PER_EXTRA_FIG = 0.55


def _fixed75_method_b_start_cycle(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    if self._time_left_total() <= 1.0:
        self._finish()
        return

    n = max(1, min(self.cfg.max_items, int(self.current_n)))
    all_cells = list(range(self.cfg.grid_size ** 2))
    random.shuffle(all_cells)
    self.current_positions = sorted(all_cells[:n])

    ordered_shapes = [s for s in _FIXED71_SHAPE_ORDER if s < len(BASIC_SYMBOLS)]
    self.current_shapes = ordered_shapes[:n]
    self.all_tray_shapes = list(self.current_shapes)

    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    self.phase = 'memorize'
    self.cycle_started_at = time.perf_counter()
    self.message_var.set('')
    self.selection_var.set('')
    self._draw_memory_matrix()
    self._draw_tray(show=False)

    # Раньше время слишком щедро росло вместе с числом фигур,
    # поэтому сложность ощущалась почти плоской.
    # Теперь прибавка ко времени небольшая, а изменение сложности
    # после каждого результата ощущается сразу.
    base_exposure = float(self.cfg.start_exposure_s) + _FIXED75_B_EXPOSURE_PER_EXTRA_FIG * max(0, n - 1)
    exposure = max(0.7, base_exposure + float(getattr(self, 'exposure_adjust_s', 0.0)))
    exposure = min(exposure, max(1.0, self._time_left_total()))
    self._update_info_label()
    self._track_after(self.win.after(int(exposure * 1000), self._start_reproduction_phase))



def _fixed75_method_b_start_reproduction_phase(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    self.phase = 'reproduce'
    n = len(self.current_positions)
    self.all_tray_shapes = list(self.current_shapes)

    base_repr = float(self.cfg.start_reproduction_s) + _FIXED75_B_REPRO_PER_EXTRA_FIG * max(0, n - 1)
    repr_time = max(1.2, base_repr + float(getattr(self, 'reproduction_adjust_s', 0.0)))
    repr_time = min(repr_time, max(1.0, self._time_left_total()))
    self.reproduction_deadline = time.perf_counter() + repr_time
    self.message_var.set('')
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)
    self._tick_reproduction_timeout()



def _fixed75_method_b_finalize_cycle(self, success: bool | None, reason: str):
    if self.phase != 'reproduce':
        return
    self._cancel_afters()
    success_eval, correct, expected = self._evaluate_cycle()
    if success is None:
        success = success_eval

    elapsed = time.perf_counter() - self.cycle_started_at
    n = len(expected)
    cycle_info = {
        'n': n,
        'success': bool(success),
        'correct_count': int(correct),
        'elapsed_s': _round2(elapsed),
        'reason': reason,
        'positions': list(self.current_positions),
        'shapes': list(self.current_shapes),
    }
    self.result['cycles'].append(cycle_info)
    self.logger.log_event(
        self.session,
        event_type='method_cycle',
        screen='method_b',
        test_name='method_b',
        stage=f'n={n}',
        action='success' if success else 'error',
        elapsed_ms=int(elapsed * 1000),
        value=correct,
        note=f'reason={reason}; placed={len(self.placements)}',
    )

    adaptive_step = max(1.0, float(getattr(self.cfg, 'adaptive_time_step_s', 0.5) or 0.5))
    max_expand = max(6.0, adaptive_step * 8)

    current_exposure_adjust = float(getattr(self, 'exposure_adjust_s', 0.0))
    current_reproduction_adjust = float(getattr(self, 'reproduction_adjust_s', 0.0))

    min_exposure_adjust = -(float(self.cfg.start_exposure_s) - 0.7)
    min_reproduction_adjust = -(float(self.cfg.start_reproduction_s) - 1.0)

    if success:
        self.current_n = min(self.cfg.max_items, self.current_n + 1)
        self.exposure_adjust_s = max(min_exposure_adjust, min(max_expand, current_exposure_adjust - adaptive_step))
        self.reproduction_adjust_s = max(min_reproduction_adjust, min(max_expand * 1.5, current_reproduction_adjust - adaptive_step))
        self.message_var.set(f'Успешно: воспроизведено {n} фигур. Следующий цикл будет сложнее.')
    else:
        self.current_n = max(1, self.current_n - 1)
        self.exposure_adjust_s = max(min_exposure_adjust, min(max_expand, current_exposure_adjust + adaptive_step))
        self.reproduction_adjust_s = max(min_reproduction_adjust, min(max_expand * 1.5, current_reproduction_adjust + adaptive_step))
        self.message_var.set(f'Ошибка: правильно размещено {correct} из {n}. Следующий цикл будет проще.')

    self.phase = 'message'
    self._track_after(self.win.after(1000, self._start_cycle))


MethodBWindow._start_cycle = _fixed75_method_b_start_cycle
MethodBWindow._start_reproduction_phase = _fixed75_method_b_start_reproduction_phase
MethodBWindow._finalize_cycle = _fixed75_method_b_finalize_cycle


