# === FIXED77: тест A — энтропия без искусственного зануления ===
def _fixed77_entropy_from_avg_error(avg_error: float, goal: float, crash: float) -> float:
    """Рабочая энтропия управления.

    В fixed73e значение H фактически занулялось для любой средней ошибки,
    которая оказывалась внутри целевой зоны, потому что ошибка сначала
    поджималась к нижней границе goal. Из-за этого разные по качеству проходы
    внутри целевой зоны выглядели одинаково как H = 0.

    Здесь H считается по реальной средней ошибке на полной шкале от 0 до
    аварийной границы. Так показатель остаётся положительным, пока средняя
    ошибка положительна, и не схлопывается в ноль только из-за того, что
    участник удерживался внутри целевой зоны.
    """
    try:
        avg_error = float(avg_error)
    except Exception:
        avg_error = 0.0
    try:
        goal = float(goal)
    except Exception:
        goal = 0.0
    try:
        crash = float(crash)
    except Exception:
        crash = max(goal, 1.0)

    avg_error = max(0.0, avg_error)
    crash = max(max(goal, 0.0) + 1e-6, crash)
    entropy_h = _fixed73e_clip(avg_error / crash, 0.0, 1.0)
    if avg_error > 0.0 and entropy_h == 0.0:
        entropy_h = 1e-6
    return entropy_h


def _fixed73e_finalize_stage_report(self, report: StageReport, elapsed_s: float, xy_integral: float, roll_integral: float, tracking_error_integral: float = 0.0, speed_integral: float = 0.0) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    report.avg_tracking_error = float(tracking_error_integral) / total
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed73e_stage_error_bounds(self, int(report.stage_no))

    # Сохраняем и прежнюю «документную» нормировку, чтобы её можно было
    # сравнивать, но основной показатель H больше не зануляется искусственно.
    doc_entropy_h = _fixed73e_clip(
        (float(getattr(report, 'avg_tracking_error', 0.0)) - goal) / max(1e-6, crash - goal),
        0.0,
        1.0,
    )
    entropy_h = _fixed77_entropy_from_avg_error(
        getattr(report, 'avg_tracking_error', 0.0),
        goal,
        crash,
    )

    report.entropy_h_doc = doc_entropy_h
    report.entropy_h = entropy_h
    report.success_gamma = _fixed73e_clip(1.0 - entropy_h, 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = goal
    report.tracking_error_crash = crash
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.entropy_formula_note = 'H считается по реальной средней ошибке на шкале 0..авария; entropy_h_doc хранит прежнюю нормировку от цели до аварии.'
    return report


