# ====== FIXED80: расчёты теста A строго по документу slezh.docx ======
# Формулы:
#   H = (Υтек. ср. - Υцели) / (Υаварии - Υцели)
#   γ = 1 - H
#   tр = Vср × γ
# В коде H дополнительно ограничивается диапазоном 0..1,
# чтобы энтропия и негэнтропия оставались физически осмысленными.

def _fixed80_method_a_finalize_stage_report(self, report: StageReport, elapsed_s: float, xy_integral: float, roll_integral: float, tracking_error_integral: float = 0.0, speed_integral: float = 0.0) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    report.avg_tracking_error = float(tracking_error_integral) / total
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed73e_stage_error_bounds(self, int(report.stage_no))
    entropy_h = (float(report.avg_tracking_error) - float(goal)) / max(1e-6, float(crash) - float(goal))
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)

    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.entropy_formula_note = 'H=(Υтек. ср.-Υцели)/(Υаварии-Υцели); γ=1-H; tр=Vср×γ'
    return report


_fixed73e_finalize_stage_report = _fixed80_method_a_finalize_stage_report
MethodAApp.finalize_stage_report = _fixed80_method_a_finalize_stage_report


# ====== FIXED81: тест A считает Yтек. ср. как среднюю ошибку ОТНОСИТЕЛЬНО границы целевой зоны ======
# Для этапов X и X+Y:
#   текущая ошибка = max(0, текущее радиальное отклонение - радиус целевой зоны)
# Тогда в формуле из документа:
#   H = (Yтек. ср. - Yцели) / (Yаварии - Yцели)
# используем Yцели = 0, Yаварии = ширина промежутка от целевой до аварийной границы.
# Это убирает ложную ситуацию "3 ошибки из 3, но H = 0 только потому, что среднее расстояние
# от центра чуть меньше радиуса цели".

def _fixed81_stage_error_bounds(self, stage_no: int) -> tuple[float, float]:
    stage_no = int(stage_no)
    if stage_no == 3 and bool(self.stage_defs.get(stage_no, {}).get('z')):
        return 0.0, 1.0
    goal = 0.0
    crash = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    return goal, crash


def _fixed81_current_tracking_error(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[stage_no]
    px_per_cm = max(1e-6, float(getattr(self.cfg, 'px_per_cm', 38.0)))

    x_cm = abs(float(getattr(state, 'x_px', 0.0))) / px_per_cm if stage.get('x') else 0.0
    y_cm = abs(float(getattr(state, 'y_px', 0.0))) / px_per_cm if stage.get('y') else 0.0
    xy_now = (x_cm * x_cm + y_cm * y_cm) ** 0.5

    if not stage.get('z'):
        target = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
        return max(0.0, xy_now - target)

    xy_goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    xy_crash = max(xy_goal + 1e-6, xy_goal + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    roll_goal = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 10.0)))
    roll_crash = max(roll_goal + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0)))

    xy_norm = _fixed73e_clip((xy_now - xy_goal) / max(1e-6, xy_crash - xy_goal), 0.0, 1.0)
    roll_now = abs(float(getattr(state, 'roll_deg', 0.0)))
    roll_norm = _fixed73e_clip((roll_now - roll_goal) / max(1e-6, roll_crash - roll_goal), 0.0, 1.0)
    return ((xy_norm * xy_norm + roll_norm * roll_norm) / 2.0) ** 0.5


def _fixed81_method_a_finalize_stage_report(self, report: StageReport, elapsed_s: float, xy_integral: float, roll_integral: float, tracking_error_integral: float = 0.0, speed_integral: float = 0.0) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    report.avg_tracking_error = float(tracking_error_integral) / total
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed81_stage_error_bounds(self, int(report.stage_no))
    entropy_h = (float(report.avg_tracking_error) - float(goal)) / max(1e-6, float(crash) - float(goal))
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)

    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.entropy_formula_note = (
        'Для этапов X и X+Y Yтек. ср. считается как средняя ошибка за пределами целевой зоны; '
        'поэтому цель = 0, авария = ширина промежутка от целевой до аварийной границы.'
    )
    return report


def _fixed81_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    stage_no = int(report.get('stage_no', 0) or 0)
    if stage_no == 3:
        v_label = 'Vср'
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} усл. ед./с"
        e_value = f"{float(report.get('avg_tracking_error', 0.0) or 0.0):.4f} норм. ед."
        bounds_value = 'цель = 0.0000, авария = 1.0000'
        error_label = 'Yтек. ср.'
    else:
        v_label = 'Vср'
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} см/с"
        e_value = f"{float(report.get('avg_tracking_error', 0.0) or 0.0):.4f} см"
        bounds_value = (
            f"цель = {float(report.get('tracking_error_target', 0.0) or 0.0):.2f} см, "
            f"авария = {float(report.get('tracking_error_crash', 0.0) or 0.0):.2f} см "
            f"(от границы цели)"
        )
        error_label = 'Yтек. ср.'

    rows = [
        ('Режим', _fixed73e_stage_name(stage_no)),
        ('Контролируемые оси', str(report.get('active_axes', ''))),
        ('Длительность', f"{float(report.get('real_time_s', 0.0) or 0.0):.1f} с"),
        ('Ошибки', f"{int(report.get('crashes', 0) or 0)} из 3"),
        (v_label, v_value),
        ('γ', f"{float(report.get('success_gamma', 0.0) or 0.0):.4f}"),
        ('Энтропия H', f"{float(report.get('entropy_h', 0.0) or 0.0):.4f}"),
        (error_label, e_value),
        ('tр = Vср × γ', f"{float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}"),
        ('Границы расчёта ошибки', bounds_value),
    ]
    if stage_no == 3:
        rows.append(('Средний крен', f"{float(report.get('mean_abs_roll_deg', 0.0) or 0.0):.2f}°"))
    else:
        rows.append(('Среднее отклонение X/Y', f"{float(report.get('mean_abs_xy_cm', 0.0) or 0.0):.2f} см"))
    return rows


_fixed73e_stage_error_bounds = _fixed81_stage_error_bounds
_fixed73e_current_tracking_error = _fixed81_current_tracking_error
_fixed73e_finalize_stage_report = _fixed81_method_a_finalize_stage_report
MethodAApp.finalize_stage_report = _fixed81_method_a_finalize_stage_report
globals()['_fixed73e_method_a_stage_metric_rows'] = _fixed81_method_a_stage_metric_rows


# ====== FIXED82 stronger crash-sensitive entropy for Method A ======

def _fixed82_method_a_crash_penalty_ratio(self, stage_no: int) -> float:
    """
    Насколько сильно каждый срыв должен поднимать Yтек. ср. на шкале goal..crash.
    0.5 означает: при 3 срывах добавляется половина всего диапазона ошибки.
    """
    return 0.5


def _fixed82_method_a_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    raw_avg_error = float(tracking_error_integral) / total
    report.avg_tracking_error_raw = raw_avg_error
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed81_stage_error_bounds(self, int(report.stage_no))
    span = max(1e-6, float(crash) - float(goal))

    raw_entropy_h = (float(raw_avg_error) - float(goal)) / span
    raw_entropy_h = _fixed73e_clip(raw_entropy_h, 0.0, 1.0)

    crash_ratio = max(0.0, min(1.0, float(getattr(report, 'crashes', 0) or 0) / max(1, int(getattr(self.cfg, 'stage_crash_limit', 3) or 3))))
    penalty_ratio = max(0.0, float(_fixed82_method_a_crash_penalty_ratio(self, int(report.stage_no))))
    crash_penalty_error = span * penalty_ratio * crash_ratio

    effective_error = float(raw_avg_error) + float(crash_penalty_error)
    effective_error = _fixed73e_clip(effective_error, float(goal), float(crash))

    entropy_h = (float(effective_error) - float(goal)) / span
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)

    report.crash_penalty_ratio = float(penalty_ratio)
    report.crash_penalty_error = float(crash_penalty_error)
    report.avg_tracking_error = float(effective_error)
    report.avg_tracking_error_effective = float(effective_error)
    report.entropy_h_raw = float(raw_entropy_h)
    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.entropy_formula_note = (
        'Yтек. ср. для расчёта H усиливается штрафом за срывы: '
        'используется эффективная ошибка = сырая ошибка + штраф за число срывов.'
    )
    return report


def _fixed82_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    stage_no = int(report.get('stage_no', 0) or 0)
    raw_error = float(report.get('avg_tracking_error_raw', report.get('avg_tracking_error', 0.0)) or 0.0)
