def _fixed83_method_a_summary_from_reports(reports: list[dict]) -> dict:
    reports = [r for r in (reports or []) if isinstance(r, dict)]
    base = _FIXED83_PREV_METHOD_A_SUMMARY_FROM_REPORTS(reports) if '_FIXED83_PREV_METHOD_A_SUMMARY_FROM_REPORTS' in globals() else {}
    # base может рекурсивно сослаться на нас, поэтому считаем вручную от безопасного минимума
    total_time_s = round(sum(float(r.get('real_time_s', 0.0) or 0.0) for r in reports), 2)
    total_crashes = int(sum(int(r.get('crashes', 0) or 0) for r in reports))
    avg_stability_pct = round(sum(float(r.get('stability_pct', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 1) if reports else 0.0
    avg_mean_xy_cm = round(sum(float(r.get('mean_abs_xy_cm', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 2) if reports else 0.0
    avg_v_avg = round(sum(float(r.get('v_avg', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_entropy_h = round(sum(float(r.get('entropy_h', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_entropy_h_raw = round(sum(float(r.get('entropy_h_raw', r.get('entropy_h', 0.0)) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_crash_penalty_h = round(sum(float(r.get('crash_penalty_h', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_success_gamma = round(sum(float(r.get('success_gamma', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_tracking_error = round(sum(float(r.get('avg_tracking_error', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_tracking_error_raw = round(sum(float(r.get('avg_tracking_error_raw', r.get('avg_tracking_error', 0.0)) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_reduced_tempo_tr = round(sum(float(r.get('reduced_tempo_tr', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0

    by_stage = {int(r.get('stage_no', 0) or 0): r for r in reports}
    t_values = {
        'min': round(float(by_stage.get(1, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'medio': round(float(by_stage.get(2, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'max': round(float(by_stage.get(3, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
    }

    best_stage = None
    if reports:
        best = max(
            reports,
            key=lambda r: (
                float(r.get('reduced_tempo_tr', 0.0) or 0.0),
                float(r.get('success_gamma', 0.0) or 0.0),
                -int(r.get('crashes', 0) or 0),
                -float(r.get('avg_tracking_error', 0.0) or 0.0),
            ),
        )
        try:
            best_stage = int(best.get('stage_no', 0) or 0)
        except Exception:
            best_stage = None

    return {
        'total_time_s': total_time_s,
        'total_crashes': total_crashes,
        'avg_stability_pct': avg_stability_pct,
        'avg_mean_xy_cm': avg_mean_xy_cm,
        'avg_v_avg': avg_v_avg,
        'avg_entropy_h': avg_entropy_h,
        'avg_entropy_h_raw': avg_entropy_h_raw,
        'avg_crash_penalty_h': avg_crash_penalty_h,
        'avg_success_gamma': avg_success_gamma,
        'avg_tracking_error': avg_tracking_error,
        'avg_tracking_error_raw': avg_tracking_error_raw,
        'avg_reduced_tempo_tr': avg_reduced_tempo_tr,
        'best_stage': best_stage,
        't_values': t_values,
        'tmin_a': t_values['min'],
        'tmedio_a': t_values['medio'],
        'tmax_a': t_values['max'],
    }


_FIXED83_PREV_SHOW_METHOD_A_RESULTS = StartPageApp.show_method_a_results

def _fixed83_show_method_a_results(self, payload: dict):
    top = _FIXED83_PREV_SHOW_METHOD_A_RESULTS(self, payload)
    # Ничего не ломаем в вёрстке, просто добавляем в общий блок пояснение новой логики,
    # если удастся найти открытую страницу результатов.
    try:
        # top у старой функции может быть None, поэтому аккуратно ищем контейнер окна.
        if top is None:
            return top
        for child in top.winfo_children():
            pass
    except Exception:
        return top
    return top


