# ====== FIXED84: final, explicit Method A calculation version with hard crash penalty ======
# Цель этого слоя:
# 1) гарантированно перехватить боевой расчёт самым последним патчем;
# 2) сделать срывы прямым и сильным фактором энтропии;
# 3) записывать версию расчёта в JSON, чтобы по результату было видно, какой именно код работал.

_FIXED84_METHOD_A_CALC_VERSION = 'fixed84_hard_crash_penalty_v1'


def _fixed84_method_a_crash_penalty_h(self, stage_no: int, crashes: int) -> float:
    crash_limit = max(1, int(getattr(self.cfg, 'stage_crash_limit', 3) or 3))
    crash_ratio = max(0.0, min(1.0, float(crashes or 0) / crash_limit))
    if int(stage_no) in (1, 2):
        weight = 0.70
    else:
        weight = 0.55
    return float(weight) * crash_ratio


def _fixed84_method_a_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    raw_avg_error = float(tracking_error_integral) / total
    report.avg_tracking_error_raw = raw_avg_error
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed81_stage_error_bounds(self, int(report.stage_no))
    span = max(1e-6, float(crash) - float(goal))

    raw_entropy_h = (float(raw_avg_error) - float(goal)) / span
    raw_entropy_h = _fixed73e_clip(raw_entropy_h, 0.0, 1.0)

    crash_penalty_h = _fixed84_method_a_crash_penalty_h(self, int(report.stage_no), int(getattr(report, 'crashes', 0) or 0))
    total_entropy_h = _fixed73e_clip(float(raw_entropy_h) + float(crash_penalty_h), 0.0, 1.0)

    # Жёсткая страховка: если этап закончился по лимиту срывов, итоговая H не может быть "почти нулевой".
    crash_limit = max(1, int(getattr(self.cfg, 'stage_crash_limit', 3) or 3))
    if int(getattr(report, 'crashes', 0) or 0) >= crash_limit:
        floor_h = 0.55 if int(report.stage_no) in (1, 2) else 0.45
        total_entropy_h = max(float(total_entropy_h), float(floor_h))

    crash_penalty_h = max(0.0, float(total_entropy_h) - float(raw_entropy_h))
    crash_penalty_error = float(crash_penalty_h) * span
    effective_error = float(goal) + float(total_entropy_h) * span

    report.crash_penalty_h = float(crash_penalty_h)
    report.crash_penalty_error = float(crash_penalty_error)
    report.avg_tracking_error = float(effective_error)
    report.avg_tracking_error_effective = float(effective_error)
    report.entropy_h_raw = float(raw_entropy_h)
    report.entropy_h = float(total_entropy_h)
    report.entropy_h_doc = float(total_entropy_h)
    report.success_gamma = _fixed73e_clip(1.0 - float(total_entropy_h), 0.0, 1.0)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.calculation_version = _FIXED84_METHOD_A_CALC_VERSION
    report.entropy_formula_note = (
        'FIXED84: Hитог = clip(Hсыр + Hштраф, 0..1). '
        'При полном наборе срывов действует нижний порог H, чтобы аварийное прохождение '
        'не выглядело как почти успешное.'
    )
    return report


def _fixed84_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    stage_no = int(report.get('stage_no', 0) or 0)
    raw_error = float(report.get('avg_tracking_error_raw', report.get('avg_tracking_error', 0.0)) or 0.0)
    effective_error = float(report.get('avg_tracking_error', 0.0) or 0.0)
    crash_penalty = float(report.get('crash_penalty_error', 0.0) or 0.0)
    entropy_raw = float(report.get('entropy_h_raw', report.get('entropy_h', 0.0)) or 0.0)
    crash_penalty_h = float(report.get('crash_penalty_h', 0.0) or 0.0)
    calc_version = str(report.get('calculation_version', _FIXED84_METHOD_A_CALC_VERSION))

    if stage_no == 3:
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} усл. ед./с"
        e_value = f"{effective_error:.4f} норм. ед."
        raw_e_value = f"{raw_error:.4f} норм. ед."
        penalty_value = f"{crash_penalty:.4f} норм. ед."
        bounds_value = 'цель = 0.0000, авария = 1.0000'
    else:
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} см/с"
        e_value = f"{effective_error:.4f} см"
        raw_e_value = f"{raw_error:.4f} см"
        penalty_value = f"{crash_penalty:.4f} см"
        bounds_value = (
            f"цель = {float(report.get('tracking_error_target', 0.0) or 0.0):.2f} см, "
            f"авария = {float(report.get('tracking_error_crash', 0.0) or 0.0):.2f} см "
            f"(от границы цели)"
        )

    rows = [
        ('Режим', _fixed73e_stage_name(stage_no)),
        ('Контролируемые оси', str(report.get('active_axes', ''))),
        ('Длительность', f"{float(report.get('real_time_s', 0.0) or 0.0):.1f} с"),
        ('Ошибки', f"{int(report.get('crashes', 0) or 0)} из 3"),
        ('Vср', v_value),
        ('γ', f"{float(report.get('success_gamma', 0.0) or 0.0):.4f}"),
        ('Энтропия H', f"{float(report.get('entropy_h', 0.0) or 0.0):.4f}"),
        ('Энтропия H без штрафа', f"{entropy_raw:.4f}"),
        ('Добавка H за срывы', f"{crash_penalty_h:.4f}"),
        ('Yтек. ср.', e_value),
        ('Сырая ошибка', raw_e_value),
        ('Штраф за срывы', penalty_value),
        ('tр = Vср × γ', f"{float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}"),
        ('Границы расчёта ошибки', bounds_value),
        ('Версия расчёта', calc_version),
    ]
    if stage_no == 3:
        rows.append(('Средний крен', f"{float(report.get('mean_abs_roll_deg', 0.0) or 0.0):.2f}°"))
    else:
        rows.append(('Среднее отклонение X/Y', f"{float(report.get('mean_abs_xy_cm', 0.0) or 0.0):.2f} см"))
    return rows


def _fixed84_method_a_summary_from_reports(reports: list[dict]) -> dict:
    reports = [r for r in (reports or []) if isinstance(r, dict)]
    total_time_s = round(sum(float(r.get('real_time_s', 0.0) or 0.0) for r in reports), 2)
    total_crashes = int(sum(int(r.get('crashes', 0) or 0) for r in reports))
    avg_stability_pct = round(sum(float(r.get('stability_pct', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 1) if reports else 0.0
    avg_mean_xy_cm = round(sum(float(r.get('mean_abs_xy_cm', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 2) if reports else 0.0
    avg_v_avg = round(sum(float(r.get('v_avg', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_entropy_h = round(sum(float(r.get('entropy_h', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_entropy_h_raw = round(sum(float(r.get('entropy_h_raw', r.get('entropy_h', 0.0)) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_crash_penalty_h = round(sum(float(r.get('crash_penalty_h', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_success_gamma = round(sum(float(r.get('success_gamma', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_tracking_error = round(sum(float(r.get('avg_tracking_error', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_tracking_error_raw = round(sum(float(r.get('avg_tracking_error_raw', r.get('avg_tracking_error', 0.0)) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    avg_reduced_tempo_tr = round(sum(float(r.get('reduced_tempo_tr', 0.0) or 0.0) for r in reports) / max(1, len(reports)), 4) if reports else 0.0
    by_stage = {int(r.get('stage_no', 0) or 0): r for r in reports}
    t_values = {
        'min': round(float(by_stage.get(1, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'medio': round(float(by_stage.get(2, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
        'max': round(float(by_stage.get(3, {}).get('reduced_tempo_tr', 0.0) or 0.0), 4),
    }
    best_stage = None
    if reports:
        best = max(
            reports,
            key=lambda r: (
                float(r.get('reduced_tempo_tr', 0.0) or 0.0),
                float(r.get('success_gamma', 0.0) or 0.0),
                -int(r.get('crashes', 0) or 0),
                -float(r.get('avg_tracking_error', 0.0) or 0.0),
            ),
        )
        try:
            best_stage = int(best.get('stage_no', 0) or 0)
        except Exception:
            best_stage = None
    return {
        'calculation_version': _FIXED84_METHOD_A_CALC_VERSION,
        'total_time_s': total_time_s,
        'total_crashes': total_crashes,
        'avg_stability_pct': avg_stability_pct,
        'avg_mean_xy_cm': avg_mean_xy_cm,
        'avg_v_avg': avg_v_avg,
        'avg_entropy_h': avg_entropy_h,
        'avg_entropy_h_raw': avg_entropy_h_raw,
        'avg_crash_penalty_h': avg_crash_penalty_h,
        'avg_success_gamma': avg_success_gamma,
        'avg_tracking_error': avg_tracking_error,
        'avg_tracking_error_raw': avg_tracking_error_raw,
        'avg_reduced_tempo_tr': avg_reduced_tempo_tr,
        'best_stage': best_stage,
        't_values': t_values,
        'tmin_a': t_values['min'],
        'tmedio_a': t_values['medio'],
        'tmax_a': t_values['max'],
    }


def _fixed84_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    reports = [r for r in (result.get('reports', []) or []) if isinstance(r, dict)]
    for item in reports:
        item.setdefault('calculation_version', _FIXED84_METHOD_A_CALC_VERSION)
    summary = _fixed84_method_a_summary_from_reports(reports)
    return {
        'test_code': 'A',
        'test_label': TEST_LABELS['A'],
        'completed_at': datetime.now().isoformat(timespec='seconds'),
        'session_id': session.session_id,
        'participant': {
            'name': session.name,
            'age': session.age,
            'gender': session.gender,
        },
        'result_path': result.get('result_path', ''),
        'reports': reports,
        'summary': summary,
        'completed': bool(result.get('completed', False)),
    }


def _fixed84_show_method_a_results(self, payload: dict):
    top = _fixed73e_show_method_a_results(self, payload)
    try:
        # Добавим скромную, но заметную подпись версии расчёта в заголовок окна результатов.
        calc_version = str((payload.get('summary', {}) or {}).get('calculation_version') or _FIXED84_METHOD_A_CALC_VERSION)
        content_root = None
        for child in top.winfo_children():
            # shell -> content frame -> canvas etc. Просто ищем первый Frame и вставляем подпись в начало.
            if hasattr(child, 'winfo_children'):
                content_root = child
                break
        if content_root is not None:
            banner = tk.Label(
                top,
                text=f'Версия расчёта теста A: {calc_version}',
                bg='#eef3f8',
                fg='#5a6678',
                font=('Arial', 10, 'bold'),
                anchor='w',
            )
            # безопасно ставим в самый низ окна, чтобы не ломать существующую вёрстку
            banner.pack(side='bottom', fill='x', padx=24, pady=(0, 10))
    except Exception:
        pass
    return top


_fixed73e_finalize_stage_report = _fixed84_method_a_finalize_stage_report
_fixed73e_method_a_summary_from_reports = _fixed84_method_a_summary_from_reports
globals()['_fixed73e_method_a_stage_metric_rows'] = _fixed84_method_a_stage_metric_rows
MethodAApp.finalize_stage_report = _fixed84_method_a_finalize_stage_report
