# ====== FIXED85: Method A strictly by document image + stepwise speed profile ======
# Что делаем в этом слое:
# 1) считаем H и γ строго по формуле с картинки, без штрафных добавок;
# 2) текущая скорость меняется ступенчато во времени, как на схеме, и после аварии
#    возвращается к стартовой, а затем снова нарастает;
# 3) экран результатов снова показывает только документные показатели.

_FIXED85_METHOD_A_CALC_VERSION = 'fixed85_doc_formula_step_speed_v1'

_FIXED85_PREV_INIT_STAGE_STATE = MethodAApp.init_stage_state


def _fixed85_init_stage_state(self):
    state = _FIXED85_PREV_INIT_STAGE_STATE(self)
    state._fixed85_speedup_origin_s = 0.0
    state._fixed85_last_step_index = 0
    state._fixed85_pending_speed_reset = False
    return state


def _fixed227_speedup_interval_s(cfg: object) -> float:
    """Speed-up interval is user-configurable from settings (method_a_config.json)."""
    try:
        return max(0.1, float(getattr(cfg, 'speedup_interval_s', 5.0) or 5.0))
    except Exception:
        return 5.0


def _fixed85_maybe_speedup(self, state: DriftState, stage_no: int, absolute_time_s: float):
    interval = _fixed227_speedup_interval_s(getattr(self, 'cfg', None))

    if not hasattr(state, '_fixed85_speedup_origin_s'):
        state._fixed85_speedup_origin_s = 0.0
        state._fixed85_last_step_index = 0
        state._fixed85_pending_speed_reset = False

    if getattr(state, '_fixed85_pending_speed_reset', False):
        state._fixed85_speedup_origin_s = float(absolute_time_s)
        state._fixed85_last_step_index = 0
        state._fixed85_pending_speed_reset = False

    elapsed_from_origin = max(0.0, float(absolute_time_s) - float(getattr(state, '_fixed85_speedup_origin_s', 0.0) or 0.0))
    step_index = max(0, int(elapsed_from_origin // interval))
    state._fixed85_last_step_index = step_index

    state.speed_xy_cm_s = float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0) + step_index * float(getattr(self.cfg, 'step_speed_xy_cm_s', 0.5) or 0.5)
    state.speed_z_deg_s = float(getattr(self.cfg, 'start_speed_z_deg_s', 6.0) or 6.0) + step_index * float(getattr(self.cfg, 'step_speed_z_deg_s', 1.0) or 1.0)



def _fixed85_reset_after_crash(self, state: DriftState):
    state.x_px = 0.0
    state.y_px = 0.0
    state.roll_deg = 0.0
    state.outside_target_since_s = None
    state.was_outside_target = False
    state.speed_xy_cm_s = float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0)
    state.speed_z_deg_s = float(getattr(self.cfg, 'start_speed_z_deg_s', 6.0) or 6.0)
    state._fixed85_pending_speed_reset = True
    state._fixed85_last_step_index = 0



def _fixed85_method_a_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    avg_error = float(tracking_error_integral) / total
    report.avg_tracking_error_raw = float(avg_error)
    report.avg_tracking_error = float(avg_error)
    report.avg_tracking_error_effective = float(avg_error)
    report.v_avg = float(speed_integral) / total

    goal, crash = _fixed73e_stage_error_bounds(self, int(report.stage_no))
    denom = max(-1e-6, float(goal) - float(crash))
    if abs(denom) < 1e-6:
        denom = -1e-6

    entropy_h = (float(goal) - float(avg_error)) / denom
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)
    success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)

    report.entropy_h_raw = float(entropy_h)
    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.crash_penalty_h = 0.0
    report.crash_penalty_error = 0.0
    report.success_gamma = float(success_gamma)
    report.reduced_tempo_tr = float(report.v_avg) * float(report.success_gamma)
    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(report.stage_no)
    report.calculation_version = _FIXED85_METHOD_A_CALC_VERSION
    report.entropy_formula_note = (
        'FIXED85: H = (Yцели - Yтек.ср.) / (Yцели - Yаварии), '
        'γ = 1 - H, tр = Vср × γ. Скорость растёт ступенчато во времени '
        'и после аварии сбрасывается к стартовой.'
    )
    return report



def _fixed85_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed73e_build_method_a_payload(self, session, result)
    try:
        payload.setdefault('summary', {})['calculation_version'] = _FIXED85_METHOD_A_CALC_VERSION
        for item in payload.get('reports', []) or []:
            if isinstance(item, dict):
                item.setdefault('calculation_version', _FIXED85_METHOD_A_CALC_VERSION)
    except Exception:
        pass
    return payload


MethodAApp.init_stage_state = _fixed85_init_stage_state
MethodAApp.maybe_speedup = _fixed85_maybe_speedup
MethodAApp.reset_after_crash = _fixed85_reset_after_crash
_fixed73e_finalize_stage_report = _fixed85_method_a_finalize_stage_report
MethodAApp.finalize_stage_report = _fixed85_method_a_finalize_stage_report
StartPageApp.build_method_a_payload = _fixed85_build_method_a_payload
StartPageApp.show_method_a_results = _fixed73e_show_method_a_results


# ====== FIXED86: тест A без обнуления ошибки после срыва ======
_FIXED86_METHOD_A_CALC_VERSION = 'fixed87_doc_formula_configurable_penalty_autofit_v1'


def _fixed86_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    stage_error = 0.0
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0
    stage_max_error = float(self.stage_smax(stage_no))
    crash_penalty_ratio = max(0.0, float(getattr(self.cfg, 'crash_penalty_ratio', 0.05) or 0.0))
    crash_penalty = stage_max_error * crash_penalty_ratio

    # Дополнительные поля для наглядности в сохранённом результате.
    report.crash_penalty_ratio = float(crash_penalty_ratio)
    report.crash_penalty_each = float(crash_penalty)
    report.crash_penalty_total = 0.0
    report.error_limit_value = float(stage_max_error)

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        stage_error += self.current_error_increment(state, stage_no, dt)
        report.sum_error = stage_error
        self.maybe_register_return(state, stage_no, report)

        inside_now = self.inside_target(state, stage_no)
        if inside_now:
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        tracking_error_integral += _fixed73e_current_tracking_error(self, state, stage_no) * dt
        speed_integral += _fixed73e_current_speed_value(self, state, stage_no) * dt

        # Достигли предела по накопленной ошибке: этап завершается без обнуления.
        if stage_error >= stage_max_error:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        # Срыв по аварийной зоне: считаем, штрафуем, но этап продолжается.
        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            stage_error += crash_penalty
            report.crash_penalty_total = float(report.crashes) * float(crash_penalty)
            report.sum_error = stage_error
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(state.x_px, 3),
                y=round(stage_error, 3),
                angle=round(state.roll_deg, 3),
                value=report.crashes,
                note=(
                    f"axes={report.active_axes}; penalty={crash_penalty:.3f}; "
                    f"penalty_ratio={crash_penalty_ratio:.3f}; max_error={stage_max_error:.3f}"
                ),
            )
            self.show_message('ОШИБКА', seconds=0.8)
            self.reset_after_crash(state)

            if stage_error >= stage_max_error:
                report.sum_error = stage_error
                return self.finalize_stage_report(
                    report,
                    elapsed_s,
                    xy_integral,
                    roll_integral,
                    tracking_error_integral,
                    speed_integral,
                )

        if elapsed_s >= self.cfg.stage_time_limit_s:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        self.draw_background()
        self.draw_zones()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, stage_error, report, state)
        pygame.display.flip()


_def_fixed85_finalize = MethodAApp.finalize_stage_report


def _fixed86_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    report = _def_fixed85_finalize(
        self,
        report,
        elapsed_s,
        xy_integral,
        roll_integral,
        tracking_error_integral,
        speed_integral,
    )
    try:
        stage_max_error = float(self.stage_smax(int(report.stage_no)))
    except Exception:
        stage_max_error = 0.0
    crash_penalty = stage_max_error * 0.05
    report.crash_penalty_each = float(crash_penalty)
    report.crash_penalty_total = float(getattr(report, 'crashes', 0) or 0) * float(crash_penalty)
    report.error_limit_value = float(stage_max_error)
    report.calculation_version = _FIXED86_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED86: после срыва накопленная ошибка не обнуляется; этап продолжается до лимита времени '
        'или до достижения максимального значения ошибки; каждый срыв добавляет штраф 5% от максимальной ошибки этапа.'
    )
    return report


def _fixed86_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = StartPageApp.build_method_a_payload.__wrapped__(self, session, result) if hasattr(StartPageApp.build_method_a_payload, '__wrapped__') else _fixed85_build_method_a_payload(self, session, result)
    try:
        payload.setdefault('summary', {})['calculation_version'] = _FIXED86_METHOD_A_CALC_VERSION
        payload.setdefault('summary', {})['runtime_rule'] = 'no_error_reset_after_crash_plus_5pct_penalty'
        for item in payload.get('reports', []) or []:
            if isinstance(item, dict):
                item['calculation_version'] = _FIXED86_METHOD_A_CALC_VERSION
                item.setdefault('runtime_rule', 'no_error_reset_after_crash_plus_5pct_penalty')
    except Exception:
        pass
    return payload


MethodAApp.run_stage = _fixed86_run_stage
MethodAApp.finalize_stage_report = _fixed86_finalize_stage_report
StartPageApp.build_method_a_payload = _fixed86_build_method_a_payload


# ====== FIXED88: all tests auto-fit to current screen, and launch moved to file end ======

def _fixed88_screen_metrics(widget_or_parent):
    try:
        sw = int(widget_or_parent.winfo_screenwidth())
        sh = int(widget_or_parent.winfo_screenheight())
    except Exception:
        sw, sh = 1920, 1080
    scale = min(sw / 1920.0, sh / 1080.0)
    scale = max(0.70, min(scale, 1.45))
    return sw, sh, scale


