def _fixed88_method_d_render_logic_cell(self, canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, spec: dict | None):
    canvas.create_rectangle(x1, y1, x2, y2, outline='#d5deea', width=2, fill='#fbfdff')
    cell_w = max(1, x2 - x1)
    cell_h = max(1, y2 - y1)
    pad = max(8, int(min(cell_w, cell_h) * 0.11))
    if spec:
        draw_basic_symbol(
            canvas,
            x1 + pad,
            y1 + pad,
            x2 - pad,
            y2 - pad,
            spec['shape'],
            outline='#1b2b40',
            fill='#1b2b40',
            rotation=spec['rotation'],
            fill_mode=spec['fill'],
            count=spec['count']
        )
    else:
        q_font = ('Arial', max(24, int(min(cell_w, cell_h) * 0.42)), 'bold')
        canvas.create_text((x1 + x2) / 2, (y1 + y2) / 2, text='?', fill='#6d7f98', font=q_font)


def _fixed88_method_d_draw_task(self):
    task = self.current_task
    self.matrix_canvas.delete('all')
    w = max(420, int(self.matrix_canvas.winfo_width() or int(self.matrix_canvas.cget('width'))))
    h = max(260, int(self.matrix_canvas.winfo_height() or int(self.matrix_canvas.cget('height'))))
    margin_x = max(20, int(w * 0.05))
    margin_y = max(18, int(h * 0.07))
    gap = max(8, int(min(w, h) * 0.025))
    arrow_zone = max(70, int(w * 0.16))
    cell = int(min((w - 2 * margin_x - 2 * gap - arrow_zone) / 3, (h - 2 * margin_y - 2 * gap) / 3))
    cell = max(70, cell)
    grid_w = 3 * cell + 2 * gap
    x0 = max(12, int((w - arrow_zone - grid_w) / 2))
    y0 = max(12, int((h - (3 * cell + 2 * gap)) / 2))

    for idx, spec in enumerate(task['matrix']):
        r, c = divmod(idx, 3)
        x1 = x0 + c * (cell + gap)
        y1 = y0 + r * (cell + gap)
        self._render_logic_cell(self.matrix_canvas, x1, y1, x1 + cell, y1 + cell, spec)

    arrow_x = x0 + grid_w + arrow_zone * 0.45
    arrow_y = h / 2
    self.matrix_canvas.create_text(arrow_x, arrow_y, text='→', fill='#7385a2', font=('Arial', max(26, int(cell * 0.38)), 'bold'))

    for i, cv in enumerate(self.option_canvases):
        cv.delete('all')
        cv.configure(highlightbackground='#afbdd1', highlightthickness=max(2, int(cell * 0.02)))
        ow = max(120, int(cv.winfo_width() or int(cv.cget('width'))))
        oh = max(96, int(cv.winfo_height() or int(cv.cget('height'))))
        cv.create_text(max(12, int(ow * 0.11)), max(12, int(oh * 0.12)), text=str(i + 1), fill='#7c8ea8', font=('Arial', max(9, int(min(ow, oh) * 0.10)), 'bold'))
        pad_x = max(12, int(ow * 0.12))
        pad_y = max(12, int(oh * 0.13))
        self._render_logic_cell(cv, pad_x, pad_y, ow - pad_x, oh - pad_y, task['options'][i])

    diff_name = {'min': 'минимальная', 'medio': 'средняя', 'max': 'максимальная'}[task['difficulty']]
    self.prompt_var.set(f'Выберите фрагмент, который завершает матрицу. Трудоёмкость: {diff_name}.')
    self.feedback_var.set('После ответа можно спокойно перейти к следующему заданию.')
    self.phase = 'task'
    if self.next_btn:
        self.next_btn.configure(state=tk.DISABLED, text='Следующее задание')


