# ====== FIXED90: B/C labels, C operand in input field, exit buttons bottom-right ======

def _fixed90_method_a_draw_exit_button(self):
    try:
        btn_w = max(120, int(self.cfg.width * 0.10))
        btn_h = max(36, int(self.cfg.height * 0.05))
        x = self.cfg.width - btn_w - 22
        y = self.cfg.height - btn_h - 18
        rect = pygame.Rect(x, y, btn_w, btn_h)
        self._exit_button_rect = rect
        pygame.draw.rect(self.screen, (217, 90, 90), rect, border_radius=10)
        pygame.draw.rect(self.screen, (150, 52, 52), rect, 2, border_radius=10)
        txt = self.font.render("ВЫХОД", True, (255, 255, 255))
        txt_rect = txt.get_rect(center=rect.center)
        self.screen.blit(txt, txt_rect)
    except Exception:
        self._exit_button_rect = None

_prev_draw_hud_fixed90 = MethodAApp.draw_hud
def _fixed90_method_a_draw_hud(self, stage_no: int, elapsed_s: float, stage_error: float, report: StageReport, state: DriftState):
    _prev_draw_hud_fixed90(self, stage_no, elapsed_s, stage_error, report, state)
    _fixed90_method_a_draw_exit_button(self)

_prev_read_runtime_events_fixed90 = MethodAApp.read_runtime_events
def _fixed90_method_a_read_runtime_events(self) -> int:
    wheel_delta = 0
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            raise MethodAAbort
        if event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
            raise MethodAAbort
        if event.type == pygame.MOUSEWHEEL:
            wheel_delta += event.y
        elif event.type == pygame.MOUSEBUTTONDOWN:
            if event.button == 1:
                rect = getattr(self, '_exit_button_rect', None)
                if rect is not None:
                    pos = getattr(event, 'pos', None)
                    if pos and rect.collidepoint(pos):
                        raise MethodAAbort
            if event.button == 4:
                wheel_delta += 1
            elif event.button == 5:
                wheel_delta -= 1
    return wheel_delta


