# ====== FIXED91: Method A no exit button, no red warning lines, no crash popup reset ======

def _fixed91_method_a_draw_zones(self):
    # Static background already contains the normal concentric circles.
    # Do not repaint alert rings on top of it.
    return


def _fixed91_method_a_draw_roll_limit_guides(self, state: DriftState, stage_no: int):
    if not self.stage_defs.get(stage_no, {}).get('z'):
        return
    if '_fixed60_draw_diagonal_family' in globals():
        _fixed60_draw_diagonal_family(self, self.cfg.grid_color, alpha=95)
    else:
        # Fallback: keep previous calm-state appearance without red alert.
        try:
            cx = int(self.center.x)
            cy = int(self.center.y)
            radius = int(self.target_half_px)
            color = self.cfg.grid_color
            line_len = max(44, int(radius * 0.95))
            side_shift = max(34, int(radius * 0.62))
            top_shift = max(78, int(radius * 1.45))
            guide_center_y = cy - top_shift
            half = line_len / 2.0
            ang = math.radians(max(8.0, float(self.cfg.target_roll_deg)))
            left_center = (cx - side_shift, guide_center_y)
            right_center = (cx + side_shift, guide_center_y)
            left_dx = math.cos(ang) * half
            left_dy = math.sin(ang) * half
            right_dx = math.cos(-ang) * half
            right_dy = math.sin(-ang) * half
            p1 = (int(left_center[0] - left_dx), int(left_center[1] - left_dy))
            p2 = (int(left_center[0] + left_dx), int(left_center[1] + left_dy))
            p3 = (int(right_center[0] - right_dx), int(right_center[1] - right_dy))
            p4 = (int(right_center[0] + right_dx), int(right_center[1] + right_dy))
            pygame.draw.line(self.screen, color, p1, p2, 6)
            pygame.draw.line(self.screen, color, p3, p4, 6)
        except Exception:
            return


def _fixed91_method_a_draw_hud(self, stage_no: int, elapsed_s: float, stage_error: float, report: StageReport, state: DriftState):
    self._exit_button_rect = None
    if '_fixed62_method_a_draw_hud' in globals():
        _fixed62_method_a_draw_hud(self, stage_no, elapsed_s, stage_error, report, state)
    else:
        time_ratio = elapsed_s / self.cfg.stage_time_limit_s
        err_ratio = stage_error / self.stage_smax(stage_no)
        self.draw_bar(16, 60, 64, 280, time_ratio, 'ВРЕМЯ', (60, 130, 255))
        self.draw_bar(self.cfg.width - 80, 60, 64, 280, err_ratio, 'ОШИБКА', (255, 118, 50))


def _fixed91_method_a_read_runtime_events(self) -> int:
    wheel_delta = 0
    for event in pygame.event.get():
        if event.type == pygame.QUIT:
            raise MethodAAbort
        if event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
            raise MethodAAbort
        if event.type == pygame.MOUSEWHEEL:
            wheel_delta += event.y
        elif event.type == pygame.MOUSEBUTTONDOWN:
            if event.button == 4:
                wheel_delta += 1
            elif event.button == 5:
                wheel_delta -= 1
    return wheel_delta


def _fixed91_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    stage_error = 0.0
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0
    stage_max_error = float(self.stage_smax(stage_no))
    crash_penalty_ratio = max(0.0, float(getattr(self.cfg, 'crash_penalty_ratio', 0.05) or 0.0))
    crash_penalty = stage_max_error * crash_penalty_ratio

    report.crash_penalty_ratio = float(crash_penalty_ratio)
    report.crash_penalty_each = float(crash_penalty)
    report.crash_penalty_total = 0.0
    report.error_limit_value = float(stage_max_error)

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        stage_error += self.current_error_increment(state, stage_no, dt)
        report.sum_error = stage_error
        self.maybe_register_return(state, stage_no, report)

        inside_now = self.inside_target(state, stage_no)
        if inside_now:
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        tracking_error_integral += _fixed73e_current_tracking_error(self, state, stage_no) * dt
        speed_integral += _fixed73e_current_speed_value(self, state, stage_no) * dt

        if stage_error >= stage_max_error:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            stage_error += crash_penalty
            report.crash_penalty_total = float(report.crashes) * float(crash_penalty)
            report.sum_error = stage_error
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(state.x_px, 3),
                y=round(stage_error, 3),
                angle=round(state.roll_deg, 3),
                value=report.crashes,
                note=(
                    f"axes={report.active_axes}; penalty={crash_penalty:.3f}; "
                    f"penalty_ratio={crash_penalty_ratio:.3f}; max_error={stage_max_error:.3f}"
                ),
            )
            # Keep accumulated error visible on screen: no separate crash popup.
            self.reset_after_crash(state)

            if stage_error >= stage_max_error:
                report.sum_error = stage_error
                return self.finalize_stage_report(
                    report,
                    elapsed_s,
                    xy_integral,
                    roll_integral,
                    tracking_error_integral,
                    speed_integral,
                )

        if elapsed_s >= self.cfg.stage_time_limit_s:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        self.draw_background()
        self.draw_zones()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, stage_error, report, state)
        pygame.display.flip()


MethodAApp.draw_zones = _fixed91_method_a_draw_zones
MethodAApp.draw_roll_limit_guides = _fixed91_method_a_draw_roll_limit_guides
MethodAApp.draw_hud = _fixed91_method_a_draw_hud
MethodAApp.read_runtime_events = _fixed91_method_a_read_runtime_events
MethodAApp.run_stage = _fixed91_run_stage

