# ====== FIXED92: test A without crash penalties, keep continuous accumulation ======
_FIXED92_METHOD_A_CALC_VERSION = 'fixed92_no_crash_penalty_v1'

def _fixed92_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    report = _fixed85_method_a_finalize_stage_report(
        self,
        report,
        elapsed_s,
        xy_integral,
        roll_integral,
        tracking_error_integral,
        speed_integral,
    )
    try:
        stage_max_error = float(self.stage_smax(int(report.stage_no)))
    except Exception:
        stage_max_error = 0.0

    report.crash_penalty_each = 0.0
    report.crash_penalty_total = 0.0
    report.crash_penalty_ratio = 0.0
    report.crash_penalty_h = 0.0
    report.crash_penalty_error = 0.0
    report.error_limit_value = float(stage_max_error)
    report.calculation_version = _FIXED92_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED92: после срыва накопленная ошибка не обнуляется, '
        'но штрафы за срывы временно отключены. Этап продолжается до лимита времени '
        'или до достижения максимального значения ошибки.'
    )
    return report


def _fixed92_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed85_build_method_a_payload(self, session, result)
    try:
        summary = payload.setdefault('summary', {})
        summary['calculation_version'] = _FIXED92_METHOD_A_CALC_VERSION
        summary['runtime_rule'] = 'no_error_reset_after_crash_without_crash_penalty'
        summary['forced_test_durations'] = {
            'A_stage_seconds': 120,
            'B_total_seconds': 120,
            'C_total_seconds': 120,
            'D_total_seconds': 120,
        }
        for item in payload.get('reports', []) or []:
            if isinstance(item, dict):
                item['calculation_version'] = _FIXED92_METHOD_A_CALC_VERSION
                item['runtime_rule'] = 'no_error_reset_after_crash_without_crash_penalty'
                item['crash_penalty_each'] = 0.0
                item['crash_penalty_total'] = 0.0
                item['crash_penalty_ratio'] = 0.0
                item['crash_penalty_h'] = 0.0
                item['crash_penalty_error'] = 0.0
    except Exception:
        pass
    return payload


def _fixed92_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    stage_no = int(report.get('stage_no', 0) or 0)
    avg_error = float(report.get('avg_tracking_error', 0.0) or 0.0)
    calc_version = str(report.get('calculation_version', _FIXED92_METHOD_A_CALC_VERSION))

    if stage_no == 3:
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} усл. ед./с"
        e_value = f"{avg_error:.4f} норм. ед."
        bounds_value = 'цель = 0.0000, авария = 1.0000'
    else:
        v_value = f"{float(report.get('v_avg', 0.0) or 0.0):.4f} см/с"
        e_value = f"{avg_error:.4f} см"
        target = float(report.get('tracking_error_target', 0.0) or 0.0)
        crash = float(report.get('tracking_error_crash', 0.0) or 0.0)
        bounds_value = f"цель = {target:.2f} см, авария = {crash:.2f} см"

    rows = [
        ('Режим', _fixed73e_stage_name(stage_no)),
        ('Контролируемые оси', str(report.get('active_axes', ''))),
        ('Длительность', f"{float(report.get('real_time_s', 0.0) or 0.0):.1f} с"),
        ('Ошибки', f"{int(report.get('crashes', 0) or 0)}"),
        ('Vср', v_value),
        ('γ', f"{float(report.get('success_gamma', 0.0) or 0.0):.4f}"),
        ('Энтропия H', f"{float(report.get('entropy_h', 0.0) or 0.0):.4f}"),
        ('Yтек. ср.', e_value),
        ('tр = Vср × γ', f"{float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}"),
        ('Границы расчёта ошибки', bounds_value),
        ('Версия расчёта', calc_version),
    ]
    if stage_no == 3:
        rows.append(('Средний крен', f"{float(report.get('mean_abs_roll_deg', 0.0) or 0.0):.2f}°"))
    else:
        rows.append(('Среднее отклонение X/Y', f"{float(report.get('mean_abs_xy_cm', 0.0) or 0.0):.2f} см"))
    return rows


def _fixed92_show_method_a_results(self, payload: dict):
    top, outer = _open_results_top(self, 'Результаты - Тест А. Слежение за объектом')
    participant = payload.get('participant', {})
    reports = payload.get('reports', [])
    if not reports:
        result_path = payload.get('result_path', '')
        if result_path:
            try:
                rp = Path(result_path)
                if not rp.is_absolute():
                    rp = self.base_dir / rp
                if rp.exists():
                    loaded = json.loads(rp.read_text(encoding='utf-8'))
                    if isinstance(loaded, list):
                        reports = [item for item in loaded if isinstance(item, dict)]
            except Exception:
                reports = []
    summary = dict(payload.get('summary', {}) or {})
    if reports:
        computed = _fixed73e_method_a_summary_from_reports(reports)
        for key, value in computed.items():
            if key == 't_values':
                merged = dict(value)
                merged.update(summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {})
                summary['t_values'] = merged
            else:
                summary.setdefault(key, value)
    t_values = summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {}

    completed_at = payload.get('completed_at', '')
    dt_label = completed_at.replace('T', ' ')[:19] if completed_at else 'не указано'

    header = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
    header.pack(fill='x', padx=24, pady=(24, 12))
    tk.Frame(header, bg='#67a9ff', height=8).pack(fill='x')
    head_body = tk.Frame(header, bg='#ffffff')
    head_body.pack(fill='both', expand=True, padx=22, pady=18)
    tk.Label(head_body, text='Тест А · Слежение за объектом', bg='#ffffff', fg='#102744', font=('Arial', 28, 'bold')).pack(anchor='w')
    subtitle = f"{participant.get('name', '')}, {participant.get('age', '')} лет, {participant.get('gender', '')}. Последнее завершение: {dt_label}."
    tk.Label(head_body, text=subtitle, bg='#ffffff', fg='#5a6678', font=('Arial', 12, 'bold'), wraplength=1180, justify='left').pack(anchor='w', pady=(8, 0))

    summary_shell = tk.Frame(outer, bg='#eef3f8')
    summary_shell.pack(fill='x', padx=24, pady=(0, 12))
    summary_grid = tk.Frame(summary_shell, bg='#eef3f8')
    summary_grid.pack(fill='x')
    for col in range(6):
        summary_grid.grid_columnconfigure(col, weight=1, uniform='a_summary92')

    total_crashes = int(summary.get('total_crashes', 0) or 0)
    summary_cards = [
        ('tр · X', f"{float(t_values.get('min', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по одной координате', '#67a9ff', 0, 0),
        ('tр · X+Y', f"{float(t_values.get('medio', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по двум координатам', '#53c26b', 0, 2),
        ('tр · X+Y+крен', f"{float(t_values.get('max', 0.0) or 0.0):.4f}", 'Приведённый темп этапа слежения по трём параметрам', '#c98cff', 0, 4),
        ('Средний γ', f"{float(summary.get('avg_success_gamma', 0.0) or 0.0):.4f}", 'Коэффициент успешности, равный негэнтропии управления', '#7bd0d5', 1, 0),
        ('Средняя энтропия H', f"{float(summary.get('avg_entropy_h', 0.0) or 0.0):.4f}", 'Чем меньше H, тем ближе средняя ошибка к целевой зоне', '#ffb35c', 1, 2),
        ('Ошибки за тест', f"{total_crashes}", 'Суммарное число срывов на трёх этапах', '#e26565', 1, 4),
    ]
    for title, value, subtitle, accent, row, col in summary_cards:
        card = self.draw_result_card(summary_grid, title, value, subtitle, accent)
        card.grid(row=row, column=col, columnspan=2, sticky='nsew', padx=8, pady=8)

    info_text = (
        'Основной показатель этапа рассчитывается как tр = Vср × γ. '
        'Коэффициент успешности γ получен через энтропию управления H, которая определяется средней текущей ошибкой слежения между целевой и аварийной границами. '
        'Штрафы за срывы в этой версии отключены. Срывы влияют только на ход этапа, но не добавляют отдельную прибавку в H.'
    )
    info_box = _add_info_box(outer, 'Как читать результат', info_text, '#6b7dff')
    info_box.pack(fill='x', padx=24, pady=(0, 14))

    stages_title = tk.Frame(outer, bg='#eef3f8')
    stages_title.pack(fill='x', padx=24, pady=(0, 8))
    tk.Label(stages_title, text='Показатели по этапам', bg='#eef3f8', fg='#102744', font=('Arial', 18, 'bold')).pack(anchor='w')
    tk.Label(stages_title, text='На каждом этапе показаны Vср, γ, энтропия H, средняя текущая ошибка и приведённый темп tр.', bg='#eef3f8', fg='#607187', font=('Arial', 11)).pack(anchor='w', pady=(2, 0))

    if not reports:
        empty = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        empty.pack(fill='x', padx=24, pady=(0, 14))
        tk.Label(empty, text='Подробные данные этапов не найдены.', bg='#ffffff', fg='#102744', font=('Arial', 16, 'bold')).pack(anchor='w', padx=18, pady=(16, 6))
        tk.Label(empty, text='Сводные карточки выше сохранены, но детальный список этапов для этого результата отсутствует.', bg='#ffffff', fg='#506176', font=('Arial', 11), wraplength=1120, justify='left').pack(anchor='w', padx=18, pady=(0, 18))
        return top

    ordered_reports = sorted(reports, key=lambda r: int(r.get('stage_no', 0) or 0))
    for report in ordered_reports:
        card = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        card.pack(fill='x', padx=24, pady=(0, 14))

        head = tk.Frame(card, bg='#ffffff')
        head.pack(fill='x', padx=18, pady=(16, 8))
        stage_no = int(report.get('stage_no', 0) or 0)
        tk.Label(head, text=f"Этап {stage_no} · {_fixed73e_stage_name(stage_no)}", bg='#ffffff', fg='#102744', font=('Arial', 20, 'bold')).pack(anchor='w')
        tk.Label(head, text=f"tр = {float(report.get('reduced_tempo_tr', 0.0) or 0.0):.4f}", bg='#ffffff', fg='#4f78ff', font=('Arial', 12, 'bold')).pack(anchor='w', pady=(4, 0))

        grid = tk.Frame(card, bg='#ffffff')
        grid.pack(fill='x', padx=18, pady=(0, 16))
        rows = _fixed92_method_a_stage_metric_rows(report)
        for idx, (label_text, value_text) in enumerate(rows):
            r = idx // 2
            c = (idx % 2) * 2
            tk.Label(grid, text=label_text, bg='#ffffff', fg='#617187', font=('Arial', 10, 'bold'), anchor='w').grid(row=r, column=c, sticky='w', padx=(0, 10), pady=4)
            tk.Label(grid, text=value_text, bg='#ffffff', fg='#102744', font=('Arial', 12, 'bold'), anchor='w').grid(row=r, column=c + 1, sticky='w', padx=(0, 26), pady=4)
        for col in range(4):
            grid.grid_columnconfigure(col, weight=1 if col % 2 else 0)

    return top


MethodAApp.finalize_stage_report = _fixed92_finalize_stage_report
StartPageApp.build_method_a_payload = _fixed92_build_method_a_payload
StartPageApp.show_method_a_results = _fixed92_show_method_a_results



# ====== FIXED93: Test B without question-mark help button, centered title ======

def _fixed93_method_b_build_ui(self):
    self.win = tk.Toplevel(self.parent)
    self.win.title('СПР - Тест B')
    self.win.configure(bg=UNIFORM_TEST_BG)
    self.win.transient(self.parent)
    self.win.grab_set()
    try:
        self.win.attributes('-fullscreen', True)
    except tk.TclError:
        self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
    self.win.bind('<Escape>', lambda _e: self._abort())
    self.win.protocol('WM_DELETE_WINDOW', self._abort)
    try:
        self.win.lift()
        self.win.focus_force()
    except Exception:
        pass

    sw, sh, scale = _fixed88_screen_metrics(self.win)

    self.win.grid_columnconfigure(0, weight=1)
    self.win.grid_rowconfigure(0, weight=1)

    shell = tk.Frame(self.win, bg=UNIFORM_TEST_BG)
    shell.grid(row=0, column=0, sticky='nsew', padx=max(12, int(24 * scale)), pady=max(10, int(18 * scale)))
    shell.grid_columnconfigure(0, weight=1)
    shell.grid_rowconfigure(1, weight=1)

    header_wrap = tk.Frame(shell, bg=UNIFORM_TEST_BG)
    header_wrap.grid(row=0, column=0, sticky='ew', pady=(0, max(8, int(10 * scale))))
    header_wrap.grid_columnconfigure(0, weight=1)
    tk.Label(
        header_wrap,
        text='Тест B · Запоминание фигур в матрице',
        bg=UNIFORM_TEST_BG,
        fg=UNIFORM_TEST_FG,
        font=('Arial', 24, 'bold'),
        justify='center',
        anchor='center'
    ).grid(row=0, column=0, sticky='ew')

    body = tk.Frame(shell, bg=UNIFORM_TEST_BG)
    body.grid(row=1, column=0, sticky='nsew')
    body.grid_columnconfigure(0, weight=1)
    body.grid_rowconfigure(0, weight=0)
    body.grid_rowconfigure(1, weight=0)

    play_row = tk.Frame(body, bg=UNIFORM_TEST_BG)
    play_row.grid(row=0, column=0, sticky='n', pady=(max(4, int(6 * scale)), max(8, int(10 * scale))))

    time_gap = max(8, int(16 * scale))
    time_w = max(60, int(74 * scale))
    available_h = max(300, sh - int(360 * scale))
    cell_size = int(min(190, max(96, min((sw - time_w - time_gap - 220) / 4.6, available_h / 5.6))))
    matrix_pad = max(2, int(4 * scale))
    time_h = int(cell_size * 4 + matrix_pad * 8)
    self._matrix_cell_size = cell_size
    self._tray_cell_size = max(92, int(cell_size * 0.96))
    self._matrix_bg = UNIFORM_TEST_BG
    self._tray_bg = UNIFORM_TEST_PANEL_2
    self._matrix_symbol_scale = max(1.10, min(1.85, 1.62 * (cell_size / 156.0)))
    self._tray_symbol_scale = max(1.10, min(1.85, 1.62 * (self._tray_cell_size / 156.0)))
    self._matrix_symbol_margin = max(6, int(cell_size * 0.064))
    self._tray_symbol_margin = max(6, int(self._tray_cell_size * 0.064))

    time_col = tk.Frame(play_row, bg=UNIFORM_TEST_BG)
    time_col.pack(side='left', padx=(0, time_gap), anchor='n')
    self.time_bar_canvas = tk.Canvas(
        time_col,
        width=time_w,
        height=max(240, time_h),
        bg=UNIFORM_TEST_BG,
        highlightthickness=0,
        bd=0
    )
    self.time_bar_canvas.pack(anchor='n', pady=(max(2, int(6 * scale)), 0))
    self.task_bar_canvas = None

    matrix_wrap = tk.Frame(play_row, bg=UNIFORM_TEST_BG)
    matrix_wrap.pack(side='left', anchor='n')
    self.matrix_frame = tk.Frame(matrix_wrap, bg=UNIFORM_TEST_BG, bd=0)
    self.matrix_frame.pack()

    self.grid_cells.clear()
    for r in range(4):
        self.matrix_frame.grid_rowconfigure(r, weight=1)
        self.matrix_frame.grid_columnconfigure(r, weight=1)
    for idx in range(16):
        c = tk.Canvas(
            self.matrix_frame,
            width=cell_size,
            height=cell_size,
            bg=self._matrix_bg,
            highlightthickness=0,
            bd=0
        )
        c.grid(row=idx // 4, column=idx % 4, padx=matrix_pad, pady=matrix_pad)
        c.bind('<Button-1>', lambda e, i=idx: self._on_matrix_cell(i))
        self.grid_cells.append(c)

    tray_panel = tk.Frame(body, bg=UNIFORM_TEST_PANEL_2, bd=1, relief='solid')
    tray_panel.grid(row=1, column=0, sticky='ew', pady=(max(2, int(4 * scale)), 0))
    tray_panel.grid_columnconfigure(0, weight=1)
    tray_panel.grid_columnconfigure(1, weight=0)

    title_font = ('Arial', max(13, int(16 * scale)), 'bold')
    btn_font = ('Arial', max(10, int(12 * scale)), 'bold')

    top_row = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2)
    top_row.grid(row=0, column=0, columnspan=2, sticky='ew', padx=max(10, int(14 * scale)), pady=(max(8, int(10 * scale)), max(4, int(6 * scale))))
    top_row.grid_columnconfigure(0, weight=1)
    top_row.grid_columnconfigure(1, weight=1)
    tk.Label(
        top_row,
        text='Касса фигур',
        bg=UNIFORM_TEST_PANEL_2,
        fg=UNIFORM_TEST_FG,
        font=title_font,
        justify='center',
        anchor='center'
    ).grid(row=0, column=0, columnspan=2, sticky='ew')

    controls = tk.Frame(top_row, bg=UNIFORM_TEST_PANEL_2)
    controls.grid(row=1, column=0, columnspan=2, pady=(max(6, int(8 * scale)), 0))
    btn_w = max(9, int(12 * scale))
    tk.Button(
        controls, text='Очистить', command=self._clear_placements,
        bg='#eee4c8', activebackground='#e1d6b6', fg='#5e372c',
        font=btn_font, width=btn_w
    ).pack(side='left', padx=(0, max(4, int(8 * scale))))
    tk.Button(
        controls, text='Далее', command=self._submit_cycle,
        bg='#d9f1d7', activebackground='#c6e7c2', fg='#214125',
        font=btn_font, width=btn_w
    ).pack(side='left')

    self.tray_frame = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2)
    self.tray_frame.grid(row=1, column=0, columnspan=2, sticky='n', padx=max(8, int(12 * scale)), pady=(0, max(8, int(12 * scale))))

    footer = tk.Frame(shell, bg=UNIFORM_TEST_BG)
    footer.grid(row=2, column=0, sticky='sew', pady=(max(8, int(10 * scale)), 0))
    footer.grid_columnconfigure(0, weight=1)
    tk.Button(
        footer,
        text='Выход',
        command=self._abort,
        bg='#d95a5a',
        activebackground='#c44d4d',
        fg='white',
        font=btn_font,
        width=max(9, int(12 * scale))
    ).grid(row=0, column=1, sticky='e')

    self.all_tray_shapes = []
    self.drag_shape = None
    self.drag_preview = None
    self._drag_motion_bind = None
    self._drag_release_bind = None
    self.message_var.set('')
    self.selection_var.set('')
    _fixed74_method_b_update_hud(self)


