# ====== FIXED97: Method A scoring aligned with slezhA.docx ======
_FIXED97_METHOD_A_CALC_VERSION = 'fixed97_doc_formula_v_sled_gamma_navar_over_vnorm_v1'

def _fixed97_stage_error_bounds(self, stage_no: int) -> tuple[float, float]:
    stage_no = int(stage_no)
    if stage_no == 3 and bool(self.stage_defs.get(stage_no, {}).get('z')):
        return 0.0, 1.0
    return 0.0, max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0)))


def _fixed97_stage_time_limit_s(self, stage_no: int) -> float:
    stage_no = int(stage_no)
    try:
        if '_fixed100_get_stage_time_limit' in globals():
            return max(1e-6, float(_fixed100_get_stage_time_limit(self.cfg, stage_no)))
    except Exception:
        pass
    return max(1e-6, float(getattr(self.cfg, 'stage_time_limit_s', 120.0) or 120.0))


def _fixed97_normative_speed_value(self, stage_no: int) -> float:
    stage_no = int(stage_no)
    stage = self.stage_defs[stage_no]
    active_xy_axes = int(bool(stage.get('x'))) + int(bool(stage.get('y')))
    xy_speed = abs(float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    xy_speed = xy_speed * (_fixed73e_math.sqrt(active_xy_axes) if active_xy_axes else 0.0)

    if not stage.get('z'):
        return max(1e-6, float(xy_speed))

    xy_goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    xy_crash = max(xy_goal + 1e-6, xy_goal + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    roll_goal = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0)))
    roll_crash = max(roll_goal + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0)))

    xy_norm_speed = float(xy_speed) / max(1e-6, xy_crash - xy_goal)
    roll_norm_speed = abs(float(getattr(self.cfg, 'start_speed_z_deg_s', 10.0) or 10.0)) / max(1e-6, roll_crash - roll_goal)
    return max(1e-6, ((xy_norm_speed * xy_norm_speed + roll_norm_speed * roll_norm_speed) / 2.0) ** 0.5)


def _fixed97_current_tracking_error(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[stage_no]
    px_per_cm = max(1e-6, float(getattr(self.cfg, 'px_per_cm', 38.0)))

    x_cm = abs(float(getattr(state, 'x_px', 0.0))) / px_per_cm if stage.get('x') else 0.0
    y_cm = abs(float(getattr(state, 'y_px', 0.0))) / px_per_cm if stage.get('y') else 0.0
    xy_now = (x_cm * x_cm + y_cm * y_cm) ** 0.5

    if not stage.get('z'):
        target = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
        crash_span = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0)))
        raw_error = max(0.0, xy_now - target)
        return _fixed73e_clip(raw_error, 0.0, crash_span)

    xy_goal = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0)))
    xy_crash = max(xy_goal + 1e-6, xy_goal + float(getattr(self.cfg, 'work_extension_cm', 15.0)))
    roll_goal = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0)))
    roll_crash = max(roll_goal + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0)))

    xy_norm = _fixed73e_clip((xy_now - xy_goal) / max(1e-6, xy_crash - xy_goal), 0.0, 1.0)
    roll_now = abs(float(getattr(state, 'roll_deg', 0.0)))
    roll_norm = _fixed73e_clip((roll_now - roll_goal) / max(1e-6, roll_crash - roll_goal), 0.0, 1.0)

    # Unified normalized current error for X+Y+roll in range 0..1.
    return ((xy_norm * xy_norm + roll_norm * roll_norm) / 2.0) ** 0.5


def _fixed97_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    stage_error = 0.0
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0
    stage_max_error = float(self.stage_smax(stage_no))

    report.crash_penalty_ratio = 0.0
    report.crash_penalty_each = 0.0
    report.crash_penalty_total = 0.0
    report.error_limit_value = float(stage_max_error)

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        stage_error += self.current_error_increment(state, stage_no, dt)
        report.sum_error = stage_error
        self.maybe_register_return(state, stage_no, report)

        inside_now = self.inside_target(state, stage_no)
        if inside_now:
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        tracking_error_integral += _fixed97_current_tracking_error(self, state, stage_no) * dt
        speed_integral += _fixed73e_current_speed_value(self, state, stage_no) * dt

        if stage_error >= stage_max_error:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = stage_error
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(stage_error, 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; no_penalty_resetless_error",
            )
            self.reset_after_crash(state)

        if elapsed_s >= float(getattr(self.cfg, 'stage_time_limit_s', 120.0)):
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, stage_error, report, state)
        pygame.display.flip()


def _fixed97_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    avg_error = float(tracking_error_integral) / total
    report.avg_tracking_error_raw = float(avg_error)
    report.avg_tracking_error = float(avg_error)
    report.avg_tracking_error_effective = float(avg_error)
    report.v_avg = float(speed_integral) / total

    stage_no = int(report.stage_no)
    goal, crash = _fixed97_stage_error_bounds(self, stage_no)
    denom = float(goal) - float(crash)
    if abs(denom) < 1e-9:
        denom = -1.0

    entropy_h = (float(goal) - float(avg_error)) / denom
    entropy_h = _fixed73e_clip(entropy_h, 0.0, 1.0)
    success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)

    # slezhA.docx: Nдоп = T/3; Nавар = 1 - (Nреал / Nдоп).
    stage_time_limit_s = _fixed97_stage_time_limit_s(self, stage_no)
    n_dop = max(1.0, float(stage_time_limit_s) / 3.0)
    n_real = max(0.0, float(getattr(report, 'crashes', 0) or 0))
    n_avar = _fixed73e_clip(1.0 - (n_real / n_dop), 0.0, 1.0)

    # slezhA.docx: tр = (Vср / Vср.норм) * γ * Nавар.
    v_avg_norm = _fixed97_normative_speed_value(self, stage_no)

    report.entropy_h_raw = float(entropy_h)
    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.crash_penalty_h = 0.0
    report.crash_penalty_error = 0.0
    report.crash_penalty_each = 0.0
    report.crash_penalty_total = 0.0
    report.crash_penalty_ratio = 0.0

    report.success_gamma = float(success_gamma)
    report.crash_coeff_n_avar = float(n_avar)
    report.crash_limit_doc = float(n_dop)
    report.v_avg_norm = float(v_avg_norm)
    report.reduced_tempo_tr = (
        float(report.v_avg) * float(report.success_gamma) * float(report.crash_coeff_n_avar) / max(1e-6, float(report.v_avg_norm))
    )

    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.stage_label_doc = _fixed73e_stage_name(stage_no)
    report.error_limit_value = float(self.stage_smax(stage_no))
    report.calculation_version = _FIXED97_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED97(doc): tр=(Vср/Vср.норм)×γ×Nавар; γ=1-H; '
        'H=(Yцели-Yтек.ср)/(Yцели-Yаварии); Nавар=1-(Nреал/Nдоп), Nдоп=T/3.'
    )
    report.entropy_formula_note = (
        'tр = (Vср / Vср.норм) × γ × Nавар, γ = 1 - H, '
        'H = (Yцели - Yтек.ср) / (Yцели - Yаварии), Nавар = 1 - (Nреал / Nдоп), Nдоп = T / 3.'
    )
    return report


def _fixed97_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed92_build_method_a_payload(self, session, result)
    try:
        summary = payload.setdefault('summary', {})
        summary['calculation_version'] = _FIXED97_METHOD_A_CALC_VERSION
        summary['runtime_rule'] = 'no_error_reset_after_crash_without_crash_penalty'
        for item in payload.get('reports', []) or []:
            if isinstance(item, dict):
                item['calculation_version'] = _FIXED97_METHOD_A_CALC_VERSION
                item['runtime_rule'] = 'no_error_reset_after_crash_without_crash_penalty'
                item['crash_penalty_each'] = 0.0
                item['crash_penalty_total'] = 0.0
                item['crash_penalty_ratio'] = 0.0
                item['crash_penalty_h'] = 0.0
                item['crash_penalty_error'] = 0.0
    except Exception:
        pass
    return payload


