# ====== FIXED100: independent stage times for Method A + build target ======
from dataclasses import dataclass as _fixed100_dataclass, fields as _fixed100_fields

_FIXED100_BASE_METHOD_A_CLASS = MethodAConfig
_FIXED100_METHOD_A_CALC_VERSION = 'fixed100_independent_stage_times_v1'

@_fixed100_dataclass
class MethodAConfigFixed100(_FIXED100_BASE_METHOD_A_CLASS):
    stage_time_limit_stage_1_s: float = 40.0
    stage_time_limit_stage_2_s: float = 40.0
    stage_time_limit_stage_3_s: float = 40.0

MethodAConfig = MethodAConfigFixed100
globals()['MethodAConfig'] = MethodAConfigFixed100


def _fixed100_get_stage_time_limit(cfg, stage_no: int) -> float:
    stage_no = int(stage_no)
    attr_name = f'stage_time_limit_stage_{stage_no}_s'
    try:
        value = float(getattr(cfg, attr_name))
        if value > 0:
            return value
    except Exception:
        pass
    try:
        value = float(getattr(cfg, 'stage_time_limit_s', 40.0))
        if value > 0:
            return value
    except Exception:
        pass
    return 40.0


_prev_load_config_fixed100 = load_config

def load_config(path: str | Path = 'method_a_config.json', screen_w: int | None = None, screen_h: int | None = None) -> MethodAConfigFixed100:
    raw = {}
    p = Path(path)
    if p.exists():
        try:
            loaded = json.loads(p.read_text(encoding='utf-8'))
            if isinstance(loaded, dict):
                raw = dict(loaded)
        except Exception:
            raw = {}

    # First try the existing chain for all legacy behavior.
    legacy_cfg = None
    try:
        legacy_cfg = _prev_load_config_fixed100(path=path, screen_w=screen_w, screen_h=screen_h)
    except Exception:
        legacy_cfg = None

    base_field_names = {f.name for f in _fixed100_fields(_FIXED100_BASE_METHOD_A_CLASS)}
    if legacy_cfg is None:
        base_kwargs = {k: v for k, v in raw.items() if k in base_field_names}
        try:
            legacy_cfg = _FIXED100_BASE_METHOD_A_CLASS(**base_kwargs)
        except Exception:
            legacy_cfg = _FIXED100_BASE_METHOD_A_CLASS()
        if screen_w and screen_h:
            legacy_cfg.width = max(1000, int(screen_w))
            legacy_cfg.height = max(700, int(screen_h))

    inherited_kwargs = {}
    for fld in _fixed100_fields(_FIXED100_BASE_METHOD_A_CLASS):
        try:
            inherited_kwargs[fld.name] = getattr(legacy_cfg, fld.name)
        except Exception:
            inherited_kwargs[fld.name] = fld.default

    cfg = MethodAConfigFixed100(**inherited_kwargs)

    legacy_limit = raw.get('stage_time_limit_s', getattr(legacy_cfg, 'stage_time_limit_s', 40.0))
    try:
        legacy_limit = float(legacy_limit)
    except Exception:
        legacy_limit = 40.0

    for stage_no in (1, 2, 3):
        key = f'stage_time_limit_stage_{stage_no}_s'
        try:
            value = float(raw.get(key, legacy_limit))
        except Exception:
            value = legacy_limit
        if value <= 0:
            value = legacy_limit if legacy_limit > 0 else 40.0
        setattr(cfg, key, float(value))

    # Keep legacy field as stage 1 fallback for older code paths.
    cfg.stage_time_limit_s = float(getattr(cfg, 'stage_time_limit_stage_1_s', legacy_limit))
    return cfg

