def _fixed100_get_research_section_groups(code: str, cls):
    groups = _prev_get_research_section_groups_fixed100(code, cls)
    if code != 'A':
        return groups
    filtered_groups = []
    for title, field_names in groups:
        cleaned = [name for name in field_names if name != 'stage_time_limit_s']
