def _fixed100_collect_researcher_configs(self):
    collected = []
    for code, title, cls, filename in RESEARCH_CONFIG_SPECS:
        kwargs = {}
        widgets_map = self.research_widgets.get(code, {})
        for fld in fields(cls):
            if fld.name not in widgets_map:
                if code == 'A' and fld.name == 'stage_time_limit_s':
                    continue
                kwargs[fld.name] = getattr(cls(), fld.name)
                continue
            info = widgets_map[fld.name]
            raw = self._research_widget_get(info)
            try:
                kwargs[fld.name] = _parse_config_value(raw, info['template'])
            except Exception as exc:
                raise ValueError(f"{title}: поле '{fld.name}' заполнено некорректно ({exc}).")
        if code == 'A' and cls is MethodAConfigFixed100:
            kwargs.setdefault('stage_time_limit_s', float(kwargs.get('stage_time_limit_stage_1_s', 40.0)))
        try:
            cfg = cls(**kwargs)
        except Exception as exc:
            raise ValueError(f"{title}: не удалось собрать конфигурацию ({exc}).")
        collected.append((filename, cfg))
    return collected

