def _fixed100_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    stage_error = 0.0
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0
    stage_max_error = float(self.stage_smax(stage_no))
    stage_time_limit = _fixed100_get_stage_time_limit(self.cfg, stage_no)

    report.crash_penalty_ratio = 0.0
    report.crash_penalty_each = 0.0
    report.crash_penalty_total = 0.0
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        stage_error += self.current_error_increment(state, stage_no, dt)
        report.sum_error = stage_error
        self.maybe_register_return(state, stage_no, report)

        inside_now = self.inside_target(state, stage_no)
        if inside_now:
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        if '_fixed97_current_tracking_error' in globals():
            tracking_error_integral += _fixed97_current_tracking_error(self, state, stage_no) * dt
        else:
            tracking_error_integral += xy_now * dt
        if '_fixed73e_current_speed_value' in globals():
            speed_integral += _fixed73e_current_speed_value(self, state, stage_no) * dt

        if stage_error >= stage_max_error:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = stage_error
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(stage_error, 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; stage_limit={stage_time_limit}",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report.sum_error = stage_error
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, stage_error, report, state)
        pygame.display.flip()

MethodAApp.run_stage = _fixed100_run_stage


_prev_build_method_a_payload_fixed100 = StartPageApp.build_method_a_payload
def _fixed100_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _prev_build_method_a_payload_fixed100(self, session, result)
    try:
        for item in payload.get('reports', []) or []:
            if isinstance(item, dict):
                item['calculation_version'] = _FIXED100_METHOD_A_CALC_VERSION
                item['stage_time_limit_used_s'] = float(item.get('stage_time_limit_used_s', _fixed100_get_stage_time_limit(load_config(self.base_dir / 'method_a_config.json'), int(item.get('stage_no', 1)))))
        payload.setdefault('summary', {})['calculation_version'] = _FIXED100_METHOD_A_CALC_VERSION
        payload['summary']['method_a_stage_time_limits'] = {
            'stage_1_s': float(getattr(load_config(self.base_dir / 'method_a_config.json'), 'stage_time_limit_stage_1_s', 40.0)),
            'stage_2_s': float(getattr(load_config(self.base_dir / 'method_a_config.json'), 'stage_time_limit_stage_2_s', 40.0)),
            'stage_3_s': float(getattr(load_config(self.base_dir / 'method_a_config.json'), 'stage_time_limit_stage_3_s', 40.0)),
        }
    except Exception:
        pass
    return payload

