# ====== FIXED104: responsive layouts for all screens and safer button sizing ======

def _fixed104_button_width_chars(text_value: str, scale: float, min_chars: int = 8, extra: int = 1) -> int:
    raw = str(text_value or '').replace('\n', ' ')
    return max(min_chars, int(len(raw) * (0.82 if scale < 0.85 else 0.72)) + extra)


def _fixed104_screen_metrics(widget_or_parent):
    try:
        sw = int(widget_or_parent.winfo_screenwidth())
        sh = int(widget_or_parent.winfo_screenheight())
    except Exception:
        sw, sh = 1920, 1080
    scale = min(sw / 1920.0, sh / 1080.0)
    if sw < 1600 or sh < 920:
        scale *= 0.92
    if sw < 1366 or sh < 768:
        scale *= 0.90
    scale = max(0.58, min(scale, 1.18))
    return sw, sh, scale

# Make all later test windows use the more conservative scaling too.
globals()['_fixed88_screen_metrics'] = _fixed104_screen_metrics


def _fixed104_apply_common_shell_layout(self, width: int, height: int, scale: float):
    compact = width < 1500 or height < 900
    ultra_compact = width < 1280 or height < 780

    try:
        self.root.minsize(960, 680)
    except Exception:
        pass

    left_weight = 5 if compact else 7
    right_weight = 15 if compact else 13
    self.main.grid_columnconfigure(0, weight=left_weight, uniform="cols")
    self.main.grid_columnconfigure(1, weight=right_weight, uniform="cols")

    # Prevent the intro text row from greedily eating the entire center on laptops.
    try:
        self.right.grid_rowconfigure(2, weight=0)
        self.right.grid_rowconfigure(3, weight=0)
        self.right.grid_rowconfigure(4, weight=0)
    except Exception:
        pass

    pad_x = int((16 if compact else 24) * scale)
    pad_y = int((12 if compact else 18) * scale)
    left_right_gap = int((14 if compact else 24) * scale)
    image_gap = int((10 if compact else 18) * scale)

    self.main.pack_configure(padx=pad_x, pady=pad_y)
    self.left.grid_configure(padx=(0, left_right_gap))
    self.title_small.grid_configure(pady=(0, int((4 if compact else 8) * scale)))
    self.title_big.grid_configure(pady=(0, int((6 if compact else 8) * scale)))
    self.body.grid_configure(pady=(int((8 if compact else 16) * scale), int((8 if compact else 16) * scale)))
    self.image_gap.configure(height=image_gap)

    title_small_size = max(18, int((30 if compact else 42) * scale))
    title_big_size = max(22, int((34 if compact else 46) * scale))
    body_size = max(10, int((15 if compact else 21) * scale))
    body_wrap = int(width * (0.60 if compact else 0.54))

    self.title_small.configure(font=("Times New Roman", title_small_size, "bold"))
    self.title_big.configure(font=("Times New Roman", title_big_size, "bold"))
    self.body.configure(font=("Times New Roman", body_size, "bold"), wraplength=body_wrap)

    left_width = int(width * (0.22 if ultra_compact else (0.24 if compact else 0.29)))
    img_height_factor = 0.26 if ultra_compact else (0.30 if compact else 0.40)
    img_size = min(left_width, int(height * img_height_factor))
    img_size = max(160 if ultra_compact else (180 if compact else 220), img_size)

    self.set_image(self.circle_label, "circle.png", img_size)
    self.set_image(self.cockpit_label, "cockpit.png", img_size)

StartPageApp._apply_common_shell_layout = _fixed104_apply_common_shell_layout


