# ====== FIXED105: Test B layout update only ======

def _fixed105_method_b_build_ui(self):
    self.win = tk.Toplevel(self.parent)
    self.win.title('СПР - Тест B')
    self.win.configure(bg=UNIFORM_TEST_BG)
    self.win.transient(self.parent)
    self.win.grab_set()
    try:
        self.win.attributes('-fullscreen', True)
    except tk.TclError:
        self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
    self.win.bind('<Escape>', lambda _e: self._abort())
    self.win.protocol('WM_DELETE_WINDOW', self._abort)
    try:
        self.win.lift()
        self.win.focus_force()
    except Exception:
        pass

    sw, sh, scale = _fixed88_screen_metrics(self.win)

    self.win.grid_columnconfigure(0, weight=1)
    self.win.grid_rowconfigure(0, weight=1)

    # Smaller outer margins so the time bar can sit closer to the screen edge.
    shell = tk.Frame(self.win, bg=UNIFORM_TEST_BG)
    shell.grid(row=0, column=0, sticky='nsew', padx=max(6, int(10 * scale)), pady=max(8, int(12 * scale)))
    shell.grid_columnconfigure(0, weight=0)
    shell.grid_columnconfigure(1, weight=0)
    shell.grid_columnconfigure(2, weight=1)
    shell.grid_rowconfigure(0, weight=1)
    shell.grid_rowconfigure(1, weight=0)

    time_gap = max(8, int(12 * scale))
    time_w = max(60, int(74 * scale))
    available_h = max(300, sh - int(340 * scale))
    cell_size = int(min(190, max(96, min((sw - time_w - time_gap - 180) / 4.8, available_h / 5.6))))
    matrix_pad = max(2, int(4 * scale))
    time_h = int(cell_size * 4 + matrix_pad * 8)
    matrix_total_w = int(cell_size * 4 + matrix_pad * 8)
    self._matrix_cell_size = cell_size
    self._tray_cell_size = max(88, int(cell_size * 0.96))
    self._matrix_bg = UNIFORM_TEST_BG
    self._tray_bg = UNIFORM_TEST_PANEL_2
    self._matrix_symbol_scale = max(1.10, min(1.85, 1.62 * (cell_size / 156.0)))
    self._tray_symbol_scale = max(1.10, min(1.85, 1.62 * (self._tray_cell_size / 156.0)))
    self._matrix_symbol_margin = max(6, int(cell_size * 0.064))
    self._tray_symbol_margin = max(6, int(self._tray_cell_size * 0.064))

    # Left time column, closer to screen edge.
    time_col = tk.Frame(shell, bg=UNIFORM_TEST_BG)
    time_col.grid(row=0, column=0, sticky='nw', padx=(0, time_gap), pady=(max(12, int(18 * scale)), 0))
    self.time_bar_canvas = tk.Canvas(
        time_col,
        width=time_w,
        height=max(240, time_h),
        bg=UNIFORM_TEST_BG,
        highlightthickness=0,
        bd=0
    )
    self.time_bar_canvas.pack(anchor='n')
    self.task_bar_canvas = None

    # Main content column with matrix and tray having identical width.
    main_col = tk.Frame(shell, bg=UNIFORM_TEST_BG, width=matrix_total_w)
    main_col.grid(row=0, column=1, sticky='n', pady=(max(12, int(18 * scale)), 0))
    main_col.grid_propagate(False)
    main_col.grid_columnconfigure(0, minsize=matrix_total_w)

    self.matrix_frame = tk.Frame(main_col, bg=UNIFORM_TEST_BG, bd=0, width=matrix_total_w)
    self.matrix_frame.grid(row=0, column=0, sticky='n')
    self.matrix_frame.grid_propagate(False)

    self.grid_cells.clear()
    for r in range(4):
        self.matrix_frame.grid_rowconfigure(r, weight=1)
        self.matrix_frame.grid_columnconfigure(r, weight=1)
    for idx in range(16):
        c = tk.Canvas(
            self.matrix_frame,
            width=cell_size,
            height=cell_size,
            bg=self._matrix_bg,
            highlightthickness=0,
            bd=0
        )
        c.grid(row=idx // 4, column=idx % 4, padx=matrix_pad, pady=matrix_pad)
        c.bind('<Button-1>', lambda e, i=idx: self._on_matrix_cell(i))
        self.grid_cells.append(c)

    tray_panel = tk.Frame(main_col, bg=UNIFORM_TEST_PANEL_2, bd=1, relief='solid', width=matrix_total_w)
    tray_panel.grid(row=1, column=0, sticky='n', pady=(max(8, int(10 * scale)), 0))
    tray_panel.grid_propagate(False)
    tray_panel.grid_columnconfigure(0, weight=1)
    tray_panel.grid_columnconfigure(1, weight=1)

    btn_font = ('Arial', max(12, int(15 * scale)), 'bold')
    btn_w = max(18, int(22 * scale))
    btn_ipadx = max(10, int(20 * scale))
    btn_ipady = max(8, int(12 * scale))

    controls = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2)
    controls.grid(row=0, column=0, columnspan=2, sticky='ew', padx=max(8, int(10 * scale)), pady=(max(10, int(12 * scale)), max(6, int(8 * scale))))
    controls.grid_columnconfigure(0, weight=1)
    controls.grid_columnconfigure(1, weight=1)

    clear_btn = tk.Button(
        controls,
        text='Очистить',
        command=self._clear_placements,
        bg='#f2d64b',
        activebackground='#e3c12d',
        fg='#4f3900',
        font=btn_font,
        width=btn_w
    )
    clear_btn.grid(row=0, column=0, padx=(0, max(8, int(12 * scale))), sticky='e', ipadx=btn_ipadx, ipady=btn_ipady)

    next_btn = tk.Button(
        controls,
        text='Далее',
        command=self._submit_cycle,
        bg='#58cc63',
        activebackground='#43b84f',
        fg='#173b1a',
        font=btn_font,
        width=btn_w
    )
    next_btn.grid(row=0, column=1, padx=(max(8, int(12 * scale)), 0), sticky='w', ipadx=btn_ipadx, ipady=btn_ipady)

    self.tray_frame = tk.Frame(tray_panel, bg=UNIFORM_TEST_PANEL_2, width=matrix_total_w)
    self.tray_frame.grid(row=1, column=0, columnspan=2, sticky='n', padx=max(6, int(8 * scale)), pady=(0, max(10, int(12 * scale))))
    self.tray_frame.grid_propagate(False)

    footer = tk.Frame(shell, bg=UNIFORM_TEST_BG)
    footer.grid(row=1, column=0, columnspan=3, sticky='sew', pady=(max(8, int(10 * scale)), 0))
    footer.grid_columnconfigure(0, weight=1)
    tk.Button(
        footer,
        text='Выход',
        command=self._abort,
        bg='#d95a5a',
        activebackground='#c44d4d',
        fg='white',
        font=('Arial', max(10, int(12 * scale)), 'bold'),
        width=max(9, int(12 * scale))
    ).grid(row=0, column=1, sticky='e')

    self.all_tray_shapes = []
    self.drag_shape = None
    self.drag_preview = None
    self._drag_motion_bind = None
    self._drag_release_bind = None
    self.message_var.set('')
    self.selection_var.set('')
    _fixed74_method_b_update_hud(self)


def _fixed105_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return

    items = sorted(list(getattr(self, 'all_tray_shapes', []) or getattr(self, 'current_shapes', [])))
    used = _fixed24_method_b_used_shapes(self)
    items = [shape for shape in items if shape not in used]

    tray_bg = getattr(self, '_tray_bg', UNIFORM_TEST_PANEL_2)
    size = int(getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 156)))
    margin = int(getattr(self, '_tray_symbol_margin', 10))
    scale = float(getattr(self, '_tray_symbol_scale', getattr(self, '_matrix_symbol_scale', 1.62)))

    # Up to two rows in the tray while keeping the overall tray width equal to the matrix width.
    if len(items) <= 4:
        columns = max(1, len(items))
    else:
        columns = min(4, int(math.ceil(len(items) / 2.0)))

    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        wrap = tk.Frame(self.tray_frame, bg=tray_bg)
        wrap.grid(row=row, column=col, padx=4, pady=4)
        canvas = tk.Canvas(
            wrap,
            width=size,
            height=size,
            bg=tray_bg,
            highlightthickness=1,
            highlightbackground='#d7c0a0',
            bd=0,
            cursor='hand2'
        )
        canvas.pack()
        _fixed73c_draw_symbol(
            canvas,
            margin,
            margin,
            size - margin,
            size - margin,
            shape,
            fill='#5a2323',
            outline='#5a2323',
            scale=scale,
            tag='symbol'
        )
        canvas.bind('<ButtonPress-1>', lambda e, s=shape, _self=self: _fixed25_method_b_start_drag(_self, e, s))
        self.tray_cells.append(canvas)

    total = len(getattr(self, 'current_positions', []) or [])
    placed = len(used)
    if placed == 0:
        self.selection_var.set('Перетащите фигуры из кассы в нужные ячейки матрицы.')
    elif placed < total:
        self.selection_var.set('Размещённые фигуры исчезают из кассы. Перетащите оставшиеся в нужные ячейки матрицы.')
    else:
        self.selection_var.set('Все фигуры этапа размещены. Проверьте матрицу и нажмите «Далее».')


MethodBWindow._build_ui = _fixed105_method_b_build_ui
MethodBWindow._draw_tray = _fixed105_method_b_draw_tray


