# ====== FIXED121: Method A gets Start/Exit buttons like Method B, bars hidden before start ======

_fixed121_original_method_a_run = MethodAApp.run

def _fixed121_wait_for_method_a_start(self) -> str:
    start_w, start_h = 360, 58
    exit_w, exit_h = 360, 58
    bottom_margin = 16
    side_margin = 16

    start_rect = pygame.Rect(side_margin, self.cfg.height - bottom_margin - start_h, start_w, start_h)
    exit_rect = pygame.Rect(self.cfg.width - side_margin - exit_w, self.cfg.height - bottom_margin - exit_h, exit_w, exit_h)

    title_font = pygame.font.SysFont('arial', 22, bold=True)
    btn_font = pygame.font.SysFont('arial', 22, bold=True)

    while True:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                return 'exit'
            if event.type == pygame.KEYDOWN and event.key == pygame.K_ESCAPE:
                return 'exit'
            if event.type == pygame.MOUSEBUTTONDOWN and event.button == 1:
                if start_rect.collidepoint(event.pos):
                    return 'start'
                if exit_rect.collidepoint(event.pos):
                    return 'exit'

        # Everything else stays untouched; only hide bars before start.
        self.draw_background()
        try:
            self.draw_zones()
        except TypeError:
            try:
                self.draw_zones(1)
            except Exception:
                pass

        title = title_font.render('Нажмите кнопку, чтобы начать тестирование', True, self.cfg.text_color)
        self.screen.blit(title, (self.cfg.width // 2 - title.get_width() // 2, 34))

        pygame.draw.rect(self.screen, (88, 204, 99), start_rect)
        pygame.draw.rect(self.screen, (23, 59, 26), start_rect, 2)
        start_text = btn_font.render('Начать тестирование', True, (23, 59, 26))
        self.screen.blit(
            start_text,
            (start_rect.centerx - start_text.get_width() // 2, start_rect.centery - start_text.get_height() // 2)
        )

        pygame.draw.rect(self.screen, (217, 90, 90), exit_rect)
        pygame.draw.rect(self.screen, (255, 255, 255), exit_rect, 2)
        exit_text = btn_font.render('Выход', True, (255, 255, 255))
        self.screen.blit(
            exit_text,
            (exit_rect.centerx - exit_text.get_width() // 2, exit_rect.centery - exit_text.get_height() // 2)
        )

        pygame.display.flip()
        self.clock.tick(60)


def _fixed121_method_a_run(self) -> dict:
    choice = _fixed121_wait_for_method_a_start(self)
    if choice != 'start':
        try:
            pygame.quit()
        except Exception:
            pass
        return {"completed": False, "reports": [], "result_path": ""}
    return _fixed121_original_method_a_run(self)


MethodAApp.run = _fixed121_method_a_run


