# ====== FIXED129: Method C first number always positive; colors define add/subtract; no negative result ======

def _fixed129_method_c_generate_operand(self, current: int, stage_index: int):
    lo, hi = self._stage_limits(stage_index)
    lo = max(1, int(lo))
    hi = int(hi)

    choices = []
    max_add = hi - current
    if max_add >= lo:
        choices.append('+')

    # Red numbers subtract from the current value, but never drive the result below zero.
    max_sub = current
    if max_sub >= lo:
        choices.append('-')

    if not choices:
        return '+', lo, current

    op = random.choice(choices)
    if op == '+':
        operand = random.randint(lo, max_add)
        correct = current + operand
    else:
        operand = random.randint(lo, max_sub)
        correct = current - operand

    if correct < 0:
        correct = 0
    return op, operand, correct


def _fixed129_method_c_start_stage(self, stage_index: int):
    self._cancel_afters()
    self.stage_index = stage_index
    if stage_index > 3:
        self._finish()
        return

    lo, hi = self._stage_limits(stage_index)
    lo = max(1, int(lo))
    hi = int(hi)

    self.exp_s = float(self.cfg.exposure_start_s[stage_index - 1])
    self.input_s = float(self.cfg.input_start_s[stage_index - 1])

    # The first shown number is always positive.
    self.current_value = random.randint(lo, hi)
    self.stage_start_at = time.perf_counter()
    self.stage_records[stage_index] = {'cycles': [], 'Gq': 0, 'Fq': 0}

    self.prompt_var.set('')
    self.big_var.set(str(self.current_value))
    self.big_label.configure(fg='#163d7a')
    self.entry_var.set('')
    self.entry.configure(state='disabled')
    self._tick_stage_clock()
    self._track_after(self.win.after(int(self.exp_s * 1000), self._start_operation_cycle))


MethodCWindow._generate_operand = _fixed129_method_c_generate_operand
MethodCWindow._start_stage = _fixed129_method_c_start_stage

