MethodCWindow._resolve_cycle = _fixed131_method_c_resolve_cycle


# ====== FIXED134: Method B action buttons aligned to PDF ======

def _fixed134_method_b_build_ui(self):
    _fixed127_method_b_build_ui(self)

    try:
        scale = _fixed88_screen_metrics(self.win)[2]
    except Exception:
        scale = 1.0

    shell_candidates = self.win.grid_slaves(row=0, column=0)
    if not shell_candidates:
        return
    shell = shell_candidates[0]

    main_candidates = shell.grid_slaves(row=0, column=2)
    if not main_candidates:
        return
    main = main_candidates[0]

    tray_panel = getattr(self, 'tray_frame', None)
    if tray_panel is None:
        return
    tray_panel = tray_panel.master

    controls = None
    for child in main.winfo_children():
        if child not in (self.matrix_frame, tray_panel):
            controls = child
            break
    if controls is None:
        return

    buttons = [child for child in controls.winfo_children() if isinstance(child, tk.Button)]
    if len(buttons) < 2:
        return
    clear_old, next_old = buttons[:2]

    try:
        base_width = int(clear_old.cget('width'))
    except Exception:
        base_width = 18
    try:
        base_padx = int(clear_old.cget('padx'))
    except Exception:
        base_padx = 14
    try:
        base_pady = int(clear_old.cget('pady'))
    except Exception:
        base_pady = 8
    clear_cfg = {
        'text': clear_old.cget('text'),
        'bg': clear_old.cget('bg'),
        'activebackground': clear_old.cget('activebackground'),
        'fg': clear_old.cget('fg'),
        'font': clear_old.cget('font'),
    }
    next_cfg = {
        'text': next_old.cget('text'),
        'bg': next_old.cget('bg'),
        'activebackground': next_old.cget('activebackground'),
        'fg': next_old.cget('fg'),
        'font': next_old.cget('font'),
    }

    matrix_total_w = max(self.matrix_frame.winfo_reqwidth(), self.matrix_frame.winfo_width())
    action_btn_w = max(10, int(base_width * 0.62))
    action_gap = max(8, int(10 * scale))
    action_row_gap_top = max(10, int(12 * scale))
    action_row_gap_bottom = max(4, int(6 * scale))

    controls.destroy()
    tray_panel.pack_forget()

    controls = tk.Frame(main, bg=UNIFORM_TEST_BG)
    controls.pack(pady=(action_row_gap_top, action_row_gap_bottom))

    center_spacer = tk.Frame(controls, bg=UNIFORM_TEST_BG, width=matrix_total_w, height=1)
    center_spacer.grid(row=0, column=1)
    center_spacer.grid_propagate(False)

    clear_btn = tk.Button(
        controls,
        text=clear_cfg['text'],
        command=self._clear_placements,
        bg=clear_cfg['bg'],
        activebackground=clear_cfg['activebackground'],
        fg=clear_cfg['fg'],
        font=clear_cfg['font'],
        width=action_btn_w,
        padx=base_padx,
        pady=base_pady,
    )
    clear_btn.grid(row=0, column=0, sticky='w', padx=(0, action_gap))

    next_btn = tk.Button(
        controls,
        text=next_cfg['text'],
        command=self._submit_cycle,
        bg=next_cfg['bg'],
        activebackground=next_cfg['activebackground'],
        fg=next_cfg['fg'],
        font=next_cfg['font'],
        width=action_btn_w,
        padx=base_padx,
        pady=base_pady,
    )
    next_btn.grid(row=0, column=2, sticky='e', padx=(action_gap, 0))

    tray_panel.pack(pady=(max(10, int(12 * scale)), 0))



