# ====== FIXED137: Test C layout matches reference composition ======

_FIXED137_PREV_METHOD_C_START_STAGE = MethodCWindow._start_stage
_FIXED137_PREV_METHOD_C_RESOLVE_CYCLE = MethodCWindow._resolve_cycle


def _fixed137_method_c_set_input_enabled(self, enabled: bool):
    state = 'normal' if enabled else 'disabled'
    try:
        self.entry.configure(state=state)
    except Exception:
        pass
    for widget in getattr(self, '_method_c_input_widgets', []):
        try:
            widget.configure(state=state)
        except Exception:
            pass
    keypad = getattr(self, '_method_c_keypad', None)
    if keypad is not None:
        try:
            if enabled:
                place_cfg = getattr(self, '_method_c_keypad_place', None) or {}
                keypad.place(
                    x=place_cfg.get('x', 0),
                    y=place_cfg.get('y', 0),
                    anchor=place_cfg.get('anchor', 'n')
                )
            else:
                keypad.place_forget()
        except Exception:
            pass


def _fixed137_method_c_sync_input_display(self):
    if getattr(self, 'phase', '') != 'input':
        return
    raw = self.entry_var.get()
    if raw:
        self.big_label.configure(
            fg='#5f646d',
            font=self._fixed137_digit_font,
            justify='center',
            anchor='center',
            wraplength=self._display_wrap,
            width=16,
        )
        self.big_var.set(raw)
    else:
        self.big_label.configure(
            fg=PDF_TURQUOISE_BG,
            font=self._fixed137_digit_font,
            justify='center',
            anchor='center',
            wraplength=self._display_wrap,
            width=16,
        )
        self.big_var.set('')


def _fixed137_method_c_normalize_entry(self):
    raw = ''.join(ch for ch in self.entry_var.get() if ch.isdigit())
    max_len = max(2, int(getattr(self, 'stage_index', 1) or 1) + 1)
    if len(raw) > max_len:
        raw = raw[:max_len]
    if raw != self.entry_var.get():
        self.entry_var.set(raw)
    _fixed137_method_c_sync_input_display(self)


def _fixed137_method_c_append_digit(self, digit: str):
    if getattr(self, 'phase', '') != 'input':
        return
    _fixed137_method_c_normalize_entry(self)
    current = self.entry_var.get()
    max_len = max(2, int(getattr(self, 'stage_index', 1) or 1) + 1)
    if len(current) >= max_len:
        return
    self.entry_var.set(f'{current}{digit}')
    _fixed137_method_c_sync_input_display(self)
    try:
        self.entry.focus_set()
        self.entry.icursor(tk.END)
    except Exception:
        pass


def _fixed137_method_c_clear_input(self):
    if getattr(self, 'phase', '') != 'input':
        return
    self.entry_var.set('')
    _fixed137_method_c_sync_input_display(self)
    try:
        self.entry.focus_set()
    except Exception:
        pass


def _fixed137_method_c_build_ui(self):
    self.win = tk.Toplevel(self.parent)
    self.win.title('\u0421\u041f\u0420 - \u0422\u0435\u0441\u0442 C')
    self.win.configure(bg=PDF_TURQUOISE_BG)
    self.win.transient(self.parent)
    self.win.grab_set()
    try:
        self.win.attributes('-fullscreen', True)
    except tk.TclError:
        self.win.geometry(f"{self.parent.winfo_screenwidth()}x{self.parent.winfo_screenheight()}+0+0")
    self.win.bind('<Escape>', lambda _e: self._abort())
    self.win.protocol('WM_DELETE_WINDOW', self._abort)
    try:
        self.win.lift()
        self.win.focus_force()
    except Exception:
        pass

    sw, sh, scale = _fixed88_screen_metrics(self.win)

    self.win.grid_columnconfigure(0, weight=1)
    self.win.grid_rowconfigure(0, weight=1)

