    side_btn_w = max(10, int(shared_btn_w * 0.62))
    shared_padx = max(14, int(20 * scale))
    shared_pady = max(8, int(10 * scale))

    stage_w = max(760, int(min(sw * 0.64, 940 * scale)))
    stage_h = max(780, int(min(sh * 0.90, 920 * scale)))
    prompt_h = max(52, int(60 * scale))
    display_h = max(210, int(240 * scale))
    keypad_w = max(520, int(stage_w * 0.62))
    keypad_h = max(320, int(350 * scale))
    keypad_cols = 5
    keypad_rows = 2
    panel_pad_x = max(18, int(26 * scale))
