def _fixed151_method_c_restyle_keypad(self):
    keypad = getattr(self, '_method_c_keypad', None)
    if keypad is not None:
        try:
            keypad.configure(bg='#ead6c8', highlightbackground='#bda592')
        except Exception:
            pass
    for widget in getattr(self, '_method_c_input_widgets', [])[2:]:
        try:
            if not str(widget.cget('text')).isdigit():
                continue
        except Exception:
            continue
        try:
            widget.configure(
                bg='#f7e9df',
                activebackground='#efdfd5',
                fg='#3a3a3a',
                font=self._fixed137_digit_font,
                bd=1,
                relief='solid',
                highlightthickness=1,
                highlightbackground='#ccb7a6',
                highlightcolor='#ccb7a6',
                padx=0,
                pady=0,
            )
            widget.grid_configure(padx=2, pady=2)
        except Exception:
            pass



