def _fixed150_method_c_feedback_clear(self):
    frame = getattr(self, '_method_c_feedback_frame', None)
    if frame is not None:
        try:
            frame.place_forget()
        except Exception:
            pass
    for attr in (
        '_method_c_feedback_text_var',
        '_method_c_feedback_line1_var',
        '_method_c_feedback_line2_var',
        '_method_c_feedback_number_var',
    ):
        var = getattr(self, attr, None)
        if var is not None:
            try:
                var.set('')
            except Exception:
                pass



def _fixed150_method_c_feedback_show(self, text: str, number: int | str | None = None):
    frame = getattr(self, '_method_c_feedback_frame', None)
    if frame is None:
        return
    text_value = '' if text is None else str(text)
    lines = text_value.splitlines()
    line1 = lines[0] if len(lines) > 0 else text_value
    line2 = lines[1] if len(lines) > 1 else ''

    text_var = getattr(self, '_method_c_feedback_text_var', None)
    if text_var is not None:
        text_var.set(text_value)
    line1_var = getattr(self, '_method_c_feedback_line1_var', None)
    if line1_var is not None:
        line1_var.set(line1)
    line2_var = getattr(self, '_method_c_feedback_line2_var', None)
    if line2_var is not None:
        line2_var.set(line2)
    number_var = getattr(self, '_method_c_feedback_number_var', None)
    if number_var is not None:
        number_var.set('' if number is None else str(number))

    try:
        frame.place(relx=0.5, rely=0.5, anchor='center')
        frame.lift()
    except Exception:
        pass



