# ====== FIXED161: Method B starts with first figure visible and tray hidden ======

_FIXED161_PREV_METHOD_B_BUILD_UI = MethodBWindow._build_ui
_FIXED161_PREV_METHOD_B_START_CYCLE = MethodBWindow._start_cycle
_FIXED161_PREV_METHOD_B_START_REPRODUCTION_PHASE = MethodBWindow._start_reproduction_phase


def _fixed161_method_b_hide_tray_panel(self):
    tray_panel = getattr(self, '_method_b_tray_panel', None)
    if tray_panel is None:
        tray_frame = getattr(self, 'tray_frame', None)
        tray_panel = tray_frame.master if tray_frame is not None else None
    if tray_panel is None:
        return
    self._method_b_tray_panel = tray_panel
    try:
        tray_panel.pack_forget()
    except Exception:
        pass



def _fixed161_method_b_show_tray_panel(self):
    tray_panel = getattr(self, '_method_b_tray_panel', None)
    if tray_panel is None:
        tray_frame = getattr(self, 'tray_frame', None)
        tray_panel = tray_frame.master if tray_frame is not None else None
    if tray_panel is None:
        return
    self._method_b_tray_panel = tray_panel
    try:
        if not tray_panel.winfo_manager():
            tray_panel.pack(pady=(0, 0))
    except Exception:
        try:
            tray_panel.pack(pady=(0, 0))
        except Exception:
            pass



def _fixed161_method_b_prepare_preview_cycle(self):
    n = max(1, min(self.cfg.max_items, int(getattr(self, 'current_n', 1) or 1)))
    all_cells = list(range(self.cfg.grid_size ** 2))
    random.shuffle(all_cells)
    self.current_positions = sorted(all_cells[:n])

    ordered_shapes = [s for s in _FIXED71_SHAPE_ORDER if s < len(BASIC_SYMBOLS)]
    self.current_shapes = ordered_shapes[:n]
    self.all_tray_shapes = list(self.current_shapes)
    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    self.phase = 'preview'
    self.cycle_started_at = 0.0
    self.message_var.set('')
    self.selection_var.set('')
    self._draw_memory_matrix()
    self._draw_tray(show=False)
    _fixed161_method_b_hide_tray_panel(self)
    self._method_b_preview_ready = True



def _fixed161_method_b_build_ui(self):
    _FIXED161_PREV_METHOD_B_BUILD_UI(self)
    try:
        self._method_b_tray_panel = self.tray_frame.master
    except Exception:
        self._method_b_tray_panel = None
    _fixed161_method_b_prepare_preview_cycle(self)



def _fixed161_method_b_start_cycle(self):
    self._method_b_preview_ready = False
    _fixed161_method_b_hide_tray_panel(self)
    return _FIXED161_PREV_METHOD_B_START_CYCLE(self)



def _fixed161_method_b_start_reproduction_phase(self):
    _fixed161_method_b_show_tray_panel(self)
    return _FIXED161_PREV_METHOD_B_START_REPRODUCTION_PHASE(self)



def _fixed161_method_b_begin_from_preview(self):
    if not getattr(self, '_method_b_preview_ready', False):
        return self._start_cycle()
    self._method_b_preview_ready = False
    self.phase = 'memorize'
    self.cycle_started_at = time.perf_counter()
    self.all_tray_shapes = list(self.current_shapes)
    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    return self._start_reproduction_phase()



def _fixed161_method_b_run(self):
    self._build_ui()

    def _start():
        try:
            self.start_btn.destroy()
        except Exception:
            pass
        try:
            self._time_col.grid()
        except Exception:
            pass
        self.total_start = time.perf_counter()
        self.logger.log_event(
            self.session,
            event_type='method_session',
            screen='method_b',
            test_name='method_b',
            action='started',
            note='\u0417\u0430\u043f\u0443\u0449\u0435\u043d\u0430 \u043c\u0435\u0442\u043e\u0434\u0438\u043a\u0430 B: Memory 4x4'
        )
        _fixed161_method_b_begin_from_preview(self)

    self.start_btn.configure(command=_start)
    self.parent.wait_window(self.win)
    return self.result


MethodBWindow._build_ui = _fixed161_method_b_build_ui
MethodBWindow._start_cycle = _fixed161_method_b_start_cycle
MethodBWindow._start_reproduction_phase = _fixed161_method_b_start_reproduction_phase
MethodBWindow.run = _fixed161_method_b_run


