_FIXED164_PREV_METHOD_C_BUILD_UI = MethodCWindow._build_ui
_FIXED164_PREV_METHOD_C_START_STAGE = MethodCWindow._start_stage
_FIXED164_PREV_METHOD_C_START_OPERATION_CYCLE = MethodCWindow._start_operation_cycle
_FIXED164_GREEN = '#18a74a'
_FIXED164_NEGATIVE = '#c93232'


def _fixed164_method_c_apply_big_value(self, value, color):
    try:
        self.big_label.configure(
            fg=color,
            font=self._fixed137_digit_font,
            justify='center',
            anchor='center',
            wraplength=self._display_wrap,
            width=16,
        )
    except Exception:
        pass
    self.big_var.set('' if value is None else str(value))


def _fixed150_method_c_feedback_show(self, text: str, number: int | str | None = None):
    frame = getattr(self, '_method_c_feedback_frame', None)
    if frame is not None:
        text_var = getattr(self, '_method_c_feedback_text_var', None)
        if text_var is not None:
            text_var.set('' if text is None else str(text))
        place_cfg = getattr(self, '_method_c_feedback_place', {}) or {}
        try:
            frame.place(
                relx=place_cfg.get('relx', 0.5),
                y=place_cfg.get('y', 0),
                anchor=place_cfg.get('anchor', 'n'),
                width=place_cfg.get('width'),
                height=place_cfg.get('height'),
            )
            frame.lift()
        except Exception:
            pass
    if number is not None:
        _fixed164_method_c_apply_big_value(self, number, _FIXED164_GREEN)


def _fixed164_method_c_build_ui(self):
    _FIXED164_PREV_METHOD_C_BUILD_UI(self)

    if getattr(self, 'big_var', None) is not None and self.big_var.get():
        _fixed164_method_c_apply_big_value(self, self.big_var.get(), _FIXED164_GREEN)

    for btn in (getattr(self, 'clear_btn', None), getattr(self, 'answer_btn', None)):
        if btn is None:
            continue
        try:
            btn.configure(
                bd=4,
                relief='raised',
                overrelief='sunken',
                highlightthickness=1,
                highlightbackground='#000000',
                highlightcolor='#000000',
            )
        except Exception:
            pass

    exit_btn = getattr(self, 'exit_btn', None)
    if exit_btn is not None:
        try:
            exit_btn.configure(
                bd=2,
                relief='raised',
                overrelief='sunken',
                highlightthickness=1,
                highlightbackground='#000000',
                highlightcolor='#000000',
            )
        except Exception:
            pass

    for widget in getattr(self, '_method_c_input_widgets', [])[2:]:
        try:
            widget.configure(
                fg=_FIXED164_GREEN,
                activeforeground=_FIXED164_GREEN,
            )
        except Exception:
            pass


def _fixed164_method_c_start_stage(self, stage_index: int):
    _FIXED164_PREV_METHOD_C_START_STAGE(self, stage_index)
    if getattr(self, 'win', None) and self.win.winfo_exists():
        _fixed164_method_c_apply_big_value(self, self.current_value, _FIXED164_GREEN)


def _fixed164_method_c_start_operation_cycle(self):
    _FIXED164_PREV_METHOD_C_START_OPERATION_CYCLE(self)
    if not (getattr(self, 'win', None) and self.win.winfo_exists()):
        return
    if getattr(self, 'phase', '') != 'show_operand':
        return
    color = _FIXED164_GREEN if getattr(self, 'current_op', '+') == '+' else _FIXED164_NEGATIVE
    _fixed164_method_c_apply_big_value(self, getattr(self, 'current_operand', ''), color)


