_FIXED165_PREV_METHOD_C_BUILD_UI = MethodCWindow._build_ui


def _fixed165_method_c_build_ui(self):
    _FIXED165_PREV_METHOD_C_BUILD_UI(self)

    btn = getattr(self, 'answer_btn', None)
    if btn is None:
        return

    try:
        btn.configure(width=max(16, int(btn.cget('width'))), anchor='center', justify='center')
    except Exception:
        pass

    try:
        self.win.update_idletasks()
    except Exception:
        pass

    try:
        current_x = int(btn.place_info().get('x', 0))
    except Exception:
        current_x = 0

    host = getattr(btn, 'master', None)
    try:
        host_w = int(host.winfo_width()) if host is not None else 0
    except Exception:
        host_w = 0
    if host_w <= 1:
        try:
            host_w = int(host.winfo_reqwidth()) if host is not None else 0
        except Exception:
            host_w = 0

    try:
        btn_w = int(btn.winfo_reqwidth())
    except Exception:
        btn_w = 0

    if host_w > 0 and btn_w > 0:
        safe_x = max(6, host_w - btn_w - 12)
        btn.place_configure(x=min(current_x, safe_x))


