# ====== FIXED169: Method C side buttons are raised/pressable; Exit moves left ======

_FIXED169_PREV_METHOD_C_BUILD_UI = MethodCWindow._build_ui


def _fixed169_method_c_make_pressable(btn):
    if btn is None:
        return
    try:
        btn.configure(
            bd=4,
            relief='raised',
            overrelief='raised',
            highlightthickness=1,
            highlightbackground='#000000',
            highlightcolor='#000000',
        )
    except Exception:
        pass

    def _raise(_event=None):
        try:
            btn.configure(relief='raised')
        except Exception:
            pass

    def _sink(_event=None):
        try:
            btn.configure(relief='sunken')
        except Exception:
            pass

    try:
        btn.bind('<ButtonPress-1>', _sink, add='+')
        btn.bind('<ButtonRelease-1>', _raise, add='+')
        btn.bind('<Leave>', _raise, add='+')
    except Exception:
        pass


def _fixed169_method_c_build_ui(self):
    _FIXED169_PREV_METHOD_C_BUILD_UI(self)

    _fixed169_method_c_make_pressable(getattr(self, 'clear_btn', None))
    _fixed169_method_c_make_pressable(getattr(self, 'answer_btn', None))

    exit_btn = getattr(self, 'exit_btn', None)
    if exit_btn is not None:
        try:
            exit_btn.grid_configure(padx=(0, 212))
        except Exception:
            pass


MethodCWindow._build_ui = _fixed169_method_c_build_ui



# ====== FIXED179: rebuild Method B cleanly from fixed169 without extra text layers ======

_FIXED179_PREV_METHOD_B_BUILD_UI = MethodBWindow._build_ui


def _fixed179_method_b_make_pressable(btn):
    if btn is None:
        return
    try:
        btn.configure(
            bd=3,
            relief='raised',
            overrelief='raised',
            highlightthickness=1,
            highlightbackground='#000000',
            highlightcolor='#000000',
        )
    except Exception:
        pass

    def _raise(_event=None):
        try:
            btn.configure(relief='raised')
        except Exception:
            pass

    def _sink(_event=None):
        try:
            btn.configure(relief='sunken')
        except Exception:
            pass

    try:
        btn.bind('<ButtonPress-1>', _sink, add='+')
        btn.bind('<ButtonRelease-1>', _raise, add='+')
        btn.bind('<Leave>', _raise, add='+')
    except Exception:
        pass



def _fixed179_method_b_grid_pad(self):
    cells = getattr(self, 'grid_cells', [])
    if not cells:
        return 4
    try:
        padx = cells[0].grid_info().get('padx', 4)
        return int(padx)
    except Exception:
        return 4



def _fixed179_method_b_bind_controls(self):
    self._method_b_clear_btn = None
    self._method_b_next_btn = None
    self._method_b_action_row = None
    main = getattr(self, 'matrix_frame', None)
    main = main.master if main is not None else None
    if main is None:
        return
    for child in main.winfo_children():
        try:
            buttons = [w for w in child.winfo_children() if isinstance(w, tk.Button)]
        except Exception:
            buttons = []
        if len(buttons) >= 2:
            try:
                child.update_idletasks()
                buttons.sort(key=lambda btn: btn.winfo_x())
            except Exception:
                pass
            self._method_b_action_row = child
            self._method_b_clear_btn = buttons[0]
            self._method_b_next_btn = buttons[-1]
            break



def _fixed179_method_b_style_ui(self):
    self._matrix_bg = '#ffffff'
    self._tray_bg = '#ffffff'
    self._matrix_cell_border = '#000000'
    self._matrix_cell_border_active = '#000000'

    size = max(1, int(round(float(getattr(self, '_matrix_cell_size', 122)) * 1.05)))
    tray_size = size
    self._matrix_cell_size = size
    self._tray_cell_size = tray_size
    self._matrix_symbol_margin = max(6, int(size * 0.05))
    self._tray_symbol_margin = self._matrix_symbol_margin
    self._matrix_symbol_scale = 1.62
    self._tray_symbol_scale = self._matrix_symbol_scale

    matrix_pad = _fixed179_method_b_grid_pad(self)
    self._method_b_matrix_total_w = int(size * 4 + matrix_pad * 8)

    for cell in getattr(self, 'grid_cells', []):
        try:
            cell.configure(
                width=size,
                height=size,
                bg='#ffffff',
                highlightthickness=1,
                highlightbackground='#000000',
                bd=0,
            )
        except Exception:
            pass

    tray_panel = getattr(self, 'tray_frame', None)
    tray_panel = tray_panel.master if tray_panel is not None else None
    if tray_panel is not None:
        self._method_b_tray_panel = tray_panel
        tray_h = int(round(tray_size * 2 + 24))
        try:
            tray_panel.configure(
                bg='#ffffff',
                bd=1,
                relief='solid',
                width=self._method_b_matrix_total_w,
                height=tray_h,
            )
            tray_panel.pack_propagate(False)
        except Exception:
            pass

    if getattr(self, 'tray_frame', None) is not None:
        try:
            self.tray_frame.configure(
                bg='#ffffff',
                width=max(120, self._method_b_matrix_total_w - 4),
                height=int(round(tray_size * 2 + 16)),
            )
            self.tray_frame.pack_configure(padx=2, pady=(4, 4))
            self.tray_frame.pack_propagate(False)
            self.tray_frame.grid_propagate(False)
        except Exception:
            pass

    _fixed179_method_b_bind_controls(self)

    for btn in (
        getattr(self, '_method_b_clear_btn', None),
        getattr(self, '_method_b_next_btn', None),
        getattr(self, 'start_btn', None),
    ):
        _fixed179_method_b_make_pressable(btn)



def _fixed179_method_b_layout_buttons(self):
    clear_btn = getattr(self, '_method_b_clear_btn', None)
    next_btn = getattr(self, '_method_b_next_btn', None)
    action_row = getattr(self, '_method_b_action_row', None)
    if clear_btn is None or next_btn is None or action_row is None:
        return

    try:
        action_row.configure(bg=PDF_TURQUOISE_BG)
    except Exception:
        pass

    for btn in (clear_btn, next_btn):
        try:
            btn.grid_forget()
        except Exception:
            pass
        try:
            btn.place_forget()
        except Exception:
            pass

    try:
        clear_btn.configure(
            text='\u041e\u0447\u0438\u0441\u0442\u0438\u0442\u044c',
            bg='#f2d64b',
            activebackground='#e3c12d',
            fg='#4f3900',
            width=11,
            padx=19,
            pady=11,
            command=self._clear_placements,
        )
    except Exception:
        pass
    try:
        next_btn.configure(
            text='\u0414\u0430\u043b\u0435\u0435',
            bg='#58cc63',
            activebackground='#43b84f',
            fg='#173b1a',
            width=11,
            padx=19,
            pady=11,
            command=self._submit_cycle,
        )
    except Exception:
        pass

    try:
        action_row.update_idletasks()
    except Exception:
        pass

    matrix_total_w = int(getattr(self, '_method_b_matrix_total_w', 520))
    gap = max(28, int(getattr(self, '_matrix_cell_size', 122) * 0.24))
    clear_w = max(clear_btn.winfo_reqwidth(), clear_btn.winfo_width(), 178)
    next_w = max(next_btn.winfo_reqwidth(), next_btn.winfo_width(), 178)
    row_h = max(clear_btn.winfo_reqheight(), next_btn.winfo_reqheight(), 65)
    row_w = matrix_total_w + clear_w + next_w + gap * 2

    try:
        action_row.configure(width=row_w, height=row_h)
        action_row.pack_propagate(False)
    except Exception:
        pass

    center_x = row_w // 2
    matrix_half = matrix_total_w // 2
    clear_btn.place(x=center_x - matrix_half - gap, y=row_h // 2, anchor='e')
    next_btn.place(x=center_x + matrix_half + gap, y=row_h // 2, anchor='w')



def _fixed179_method_b_refresh_controls(self):
    clear_btn = getattr(self, '_method_b_clear_btn', None)
    next_btn = getattr(self, '_method_b_next_btn', None)
    phase = str(getattr(self, 'phase', 'idle') or 'idle')
    started = bool(getattr(self, '_method_b_started', False))

    if clear_btn is not None:
        clear_state = 'normal' if phase == 'reproduce' else 'disabled'
        try:
            clear_btn.configure(state=clear_state, command=self._clear_placements)
        except Exception:
            pass

    if next_btn is not None:
        next_state = 'disabled'
        if started and phase in ('preview_wait_next', 'reproduce'):
            next_state = 'normal'
        try:
            next_btn.configure(state=next_state, command=self._submit_cycle)
        except Exception:
            pass



def _fixed179_method_b_prepare_preview_cycle(self, started: bool):
    n = max(1, min(self.cfg.max_items, int(getattr(self, 'current_n', 1) or 1)))
    all_cells = list(range(self.cfg.grid_size ** 2))
    random.shuffle(all_cells)
    self.current_positions = sorted(all_cells[:n])

    ordered_shapes = [s for s in _FIXED71_SHAPE_ORDER if s < len(BASIC_SYMBOLS)]
    self.current_shapes = ordered_shapes[:n]
    self.all_tray_shapes = list(self.current_shapes)
    self.placements = {}
    self.available_shapes = list(self.current_shapes)
    self.selected_shape = None
    self.phase = 'preview_wait_next' if started else 'preview'
    self.cycle_started_at = 0.0
    self.message_var.set('')
    self.selection_var.set('')
    self._draw_memory_matrix()
    self._draw_tray(show=False)
    _fixed161_method_b_hide_tray_panel(self)
    try:
        self._update_info_label()
    except Exception:
        pass
    _fixed179_method_b_refresh_controls(self)



def _fixed179_method_b_start_cycle(self):
    _fixed179_method_b_prepare_preview_cycle(self, started=bool(getattr(self, '_method_b_started', False)))



def _fixed179_method_b_start_reproduction_phase(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    self.phase = 'reproduce'
    self.cycle_started_at = time.perf_counter()
    n = len(self.current_positions)
    self.all_tray_shapes = list(self.current_shapes)

    base_repr = float(self.cfg.start_reproduction_s) + _FIXED75_B_REPRO_PER_EXTRA_FIG * max(0, n - 1)
    if n >= 3:
        base_repr += _FIXED98_B_REPRO_BONUS_FROM_THREE + _FIXED98_B_REPRO_BONUS_PER_EXTRA * max(0, n - 3)
    repr_time = max(1.8, base_repr + float(getattr(self, 'reproduction_adjust_s', 0.0)) + 2.0)
    repr_time = min(repr_time, max(1.0, self._time_left_total()))
    self.reproduction_deadline = time.perf_counter() + repr_time
    self.message_var.set('')
    self.selection_var.set('')
    _fixed161_method_b_show_tray_panel(self)
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)
    _fixed179_method_b_refresh_controls(self)
    self._tick_reproduction_timeout()



def _fixed179_method_b_submit_cycle(self):
    phase = str(getattr(self, 'phase', '') or '')
    if phase == 'preview_wait_next':
        _fixed179_method_b_start_reproduction_phase(self)
        return
    if phase == 'reproduce':
        self._finalize_cycle(success=None, reason='submitted')



def _fixed179_method_b_finalize_cycle(self, success: bool | None, reason: str):
    if self.phase != 'reproduce':
        return
    self._cancel_afters()
    success_eval, correct, expected = self._evaluate_cycle()
    if success is None:
        success = success_eval

    elapsed = time.perf_counter() - self.cycle_started_at
    n = len(expected)
    cycle_info = {
        'n': n,
        'success': bool(success),
        'correct_count': int(correct),
        'elapsed_s': _round2(elapsed),
        'reason': reason,
        'positions': list(self.current_positions),
        'shapes': list(self.current_shapes),
    }
    self.result['cycles'].append(cycle_info)
    self.logger.log_event(
        self.session,
        event_type='method_cycle',
        screen='method_b',
        test_name='method_b',
        stage=f'n={n}',
        action='success' if success else 'error',
        elapsed_ms=int(elapsed * 1000),
        value=correct,
        note=f'reason={reason}; placed={len(self.placements)}',
    )

    adaptive_step = max(1.0, float(getattr(self.cfg, 'adaptive_time_step_s', 0.5) or 0.5))
    max_expand = max(6.0, adaptive_step * 8)
    current_exposure_adjust = float(getattr(self, 'exposure_adjust_s', 0.0))
    current_reproduction_adjust = float(getattr(self, 'reproduction_adjust_s', 0.0))
    min_exposure_adjust = -(float(self.cfg.start_exposure_s) - 0.7)
    min_reproduction_adjust = -(float(self.cfg.start_reproduction_s) - 1.0)

    if success:
        self.current_n = min(self.cfg.max_items, self.current_n + 1)
        self.exposure_adjust_s = max(min_exposure_adjust, min(max_expand, current_exposure_adjust - adaptive_step))
        self.reproduction_adjust_s = max(min_reproduction_adjust, min(max_expand * 1.5, current_reproduction_adjust - adaptive_step))
    else:
        self.current_n = max(1, self.current_n - 1)
        self.exposure_adjust_s = max(min_exposure_adjust, min(max_expand, current_exposure_adjust + adaptive_step))
        self.reproduction_adjust_s = max(min_reproduction_adjust, min(max_expand * 1.5, current_reproduction_adjust + adaptive_step))

    if self._time_left_total() <= 1.0:
        self._finish()
        return

    self._start_cycle()



def _fixed179_method_b_draw_memory_matrix(self):
    size = int(getattr(self, '_matrix_cell_size', 122))
    pad = max(6, int(size * 0.055))
    margin = int(getattr(self, '_matrix_symbol_margin', 10))
    scale = float(getattr(self, '_matrix_symbol_scale', 1.36))
    for idx, cell in enumerate(getattr(self, 'grid_cells', [])):
        try:
            cell.configure(width=size, height=size, bg='#ffffff', highlightthickness=1, highlightbackground='#000000', bd=0)
        except Exception:
            pass
        cell.delete('all')
        cell.create_rectangle(pad, pad, size - pad, size - pad, outline='#000000', width=2, fill='#ffffff')
        if idx in self.current_positions:
            shape = self.current_shapes[self.current_positions.index(idx)]
            _fixed73c_draw_symbol(
                cell,
                margin,
                margin,
                size - margin,
                size - margin,
                shape,
                fill='#5a2323',
                outline='#5a2323',
                scale=scale,
                tag='symbol'
            )



