def _fixed179_method_b_draw_tray(self, show=True):
    for child in self.tray_frame.winfo_children():
        child.destroy()
    self.tray_cells.clear()
    if not show:
        return

    items = sorted(list(getattr(self, 'all_tray_shapes', []) or getattr(self, 'current_shapes', [])))
    used = _fixed24_method_b_used_shapes(self)
    size = int(getattr(self, '_tray_cell_size', getattr(self, '_matrix_cell_size', 122)))
    margin = int(getattr(self, '_tray_symbol_margin', 10))
    scale = float(getattr(self, '_tray_symbol_scale', getattr(self, '_matrix_symbol_scale', 1.36)))
    columns = max(1, min(4, len(items)))

    for pos, shape in enumerate(items):
        row, col = divmod(pos, columns)
        is_used = shape in used
        canvas = tk.Canvas(
            self.tray_frame,
            width=size,
            height=size,
            bg='#ffffff',
            highlightthickness=0,
            bd=0,
            cursor='hand2' if not is_used else 'arrow'
        )
        canvas.grid(row=row, column=col, padx=2, pady=4)
        if not is_used:
            _fixed73c_draw_symbol(
                canvas,
                margin,
                margin,
                size - margin,
                size - margin,
                shape,
                fill='#5a2323',
                outline='#5a2323',
                scale=scale,
                tag='symbol'
            )
            canvas.bind('<ButtonPress-1>', lambda e, s=shape, _self=self: _fixed25_method_b_start_drag(_self, e, s))
        self.tray_cells.append(canvas)



