# ====== FIXED190: adaptive shells for different monitor sizes ======

_FIXED190_PREV_STARTPAGE_INIT = StartPageApp.__init__


def _fixed190_startpage_init(self, root: tk.Tk):
    _FIXED190_PREV_STARTPAGE_INIT(self, root)
    try:
        sw = int(self.root.winfo_screenwidth() or 1366)
        sh = int(self.root.winfo_screenheight() or 768)
        min_w = max(820, min(1100, sw - 120))
        min_h = max(620, min(760, sh - 120))
        self.root.minsize(min_w, min_h)
    except Exception:
        pass


def _fixed190_fit_dialog_to_parent(parent: tk.Misc, dialog: tk.Toplevel):
    dialog.update_idletasks()
    req_w = int(dialog.winfo_reqwidth() or dialog.winfo_width() or 560)
    req_h = int(dialog.winfo_reqheight() or dialog.winfo_height() or 320)
    screen_w = int(dialog.winfo_screenwidth() or 1366)
    screen_h = int(dialog.winfo_screenheight() or 768)

    max_w = max(640, screen_w - 40)
    max_h = max(480, screen_h - 48)
    width = min(req_w, max_w)
    height = min(req_h, max_h)

    try:
        parent_x = int(parent.winfo_rootx())
        parent_y = int(parent.winfo_rooty())
        parent_w = int(parent.winfo_width())
        parent_h = int(parent.winfo_height())
    except Exception:
        parent_x, parent_y, parent_w, parent_h = 0, 0, screen_w, screen_h

    x = parent_x + max(12, (parent_w - width) // 2)
    y = parent_y + max(12, (parent_h - height) // 2)
    x = max(0, min(x, screen_w - width))
    y = max(0, min(y, screen_h - height))
    dialog.geometry(f'{width}x{height}+{x}+{y}')


def _fixed190_show_test_completed_dialog(self, code: str):
    dialog = tk.Toplevel(self.root)
    dialog.title(f'{TEST_LABELS[code]} завершён')
    dialog.configure(bg=BG_COLOR)
    dialog.transient(self.root)
    dialog.grab_set()
    dialog.resizable(True, False)

    frame = tk.Frame(dialog, bg=PANEL_COLOR, bd=2, relief='groove')
    frame.pack(fill='both', expand=True, padx=18, pady=18)

    screen_w = int(dialog.winfo_screenwidth() or 1366)
    text_wrap = max(340, min(760, int(screen_w * 0.50)))

    tk.Label(
        frame,
        text=f'{TEST_LABELS[code]} завершён',
        bg=PANEL_COLOR,
        fg=TITLE_COLOR,
        font=('Arial', 20, 'bold'),
    ).pack(pady=(12, 10))

    all_done = self.current_profile and self.progress_store.next_test_code(self.current_profile) is None
    descr = (
        'Можно сразу открыть наглядный экран с результатами или вернуться в меню.'
        if not all_done
        else 'Все методики завершены. Можно открыть общий профиль СПР или вернуться в меню.'
    )
    tk.Label(
        frame,
        text=descr,
        bg=PANEL_COLOR,
        fg=TEXT_COLOR,
        justify='center',
        font=('Arial', 12, 'bold'),
        wraplength=text_wrap,
    ).pack(padx=18, pady=(0, 16))

    btns = tk.Frame(frame, bg=PANEL_COLOR)
    btns.pack(pady=(0, 14))
    primary_text = 'ОБЩИЙ\nПРОФИЛЬ СПР' if all_done else 'ПОСМОТРЕТЬ\nСВОИ РЕЗУЛЬТАТЫ'
    primary_cmd = (lambda: (dialog.destroy(), _show_integral_results(self))) if all_done else (lambda: (dialog.destroy(), self.view_results(code)))
    tk.Button(
        btns,
        text=primary_text,
        command=primary_cmd,
        bg=RESULT_BG,
        activebackground=RESULT_ACTIVE,
        relief='raised',
        bd=3,
        cursor='hand2',
        font=('Arial', 12, 'bold'),
        width=18,
        height=2,
    ).pack(side='left', padx=(0, 12))
    tk.Button(
        btns,
        text='В МЕНЮ',
        command=dialog.destroy,
        bg=NEXT_BG,
        activebackground=NEXT_ACTIVE,
        relief='raised',
        bd=3,
        cursor='hand2',
        font=('Arial', 12, 'bold'),
        width=12,
        height=2,
    ).pack(side='left')

    _fixed190_fit_dialog_to_parent(self.root, dialog)
    self.root.wait_window(dialog)


