# ====== FIXED193: B/C use only total test timer, without per-task timeouts ======
_FIXED193_PREV_METHOD_B_START_REPRODUCTION_PHASE = MethodBWindow._start_reproduction_phase
_FIXED193_PREV_METHOD_B_COMPUTE_SUMMARY = MethodBWindow._compute_summary
_FIXED193_PREV_METHOD_C_RUN = MethodCWindow.run
_FIXED193_PREV_METHOD_C_START_OPERATION_CYCLE = MethodCWindow._start_operation_cycle
_FIXED193_PREV_METHOD_C_BEGIN_INPUT_PHASE = MethodCWindow._begin_input_phase
_FIXED193_PREV_METHOD_C_TICK_STAGE_CLOCK = MethodCWindow._tick_stage_clock
_FIXED193_PREV_METHOD_C_COMPUTE_SUMMARY = MethodCWindow._compute_summary


def _fixed193_method_b_total_guard_tick(self):
    if not self.win or not self.win.winfo_exists():
        return
    try:
        self._update_info_label()
    except Exception:
        pass
    if self._time_left_total() <= 0.05:
        self._finish()
        return
    self._track_after(self.win.after(120, self._fixed193_total_guard_tick))


def _fixed193_method_b_start_reproduction_phase(self):
    _FIXED193_PREV_METHOD_B_START_REPRODUCTION_PHASE(self)
    # Disable per-cycle timeout in reproduction: only global timer limits the test.
    self._cancel_afters()
    if getattr(self, "phase", "") == "reproduce":
        self._track_after(self.win.after(120, self._fixed193_total_guard_tick))


def _fixed193_method_b_compute_summary(self):
    summary = _FIXED193_PREV_METHOD_B_COMPUTE_SUMMARY(self)
    try:
        summary["total_time_s"] = _round2(float(getattr(self, "_elapsed_total", lambda: 0.0)()))
    except Exception:
        summary["total_time_s"] = 0.0
    return summary


def _fixed193_method_c_total_time_left(self) -> float:
    total_cfg = float(getattr(self.cfg, "total_test_s", 0.0) or 0.0)
    if total_cfg <= 0.0:
        stage_cfg = getattr(self.cfg, "stage_time_s", [40.0, 40.0, 40.0]) or [40.0, 40.0, 40.0]
        total_cfg = float(sum(float(x) for x in stage_cfg))
    started = float(getattr(self, "total_started_at", 0.0) or 0.0)
    if started <= 0.0:
        return total_cfg
    return max(0.0, total_cfg - (time.perf_counter() - started))


def _fixed193_method_c_should_advance_stage(self) -> bool:
    stage = int(getattr(self, "stage_index", 1) or 1)
    if stage >= 3:
        return False
    stage_cfg = getattr(self.cfg, "stage_time_s", [40.0, 40.0, 40.0]) or [40.0, 40.0, 40.0]
    portions = [max(0.001, float(x)) for x in stage_cfg[:3]]
    total_portion = sum(portions)
    elapsed = max(0.0, float(getattr(self.cfg, "total_test_s", total_portion)) - self._fixed193_total_time_left())
    boundary = float(getattr(self.cfg, "total_test_s", total_portion)) * (sum(portions[:stage]) / total_portion)
    return elapsed >= boundary


def _fixed193_method_c_run(self):
    self.total_started_at = time.perf_counter()
    return _FIXED193_PREV_METHOD_C_RUN(self)


def _fixed193_method_c_tick_stage_clock(self):
    if not self.win or not self.win.winfo_exists() or getattr(self, "phase", "") == "finished":
        return
    if self._fixed193_total_time_left() <= 0.05:
        self._finish()
        return
    self.info_var.set(
        f'Этап {self.stage_index} из 3    Цифр в числе: {self.stage_index}    '
        f'Осталось времени теста: {_fmt_sec(self._fixed193_total_time_left())}    '
        f'Экспозиция: {self.exp_s:.0f} с    Ввод: {self.input_s:.0f} с'
    )
    self._track_after(self.win.after(150, self._tick_stage_clock))


def _fixed193_method_c_start_operation_cycle(self):
    if self._fixed193_total_time_left() <= 0.05:
        self._finish()
        return
    if self._fixed193_should_advance_stage():
        self.prompt_var.set(f'Этап {self.stage_index} завершён. Переход к следующему.')
        self.big_var.set('')
        self.entry.configure(state='disabled')
        self._tick_stage_clock()
        self._track_after(self.win.after(700, lambda: self._start_stage(self.stage_index + 1)))
        return
    self._cancel_afters()
    self.phase = 'show_operand'
    self.current_op, self.current_operand, self.current_correct = self._generate_operand(self.current_value, self.stage_index)
    self.current_cycle_started_at = time.perf_counter()
    color = '#2a972f' if self.current_op == '+' else '#b62828'
    action = 'прибавьте' if self.current_op == '+' else 'вычтите'
    self.prompt_var.set(
        f'Используйте текущее число {self.current_value} как исходный результат. '
        f'{action.capitalize()} показанное число.'
    )
    self.big_var.set(str(self.current_operand))
    self.big_label.configure(fg=color)
    self.entry_var.set('')
    self.entry.configure(state='disabled')
    self._tick_stage_clock()
    self._track_after(self.win.after(int(self.exp_s * 1000), self._begin_input_phase))


def _fixed193_method_c_begin_input_phase(self):
    self.phase = 'input'
    self.prompt_var.set('Введите новый результат вычисления.')
    self.big_var.set('')
    self.big_label.configure(fg='#163d7a')
    self.entry.configure(state='normal')
    self.entry.focus_set()
    self.entry.selection_range(0, tk.END)
    self.input_deadline = 0.0
    self._tick_stage_clock()


def _fixed193_method_c_compute_summary(self):
    summary = _FIXED193_PREV_METHOD_C_COMPUTE_SUMMARY(self)
    total_cfg = float(getattr(self.cfg, "total_test_s", 0.0) or 0.0)
    if total_cfg <= 0.0:
        total_cfg = float(sum(float(x) for x in (getattr(self.cfg, "stage_time_s", [40.0, 40.0, 40.0]) or [40.0, 40.0, 40.0])))
    total_left = getattr(self, "_fixed193_total_time_left", lambda: 0.0)()
    summary["total_time_s"] = _round2(max(0.0, total_cfg - total_left))
    return summary


MethodBWindow._fixed193_total_guard_tick = _fixed193_method_b_total_guard_tick
MethodBWindow._start_reproduction_phase = _fixed193_method_b_start_reproduction_phase
MethodBWindow._compute_summary = _fixed193_method_b_compute_summary

MethodCWindow._fixed193_total_time_left = _fixed193_method_c_total_time_left
MethodCWindow._fixed193_should_advance_stage = _fixed193_method_c_should_advance_stage
MethodCWindow.run = _fixed193_method_c_run
MethodCWindow._tick_stage_clock = _fixed193_method_c_tick_stage_clock
MethodCWindow._start_operation_cycle = _fixed193_method_c_start_operation_cycle
MethodCWindow._begin_input_phase = _fixed193_method_c_begin_input_phase
MethodCWindow._compute_summary = _fixed193_method_c_compute_summary


# ====== FIXED194: enforce no per-task timeout in Method B submit/start flow ======
def _fixed194_method_b_start_reproduction_phase(self):
    if not self.win or not self.win.winfo_exists():
        return
    self._cancel_afters()
    self.phase = 'reproduce'
    self.cycle_started_at = time.perf_counter()
    self.all_tray_shapes = list(self.current_shapes)
    self.reproduction_deadline = 0.0
    self.message_var.set('')
    self.selection_var.set('')
    _fixed161_method_b_show_tray_panel(self)
    self._draw_reproduction_matrix()
    self._draw_tray(show=True)
    _fixed179_method_b_refresh_controls(self)
    if self._time_left_total() <= 0.05:
        self._finish()
        return
    self._track_after(self.win.after(120, self._fixed193_total_guard_tick))


def _fixed194_method_b_submit_cycle(self):
    phase = str(getattr(self, 'phase', '') or '')
    if phase == 'preview_wait_next':
        self._start_reproduction_phase()
        return
    if phase == 'reproduce':
        self._finalize_cycle(success=None, reason='submitted')


def _fixed194_method_b_tick_reproduction_timeout(self):
    # Disabled: Method B has only total test timer in fixed194.
    return


MethodBWindow._start_reproduction_phase = _fixed194_method_b_start_reproduction_phase
MethodBWindow._submit_cycle = _fixed194_method_b_submit_cycle
MethodBWindow._tick_reproduction_timeout = _fixed194_method_b_tick_reproduction_timeout


# ====== FIXED195: restore Method C native UI flow, keep only total-test timer ======
def _fixed195_method_c_stage_time_left(self) -> float:
    stage = max(1, int(getattr(self, "stage_index", 1) or 1))
    raw_parts = list(getattr(self.cfg, "stage_time_s", [40.0, 40.0, 40.0]) or [40.0, 40.0, 40.0])[:3]
    parts = [max(0.001, float(x)) for x in raw_parts]
    while len(parts) < 3:
        parts.append(parts[-1] if parts else 40.0)
    total_parts = max(0.001, sum(parts))
    total_cfg = float(getattr(self.cfg, "total_test_s", 0.0) or 0.0)
    if total_cfg <= 0.0:
        total_cfg = float(sum(parts))
    total_left = self._fixed193_total_time_left() if hasattr(self, "_fixed193_total_time_left") else 0.0
    elapsed_total = max(0.0, total_cfg - total_left)
    start_bound = total_cfg * (sum(parts[: stage - 1]) / total_parts)
    end_bound = total_cfg * (sum(parts[:stage]) / total_parts)
    return max(0.0, end_bound - elapsed_total)


def _fixed195_method_c_start_operation_cycle(self):
    if hasattr(self, "_fixed193_total_time_left") and self._fixed193_total_time_left() <= 0.05:
        self._finish()
        return
    _FIXED193_PREV_METHOD_C_START_OPERATION_CYCLE(self)


def _fixed195_method_c_begin_input_phase(self):
    # Keep all original UI behaviors (including keypad / input panel).
    _FIXED193_PREV_METHOD_C_BEGIN_INPUT_PHASE(self)
    # Remove per-task deadline for input; total timer is enforced separately.
    self.input_deadline = 0.0


def _fixed195_method_c_tick_input_timeout(self):
    if getattr(self, "phase", "") != "input":
        return
    if hasattr(self, "_fixed193_total_time_left") and self._fixed193_total_time_left() <= 0.05:
        self._finish()
        return
    # No per-task countdown/timeout; just keep polling total test timer.
    self._track_after(self.win.after(150, self._tick_input_timeout))


MethodCWindow._stage_time_left = _fixed195_method_c_stage_time_left
MethodCWindow._start_operation_cycle = _fixed195_method_c_start_operation_cycle
MethodCWindow._begin_input_phase = _fixed195_method_c_begin_input_phase
MethodCWindow._tick_input_timeout = _fixed195_method_c_tick_input_timeout


# ====== FIXED196: Method C timer bar restored, driven by total test time ======
def _fixed196_method_c_update_hud(self):
    canvas = getattr(self, 'time_bar_canvas', None)
    if canvas is None:
        return
    total_cfg = float(getattr(self.cfg, 'total_test_s', 0.0) or 0.0)
    if total_cfg <= 0.0:
        parts = getattr(self.cfg, 'stage_time_s', [40.0, 40.0, 40.0]) or [40.0, 40.0, 40.0]
        total_cfg = float(sum(float(x) for x in parts))
    left = self._fixed193_total_time_left() if hasattr(self, '_fixed193_total_time_left') else 0.0
    ratio = 1.0 - max(0.0, min(1.0, left / max(1.0, total_cfg)))
    _fixed74_draw_vertical_time_bar(canvas, ratio)


def _fixed196_method_c_tick_stage_clock(self):
    if not self.win or not self.win.winfo_exists() or getattr(self, 'phase', '') == 'finished':
        return
    if hasattr(self, '_fixed193_total_time_left') and self._fixed193_total_time_left() <= 0.05:
        self._finish()
        return
    self.info_var.set(
        f'Этап {self.stage_index} из 3    Цифр в числе: {self.stage_index}    '
        f'Осталось времени теста: {_fmt_sec(self._fixed193_total_time_left() if hasattr(self, "_fixed193_total_time_left") else 0.0)}    '
        f'Экспозиция: {self.exp_s:.0f} с    Ввод: {self.input_s:.0f} с'
    )
    _fixed196_method_c_update_hud(self)
    self._track_after(self.win.after(150, self._tick_stage_clock))


MethodCWindow._tick_stage_clock = _fixed196_method_c_tick_stage_clock


# ====== FIXED197: Method B timer bar updates smoothly (independent 50ms ticker) ======
def _fixed197_method_b_smooth_timer_tick(self):
    if not self.win or not self.win.winfo_exists():
        return
    if not bool(getattr(self, '_method_b_started', False)):
        try:
            self._fixed197_smooth_after_id = self.win.after(50, self._fixed197_smooth_timer_tick)
        except Exception:
            self._fixed197_smooth_after_id = None
        return
    try:
        _fixed74_method_b_update_hud(self)
    except Exception:
        pass
    if str(getattr(self, 'phase', '') or '') == 'finished':
        self._fixed197_smooth_after_id = None
        return
    try:
        self._fixed197_smooth_after_id = self.win.after(50, self._fixed197_smooth_timer_tick)
    except Exception:
        self._fixed197_smooth_after_id = None


def _fixed197_method_b_run(self):
    self._build_ui()
    self._fixed197_smooth_after_id = None

    def _start():
        try:
            self.start_btn.destroy()
        except Exception:
            pass
        try:
            self._time_col.grid()
        except Exception:
            pass
        self.total_start = time.perf_counter()
        self._method_b_started = True
        self.logger.log_event(
            self.session,
            event_type='method_session',
            screen='method_b',
            test_name='method_b',
            action='started',
            note='Запущена методика B: Memory 4x4'
        )
        self.phase = 'preview_wait_next'
        try:
            self._fixed197_smooth_timer_tick()
        except Exception:
            pass
        try:
            self._update_info_label()
        except Exception:
            pass
        _fixed179_method_b_refresh_controls(self)

    self.start_btn.configure(command=_start)
    self.parent.wait_window(self.win)
    return self.result


MethodBWindow._fixed197_smooth_timer_tick = _fixed197_method_b_smooth_timer_tick
MethodBWindow.run = _fixed197_method_b_run


