# ====== FIXED199: Method A formulas and settings aligned with "СЛЕЖЕНИЕ ОБРАБОТКА.docx" ======
from dataclasses import dataclass as _fixed199_dataclass, fields as _fixed199_fields

_FIXED199_BASE_METHOD_A_CLASS = MethodAConfig
_FIXED199_METHOD_A_CALC_VERSION = 'fixed199_docx_formula_full_trace_v1'


@_fixed199_dataclass
class MethodAConfigFixed199(_FIXED199_BASE_METHOD_A_CLASS):
    y_lim_per_sec: float = 200.0
    y_limit_t_norm_s: float = 60.0
    n_dop_for_60s: float = 20.0
    v_avg_norm_stage_1: float = 3.0
    v_avg_norm_stage_2: float = 6.0
    v_avg_norm_stage_3: float = 0.52


MethodAConfig = MethodAConfigFixed199
MethodAConfigFixed100 = MethodAConfigFixed199
globals()['MethodAConfig'] = MethodAConfigFixed199
globals()['MethodAConfigFixed100'] = MethodAConfigFixed199


_fixed199_prev_load_config = load_config


def load_config(path: str | Path = 'method_a_config.json', screen_w: int | None = None, screen_h: int | None = None) -> MethodAConfigFixed199:
    raw = {}
    p = Path(path)
    if p.exists():
        try:
            loaded = json.loads(p.read_text(encoding='utf-8'))
            if isinstance(loaded, dict):
                raw = dict(loaded)
        except Exception:
            raw = {}

    legacy_cfg = None
    try:
        legacy_cfg = _fixed199_prev_load_config(path=path, screen_w=screen_w, screen_h=screen_h)
    except Exception:
        legacy_cfg = None

    base_field_names = {f.name for f in _fixed199_fields(_FIXED199_BASE_METHOD_A_CLASS)}
    if legacy_cfg is None:
        base_kwargs = {k: v for k, v in raw.items() if k in base_field_names}
        try:
            legacy_cfg = _FIXED199_BASE_METHOD_A_CLASS(**base_kwargs)
        except Exception:
            legacy_cfg = _FIXED199_BASE_METHOD_A_CLASS()
        if screen_w and screen_h:
            legacy_cfg.width = max(1000, int(screen_w))
            legacy_cfg.height = max(700, int(screen_h))

    inherited_kwargs = {}
    for fld in _fixed199_fields(_FIXED199_BASE_METHOD_A_CLASS):
        try:
            inherited_kwargs[fld.name] = getattr(legacy_cfg, fld.name)
        except Exception:
            inherited_kwargs[fld.name] = fld.default

    cfg = MethodAConfigFixed199(**inherited_kwargs)

    for key in (
        'y_lim_per_sec',
        'y_limit_t_norm_s',
        'n_dop_for_60s',
        'v_avg_norm_stage_1',
        'v_avg_norm_stage_2',
        'v_avg_norm_stage_3',
    ):
        try:
            setattr(cfg, key, float(raw.get(key, getattr(cfg, key))))
        except Exception:
            pass

    cfg.y_lim_per_sec = max(1e-6, float(getattr(cfg, 'y_lim_per_sec', 200.0) or 200.0))
    cfg.y_limit_t_norm_s = max(1e-6, float(getattr(cfg, 'y_limit_t_norm_s', 60.0) or 60.0))
    cfg.n_dop_for_60s = max(1e-6, float(getattr(cfg, 'n_dop_for_60s', 20.0) or 20.0))
    cfg.v_avg_norm_stage_1 = max(1e-6, float(getattr(cfg, 'v_avg_norm_stage_1', 3.0) or 3.0))
    cfg.v_avg_norm_stage_2 = max(1e-6, float(getattr(cfg, 'v_avg_norm_stage_2', 6.0) or 6.0))
    cfg.v_avg_norm_stage_3 = max(1e-6, float(getattr(cfg, 'v_avg_norm_stage_3', 0.52) or 0.52))

    try:
        cfg.stage_time_limit_s = float(getattr(cfg, 'stage_time_limit_stage_1_s', getattr(cfg, 'stage_time_limit_s', 40.0)))
    except Exception:
        cfg.stage_time_limit_s = 120.0
    return cfg


globals()['load_config'] = load_config

