_fixed199_prev_get_research_section_groups = _get_research_section_groups


def _fixed199_get_research_section_groups(code: str, cls):
    groups = _fixed199_prev_get_research_section_groups(code, cls)
    if code != 'A':
        return groups
    hidden_fields = {'stage_time_limit_s', 'stage_crash_limit', 'crash_penalty_ratio', 'y_lim_per_sec', 'error_gain'}
    cleaned_groups = []
    for title, field_names in groups:
        cleaned = [name for name in field_names if name not in hidden_fields]
        if cleaned:
            cleaned_groups.append((title, cleaned))
    return cleaned_groups


globals()['_get_research_section_groups'] = _fixed199_get_research_section_groups


def _fixed199_stage_time_limit_s(self, stage_no: int) -> float:
    try:
        if '_fixed100_get_stage_time_limit' in globals():
            return max(1e-6, float(_fixed100_get_stage_time_limit(self.cfg, int(stage_no))))
    except Exception:
        pass
    return max(1e-6, float(getattr(self.cfg, 'stage_time_limit_s', 40.0) or 40.0))


def _fixed199_active_axes_count(self, stage_no: int) -> int:
    stage = self.stage_defs[int(stage_no)]
    return int(bool(stage.get('x'))) + int(bool(stage.get('y'))) + int(bool(stage.get('z')))


def _fixed199_stage_error_bounds(self, stage_no: int) -> tuple[float, float]:
    stage_no = int(stage_no)
    stage = self.stage_defs[stage_no]
    goal = 0.0
    if stage.get('z'):
        crash = float(_fixed199_active_axes_count(self, stage_no))
    else:
        axis_xy = int(bool(stage.get('x'))) + int(bool(stage.get('y')))
        crash = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0) * max(1, axis_xy))
    return goal, max(goal + 1e-6, float(crash))


def _fixed199_stage_error_limit(self, stage_no: int) -> float:
    t_stage = _fixed199_stage_time_limit_s(self, int(stage_no))
    y_lim = max(1e-6, float(getattr(self.cfg, 'y_lim_per_sec', 200.0) or 200.0))
    t_norm = max(1e-6, float(getattr(self.cfg, 'y_limit_t_norm_s', 60.0) or 60.0))
    return max(1.0, y_lim * t_stage / t_norm)


def _fixed199_current_tracking_error(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[int(stage_no)]
    px_per_cm = max(1e-6, float(getattr(self.cfg, 'px_per_cm', 38.0) or 38.0))
    target_xy = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0) or 3.0))
    work_span_xy = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))

    x_cm = abs(float(getattr(state, 'x_px', 0.0))) / px_per_cm if stage.get('x') else 0.0
    y_cm = abs(float(getattr(state, 'y_px', 0.0))) / px_per_cm if stage.get('y') else 0.0
    x_excess = _fixed73e_clip(max(0.0, x_cm - target_xy), 0.0, work_span_xy) if stage.get('x') else 0.0
    y_excess = _fixed73e_clip(max(0.0, y_cm - target_xy), 0.0, work_span_xy) if stage.get('y') else 0.0

    if not stage.get('z'):
        return float(x_excess + y_excess)

    roll_target = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    roll_span = max(1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0) - roll_target)
    roll_now = abs(float(getattr(state, 'roll_deg', 0.0)))
    # Этап 3: непрерывное рассогласование от центра, а не только "за порогом".
    # Это делает рост столбика ошибки понятным и устойчивым.
    crash_xy_radius = max(1e-6, target_xy + work_span_xy)
    crash_roll = max(1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0))

    x_norm = _fixed73e_clip(x_cm / crash_xy_radius, 0.0, 1.0) if stage.get('x') else 0.0
    y_norm = _fixed73e_clip(y_cm / crash_xy_radius, 0.0, 1.0) if stage.get('y') else 0.0
    roll_norm = _fixed73e_clip(roll_now / crash_roll, 0.0, 1.0) if stage.get('z') else 0.0
    return float(x_norm + y_norm + roll_norm)


def _fixed199_current_speed_value(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[int(stage_no)]
    speed_xy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
    vx = speed_xy if bool(stage.get('x')) else 0.0
    vy = speed_xy if bool(stage.get('y')) else 0.0

    if not stage.get('z'):
        # Для этапа 2: Vср = sqrt(Vx^2 + Vy^2). Для этапа 1 это эквивалентно |Vx|.
        return float((vx * vx + vy * vy) ** 0.5)

    work_span_xy = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))
    roll_target = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    roll_span = max(1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0) - roll_target)
    speed_z = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0))
    # Этап 3: обязательно учитываем и X, и Y, плюс крен.
    return float((vx / work_span_xy) + (vy / work_span_xy) + (speed_z / roll_span))


def _fixed199_normative_speed_value(self, stage_no: int) -> float:
    stage_no = int(stage_no)
    key = {1: 'v_avg_norm_stage_1', 2: 'v_avg_norm_stage_2', 3: 'v_avg_norm_stage_3'}.get(stage_no, 'v_avg_norm_stage_1')
    configured = max(1e-6, float(getattr(self.cfg, key, 0.0) or 0.0))
    if configured > 0.0:
        return configured

    stage = self.stage_defs[stage_no]
    start_xy = abs(float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    vx_norm = start_xy if bool(stage.get('x')) else 0.0
    vy_norm = start_xy if bool(stage.get('y')) else 0.0
    if not stage.get('z'):
        # Норматив для этапов без крена в той же метрике sqrt(Vx^2 + Vy^2).
        return max(1e-6, (vx_norm * vx_norm + vy_norm * vy_norm) ** 0.5)

    work_span_xy = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))
    roll_target = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    roll_span = max(1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0) - roll_target)
    start_z = abs(float(getattr(self.cfg, 'start_speed_z_deg_s', 10.0) or 10.0))
    return max(1e-6, (vx_norm / work_span_xy) + (vy_norm / work_span_xy) + (start_z / roll_span))


def _fixed199_n_dop_value(self, stage_no: int) -> float:
    t_stage = _fixed199_stage_time_limit_s(self, int(stage_no))
    n60 = max(1e-6, float(getattr(self.cfg, 'n_dop_for_60s', 20.0) or 20.0))
    return max(1e-6, n60 * t_stage / 60.0)


def _fixed199_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0

    stage_time_limit = _fixed199_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed199_stage_error_limit(self, stage_no)

    # Y(тек): среднее 10 ошибок по 0.1с; пересчитывается каждую секунду.
    # Y(сигма): сумма всех Y(тек) от 1 до n секунд.
    y_tek_current = 0.0
    y_sigma = 0.0
    sample_buffer: list[float] = []
    sample_tick_accum_s = 0.0
    second_tick_accum_s = 0.0

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        # Сохраняем совместимость визуальной логики подсветки зон.
        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        current_error = _fixed199_current_tracking_error(self, state, stage_no)
        tracking_error_integral += current_error * dt
        speed_integral += _fixed199_current_speed_value(self, state, stage_no) * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= 0.1:
            sample_tick_accum_s -= 0.1
            sample_buffer.append(float(current_error))
            if len(sample_buffer) > 10:
                sample_buffer.pop(0)

        second_tick_accum_s += dt
        while second_tick_accum_s >= 1.0:
            second_tick_accum_s -= 1.0
            y_tek_current = (sum(sample_buffer) / len(sample_buffer)) if sample_buffer else 0.0
            y_sigma += y_tek_current
            report.y_tek_series.append(round(float(y_tek_current), 6))
            report.y_sigma_series.append(round(float(y_sigma), 6))

        report.y_tek_window_avg = float((sum(sample_buffer) / len(sample_buffer)) if sample_buffer else 0.0)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)

        if y_sigma >= stage_max_error:
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; y_tek={y_tek_current:.4f}; y_sigma={y_sigma:.4f}",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(
                report,
                elapsed_s,
                xy_integral,
                roll_integral,
                tracking_error_integral,
                speed_integral,
            )

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        # По задаче: высота столбика ошибки = Y(сигма).
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed199_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    avg_error = float(tracking_error_integral) / total
    report.avg_tracking_error_raw = float(avg_error)
    report.avg_tracking_error = float(avg_error)
    report.avg_tracking_error_effective = float(avg_error)
    report.v_avg = float(speed_integral) / total

    stage_no = int(report.stage_no)
    goal, crash = _fixed199_stage_error_bounds(self, stage_no)
    denom = float(goal) - float(crash)
    if abs(denom) < 1e-9:
        denom = -1.0

    entropy_h = _fixed73e_clip((float(goal) - float(avg_error)) / denom, 0.0, 1.0)
    success_gamma = _fixed73e_clip(1.0 - float(entropy_h), 0.0, 1.0)

    n_dop = _fixed199_n_dop_value(self, stage_no)
    n_real = max(0.0, float(getattr(report, 'crashes', 0) or 0))
    n_avar = _fixed73e_clip(1.0 - (n_real / max(1e-6, n_dop)), 0.0, 1.0)

    v_avg_norm = _fixed199_normative_speed_value(self, stage_no)
    v_ratio = float(report.v_avg) / max(1e-6, float(v_avg_norm))
    t_sled = float(v_ratio) * float(success_gamma) * float(n_avar)

    t_stage = _fixed199_stage_time_limit_s(self, stage_no)
    y_lim = max(1e-6, float(getattr(self.cfg, 'y_lim_per_sec', 200.0) or 200.0))
    t_norm = max(1e-6, float(getattr(self.cfg, 'y_limit_t_norm_s', 60.0) or 60.0))
    y_predel = _fixed199_stage_error_limit(self, stage_no)

    report.entropy_h_raw = float(entropy_h)
    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.success_gamma = float(success_gamma)

    report.tracking_error_target = float(goal)
    report.tracking_error_crash = float(crash)
    report.tracking_error_current_avg = float(avg_error)

    report.crash_coeff_n_avar = float(n_avar)
    report.crash_limit_doc = float(n_dop)
    report.n_real_doc = float(n_real)

    report.v_avg_norm = float(v_avg_norm)
    report.v_ratio = float(v_ratio)
    report.reduced_tempo_tr = float(t_sled)
    report.t_slezh = float(t_sled)

    report.y_lim_per_sec = float(y_lim)
    report.y_limit_t_norm_s = float(t_norm)
    report.error_limit_formula_value = float(y_predel)
    report.error_limit_value = float(y_predel)
    report.stage_time_limit_used_s = float(getattr(report, 'stage_time_limit_used_s', t_stage) or t_stage)
    report.y_tek_current = float(getattr(report, 'y_tek_current', 0.0) or 0.0)
    report.y_sigma = float(getattr(report, 'y_sigma', report.sum_error) or 0.0)
    report.y_tek_window_avg = float(getattr(report, 'y_tek_window_avg', 0.0) or 0.0)
    y_tek_series = getattr(report, 'y_tek_series', [])
    report.y_tek_avg_per_sec = float(sum(y_tek_series) / len(y_tek_series)) if y_tek_series else float(report.y_tek_current)

    report.stage_label_doc = _fixed73e_stage_name(stage_no)
    report.calculation_version = _FIXED199_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED199(doc): Υпредел=Υlim*T/Tнорм; tслеж=(Vср/Vср.норм)*Υслеж*Nавар; '
        'Υслеж=1-H; H=(Rцели-Rтек.ср)/(Rцели-Rаварии); Nавар=1-(Nреал/Nдоп).'
    )
    report.entropy_formula_note = (
        'Υслеж = 1 - H, H = (Rцели - Rтек.ср) / (Rцели - Rаварии), '
        'Nавар = 1 - (Nреал / Nдоп), tслеж = (Vср / Vср.норм) × Υслеж × Nавар.'
    )
    return report


def _fixed199_method_a_summary_from_reports(reports: list[dict]) -> dict:
    reports = [r for r in (reports or []) if isinstance(r, dict)]
    count = max(1, len(reports))
    total_time_s = round(sum(float(r.get('real_time_s', 0.0) or 0.0) for r in reports), 2)
    total_crashes = int(sum(int(r.get('crashes', 0) or 0) for r in reports))
    avg_success_gamma = round(sum(float(r.get('success_gamma', 0.0) or 0.0) for r in reports) / count, 4) if reports else 0.0
    avg_entropy_h = round(sum(float(r.get('entropy_h', 0.0) or 0.0) for r in reports) / count, 4) if reports else 0.0
    avg_n_avar = round(sum(float(r.get('crash_coeff_n_avar', 0.0) or 0.0) for r in reports) / count, 4) if reports else 0.0
    avg_v_ratio = round(sum(float(r.get('v_ratio', 0.0) or 0.0) for r in reports) / count, 4) if reports else 0.0
    avg_reduced_tempo_tr = round(
        sum(float(r.get('t_slezh', r.get('reduced_tempo_tr', 0.0)) or 0.0) for r in reports) / count,
        4
    ) if reports else 0.0
    by_stage = {int(r.get('stage_no', 0) or 0): r for r in reports}
    t_values = {
        'min': round(float(by_stage.get(1, {}).get('t_slezh', by_stage.get(1, {}).get('reduced_tempo_tr', 0.0)) or 0.0), 4),
        'medio': round(float(by_stage.get(2, {}).get('t_slezh', by_stage.get(2, {}).get('reduced_tempo_tr', 0.0)) or 0.0), 4),
        'max': round(float(by_stage.get(3, {}).get('t_slezh', by_stage.get(3, {}).get('reduced_tempo_tr', 0.0)) or 0.0), 4),
    }
    return {
        'calculation_version': _FIXED199_METHOD_A_CALC_VERSION,
        'total_time_s': total_time_s,
        'total_crashes': total_crashes,
        'avg_success_gamma': avg_success_gamma,
        'avg_entropy_h': avg_entropy_h,
        'avg_n_avar': avg_n_avar,
        'avg_v_ratio': avg_v_ratio,
        'avg_reduced_tempo_tr': avg_reduced_tempo_tr,
        't_values': t_values,
        'tmin_a': t_values['min'],
        'tmedio_a': t_values['medio'],
        'tmax_a': t_values['max'],
    }


def _fixed199_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    reports = [r for r in (result.get('reports', []) or []) if isinstance(r, dict)]
    for item in reports:
        item.setdefault('calculation_version', _FIXED199_METHOD_A_CALC_VERSION)
    summary = _fixed199_method_a_summary_from_reports(reports)
    try:
        cfg = load_config(path=self.base_dir / 'method_a_config.json', screen_w=self.root.winfo_screenwidth(), screen_h=self.root.winfo_screenheight())
        summary['method_a_stage_time_limits'] = {
            'stage_1_s': float(getattr(cfg, 'stage_time_limit_stage_1_s', 40.0)),
            'stage_2_s': float(getattr(cfg, 'stage_time_limit_stage_2_s', 40.0)),
            'stage_3_s': float(getattr(cfg, 'stage_time_limit_stage_3_s', 40.0)),
        }
    except Exception:
        pass
    return {
        'test_code': 'A',
        'test_label': TEST_LABELS['A'],
        'completed_at': datetime.now().isoformat(timespec='seconds'),
        'session_id': session.session_id,
        'participant': {
            'name': session.name,
            'age': session.age,
            'gender': session.gender,
        },
        'result_path': result.get('result_path', ''),
        'reports': reports,
        'summary': summary,
        'completed': bool(result.get('completed', False)),
    }


def _fixed199_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    def _num(value, default: float = 0.0) -> float:
        try:
            if isinstance(value, str):
                value = value.replace(',', '.').strip()
            return float(value)
        except Exception:
            return float(default)

    stage_no = int(report.get('stage_no', 0) or 0)
    is_stage3 = stage_no == 3

    r_unit = 'усл. ед.' if is_stage3 else 'см'
    v_unit = 'усл. ед./с' if is_stage3 else 'см/с'

    t_stage = _num(report.get('stage_time_limit_used_s', report.get('real_time_s', 0.0)), 0.0)
    y_lim = _num(report.get('y_lim_per_sec', 0.0), 0.0)
    y_pred = _num(report.get('error_limit_formula_value', report.get('error_limit_value', 0.0)), 0.0)
    v_avg = _num(report.get('v_avg', 0.0), 0.0)
    v_avg_norm = _num(report.get('v_avg_norm', 0.0), 0.0)
    v_ratio = _num(report.get('v_ratio', (v_avg / max(1e-6, v_avg_norm)) if v_avg_norm > 0.0 else 0.0), 0.0)
    r_target = _num(report.get('tracking_error_target', 0.0), 0.0)
    r_avg = _num(report.get('tracking_error_current_avg', report.get('avg_tracking_error', 0.0)), 0.0)
    r_crash = _num(report.get('tracking_error_crash', 0.0), 0.0)
    entropy_h = abs(_num(report.get('entropy_h', 0.0), 0.0))
    gamma = _num(report.get('success_gamma', 0.0), 0.0)
    n_real = _num(report.get('n_real_doc', report.get('crashes', 0.0)), 0.0)
    n_dop = _num(report.get('crash_limit_doc', 0.0), 0.0)
    n_avar = _num(report.get('crash_coeff_n_avar', 0.0), 0.0)
    t_sled = _num(report.get('t_slezh', report.get('reduced_tempo_tr', 0.0)), 0.0)
    y_tek = _num(report.get('y_tek_current', 0.0), 0.0)
    y_tek_avg = _num(report.get('y_tek_avg_per_sec', report.get('y_tek_window_avg', 0.0)), 0.0)
    y_sigma = _num(report.get('y_sigma', report.get('sum_error', 0.0)), 0.0)

    # Backward compatibility for older reports:
    # if combined target/crash radii were not stored explicitly, restore them
    # from per-step axis values and then recompute formula-based H and Y(слеж).
    second_metrics = report.get('second_metrics', [])
    first_row = None
    if isinstance(second_metrics, list):
        for item in second_metrics:
            if isinstance(item, dict):
                first_row = item
                break
    if isinstance(first_row, dict):
        goal_x = _num(first_row.get('goal_x', report.get('goal_x', 0.0)), 0.0)
        goal_y = _num(first_row.get('goal_y', report.get('goal_y', 0.0)), 0.0)
        goal_z = _num(first_row.get('goal_z', report.get('goal_z', 0.0)), 0.0)
        crash_x = _num(first_row.get('crash_x', report.get('crash_x', 0.0)), 0.0)
        crash_y = _num(first_row.get('crash_y', report.get('crash_y', 0.0)), 0.0)
        crash_z = _num(first_row.get('crash_z', report.get('crash_z', 0.0)), 0.0)

        r_target_from_axes = (goal_x * goal_x + goal_y * goal_y + goal_z * goal_z) ** 0.5
        r_crash_from_axes = (crash_x * crash_x + crash_y * crash_y + crash_z * crash_z) ** 0.5
        if r_target_from_axes > 0.0:
            r_target = float(r_target_from_axes)
        if r_crash_from_axes > 0.0:
            r_crash = float(r_crash_from_axes)

    den = float(r_target - r_crash)
    if abs(den) > 1e-9:
        entropy_h = abs(float(r_target - r_avg) / den)
        gamma = 1.0 - float(entropy_h)
        t_sled = float(v_ratio) * float(gamma) * float(n_avar)

    rows = [
        ('Режим', _fixed73e_stage_name(stage_no)),
        ('Контролируемые оси', str(report.get('active_axes', ''))),
        ('Длительность этапа T', f"{t_stage:.1f} с"),
        ('Υlim', f"{y_lim:.4f}"),
        ('Υпредел', f"{y_pred:.4f}"),
        ('Vср', f"{v_avg:.4f} {v_unit}"),
        ('Vср.норм', f"{v_avg_norm:.4f} {v_unit}"),
        ('Vср / Vср.норм', f"{v_ratio:.4f}"),
        ('Rцели', f"{r_target:.4f} {r_unit}"),
        ('Rтек.ср', f"{r_avg:.4f} {r_unit}"),
        ('Rаварии', f"{r_crash:.4f} {r_unit}"),
        ('H = (Rцели - Rтек.ср)/(Rцели - Rаварии)', f"{entropy_h:.4f}"),
        ('Y(слеж) = 1 - H', f"{gamma:.4f}"),
        ('Υслеж = 1 - H', f"{gamma:.4f}"),
        ('Nреал', f"{n_real:.2f}"),
        ('Nдоп', f"{n_dop:.2f}"),
        ('βавар = 1 - (Nреал/Nдоп)', f"{n_avar:.4f}"),
        ('Y(тек), 1с окно', f"{y_tek:.4f}"),
        ('Y(тек) среднее за этап', f"{y_tek_avg:.4f}"),
        ('Y(сигма) = ΣY(тек)', f"{y_sigma:.4f}"),
        ('tслеж = (Vср/Vср.норм) × Y(слеж) × βавар', f"{t_sled:.4f}"),
        ('Версия расчёта', str(report.get('calculation_version', _FIXED199_METHOD_A_CALC_VERSION))),
    ]
    if is_stage3:
        rows.append(('Средний крен', f"{float(report.get('mean_abs_roll_deg', 0.0) or 0.0):.2f}°"))
    else:
        rows.append(('Среднее отклонение X/Y', f"{float(report.get('mean_abs_xy_cm', 0.0) or 0.0):.2f} см"))
    return rows


def _fixed199_show_method_a_results(self, payload: dict):
    top, outer = _open_results_top(self, 'Результаты - Тест А. Слежение за объектом')
    participant = payload.get('participant', {})
    reports = payload.get('reports', [])
    if not reports:
        result_path = payload.get('result_path', '')
        if result_path:
            try:
                rp = Path(result_path)
                if not rp.is_absolute():
                    rp = self.base_dir / rp
                if rp.exists():
                    loaded = json.loads(rp.read_text(encoding='utf-8'))
                    if isinstance(loaded, list):
                        reports = [item for item in loaded if isinstance(item, dict)]
            except Exception:
                reports = []

    summary = dict(payload.get('summary', {}) or {})
    if reports:
        computed = _fixed199_method_a_summary_from_reports(reports)
        for key, value in computed.items():
            if key == 't_values':
                merged = dict(value)
                merged.update(summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {})
                summary['t_values'] = merged
            else:
                summary.setdefault(key, value)
    t_values = summary.get('t_values', {}) if isinstance(summary.get('t_values'), dict) else {}

    completed_at = payload.get('completed_at', '')
    dt_label = completed_at.replace('T', ' ')[:19] if completed_at else 'не указано'

    header = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
    header.pack(fill='x', padx=24, pady=(24, 12))
    tk.Frame(header, bg='#67a9ff', height=8).pack(fill='x')
    head_body = tk.Frame(header, bg='#ffffff')
    head_body.pack(fill='both', expand=True, padx=22, pady=18)
    tk.Label(head_body, text='Тест А · Слежение за объектом', bg='#ffffff', fg='#102744', font=('Arial', 28, 'bold')).pack(anchor='w')
    subtitle = f"{participant.get('name', '')}, {participant.get('age', '')} лет, {participant.get('gender', '')}. Последнее завершение: {dt_label}."
    tk.Label(head_body, text=subtitle, bg='#ffffff', fg='#5a6678', font=('Arial', 12, 'bold'), wraplength=1180, justify='left').pack(anchor='w', pady=(8, 0))

    summary_shell = tk.Frame(outer, bg='#eef3f8')
    summary_shell.pack(fill='x', padx=24, pady=(0, 12))
    summary_grid = tk.Frame(summary_shell, bg='#eef3f8')
    summary_grid.pack(fill='x')
    for col in range(6):
        summary_grid.grid_columnconfigure(col, weight=1, uniform='a_summary199')

    total_crashes = int(summary.get('total_crashes', 0) or 0)
    summary_cards = [
        ('tслеж · X', f"{float(t_values.get('min', 0.0) or 0.0):.4f}", 'Этап 1: одна координата', '#67a9ff', 0, 0),
        ('tслеж · X+Y', f"{float(t_values.get('medio', 0.0) or 0.0):.4f}", 'Этап 2: две координаты', '#53c26b', 0, 2),
        ('tслеж · X+Y+крен', f"{float(t_values.get('max', 0.0) or 0.0):.4f}", 'Этап 3: три координаты', '#c98cff', 0, 4),
        ('Средний Y(слеж)', f"{float(summary.get('avg_success_gamma', 0.0) or 0.0):.4f}", 'Коэффициент успешности (1 - H)', '#7bd0d5', 1, 0),
        ('Средний Nавар', f"{float(summary.get('avg_n_avar', 0.0) or 0.0):.4f}", 'Понижающий коэффициент за аварии', '#ffb35c', 1, 2),
        ('Ошибки за тест', f"{total_crashes}", 'Суммарное число аварий на трёх этапах', '#e26565', 1, 4),
    ]
    for title, value, subtitle, accent, row, col in summary_cards:
        card = self.draw_result_card(summary_grid, title, value, subtitle, accent)
        card.grid(row=row, column=col, columnspan=2, sticky='nsew', padx=8, pady=8)

    info_text = (
        'Формулы по документу: Υпредел = Υlim × T / Tнорм; '
        'H = (Rцели - Rтек.ср)/(Rцели - Rаварии); Y(слеж) = 1 - H; '
        'βавар = 1 - (Nреал/Nдоп); '
        'NдопX = NдопX180 × T / 180; NдопXY = NдопX180 × T / 120; NдопXYZ = NдопX180 × T / 90; '
        'tслеж = (Vср/Vср.норм) × Y(слеж) × βавар.'
    )
    info_box = _add_info_box(outer, 'Как читать результат', info_text, '#6b7dff')
    info_box.pack(fill='x', padx=24, pady=(0, 14))

    stages_title = tk.Frame(outer, bg='#eef3f8')
    stages_title.pack(fill='x', padx=24, pady=(0, 8))
    tk.Label(stages_title, text='Показатели по этапам', bg='#eef3f8', fg='#102744', font=('Arial', 18, 'bold')).pack(anchor='w')
    tk.Label(stages_title, text='Для каждого этапа показаны все подстановки в формулы расчёта tслеж.', bg='#eef3f8', fg='#607187', font=('Arial', 11)).pack(anchor='w', pady=(2, 0))

    if not reports:
        empty = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        empty.pack(fill='x', padx=24, pady=(0, 14))
        tk.Label(empty, text='Подробные данные этапов не найдены.', bg='#ffffff', fg='#102744', font=('Arial', 16, 'bold')).pack(anchor='w', padx=18, pady=(16, 6))
        tk.Label(empty, text='Сводные карточки выше сохранены, но детальный список этапов для этого результата отсутствует.', bg='#ffffff', fg='#506176', font=('Arial', 11), wraplength=1120, justify='left').pack(anchor='w', padx=18, pady=(0, 18))
        return top

    ordered_reports = sorted(reports, key=lambda r: int(r.get('stage_no', 0) or 0))
    for report in ordered_reports:
        card = tk.Frame(outer, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        card.pack(fill='x', padx=24, pady=(0, 14))

        head = tk.Frame(card, bg='#ffffff')
        head.pack(fill='x', padx=18, pady=(16, 8))
        stage_no = int(report.get('stage_no', 0) or 0)
        tk.Label(head, text=f"Этап {stage_no} · {_fixed73e_stage_name(stage_no)}", bg='#ffffff', fg='#102744', font=('Arial', 20, 'bold')).pack(anchor='w')
        tk.Label(head, text=f"tслеж = {float(report.get('t_slezh', report.get('reduced_tempo_tr', 0.0)) or 0.0):.4f}", bg='#ffffff', fg='#4f78ff', font=('Arial', 12, 'bold')).pack(anchor='w', pady=(4, 0))

        grid = tk.Frame(card, bg='#ffffff')
        grid.pack(fill='x', padx=18, pady=(0, 16))
        rows = _fixed199_method_a_stage_metric_rows(report)
        for idx, (label_text, value_text) in enumerate(rows):
            r = idx // 2
            c = (idx % 2) * 2
            tk.Label(grid, text=label_text, bg='#ffffff', fg='#617187', font=('Arial', 10, 'bold'), anchor='w').grid(row=r, column=c, sticky='w', padx=(0, 10), pady=4)
            tk.Label(grid, text=value_text, bg='#ffffff', fg='#102744', font=('Arial', 12, 'bold'), anchor='w').grid(row=r, column=c + 1, sticky='w', padx=(0, 26), pady=4)
        for col in range(4):
            grid.grid_columnconfigure(col, weight=1 if col % 2 else 0)

    return top


globals()['_fixed73e_stage_error_bounds'] = _fixed199_stage_error_bounds
globals()['_fixed97_current_tracking_error'] = _fixed199_current_tracking_error
globals()['_fixed73e_current_speed_value'] = _fixed199_current_speed_value
globals()['_fixed73e_method_a_summary_from_reports'] = _fixed199_method_a_summary_from_reports
globals()['_fixed92_method_a_stage_metric_rows'] = _fixed199_method_a_stage_metric_rows
MethodAApp.stage_smax = _fixed199_stage_error_limit
MethodAApp.run_stage = _fixed199_run_stage
MethodAApp.finalize_stage_report = _fixed199_finalize_stage_report
StartPageApp.build_method_a_payload = _fixed199_build_method_a_payload
StartPageApp.show_method_a_results = _fixed199_show_method_a_results

# ====== FIXED200: Method A aligned with "СЛЕЖЕНИЕ ОБРАБОТКА 22.04.docx" ======
from dataclasses import dataclass as _fixed200_dataclass

_FIXED200_METHOD_A_CALC_VERSION = 'fixed200_doc2204_rss_axes_v1'


@_fixed200_dataclass
class MethodAConfigFixed200(MethodAConfig):
    y_lim_x_per_sec: float = 0.7
    y_lim_y_per_sec: float = 0.7
    y_lim_z_per_sec: float = 0.7


MethodAConfig = MethodAConfigFixed200
globals()['MethodAConfig'] = MethodAConfigFixed200

_fixed200_prev_load_config = load_config


def load_config(path: str | Path = 'method_a_config.json', screen_w: int | None = None, screen_h: int | None = None) -> MethodAConfigFixed200:
    cfg = _fixed200_prev_load_config(path=path, screen_w=screen_w, screen_h=screen_h)
    raw = {}
    p = Path(path)
    if p.exists():
        try:
            loaded = json.loads(p.read_text(encoding='utf-8'))
            if isinstance(loaded, dict):
                raw = dict(loaded)
        except Exception:
            raw = {}

    base = max(1e-6, float(getattr(cfg, 'y_lim_per_sec', 200.0) or 200.0))
    legacy_t_norm = max(1e-6, float(getattr(cfg, 'y_limit_t_norm_s', 60.0) or 60.0))

    # Migration from fixed199 semantics:
    # old effective threshold was Ylim * T / Tnorm; new formula is Ylim * T.
    # To preserve practical scale for existing configs, convert legacy Ylim -> per-second Ylim.
    converted_base = base / legacy_t_norm

    has_new_axis_limits = any(k in raw for k in ('y_lim_x_per_sec', 'y_lim_y_per_sec', 'y_lim_z_per_sec'))
    if not has_new_axis_limits:
        cfg.y_lim_x_per_sec = max(1e-6, float(converted_base))
        cfg.y_lim_y_per_sec = max(1e-6, float(converted_base))
        cfg.y_lim_z_per_sec = max(1e-6, float(converted_base))
    else:
        for key in ('y_lim_x_per_sec', 'y_lim_y_per_sec', 'y_lim_z_per_sec'):
            try:
                setattr(cfg, key, max(1e-6, float(raw.get(key, getattr(cfg, key, converted_base) or converted_base))))
            except Exception:
                setattr(cfg, key, max(1e-6, float(converted_base)))
    return cfg


globals()['load_config'] = load_config

try:
    RESEARCH_FIELD_META['A'].update({
        'y_lim_x_per_sec': {
            'label': 'Υlim X (в сек)',
            'help': 'Лимит ошибки по оси X за 1 секунду.'
        },
        'y_lim_y_per_sec': {
            'label': 'Υlim Y (в сек)',
            'help': 'Лимит ошибки по оси Y за 1 секунду.'
        },
        'y_lim_z_per_sec': {
            'label': 'Υlim Z (в сек)',
            'help': 'Лимит ошибки по крену за 1 секунду.'
        },
    })
    RESEARCH_SECTION_META['A'] = [
        ('Окно и обновление', ['width', 'height', 'fps', 'px_per_cm']),
        ('Зоны и допуски', ['target_half_cm', 'work_extension_cm', 'crash_extension_cm', 'target_roll_deg', 'work_roll_deg']),
        ('Динамика объекта', ['start_speed_xy_cm_s', 'step_speed_xy_cm_s', 'start_speed_z_deg_s', 'step_speed_z_deg_s', 'direction_change_min_s', 'direction_change_max_s', 'speedup_interval_s', 'error_gain']),
        ('Этапы', ['stage_time_limit_stage_1_s', 'stage_time_limit_stage_2_s', 'stage_time_limit_stage_3_s']),
        ('Формулы (docx 22.04)', ['y_lim_x_per_sec', 'y_lim_y_per_sec', 'y_lim_z_per_sec', 'n_dop_for_60s', 'v_avg_norm_stage_1', 'v_avg_norm_stage_2', 'v_avg_norm_stage_3']),
        ('Совместимость', ['y_lim_per_sec', 'y_limit_t_norm_s', 'stage_crash_limit', 'crash_penalty_ratio', 'smax_stage_1', 'smax_stage_2', 'smax_stage_3']),
        ('Управление и оформление', ['mouse_gain_px', 'roll_step_per_wheel_notch_deg', 'bg_color', 'target_color', 'work_color', 'crash_color', 'obj_color', 'text_color', 'grid_color']),
    ]
except Exception:
    pass


def _fixed200_stage_time_limit_s(self, stage_no: int) -> float:
    return _fixed199_stage_time_limit_s(self, stage_no)


def _fixed200_stage_y_lim_per_sec(self, stage_no: int) -> float:
    # Stage-specific entropy limits from slezh_final.docx:
    # Ylim_X, Ylim_XY, Ylim_XYZ (per second).
    st = int(stage_no)
    legacy = float(getattr(self.cfg, 'y_lim_per_sec', 200.0) or 200.0)
    if st == 1:
        value = float(getattr(self.cfg, 'y_lim_x_per_sec', legacy) or legacy)
    elif st == 2:
        value = float(getattr(self.cfg, 'y_lim_y_per_sec', legacy) or legacy)
    else:
        value = float(getattr(self.cfg, 'y_lim_z_per_sec', legacy) or legacy)
    return max(1e-6, value)


def _fixed200_stage_error_limit(self, stage_no: int) -> float:
    # doc 22.04: Υпредел = Υlim * T
    return max(1.0, _fixed200_stage_y_lim_per_sec(self, stage_no) * _fixed200_stage_time_limit_s(self, stage_no))


def _fixed200_axis_snapshot(self, state: DriftState, stage_no: int) -> dict[str, float]:
    stage = self.stage_defs[int(stage_no)]
    px_per_cm = max(1e-6, float(getattr(self.cfg, 'px_per_cm', 38.0) or 38.0))
    target_xy = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0) or 3.0))
    target_roll = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    work_span_xy = max(1e-6, float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))
    crash_xy = target_xy + work_span_xy
    crash_roll = max(target_roll + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0))

    x_cm = abs(float(getattr(state, 'x_px', 0.0))) / px_per_cm if stage.get('x') else 0.0
    y_cm = abs(float(getattr(state, 'y_px', 0.0))) / px_per_cm if stage.get('y') else 0.0
    z_deg = abs(float(getattr(state, 'roll_deg', 0.0))) if stage.get('z') else 0.0

    e_x = _fixed73e_clip(max(0.0, x_cm - target_xy), 0.0, work_span_xy) if stage.get('x') else 0.0
    e_y = _fixed73e_clip(max(0.0, y_cm - target_xy), 0.0, work_span_xy) if stage.get('y') else 0.0
    e_z = _fixed73e_clip(max(0.0, z_deg - target_roll), 0.0, crash_roll - target_roll) if stage.get('z') else 0.0

    return {
        'x_cm': x_cm, 'y_cm': y_cm, 'z_deg': z_deg,
        'e_x': e_x, 'e_y': e_y, 'e_z': e_z,
        'goal_x': target_xy if stage.get('x') else 0.0,
        'goal_y': target_xy if stage.get('y') else 0.0,
        'goal_z': target_roll if stage.get('z') else 0.0,
        'crash_x': crash_xy if stage.get('x') else 0.0,
        'crash_y': crash_xy if stage.get('y') else 0.0,
        'crash_z': crash_roll if stage.get('z') else 0.0,
    }


def _fixed200_current_tracking_error(self, state: DriftState, stage_no: int) -> float:
    snap = _fixed200_axis_snapshot(self, state, stage_no)
    # doc 22.04 for multiple coords: sqrt(sum of squares)
    return float((snap['e_x'] ** 2 + snap['e_y'] ** 2 + snap['e_z'] ** 2) ** 0.5)


def _fixed200_current_speed_value(self, state: DriftState, stage_no: int) -> float:
    stage = self.stage_defs[int(stage_no)]
    vxy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
    vx = vxy if stage.get('x') else 0.0
    vy = vxy if stage.get('y') else 0.0
    vz = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0)) if stage.get('z') else 0.0
    # doc 22.04: VсрXYZ = sqrt(Vx^2 + Vy^2 + Vz^2)
    return float((vx * vx + vy * vy + vz * vz) ** 0.5)


def _fixed200_normative_speed_value(self, stage_no: int) -> float:
    return _fixed199_normative_speed_value(self, stage_no)


def _fixed200_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0
    speed_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_y_lim = _fixed200_stage_y_lim_per_sec(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)

    y_tek_current = 0.0
    y_sigma = 0.0
    sample_buffer: list[float] = []
    sample_tick_accum_s = 0.0
    second_tick_accum_s = 0.0

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.y_lim_per_sec = float(stage_y_lim)
    report.y_lim_x_per_sec = float(getattr(self.cfg, 'y_lim_x_per_sec', stage_y_lim) or stage_y_lim)
    report.y_lim_y_per_sec = float(getattr(self.cfg, 'y_lim_y_per_sec', stage_y_lim) or stage_y_lim)
    report.y_lim_z_per_sec = float(getattr(self.cfg, 'y_lim_z_per_sec', stage_y_lim) or stage_y_lim)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        x_abs_integral += snap['x_cm'] * dt
        y_abs_integral += snap['y_cm'] * dt
        z_abs_integral += snap['z_deg'] * dt

        current_error = _fixed200_current_tracking_error(self, state, stage_no)
        tracking_error_integral += current_error * dt
        speed_integral += _fixed200_current_speed_value(self, state, stage_no) * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= 0.1:
            sample_tick_accum_s -= 0.1
            sample_buffer.append(float(current_error))
            if len(sample_buffer) > 10:
                sample_buffer.pop(0)

        second_tick_accum_s += dt
        while second_tick_accum_s >= 1.0:
            second_tick_accum_s -= 1.0
            y_tek_current = (sum(sample_buffer) / len(sample_buffer)) if sample_buffer else 0.0
            y_sigma += y_tek_current
            report.y_tek_series.append(round(float(y_tek_current), 6))
            report.y_sigma_series.append(round(float(y_sigma), 6))

        report.y_tek_window_avg = float((sum(sample_buffer) / len(sample_buffer)) if sample_buffer else 0.0)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; y_tek={y_tek_current:.4f}; y_sigma={y_sigma:.4f}",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed200_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))

    x_avg = float(getattr(report, '_fixed200_x_abs_integral', 0.0) or 0.0) / total
    y_avg = float(getattr(report, '_fixed200_y_abs_integral', 0.0) or 0.0) / total
    z_avg = float(getattr(report, '_fixed200_z_abs_integral', 0.0) or 0.0) / total

    report.avg_abs_x_cm = x_avg
    report.avg_abs_y_cm = y_avg
    report.avg_abs_z_deg = z_avg

    report.avg_tracking_error_raw = float(tracking_error_integral) / total
    report.avg_tracking_error = float(report.avg_tracking_error_raw)
    report.avg_tracking_error_effective = float(report.avg_tracking_error_raw)
    report.v_avg = float(speed_integral) / total

    stage_no = int(report.stage_no)
    stage = self.stage_defs[stage_no]
    goal_xy = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0) or 3.0))
    crash_xy = max(goal_xy + 1e-6, goal_xy + float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))
    goal_z = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    crash_z = max(goal_z + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0))

    h_x = _fixed73e_clip((goal_xy - x_avg) / (goal_xy - crash_xy), 0.0, 1.0) if stage.get('x') else 0.0
    h_y = _fixed73e_clip((goal_xy - y_avg) / (goal_xy - crash_xy), 0.0, 1.0) if stage.get('y') else 0.0
    h_z = _fixed73e_clip((goal_z - z_avg) / (goal_z - crash_z), 0.0, 1.0) if stage.get('z') else 0.0

    g_x = (1.0 - h_x) if stage.get('x') else 0.0
    g_y = (1.0 - h_y) if stage.get('y') else 0.0
    g_z = (1.0 - h_z) if stage.get('z') else 0.0

    entropy_h = float((h_x * h_x + h_y * h_y + h_z * h_z) ** 0.5)
    success_gamma = float((g_x * g_x + g_y * g_y + g_z * g_z) ** 0.5)

    n_dop = _fixed199_n_dop_value(self, stage_no)
    n_real = max(0.0, float(getattr(report, 'crashes', 0) or 0))
    n_avar = _fixed73e_clip(1.0 - (n_real / max(1e-6, n_dop)), 0.0, 1.0)

    v_avg_norm = _fixed200_normative_speed_value(self, stage_no)
    v_ratio = float(report.v_avg) / max(1e-6, float(v_avg_norm))
    t_sled = float(v_ratio) * float(success_gamma) * float(n_avar)

    t_stage = _fixed200_stage_time_limit_s(self, stage_no)
    y_lim_vec = _fixed200_stage_y_lim_per_sec(self, stage_no)
    y_predel = _fixed200_stage_error_limit(self, stage_no)

    goal_combined = float(((goal_xy if stage.get('x') else 0.0) ** 2 + (goal_xy if stage.get('y') else 0.0) ** 2 + (goal_z if stage.get('z') else 0.0) ** 2) ** 0.5)
    crash_combined = float(((crash_xy if stage.get('x') else 0.0) ** 2 + (crash_xy if stage.get('y') else 0.0) ** 2 + (crash_z if stage.get('z') else 0.0) ** 2) ** 0.5)
    avg_combined = float((x_avg * x_avg + y_avg * y_avg + z_avg * z_avg) ** 0.5)

    report.entropy_h_raw = float(entropy_h)
    report.entropy_h = float(entropy_h)
    report.entropy_h_doc = float(entropy_h)
    report.success_gamma = float(success_gamma)
    report.gamma_x = float(g_x)
    report.gamma_y = float(g_y)
    report.gamma_z = float(g_z)

    report.tracking_error_target = float(goal_combined)
    report.tracking_error_crash = float(crash_combined)
    report.tracking_error_current_avg = float(avg_combined)

    report.crash_coeff_n_avar = float(n_avar)
    report.crash_limit_doc = float(n_dop)
    report.n_real_doc = float(n_real)

    report.v_avg_norm = float(v_avg_norm)
    report.v_ratio = float(v_ratio)
    report.reduced_tempo_tr = float(t_sled)
    report.t_slezh = float(t_sled)

    report.y_lim_per_sec = float(y_lim_vec)
    report.y_lim_x_per_sec = float(getattr(self.cfg, 'y_lim_x_per_sec', y_lim_vec))
    report.y_lim_y_per_sec = float(getattr(self.cfg, 'y_lim_y_per_sec', y_lim_vec))
    report.y_lim_z_per_sec = float(getattr(self.cfg, 'y_lim_z_per_sec', y_lim_vec))
    report.error_limit_formula_value = float(y_predel)
    report.error_limit_value = float(y_predel)
    report.stage_time_limit_used_s = float(getattr(report, 'stage_time_limit_used_s', t_stage) or t_stage)
    report.y_tek_current = float(getattr(report, 'y_tek_current', 0.0) or 0.0)
    report.y_sigma = float(getattr(report, 'y_sigma', report.sum_error) or 0.0)
    report.y_tek_window_avg = float(getattr(report, 'y_tek_window_avg', 0.0) or 0.0)
    y_tek_series = getattr(report, 'y_tek_series', [])
    report.y_tek_avg_per_sec = float(sum(y_tek_series) / len(y_tek_series)) if y_tek_series else float(report.y_tek_current)

    report.stage_label_doc = _fixed73e_stage_name(stage_no)
    report.calculation_version = _FIXED200_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED200(doc 22.04): Υпредел=Υlim*T; для нескольких координат действует '
        'RSS-объединение по осям: sqrt(sum(axis^2)).'
    )
    report.entropy_formula_note = (
        'Y(слеж) по осям объединяется через RSS, '
        'Nавар = 1 - (Nреал / Nдоп), tслеж = (Vср / Vср.норм) × Y(слеж) × Nавар.'
    )
    return report


def _fixed200_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    rows = _fixed199_method_a_stage_metric_rows(report)
    updated = []
    for label, value in rows:
        # Tнорм removed in newer display blocks.
        if label == 'Tнорм':
            continue
        # Keep current Υпредел label as-is (already normalized upstream).
        updated.append((label, value))
    return updated


def _fixed200_show_method_a_results(self, payload: dict):
    return _fixed199_show_method_a_results(self, payload)


def _fixed200_method_a_summary_from_reports(reports: list[dict]) -> dict:
    summary = _fixed199_method_a_summary_from_reports(reports)
    summary['calculation_version'] = _FIXED200_METHOD_A_CALC_VERSION
    return summary


def _fixed200_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed199_build_method_a_payload(self, session, result)
    payload['summary'] = _fixed200_method_a_summary_from_reports(payload.get('reports', []))
    try:
        cfg = load_config(path=self.base_dir / 'method_a_config.json', screen_w=self.root.winfo_screenwidth(), screen_h=self.root.winfo_screenheight())
        payload['summary']['method_a_stage_time_limits'] = {
            'stage_1_s': float(getattr(cfg, 'stage_time_limit_stage_1_s', 40.0)),
            'stage_2_s': float(getattr(cfg, 'stage_time_limit_stage_2_s', 40.0)),
            'stage_3_s': float(getattr(cfg, 'stage_time_limit_stage_3_s', 40.0)),
        }
    except Exception:
        pass
    return payload


# ====== FIXED201: strict per-axis accumulation (doc testA_1) ======
_FIXED201_METHOD_A_CALC_VERSION = 'fixed201_doc_testA1_axis_accum_v1'


def _fixed201_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    v_x_integral = 0.0
    v_y_integral = 0.0
    v_z_integral = 0.0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)

    y_tek_current = 0.0
    y_sigma = 0.0
    y_sigma_x = 0.0
    y_sigma_y = 0.0
    y_sigma_z = 0.0

    sample_x: list[float] = []
    sample_y: list[float] = []
    sample_z: list[float] = []
    sample_tick_accum_s = 0.0
    second_tick_accum_s = 0.0

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        e_x = float(snap.get('e_x', 0.0))
        e_y = float(snap.get('e_y', 0.0))
        e_z = float(snap.get('e_z', 0.0))

        x_abs_integral += float(snap.get('x_cm', 0.0)) * dt
        y_abs_integral += float(snap.get('y_cm', 0.0)) * dt
        z_abs_integral += float(snap.get('z_deg', 0.0)) * dt

        vxy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
        stage = self.stage_defs[int(stage_no)]
        vx = vxy if stage.get('x') else 0.0
        vy = vxy if stage.get('y') else 0.0
        vz = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0)) if stage.get('z') else 0.0
        v_x_integral += vx * dt
        v_y_integral += vy * dt
        v_z_integral += vz * dt

        # интеграл текущей ошибки для совместимости отчёта
        tracking_error_integral += (e_x * e_x + e_y * e_y + e_z * e_z) ** 0.5 * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= 0.1:
            sample_tick_accum_s -= 0.1
            sample_x.append(e_x)
            sample_y.append(e_y)
            sample_z.append(e_z)
            if len(sample_x) > 10:
                sample_x.pop(0)
                sample_y.pop(0)
                sample_z.pop(0)

        second_tick_accum_s += dt
        while second_tick_accum_s >= 1.0:
            second_tick_accum_s -= 1.0
            y_tek_x = (sum(sample_x) / len(sample_x)) if sample_x else 0.0
            y_tek_y = (sum(sample_y) / len(sample_y)) if sample_y else 0.0
            y_tek_z = (sum(sample_z) / len(sample_z)) if sample_z else 0.0

            y_sigma_x += y_tek_x
            y_sigma_y += y_tek_y
            y_sigma_z += y_tek_z

            # doc: YΣXYZ = sqrt(YΣX^2 + YΣY^2 + YΣZ^2)
            y_tek_current = (y_tek_x * y_tek_x + y_tek_y * y_tek_y + y_tek_z * y_tek_z) ** 0.5
            y_sigma = (y_sigma_x * y_sigma_x + y_sigma_y * y_sigma_y + y_sigma_z * y_sigma_z) ** 0.5

            report.y_tek_series.append(round(float(y_tek_current), 6))
            report.y_sigma_series.append(round(float(y_sigma), 6))

        report.y_tek_window_avg = float(y_tek_current)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)
        report._fixed201_y_sigma_x = float(y_sigma_x)
        report._fixed201_y_sigma_y = float(y_sigma_y)
        report._fixed201_y_sigma_z = float(y_sigma_z)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed201_speed_x_integral = float(v_x_integral)
            report._fixed201_speed_y_integral = float(v_y_integral)
            report._fixed201_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; y_tek={y_tek_current:.4f}; y_sigma={y_sigma:.4f}",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed201_speed_x_integral = float(v_x_integral)
            report._fixed201_speed_y_integral = float(v_y_integral)
            report._fixed201_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed201_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    rep = _fixed200_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)
    total = max(float(elapsed_s), 1e-6)
    vx_avg = float(getattr(rep, '_fixed201_speed_x_integral', 0.0) or 0.0) / total
    vy_avg = float(getattr(rep, '_fixed201_speed_y_integral', 0.0) or 0.0) / total
    vz_avg = float(getattr(rep, '_fixed201_speed_z_integral', 0.0) or 0.0) / total
    # doc: VsrXYZ = sqrt(VsrX^2 + VsrY^2 + VsrZ^2)
    rep.v_avg = float((vx_avg * vx_avg + vy_avg * vy_avg + vz_avg * vz_avg) ** 0.5)
    rep.v_avg_x = float(vx_avg)
    rep.v_avg_y = float(vy_avg)
    rep.v_avg_z = float(vz_avg)
    rep.v_ratio = float(rep.v_avg) / max(1e-6, float(getattr(rep, 'v_avg_norm', 1.0) or 1.0))
    rep.reduced_tempo_tr = float(rep.v_ratio) * float(getattr(rep, 'success_gamma', 0.0) or 0.0) * float(getattr(rep, 'crash_coeff_n_avar', 0.0) or 0.0)
    rep.t_slezh = float(rep.reduced_tempo_tr)
    rep.y_sigma_x = float(getattr(rep, '_fixed201_y_sigma_x', 0.0) or 0.0)
    rep.y_sigma_y = float(getattr(rep, '_fixed201_y_sigma_y', 0.0) or 0.0)
    rep.y_sigma_z = float(getattr(rep, '_fixed201_y_sigma_z', 0.0) or 0.0)
    rep.calculation_version = _FIXED201_METHOD_A_CALC_VERSION
    rep.runtime_rule_note = (
        'FIXED201(doc testA_1): накопление и объединение по осям строго через RSS; '
        'YΣXYZ=sqrt(YΣX^2+YΣY^2+YΣZ^2), VsrXYZ=sqrt(VsrX^2+VsrY^2+VsrZ^2).'
    )
    return rep


def _fixed201_method_a_summary_from_reports(reports: list[dict]) -> dict:
    summary = _fixed200_method_a_summary_from_reports(reports)
    summary['calculation_version'] = _FIXED201_METHOD_A_CALC_VERSION
    return summary


def _fixed201_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed200_build_method_a_payload(self, session, result)
    payload['summary'] = _fixed201_method_a_summary_from_reports(payload.get('reports', []))
    return payload


# Keep original FIXED199 rows generator before overriding globals below.
_FIXED201_BASE_STAGE_ROWS = _fixed199_method_a_stage_metric_rows


def _fixed201_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    base_rows = _FIXED201_BASE_STAGE_ROWS(report)
    relabeled: list[tuple[str, str]] = []
    for label, value in base_rows:
        if label == 'Длительность этапа T':
            relabeled.append(('T = длительность этапа', value))
        elif label == 'Υlim':
            relabeled.append(('Υlim = √(ΥlimX² + ΥlimY² + ΥlimZ²)', value))
        elif label.startswith('Υпредел ='):
            relabeled.append(('Υпредел = Υlim × T', value))
        elif label == 'Vср':
            relabeled.append(('Vср = √(VсрX² + VсрY² + VсрZ²)', value))
        elif label == 'Vср.норм':
            relabeled.append(('Vср.норм = параметр из настроек этапа', value))
        elif label == 'Vср / Vср.норм':
            relabeled.append(('Vср / Vср.норм = деление Vср на Vср.норм', value))
        elif label == 'Rцели':
            relabeled.append(('Rtarget (from settings)', value))
        elif label == 'Rтек.ср':
            relabeled.append(('Rтек.ср = √(RтекX² + RтекY² + RтекZ²)', value))
        elif label == 'Rаварии':
            relabeled.append(('Rcrash (from settings)', value))
        elif label.startswith('H ='):
            relabeled.append(('H = (Rtarget(settings) - Rcurrent_avg) / (Rtarget(settings) - Rcrash(settings))', value))
        elif label in ('Y(слеж) = 1 - H', 'Υслеж = 1 - H'):
            relabeled.append(('Y(слеж) = 1 - H', value))
        elif label == 'Nреал':
            relabeled.append(('Nреал = число аварий этапа', value))
        elif label == 'Nдоп':
            relabeled.append(('Nдоп = Nдоп(60с) × T / 60', value))
        elif label.startswith('Nавар ='):
            relabeled.append(('Nавар = 1 - (Nреал / Nдоп)', value))
        elif label == 'Y(тек), 1с окно':
            relabeled.append(('Y(тек) = (Σ 10 значений за 0.1с) / 10', value))
        elif label == 'Y(тек) среднее за этап':
            relabeled.append(('Y(тек)_ср = (Σ Y(тек)_i) / n', value))
        elif label.startswith('Y(сигма)'):
            relabeled.append(('Y(сигма) = Σ Y(тек)_i', value))
        elif label.startswith('tслеж ='):
            relabeled.append(('tслеж = (Vср/Vср.норм) × Y(слеж) × Nавар', value))
        elif label == 'Средний крен':
            relabeled.append(('Средний крен = (Σ |крен|) / T', value))
        elif label == 'Среднее отклонение X/Y':
            relabeled.append(('Среднее отклонение X/Y = (Σ √(x²+y²)) / T', value))
        else:
            relabeled.append((label, value))
    return relabeled


def _fixed201_show_method_a_results(self, payload: dict):
    return _fixed199_show_method_a_results(self, payload)


