# ====== FIXED203: Method A update by "slezh 25.04.2026.docx" (only Test A) ======
from dataclasses import dataclass as _fixed203_dataclass

_FIXED203_METHOD_A_CALC_VERSION = 'fixed203_doc_2026_04_25_step05_ndop180_v1'
_FIXED203_DEFAULT_CALC_TICK_S = 0.5

_FIXED203_BASE_METHOD_A_CLASS = MethodAConfig


@_fixed203_dataclass
class MethodAConfigFixed203(_FIXED203_BASE_METHOD_A_CLASS):
    calc_tick_s: float = _FIXED203_DEFAULT_CALC_TICK_S
    n_dop_x_for_180s: float = 50.0
    n_dop_xy_for_180s: float = 40.0
    n_dop_xyz_for_180s: float = 40.0


MethodAConfig = MethodAConfigFixed203
globals()['MethodAConfig'] = MethodAConfigFixed203

_fixed203_prev_load_config = load_config


def load_config(path: str | Path = 'method_a_config.json', screen_w: int | None = None, screen_h: int | None = None) -> MethodAConfigFixed203:
    base_cfg = _fixed203_prev_load_config(path=path, screen_w=screen_w, screen_h=screen_h)
    raw = {}
    p = Path(path)
    if p.exists():
        try:
            loaded = json.loads(p.read_text(encoding='utf-8'))
            if isinstance(loaded, dict):
                raw = dict(loaded)
        except Exception:
            raw = {}

    inherited_kwargs = {}
    for fld in _fixed199_fields(_FIXED203_BASE_METHOD_A_CLASS):
        try:
            inherited_kwargs[fld.name] = getattr(base_cfg, fld.name)
        except Exception:
            inherited_kwargs[fld.name] = fld.default

    cfg = MethodAConfigFixed203(**inherited_kwargs)

    try:
        cfg.calc_tick_s = float(raw.get('calc_tick_s', getattr(cfg, 'calc_tick_s', _FIXED203_DEFAULT_CALC_TICK_S)))
    except Exception:
        cfg.calc_tick_s = _FIXED203_DEFAULT_CALC_TICK_S
    cfg.calc_tick_s = max(0.05, min(2.0, float(cfg.calc_tick_s or _FIXED203_DEFAULT_CALC_TICK_S)))

    for key, default in (
        ('n_dop_x_for_180s', 50.0),
        ('n_dop_xy_for_180s', 40.0),
        ('n_dop_xyz_for_180s', 40.0),
    ):
        try:
            setattr(cfg, key, max(1e-6, float(raw.get(key, getattr(cfg, key, default)))))
        except Exception:
            setattr(cfg, key, float(default))

    return cfg


globals()['load_config'] = load_config

