def _fixed203_n_dop_for_180s(self, stage_no: int) -> float:
    stage_no = int(stage_no)
    if stage_no == 1:
        return max(1e-6, float(getattr(self.cfg, 'n_dop_x_for_180s', 50.0) or 50.0))
    if stage_no == 2:
        return max(1e-6, float(getattr(self.cfg, 'n_dop_xy_for_180s', 40.0) or 40.0))
    return max(1e-6, float(getattr(self.cfg, 'n_dop_xyz_for_180s', 40.0) or 40.0))


def _fixed203_n_dop_value(self, stage_no: int) -> float:
    t_stage = _fixed200_stage_time_limit_s(self, int(stage_no))
    return max(1e-6, _fixed203_n_dop_for_180s(self, stage_no) * t_stage / 180.0)


def _fixed203_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    v_x_integral = 0.0
    v_y_integral = 0.0
    v_z_integral = 0.0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)
    calc_tick_s = max(0.05, float(getattr(self.cfg, 'calc_tick_s', _FIXED203_DEFAULT_CALC_TICK_S) or _FIXED203_DEFAULT_CALC_TICK_S))

    y_tek_current = 0.0
    y_sigma = 0.0
    y_sigma_x = 0.0
    y_sigma_y = 0.0
    y_sigma_z = 0.0

    sample_tick_accum_s = 0.0

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0
    report.calc_tick_s = float(calc_tick_s)

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        e_x = float(snap.get('e_x', 0.0))
        e_y = float(snap.get('e_y', 0.0))
        e_z = float(snap.get('e_z', 0.0))

        x_abs_integral += float(snap.get('x_cm', 0.0)) * dt
        y_abs_integral += float(snap.get('y_cm', 0.0)) * dt
        z_abs_integral += float(snap.get('z_deg', 0.0)) * dt

        vxy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
        stage = self.stage_defs[int(stage_no)]
        vx = vxy if stage.get('x') else 0.0
        vy = vxy if stage.get('y') else 0.0
        vz = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0)) if stage.get('z') else 0.0
        v_x_integral += vx * dt
        v_y_integral += vy * dt
        v_z_integral += vz * dt

        tracking_error_integral += (e_x * e_x + e_y * e_y + e_z * e_z) ** 0.5 * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= calc_tick_s:
            sample_tick_accum_s -= calc_tick_s

            y_sigma_x += e_x * calc_tick_s
            y_sigma_y += e_y * calc_tick_s
            y_sigma_z += e_z * calc_tick_s

            y_tek_current = (e_x * e_x + e_y * e_y + e_z * e_z) ** 0.5
            y_sigma = (y_sigma_x * y_sigma_x + y_sigma_y * y_sigma_y + y_sigma_z * y_sigma_z) ** 0.5

            report.y_tek_series.append(round(float(y_tek_current), 6))
            report.y_sigma_series.append(round(float(y_sigma), 6))

        report.y_tek_window_avg = float(y_tek_current)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)
        report._fixed203_y_sigma_x = float(y_sigma_x)
        report._fixed203_y_sigma_y = float(y_sigma_y)
        report._fixed203_y_sigma_z = float(y_sigma_z)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        if self.in_crash_zone(state, stage_no):
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; y_tek={y_tek_current:.4f}; y_sigma={y_sigma:.4f}; step={calc_tick_s:.2f}s",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed203_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    rep = _fixed200_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)
    total = max(float(elapsed_s), 1e-6)

    vx_avg = float(getattr(rep, '_fixed203_speed_x_integral', 0.0) or 0.0) / total
    vy_avg = float(getattr(rep, '_fixed203_speed_y_integral', 0.0) or 0.0) / total
    vz_avg = float(getattr(rep, '_fixed203_speed_z_integral', 0.0) or 0.0) / total

    rep.v_avg = float((vx_avg * vx_avg + vy_avg * vy_avg + vz_avg * vz_avg) ** 0.5)
    rep.v_avg_x = float(vx_avg)
    rep.v_avg_y = float(vy_avg)
    rep.v_avg_z = float(vz_avg)
    rep.v_ratio = float(rep.v_avg) / max(1e-6, float(getattr(rep, 'v_avg_norm', 1.0) or 1.0))

    stage_no = int(rep.stage_no)
    n_dop = _fixed203_n_dop_value(self, stage_no)
    n_real = max(0.0, float(getattr(rep, 'crashes', 0) or 0))
    n_avar = _fixed73e_clip(1.0 - (n_real / max(1e-6, n_dop)), 0.0, 1.0)

    rep.crash_limit_doc = float(n_dop)
    rep.n_real_doc = float(n_real)
    rep.crash_coeff_n_avar = float(n_avar)

    rep.reduced_tempo_tr = float(rep.v_ratio) * float(getattr(rep, 'success_gamma', 0.0) or 0.0) * float(n_avar)
    rep.t_slezh = float(rep.reduced_tempo_tr)

    rep.y_sigma_x = float(getattr(rep, '_fixed203_y_sigma_x', 0.0) or 0.0)
    rep.y_sigma_y = float(getattr(rep, '_fixed203_y_sigma_y', 0.0) or 0.0)
    rep.y_sigma_z = float(getattr(rep, '_fixed203_y_sigma_z', 0.0) or 0.0)
    rep.calculation_version = _FIXED203_METHOD_A_CALC_VERSION
    rep.runtime_rule_note = (
        'FIXED203(doc 25.04.2026): 0.5s sampling for accumulation, '
        'Ysum from axis integrals via RSS, Ndop(T)=Ndop(180s)*T/180.'
    )
    rep.entropy_formula_note = (
        't_slezh=(Vsr/Vsr_norm)*Y_slezh*N_avar, '
        'N_avar=1-(N_real/N_dop(T)), N_dop(T)=N_dop(180s)*T/180.'
    )
    return rep


def _fixed203_method_a_summary_from_reports(reports: list[dict]) -> dict:
    summary = _fixed200_method_a_summary_from_reports(reports)
    summary['calculation_version'] = _FIXED203_METHOD_A_CALC_VERSION
    return summary


def _fixed203_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed200_build_method_a_payload(self, session, result)
    payload['summary'] = _fixed203_method_a_summary_from_reports(payload.get('reports', []))
    return payload


def _fixed203_method_a_stage_metric_rows(report: dict) -> list[tuple[str, str]]:
    base_rows = _fixed201_method_a_stage_metric_rows(report)
    relabeled: list[tuple[str, str]] = []
    for label, value in base_rows:
        if 'N' in label and '60' in label:
            relabeled.append(('Ndop = Ndop(180s) * T / 180', value))
        elif label.startswith('N') and '1 -' in label:
            relabeled.append(('Navar = 1 - (Nreal / Ndop(T))', value))
        elif '0.1' in label or '1СЃ' in label:
            relabeled.append(('Ytek sampled every 0.5s by document', value))
        else:
            relabeled.append((label, value))
    return relabeled


def _fixed203_show_method_a_results(self, payload: dict):
    return _fixed199_show_method_a_results(self, payload)


globals()['_fixed97_current_tracking_error'] = _fixed200_current_tracking_error
globals()['_fixed73e_current_speed_value'] = _fixed200_current_speed_value
globals()['_fixed92_method_a_stage_metric_rows'] = _fixed203_method_a_stage_metric_rows
globals()['_fixed199_method_a_stage_metric_rows'] = _fixed203_method_a_stage_metric_rows
globals()['_fixed73e_method_a_summary_from_reports'] = _fixed203_method_a_summary_from_reports
MethodAApp.stage_smax = _fixed200_stage_error_limit
MethodAApp.run_stage = _fixed203_run_stage
MethodAApp.finalize_stage_report = _fixed203_finalize_stage_report
