StartPageApp.show_method_a_results = _fixed203_show_method_a_results


# ====== FIXED204: Method A per-second metrics table + crash beep ======
_FIXED204_METHOD_A_CALC_VERSION = 'fixed204_doc_2026_04_25_table_beep_v1'

try:
    import winsound as _fixed204_winsound
except Exception:
    _fixed204_winsound = None


def _fixed204_play_crash_beep():
    if _fixed204_winsound is None:
        return
    try:
        _fixed204_winsound.Beep(1400, 80)
        return
    except Exception:
        pass
    try:
        _fixed204_winsound.MessageBeep(-1)
    except Exception:
        pass


def _fixed204_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    v_x_integral = 0.0
    v_y_integral = 0.0
    v_z_integral = 0.0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)
    calc_tick_s = max(0.05, float(getattr(self.cfg, 'calc_tick_s', _FIXED203_DEFAULT_CALC_TICK_S) or _FIXED203_DEFAULT_CALC_TICK_S))
    v_norm = max(1e-6, float(_fixed200_normative_speed_value(self, stage_no)))

    y_tek_current = 0.0
    y_sigma = 0.0
    y_sigma_x = 0.0
    y_sigma_y = 0.0
    y_sigma_z = 0.0

    sample_tick_accum_s = 0.0

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0
    report.calc_tick_s = float(calc_tick_s)
    report.second_metrics = []

    latest_speed = 0.0
    latest_speed_reduced = 0.0
    latest_entropy_now = 0.0
    latest_entropy_sum = 0.0
    next_second_mark = 1.0

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        e_x = float(snap.get('e_x', 0.0))
        e_y = float(snap.get('e_y', 0.0))
        e_z = float(snap.get('e_z', 0.0))

        x_abs_integral += float(snap.get('x_cm', 0.0)) * dt
        y_abs_integral += float(snap.get('y_cm', 0.0)) * dt
        z_abs_integral += float(snap.get('z_deg', 0.0)) * dt

        vxy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
        stage = self.stage_defs[int(stage_no)]
        vx = vxy if stage.get('x') else 0.0
        vy = vxy if stage.get('y') else 0.0
        vz = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0)) if stage.get('z') else 0.0
        v_x_integral += vx * dt
        v_y_integral += vy * dt
        v_z_integral += vz * dt

        current_speed = float((vx * vx + vy * vy + vz * vz) ** 0.5)
        # λтек on plane/space is combined via plus under sqrt:
        # λ = sqrt(λx^2 + λy^2 [+ λz^2]), where λaxis = Vaxis / Vnorm.
        lam_x = float(vx) / v_norm if stage.get('x') else 0.0
        lam_y = float(vy) / v_norm if stage.get('y') else 0.0
        lam_z = float(vz) / v_norm if stage.get('z') else 0.0
        current_speed_reduced = float((lam_x * lam_x + lam_y * lam_y + lam_z * lam_z) ** 0.5)
        latest_speed = current_speed
        latest_speed_reduced = current_speed_reduced

        tracking_error_integral += (e_x * e_x + e_y * e_y + e_z * e_z) ** 0.5 * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= calc_tick_s:
            sample_tick_accum_s -= calc_tick_s

            y_sigma_x += e_x * calc_tick_s
            y_sigma_y += e_y * calc_tick_s
            y_sigma_z += e_z * calc_tick_s

            y_tek_current = (e_x * e_x + e_y * e_y + e_z * e_z) ** 0.5
            y_sigma = (y_sigma_x * y_sigma_x + y_sigma_y * y_sigma_y + y_sigma_z * y_sigma_z) ** 0.5

            report.y_tek_series.append(round(float(y_tek_current), 6))
            report.y_sigma_series.append(round(float(y_sigma), 6))

        latest_entropy_now = float(y_tek_current)
        latest_entropy_sum = float(y_sigma)

        while elapsed_s >= next_second_mark:
            report.second_metrics.append({
                'second': int(next_second_mark),
                'speed_current': round(float(latest_speed), 6),
                'speed_reduced': round(float(latest_speed_reduced), 6),
                'entropy_current': round(float(latest_entropy_now), 6),
                'entropy_accumulated': round(float(latest_entropy_sum), 6),
            })
            next_second_mark += 1.0

        report.y_tek_window_avg = float(y_tek_current)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)
        report._fixed203_y_sigma_x = float(y_sigma_x)
        report._fixed203_y_sigma_y = float(y_sigma_y)
        report._fixed203_y_sigma_z = float(y_sigma_z)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        if self.in_crash_zone(state, stage_no):
            _fixed204_play_crash_beep()
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; y_tek={y_tek_current:.4f}; y_sigma={y_sigma:.4f}; step={calc_tick_s:.2f}s",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed204_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    rep = _fixed203_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)
    rep.calculation_version = _FIXED204_METHOD_A_CALC_VERSION
    rep.runtime_rule_note = (
        'FIXED204: per-second table (Vcur, lambda_cur, Hcur, Hsum) + short crash beep.'
    )
    return rep


def _fixed204_method_a_summary_from_reports(reports: list[dict]) -> dict:
    summary = _fixed203_method_a_summary_from_reports(reports)
    summary['calculation_version'] = _FIXED204_METHOD_A_CALC_VERSION
    return summary


def _fixed204_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed203_build_method_a_payload(self, session, result)
    payload['summary'] = _fixed204_method_a_summary_from_reports(payload.get('reports', []))
    return payload


def _fixed204_find_results_body(top: tk.Toplevel) -> tk.Frame | None:
    try:
        shell = top.winfo_children()[0]
        content = shell.winfo_children()[1]
        canvas = next((w for w in content.winfo_children() if isinstance(w, tk.Canvas)), None)
        if canvas is None:
            return None
        body = next((w for w in canvas.winfo_children() if isinstance(w, tk.Frame)), None)
        return body
    except Exception:
        return None


def _fixed204_render_second_metrics_table(parent: tk.Widget, report: dict):
    rows = report.get('second_metrics', [])
    if not isinstance(rows, list) or not rows:
        return

    stage_no = int(report.get('stage_no', 0) or 0)
    box = tk.Frame(parent, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
    box.pack(fill='x', padx=24, pady=(0, 14))
    tk.Frame(box, bg='#53c26b', height=6).pack(fill='x')
    tk.Label(
        box,
        text=f'Посекундная таблица · Этап {stage_no}',
        bg='#ffffff',
        fg='#102744',
        font=('Arial', 13, 'bold'),
    ).pack(anchor='w', padx=14, pady=(10, 6))

    grid = tk.Frame(box, bg='#ffffff')
    grid.pack(fill='x', padx=14, pady=(0, 12))
    headers = ['Сек', 'Vтек', 'λтек', 'Hтек', 'Hнакопл']
    for col, h in enumerate(headers):
        tk.Label(grid, text=h, bg='#ffffff', fg='#5a6678', font=('Arial', 10, 'bold')).grid(row=0, column=col, sticky='w', padx=(0, 18), pady=(0, 6))

    for idx, item in enumerate(rows, start=1):
        sec = int(item.get('second', idx) or idx)
        v_cur = float(item.get('v_current', item.get('speed_current', 0.0)) or 0.0)
        lam = float(item.get('lambda_total', item.get('speed_reduced', 0.0)) or 0.0)
        h_cur = float(item.get('h_current', item.get('entropy_current', 0.0)) or 0.0)
        h_sum = float(item.get('h_sigma', item.get('entropy_accumulated', 0.0)) or 0.0)
        vals = [f'{sec}', f'{v_cur:.4f}', f'{lam:.4f}', f'{h_cur:.4f}', f'{h_sum:.4f}']
        for col, text in enumerate(vals):
            tk.Label(grid, text=text, bg='#ffffff', fg='#102744', font=('Arial', 10)).grid(row=idx, column=col, sticky='w', padx=(0, 18), pady=2)


def _fixed204_show_method_a_results(self, payload: dict):
    top = _fixed199_show_method_a_results(self, payload)
    body = _fixed204_find_results_body(top)
    if body is None:
        return top

    reports = payload.get('reports', [])
    if (not reports) and payload.get('result_path'):
        try:
            rp = Path(payload.get('result_path', ''))
            if not rp.is_absolute():
                rp = self.base_dir / rp
            if rp.exists():
                loaded = json.loads(rp.read_text(encoding='utf-8'))
                if isinstance(loaded, list):
                    reports = [r for r in loaded if isinstance(r, dict)]
        except Exception:
            reports = []

    ordered_reports = sorted([r for r in reports if isinstance(r, dict)], key=lambda r: int(r.get('stage_no', 0) or 0))
    if not ordered_reports:
        return top

    title_box = tk.Frame(body, bg='#eef3f8')
    title_box.pack(fill='x', padx=24, pady=(2, 8))
    tk.Label(title_box, text='Таблица параметров по секундам (Тест A)', bg='#eef3f8', fg='#102744', font=('Arial', 17, 'bold')).pack(anchor='w')
    tk.Label(
        title_box,
        text='Каждая строка: текущая скорость, приведённая текущая скорость, текущая энтропия и накопленная энтропия. Формула: λ = √(λx² + λy² [+ λz²]).',
        bg='#eef3f8',
        fg='#607187',
        font=('Arial', 10),
    ).pack(anchor='w', pady=(2, 0))

    for rep in ordered_reports:
        _fixed204_render_second_metrics_table(body, rep)
    return top


