# ====== FIXED205: Method A results on screen + PDF export ======
_FIXED205_METHOD_A_CALC_VERSION = 'fixed205_screen_plus_pdf_v1'


def _fixed205_collect_method_a_reports(self, payload: dict) -> list[dict]:
    reports = payload.get('reports', [])
    if isinstance(reports, list) and reports:
        return [r for r in reports if isinstance(r, dict)]
    result_path = payload.get('result_path', '')
    if not result_path:
        return []
    try:
        rp = Path(result_path)
        if not rp.is_absolute():
            rp = self.base_dir / rp
        if rp.exists():
            loaded = json.loads(rp.read_text(encoding='utf-8'))
            if isinstance(loaded, list):
                return [r for r in loaded if isinstance(r, dict)]
    except Exception:
        return []
    return []


def _fixed205_pdf_pages_from_lines(lines: list[str], title: str) -> list[Image.Image]:
    page_w, page_h = 1654, 2339
    margin_x, margin_y = 84, 84
    line_h = 28
    usable_h = page_h - margin_y * 2 - 64
    max_lines = max(10, usable_h // line_h)
    pages: list[Image.Image] = []
    for start in range(0, max(1, len(lines)), max_lines):
        chunk = lines[start:start + max_lines]
        img = Image.new('RGB', (page_w, page_h), 'white')
        dr = ImageDraw.Draw(img)
        dr.text((margin_x, margin_y), title, fill='black')
        y = margin_y + 44
        for line in chunk:
            dr.text((margin_x, y), line, fill='black')
            y += line_h
        pages.append(img)
    if not pages:
        img = Image.new('RGB', (page_w, page_h), 'white')
        dr = ImageDraw.Draw(img)
        dr.text((margin_x, margin_y), title, fill='black')
        dr.text((margin_x, margin_y + 44), 'No data', fill='black')
        pages.append(img)
    return pages


def _fixed205_export_method_a_pdf(self, payload: dict) -> str:
    reports = sorted(
        _fixed205_collect_method_a_reports(self, payload),
        key=lambda r: int(r.get('stage_no', 0) or 0),
    )
    if not reports:
        return ''
    try:
        summary = payload.get('summary', {}) if isinstance(payload.get('summary', {}), dict) else {}
        participant = payload.get('participant', {}) if isinstance(payload.get('participant', {}), dict) else {}
        session_id = str(payload.get('session_id', 'session') or 'session')
        ts = datetime.now().strftime('%Y%m%d_%H%M%S')
        pdf_path = _results_dir(self.base_dir) / f'method_a_{session_id}_{ts}.pdf'

        lines: list[str] = []
        lines.append(f"Generated: {datetime.now().isoformat(timespec='seconds')}")
        lines.append(f"Participant: {participant.get('name', '')} | age={participant.get('age', '')} | gender={participant.get('gender', '')}")
        lines.append(f"Session: {session_id}")
        lines.append("")
        lines.append("Summary")
        lines.append(f"calculation_version: {summary.get('calculation_version', '')}")
        tvals = summary.get('t_values', {}) if isinstance(summary.get('t_values', {}), dict) else {}
        lines.append(f"t_slezh stage1={float(tvals.get('min', 0.0) or 0.0):.4f} stage2={float(tvals.get('medio', 0.0) or 0.0):.4f} stage3={float(tvals.get('max', 0.0) or 0.0):.4f}")
        lines.append(f"total_crashes: {int(summary.get('total_crashes', 0) or 0)}")
        lines.append("")

        for rep in reports:
            stage_no = int(rep.get('stage_no', 0) or 0)
            lines.append(f"Stage {stage_no} ({rep.get('active_axes', '')})")
            lines.append(f"T={float(rep.get('real_time_s', 0.0) or 0.0):.2f}s crashes={int(rep.get('crashes', 0) or 0)} t_slezh={float(rep.get('t_slezh', rep.get('reduced_tempo_tr', 0.0)) or 0.0):.4f}")
            lines.append(f"Ytek={float(rep.get('y_tek_current', 0.0) or 0.0):.4f} Ysigma={float(rep.get('y_sigma', rep.get('sum_error', 0.0)) or 0.0):.4f}")
            lines.append("sec | Vcur | lambda_cur | Hcur | Hsum")
            second_metrics = rep.get('second_metrics', [])
            if isinstance(second_metrics, list) and second_metrics:
                for row in second_metrics:
                    sec = int(row.get('second', 0) or 0)
                    vcur = float(row.get('v_current', row.get('speed_current', 0.0)) or 0.0)
                    lam = float(row.get('lambda_total', row.get('speed_reduced', 0.0)) or 0.0)
                    hcur = float(row.get('h_current', row.get('entropy_current', 0.0)) or 0.0)
                    hsum = float(row.get('h_sigma', row.get('entropy_accumulated', 0.0)) or 0.0)
                    lines.append(f"{sec:>3} | {vcur:>8.4f} | {lam:>10.4f} | {hcur:>8.4f} | {hsum:>8.4f}")
            else:
                lines.append("no per-second rows")
            lines.append("")

        pages = _fixed205_pdf_pages_from_lines(lines, 'Method A Results (Screen + PDF)')
        pages[0].save(str(pdf_path), format='PDF', save_all=True, append_images=pages[1:])
        return str(pdf_path)
    except Exception:
        return ''


def _fixed205_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed204_build_method_a_payload(self, session, result)
    summary = payload.get('summary', {}) if isinstance(payload.get('summary', {}), dict) else {}
    summary['calculation_version'] = _FIXED205_METHOD_A_CALC_VERSION
    payload['summary'] = summary
    pdf_path = _fixed205_export_method_a_pdf(self, payload)
    if pdf_path:
        payload['pdf_path'] = pdf_path
        payload['summary']['pdf_path'] = pdf_path
    return payload


def _fixed205_show_method_a_results(self, payload: dict):
    top = _fixed204_show_method_a_results(self, payload)
    pdf_path = str(payload.get('pdf_path', '') or '')
    if not pdf_path:
        pdf_path = _fixed205_export_method_a_pdf(self, payload)
        if pdf_path:
            payload['pdf_path'] = pdf_path
            if isinstance(payload.get('summary', None), dict):
                payload['summary']['pdf_path'] = pdf_path
    body = _fixed204_find_results_body(top)
    if body is not None:
        box = tk.Frame(body, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        box.pack(fill='x', padx=24, pady=(2, 12))
        tk.Frame(box, bg='#6b7dff', height=6).pack(fill='x')
        txt = f"PDF: {pdf_path}" if pdf_path else "PDF export: failed"
        tk.Label(box, text=txt, bg='#ffffff', fg='#102744', font=('Arial', 10, 'bold'), wraplength=1180, justify='left').pack(anchor='w', padx=12, pady=10)
    return top


