def _fixed206_export_pdf_from_top_window(self, top: tk.Toplevel, payload: dict) -> str:
    try:
        from PIL import ImageGrab as _fixed206_imagegrab
    except Exception:
        return ''
    try:
        top.update_idletasks()
        top.update()
        x1 = int(top.winfo_rootx())
        y1 = int(top.winfo_rooty())
        x2 = x1 + int(top.winfo_width())
        y2 = y1 + int(top.winfo_height())
        if x2 <= x1 or y2 <= y1:
            return ''
        shot = _fixed206_imagegrab.grab(bbox=(x1, y1, x2, y2))
        if shot.mode != 'RGB':
            shot = shot.convert('RGB')
        session_id = str(payload.get('session_id', 'session') or 'session')
        ts = datetime.now().strftime('%Y%m%d_%H%M%S')
        pdf_path = _results_dir(self.base_dir) / f'method_a_screen_{session_id}_{ts}.pdf'
        shot.save(str(pdf_path), format='PDF', resolution=150.0)
        return str(pdf_path)
    except Exception:
        return ''


