# ====== FIXED207: Method A PDF includes ALL result pages (full scroll capture) ======
_FIXED207_METHOD_A_CALC_VERSION = 'fixed207_pdf_all_results_scroll_capture_v1'


def _fixed207_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed204_build_method_a_payload(self, session, result)
    summary = payload.get('summary', {}) if isinstance(payload.get('summary', {}), dict) else {}
    summary['calculation_version'] = _FIXED207_METHOD_A_CALC_VERSION
    payload['summary'] = summary
    return payload


def _fixed207_find_results_canvas(top: tk.Toplevel) -> tk.Canvas | None:
    try:
        shell = top.winfo_children()[0]
        content = shell.winfo_children()[1]
        canvas = next((w for w in content.winfo_children() if isinstance(w, tk.Canvas)), None)
        return canvas
    except Exception:
        return None


def _fixed207_export_pdf_all_results(self, top: tk.Toplevel, payload: dict) -> str:
    try:
        from PIL import ImageGrab as _fixed207_imagegrab
    except Exception:
        return ''

    canvas = _fixed207_find_results_canvas(top)
    if canvas is None:
        return ''

    try:
        top.update_idletasks()
        top.update()

        region = str(canvas.cget('scrollregion') or '').strip()
        if region:
            parts = region.split()
            if len(parts) == 4:
                _, y1s, _, y2s = parts
                total_h = max(1, int(float(y2s) - float(y1s)))
            else:
                total_h = max(1, int(canvas.bbox('all')[3] if canvas.bbox('all') else canvas.winfo_height()))
        else:
            box = canvas.bbox('all')
            total_h = max(1, int((box[3] - box[1]) if box else canvas.winfo_height()))

        vis_h = max(1, int(canvas.winfo_height()))
        max_offset = max(0, total_h - vis_h)

        offsets: list[int] = []
        current = 0
        while current < max_offset:
            offsets.append(current)
            current += vis_h
        offsets.append(max_offset)

        captured: list[Image.Image] = []
        for off in offsets:
            frac = float(off) / float(max(1, max_offset))
            canvas.yview_moveto(frac)
            top.update_idletasks()
            top.update()

            x1 = int(canvas.winfo_rootx())
            y1 = int(canvas.winfo_rooty())
            x2 = x1 + int(canvas.winfo_width())
            y2 = y1 + int(canvas.winfo_height())
            if x2 <= x1 or y2 <= y1:
                continue
            shot = _fixed207_imagegrab.grab(bbox=(x1, y1, x2, y2))
            if shot.mode != 'RGB':
                shot = shot.convert('RGB')
            captured.append(shot)

        canvas.yview_moveto(0.0)
        top.update_idletasks()
        top.update()

        if not captured:
            return ''

        session_id = str(payload.get('session_id', 'session') or 'session')
        ts = datetime.now().strftime('%Y%m%d_%H%M%S')
        pdf_path = _results_dir(self.base_dir) / f'method_a_all_results_{session_id}_{ts}.pdf'
        captured[0].save(str(pdf_path), format='PDF', save_all=True, append_images=captured[1:], resolution=150.0)
        return str(pdf_path)
    except Exception:
        return ''


def _fixed207_show_method_a_results(self, payload: dict):
    top = _fixed204_show_method_a_results(self, payload)
    pdf_path = _fixed207_export_pdf_all_results(self, top, payload)
    if pdf_path:
        payload['pdf_path'] = pdf_path
        if isinstance(payload.get('summary', None), dict):
            payload['summary']['pdf_path'] = pdf_path

    body = _fixed204_find_results_body(top)
    if body is not None:
        box = tk.Frame(body, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        box.pack(fill='x', padx=24, pady=(2, 12))
        tk.Frame(box, bg='#6b7dff', height=6).pack(fill='x')
        txt = f"PDF (all results): {pdf_path}" if pdf_path else "PDF export (all results): failed"
        tk.Label(
            box,
            text=txt,
            bg='#ffffff',
            fg='#102744',
            font=('Arial', 10, 'bold'),
            wraplength=1180,
            justify='left',
        ).pack(anchor='w', padx=12, pady=10)
    return top


