# ====== FIXED208: full per-second table (all measured+calculated) + normalized stage-3 components ======
_FIXED208_METHOD_A_CALC_VERSION = 'fixed208_full_second_table_normalized_v1'


def _fixed208_inside_target_center(self, state: DriftState, stage_no: int) -> bool:
    """Target-zone decision strictly by object center (crosshair), not sprite edges."""
    stage = self.stage_defs[int(stage_no)]
    ok_x = (not stage.get('x')) or (abs(float(getattr(state, 'x_px', 0.0))) <= float(self.target_half_px))
    ok_y = (not stage.get('y')) or (abs(float(getattr(state, 'y_px', 0.0))) <= float(self.target_half_px))
    ok_z = (not stage.get('z')) or (abs(float(getattr(state, 'roll_deg', 0.0))) <= float(getattr(self.cfg, 'target_roll_deg', 5.0)))
    return bool(ok_x and ok_y and ok_z)


def _fixed208_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0
    tracking_error_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    v_x_integral = 0.0
    v_y_integral = 0.0
    v_z_integral = 0.0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)
    calc_tick_s = max(0.05, float(getattr(self.cfg, 'calc_tick_s', _FIXED203_DEFAULT_CALC_TICK_S) or _FIXED203_DEFAULT_CALC_TICK_S))
    v_norm_total = max(1e-6, float(_fixed200_normative_speed_value(self, stage_no)))
    v_norm_x = max(1e-6, float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    v_norm_y = max(1e-6, float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    v_norm_z = max(1e-6, float(getattr(self.cfg, 'start_speed_z_deg_s', 10.0) or 10.0))

    y_tek_current = 0.0
    y_sigma = 0.0
    y_sigma_x = 0.0
    y_sigma_y = 0.0
    y_sigma_z = 0.0

    sample_tick_accum_s = 0.0
    next_second_mark = 1.0
    latest_second_row: dict = {}

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0
    report.calc_tick_s = float(calc_tick_s)
    report.second_metrics = []

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        x_cm = float(snap.get('x_cm', 0.0))
        y_cm = float(snap.get('y_cm', 0.0))
        z_deg = float(snap.get('z_deg', 0.0))
        e_x = float(snap.get('e_x', 0.0))
        e_y = float(snap.get('e_y', 0.0))
        e_z = float(snap.get('e_z', 0.0))
        goal_x = float(snap.get('goal_x', 0.0))
        goal_y = float(snap.get('goal_y', 0.0))
        goal_z = float(snap.get('goal_z', 0.0))
        crash_x = float(snap.get('crash_x', 0.0))
        crash_y = float(snap.get('crash_y', 0.0))
        crash_z = float(snap.get('crash_z', 0.0))

        span_x = max(1e-6, crash_x - goal_x) if bool(self.stage_defs[int(stage_no)].get('x')) else 1.0
        span_y = max(1e-6, crash_y - goal_y) if bool(self.stage_defs[int(stage_no)].get('y')) else 1.0
        span_z = max(1e-6, crash_z - goal_z) if bool(self.stage_defs[int(stage_no)].get('z')) else 1.0
        e_nx = (e_x / span_x) if bool(self.stage_defs[int(stage_no)].get('x')) else 0.0
        e_ny = (e_y / span_y) if bool(self.stage_defs[int(stage_no)].get('y')) else 0.0
        e_nz = (e_z / span_z) if bool(self.stage_defs[int(stage_no)].get('z')) else 0.0

        x_abs_integral += x_cm * dt
        y_abs_integral += y_cm * dt
        z_abs_integral += z_deg * dt

        vxy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
        stage = self.stage_defs[int(stage_no)]
        vx = vxy if stage.get('x') else 0.0
        vy = vxy if stage.get('y') else 0.0
        vz = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0)) if stage.get('z') else 0.0
        v_x_integral += vx * dt
        v_y_integral += vy * dt
        v_z_integral += vz * dt

        v_cur = float((vx * vx + vy * vy + vz * vz) ** 0.5)
        lam_x = (vx / v_norm_x) if stage.get('x') else 0.0
        lam_y = (vy / v_norm_y) if stage.get('y') else 0.0
        lam_z = (vz / v_norm_z) if stage.get('z') else 0.0
        lam_xyz = float((lam_x * lam_x + lam_y * lam_y + lam_z * lam_z) ** 0.5)
        lam_total = v_cur / v_norm_total

        # Use normalized axis components for entropy accumulation (fixes stage 3 unit mixing: cm vs deg).
        tracking_error_integral += float((e_nx * e_nx + e_ny * e_ny + e_nz * e_nz) ** 0.5) * dt

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= calc_tick_s:
            sample_tick_accum_s -= calc_tick_s
            # Discrete accumulation per sampling instant (doc-style sum),
            # without extra time multiplier; this avoids artificially slow growth.
            y_sigma_x += e_nx
            y_sigma_y += e_ny
            y_sigma_z += e_nz
            y_tek_current = float((e_nx * e_nx + e_ny * e_ny + e_nz * e_nz) ** 0.5)
            y_sigma = float((y_sigma_x * y_sigma_x + y_sigma_y * y_sigma_y + y_sigma_z * y_sigma_z) ** 0.5)
            report.y_tek_series.append(round(y_tek_current, 6))
            report.y_sigma_series.append(round(y_sigma, 6))

        latest_second_row = {
            'second': int(max(1.0, next_second_mark)),
            'x_cm': round(x_cm, 6),
            'y_cm': round(y_cm, 6),
            'z_deg': round(z_deg, 6),
            'vx': round(vx, 6),
            'vy': round(vy, 6),
            'vz': round(vz, 6),
            'v_current': round(v_cur, 6),
            'lambda_x': round(lam_x, 6),
            'lambda_y': round(lam_y, 6),
            'lambda_z': round(lam_z, 6),
            'lambda_xyz': round(lam_xyz, 6),
            'lambda_total': round(float(lam_total), 6),
            'e_x': round(e_x, 6),
            'e_y': round(e_y, 6),
            'e_z': round(e_z, 6),
            'e_nx': round(e_nx, 6),
            'e_ny': round(e_ny, 6),
            'e_nz': round(e_nz, 6),
            'h_current': round(y_tek_current, 6),
            'h_sigma_x': round(y_sigma_x, 6),
            'h_sigma_y': round(y_sigma_y, 6),
            'h_sigma_z': round(y_sigma_z, 6),
            'h_sigma': round(y_sigma, 6),
            'crashes': int(report.crashes),
        }

        while elapsed_s >= next_second_mark:
            row = dict(latest_second_row) if latest_second_row else {'second': int(next_second_mark)}
            row['second'] = int(next_second_mark)
            report.second_metrics.append(row)
            next_second_mark += 1.0

        report.y_tek_window_avg = float(y_tek_current)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)
        report._fixed203_y_sigma_x = float(y_sigma_x)
        report._fixed203_y_sigma_y = float(y_sigma_y)
        report._fixed203_y_sigma_z = float(y_sigma_z)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        if self.in_crash_zone(state, stage_no):
            _fixed204_play_crash_beep()
            report.crashes += 1
            report.sum_error = float(y_sigma)
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; h_cur={y_tek_current:.4f}; h_sum={y_sigma:.4f}; normalized=1",
            )
            self.reset_after_crash(state)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            report.sum_error = float(y_sigma)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, 0.0)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed208_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    rep = _fixed203_finalize_stage_report(self, report, elapsed_s, xy_integral, roll_integral, tracking_error_integral, speed_integral)
    rep.calculation_version = _FIXED208_METHOD_A_CALC_VERSION
    rep.runtime_rule_note = (
        'FIXED208: full per-second metrics table for all stages; '
        'stage-3 entropy/speed components normalized per axis; '
        'center-based target check; discrete H accumulation per tick.'
    )
    return rep


def _fixed208_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed204_build_method_a_payload(self, session, result)
    summary = payload.get('summary', {}) if isinstance(payload.get('summary', {}), dict) else {}
    summary['calculation_version'] = _FIXED208_METHOD_A_CALC_VERSION
    payload['summary'] = summary
    return payload


