def _fixed208_show_method_a_results(self, payload: dict):
    # Use fixed199 base screen (summary/stage cards) and render per-second tables here,
    # to avoid duplicate legacy per-second blocks from fixed204.
    top = _fixed199_show_method_a_results(self, payload)

    reports = payload.get('reports', [])
    if (not reports) and payload.get('result_path'):
        try:
            rp = Path(payload.get('result_path', ''))
            if not rp.is_absolute():
                rp = self.base_dir / rp
            if rp.exists():
                loaded = json.loads(rp.read_text(encoding='utf-8'))
                if isinstance(loaded, list):
                    reports = [r for r in loaded if isinstance(r, dict)]
        except Exception:
            reports = []

    body = _fixed204_find_results_body(top)
    if body is not None:
        title = tk.Frame(body, bg='#eef3f8')
        title.pack(fill='x', padx=24, pady=(2, 8))
        tk.Label(title, text='Детальная таблица по секундам: все измеряемые и расчетные величины', bg='#eef3f8', fg='#102744', font=('Arial', 16, 'bold')).pack(anchor='w')
        tk.Label(title, text='Режим FIXED211: этапы 2–3 по slezh_final.docx, шаг таблиц 0.5 с, под каждой таблицей показаны итоговые значения.', bg='#eef3f8', fg='#607187', font=('Arial', 10)).pack(anchor='w', pady=(2, 0))

        for rep in sorted([r for r in reports if isinstance(r, dict)], key=lambda x: int(x.get('stage_no', 0) or 0)):
            _fixed211_render_stage_full_table_halfsec(body, rep)

    pdf_path = _fixed207_export_pdf_all_results(self, top, payload)
    if pdf_path:
        payload['pdf_path'] = pdf_path
        if isinstance(payload.get('summary', None), dict):
            payload['summary']['pdf_path'] = pdf_path

    body = _fixed204_find_results_body(top)
    if body is not None:
        box = tk.Frame(body, bg='#ffffff', highlightthickness=1, highlightbackground='#d8e1ec')
        box.pack(fill='x', padx=24, pady=(2, 12))
        tk.Frame(box, bg='#6b7dff', height=6).pack(fill='x')
        txt = f"PDF (all results): {pdf_path}" if pdf_path else "PDF export (all results): failed"
        tk.Label(box, text=txt, bg='#ffffff', fg='#102744', font=('Arial', 10, 'bold'), wraplength=1180, justify='left').pack(anchor='w', padx=12, pady=10)
    return top


