# ====== FIXED211: Method A strict formulas from slezh_final.docx ======
_FIXED209_METHOD_A_CALC_VERSION = 'fixed213_error_gain_applied_v1'


def _fixed209_clip01(v: float) -> float:
    return max(0.0, min(1.0, float(v)))


def _fixed211_n_dop_x180(self) -> float:
    return max(1e-6, float(getattr(self.cfg, 'n_dop_x_for_180s', 50.0) or 50.0))


def _fixed211_n_dop_stage(self, stage_no: int, t_value: float) -> float:
    st = int(stage_no)
    t = max(1e-6, float(t_value))
    base = _fixed211_n_dop_x180(self)
    if st == 1:
        den = 180.0
    elif st == 2:
        den = 120.0
    else:
        den = 90.0
    return max(1e-6, base * t / den)


def _fixed209_axis_s(current_abs: float, goal: float, crash: float, axis_enabled: bool) -> float:
    if not axis_enabled:
        return 0.0
    span = max(1e-6, float(crash) - float(goal))
    # Document-style entropy/error component from target boundary to аварийная зона.
    return _fixed209_clip01(max(0.0, float(current_abs) - float(goal)) / span)


def _fixed209_run_stage(self, stage_no: int) -> StageReport:
    report = StageReport(stage_no=stage_no, active_axes=self.stage_defs[stage_no]['label'])
    state = self.init_stage_state()
    elapsed_s = 0.0
    xy_integral = 0.0
    roll_integral = 0.0

    x_abs_integral = 0.0
    y_abs_integral = 0.0
    z_abs_integral = 0.0

    v_x_integral = 0.0
    v_y_integral = 0.0
    v_z_integral = 0.0

    lambda_sum = 0.0
    s_sum = 0.0
    sample_count = 0

    stage_time_limit = _fixed200_stage_time_limit_s(self, stage_no)
    stage_max_error = _fixed200_stage_error_limit(self, stage_no)
    stage_crash_limit = _fixed211_n_dop_stage(self, stage_no, stage_time_limit)
    # Force stage stop when allowed crash count is reached.
    # Ndop can be fractional, while crashes are integer events, so we use the
    # first integer count that reaches/exceeds Ndop.
    stage_crash_limit_count = max(1, int(_fixed73e_math.ceil(float(stage_crash_limit))))
    calc_tick_s = 0.5
    row_step_s = 0.5

    v_norm_x = max(1e-6, float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    v_norm_y = max(1e-6, float(getattr(self.cfg, 'start_speed_xy_cm_s', 3.0) or 3.0))
    v_norm_z = max(1e-6, float(getattr(self.cfg, 'start_speed_z_deg_s', 10.0) or 10.0))

    y_tek_current = 0.0
    y_sigma = 0.0
    y_sigma_x = 0.0
    y_sigma_y = 0.0
    y_sigma_z = 0.0

    sample_tick_accum_s = 0.0
    next_row_mark = row_step_s
    latest_second_row: dict = {}
    # History of coordinates for Vтек over the last second.
    coord_history: list[tuple[float, float, float, float]] = []

    report.error_limit_formula_value = float(stage_max_error)
    report.error_limit_value = float(stage_max_error)
    report.crash_limit_doc = float(stage_crash_limit)
    report.stage_time_limit_used_s = float(stage_time_limit)
    report.y_tek_current = 0.0
    report.y_sigma = 0.0
    report.y_tek_series = []
    report.y_sigma_series = []
    report.y_tek_window_avg = 0.0
    report.calc_tick_s = float(calc_tick_s)
    report.row_step_s = float(row_step_s)
    report.second_metrics = []

    pygame.event.set_grab(True)
    pygame.mouse.set_visible(False)
    pygame.mouse.get_rel()

    while True:
        dt = self.clock.tick(self.cfg.fps) / 1000.0
        elapsed_s += dt
        report.real_time_s = elapsed_s

        wheel_delta = self.read_runtime_events()
        self.update_direction_timers(state, stage_no, dt)
        self.handle_control(state, stage_no, wheel_delta)
        self.update_drift(state, stage_no, dt)
        self.maybe_speedup(state, stage_no, elapsed_s)

        _ = self.current_error_increment(state, stage_no, dt)
        self.maybe_register_return(state, stage_no, report)

        if self.inside_target(state, stage_no):
            report.inside_time_s += dt

        xy_now = self.current_xy_deviation_cm(state, stage_no)
        roll_now = self.current_roll_deviation_deg(state, stage_no)
        xy_integral += xy_now * dt
        roll_integral += roll_now * dt
        report.peak_abs_xy_cm = max(report.peak_abs_xy_cm, xy_now)
        report.peak_abs_roll_deg = max(report.peak_abs_roll_deg, roll_now)

        snap = _fixed200_axis_snapshot(self, state, stage_no)
        x_cm = float(snap.get('x_cm', 0.0))
        y_cm = float(snap.get('y_cm', 0.0))
        z_deg = float(snap.get('z_deg', 0.0))
        goal_x = float(snap.get('goal_x', 0.0))
        goal_y = float(snap.get('goal_y', 0.0))
        goal_z = float(snap.get('goal_z', 0.0))
        crash_x = float(snap.get('crash_x', 0.0))
        crash_y = float(snap.get('crash_y', 0.0))
        crash_z = float(snap.get('crash_z', 0.0))

        x_abs_integral += x_cm * dt
        y_abs_integral += y_cm * dt
        z_abs_integral += z_deg * dt

        stage = self.stage_defs[int(stage_no)]
        active_axes = int(bool(stage.get('x'))) + int(bool(stage.get('y'))) + int(bool(stage.get('z')))
        coord_history.append((elapsed_s, x_cm, y_cm, z_deg))
        # Keep only recent samples; 1.25 s is enough for stable nearest-point lookup.
        cutoff_t = float(elapsed_s) - 1.25
        while len(coord_history) > 2 and coord_history[0][0] < cutoff_t:
            coord_history.pop(0)
        target_t = max(0.0, float(elapsed_s) - 1.0)
        prev_t, prev_x, prev_y, prev_z = min(coord_history, key=lambda item: abs(item[0] - target_t))
        # Fact speed by trajectory over the last second (includes operator control).
        vx = (x_cm - prev_x) if stage.get('x') else 0.0
        vy = (y_cm - prev_y) if stage.get('y') else 0.0
        vz = (z_deg - prev_z) if stage.get('z') else 0.0
        v_current_fact = float((vx * vx + vy * vy + vz * vz) ** 0.5)
        v_x_integral += vx * dt
        v_y_integral += vy * dt
        v_z_integral += vz * dt

        # Programmed axis speeds from settings/runtime profile (not used in formulas).
        v_cmd_xy = abs(float(getattr(state, 'speed_xy_cm_s', 0.0) or 0.0))
        v_cmd_z = abs(float(getattr(state, 'speed_z_deg_s', 0.0) or 0.0))
        v_cmd_x = v_cmd_xy if stage.get('x') else 0.0
        v_cmd_y = v_cmd_xy if stage.get('y') else 0.0
        v_cmd_z = v_cmd_z if stage.get('z') else 0.0

        lam_x = (vx / v_norm_x) if stage.get('x') else 0.0
        lam_y = (vy / v_norm_y) if stage.get('y') else 0.0
        lam_z = (vz / v_norm_z) if stage.get('z') else 0.0
        # Stage-2 corrected formula: plus under root.
        lam_cur = float((lam_x * lam_x + lam_y * lam_y + lam_z * lam_z) ** 0.5)

        s_x = _fixed209_axis_s(x_cm, goal_x, crash_x, bool(stage.get('x')))
        s_y = _fixed209_axis_s(y_cm, goal_y, crash_y, bool(stage.get('y')))
        s_z = _fixed209_axis_s(z_deg, goal_z, crash_z, bool(stage.get('z')))
        s_cur = float((s_x * s_x + s_y * s_y + s_z * s_z) ** 0.5)

        sample_tick_accum_s += dt
        while sample_tick_accum_s >= calc_tick_s:
            sample_tick_accum_s -= calc_tick_s
            # Strict doc mode: ΥΣi = ΣSi (all stages).
            y_sigma_x += s_x
            y_sigma_y += s_y
            y_sigma_z += s_z
            y_tek_current = float(s_cur)
            y_sigma = float((y_sigma_x * y_sigma_x + y_sigma_y * y_sigma_y + y_sigma_z * y_sigma_z) ** 0.5)
            # Integral by time with 0.5 s sampling step.
            lambda_sum += lam_cur * calc_tick_s
            s_sum += s_cur * calc_tick_s
            sample_count += 1
            report.y_tek_series.append(round(y_tek_current, 6))
            report.y_sigma_series.append(round(y_sigma, 6))

        latest_second_row = {
            'time_s': round(float(max(row_step_s, next_row_mark)), 3),
            'second': int(round(float(max(row_step_s, next_row_mark)))),
            'x_cm': round(x_cm, 6), 'y_cm': round(y_cm, 6), 'z_deg': round(z_deg, 6),
            'goal_x': round(goal_x, 6), 'goal_y': round(goal_y, 6), 'goal_z': round(goal_z, 6),
            'crash_x': round(crash_x, 6), 'crash_y': round(crash_y, 6), 'crash_z': round(crash_z, 6),
            'vx': round(v_cmd_x, 6), 'vy': round(v_cmd_y, 6), 'vz': round(v_cmd_z, 6),
            'v_current': round(v_current_fact, 6),
            'lambda_x': round(lam_x, 6), 'lambda_y': round(lam_y, 6), 'lambda_z': round(lam_z, 6),
            'lambda_xyz': round(lam_cur, 6), 'lambda_total': round(lam_cur, 6),
            'e_x': round(s_x, 6), 'e_y': round(s_y, 6), 'e_z': round(s_z, 6),
            'e_nx': round(s_x, 6), 'e_ny': round(s_y, 6), 'e_nz': round(s_z, 6),
            's_x': round(s_x, 6), 's_y': round(s_y, 6), 's_z': round(s_z, 6),
            'h_current': round(s_cur, 6),
            'h_sigma_x': round(y_sigma_x, 6), 'h_sigma_y': round(y_sigma_y, 6), 'h_sigma_z': round(y_sigma_z, 6), 'h_sigma': round(y_sigma, 6),
            'y_pred': round(stage_max_error, 6), 'n_dop_t': round(stage_crash_limit, 6),
            'crashes': int(report.crashes),
        }

        while elapsed_s >= next_row_mark:
            row = dict(latest_second_row) if latest_second_row else {'time_s': round(next_row_mark, 3)}
            row['time_s'] = round(next_row_mark, 3)
            row['second'] = int(round(next_row_mark))
            report.second_metrics.append(row)
            next_row_mark += row_step_s

        report.y_tek_window_avg = float(y_tek_current)
        report.y_tek_current = float(y_tek_current)
        report.y_sigma = float(y_sigma)
        report.sum_error = float(y_sigma)
        report._fixed203_y_sigma_x = float(y_sigma_x)
        report._fixed203_y_sigma_y = float(y_sigma_y)
        report._fixed203_y_sigma_z = float(y_sigma_z)
        report._fixed209_lambda_sum = float(lambda_sum)
        report._fixed209_s_sum = float(s_sum)
        report._fixed209_samples = int(sample_count)
        report._fixed209_v_norm_x = float(v_norm_x)
        report._fixed209_v_norm_y = float(v_norm_y)
        report._fixed209_v_norm_z = float(v_norm_z)
        report._fixed209_active_axes = int(active_axes)

        if y_sigma >= stage_max_error:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, 0.0, 0.0)

        if self.in_crash_zone(state, stage_no):
            _fixed204_play_crash_beep()
            report.crashes += 1
            self.logger.log_event(
                self.session,
                event_type='stage_event',
                screen='method_a',
                test_name='method_a_stage',
                stage=str(stage_no),
                action='crash',
                elapsed_ms=int(elapsed_s * 1000),
                x=round(getattr(state, 'x_px', 0.0), 3),
                y=round(float(y_sigma), 3),
                angle=round(getattr(state, 'roll_deg', 0.0), 3),
                value=report.crashes,
                note=f"axes={report.active_axes}; Scur={s_cur:.4f}; Ssum={y_sigma:.4f}; lambda={lam_cur:.4f}",
            )
            self.reset_after_crash(state)
            if int(report.crashes) >= int(stage_crash_limit_count):
                report.stage_end_reason = 'crash_limit_reached'
                self.logger.log_event(
                    self.session,
                    event_type='stage_event',
                    screen='method_a',
                    test_name='method_a_stage',
                    stage=str(stage_no),
                    action='stage_stop_crash_limit',
                    elapsed_ms=int(elapsed_s * 1000),
                    x=round(getattr(state, 'x_px', 0.0), 3),
                    y=round(float(y_sigma), 3),
                    angle=round(getattr(state, 'roll_deg', 0.0), 3),
                    value=report.crashes,
                    note=f"Nreal={report.crashes}; Ndop={stage_crash_limit:.4f}; stop_at={stage_crash_limit_count}",
                )
                report._fixed200_x_abs_integral = float(x_abs_integral)
                report._fixed200_y_abs_integral = float(y_abs_integral)
                report._fixed200_z_abs_integral = float(z_abs_integral)
                report._fixed203_speed_x_integral = float(v_x_integral)
                report._fixed203_speed_y_integral = float(v_y_integral)
                report._fixed203_speed_z_integral = float(v_z_integral)
                return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, 0.0, 0.0)

        if elapsed_s >= stage_time_limit:
            report._fixed200_x_abs_integral = float(x_abs_integral)
            report._fixed200_y_abs_integral = float(y_abs_integral)
            report._fixed200_z_abs_integral = float(z_abs_integral)
            report._fixed203_speed_x_integral = float(v_x_integral)
            report._fixed203_speed_y_integral = float(v_y_integral)
            report._fixed203_speed_z_integral = float(v_z_integral)
            return self.finalize_stage_report(report, elapsed_s, xy_integral, roll_integral, 0.0, 0.0)

        self.draw_background()
        self.draw_roll_limit_guides(state, stage_no)
        self.draw_object(state)
        self.draw_hud(stage_no, elapsed_s, float(y_sigma), report, state)
        pygame.display.flip()


def _fixed209_finalize_stage_report(
    self,
    report: StageReport,
    elapsed_s: float,
    xy_integral: float,
    roll_integral: float,
    tracking_error_integral: float = 0.0,
    speed_integral: float = 0.0,
) -> StageReport:
    total = max(float(elapsed_s), 1e-6)
    stage_no = int(report.stage_no)
    t_fact = max(1e-6, float(getattr(report, 'real_time_s', elapsed_s) or elapsed_s))
    report.mean_abs_xy_cm = float(xy_integral) / total
    report.mean_abs_roll_deg = float(roll_integral) / total
    report.stability_pct = max(0.0, min(100.0, float(report.inside_time_s) / total * 100.0))
    x_avg = float(getattr(report, '_fixed200_x_abs_integral', 0.0) or 0.0) / total
    y_avg = float(getattr(report, '_fixed200_y_abs_integral', 0.0) or 0.0) / total
    z_avg = float(getattr(report, '_fixed200_z_abs_integral', 0.0) or 0.0) / total
    report.avg_abs_x_cm = float(x_avg)
    report.avg_abs_y_cm = float(y_avg)
    report.avg_abs_z_deg = float(z_avg)

    vxs = float(getattr(report, '_fixed203_speed_x_integral', 0.0) or 0.0) / total
    vys = float(getattr(report, '_fixed203_speed_y_integral', 0.0) or 0.0) / total
    vzs = float(getattr(report, '_fixed203_speed_z_integral', 0.0) or 0.0) / total
    report.v_avg_x = float(vxs)
    report.v_avg_y = float(vys)
    report.v_avg_z = float(vzs)

    lambda_sum = float(getattr(report, '_fixed209_lambda_sum', 0.0) or 0.0)
    s_sum = float(getattr(report, '_fixed209_s_sum', 0.0) or 0.0)
    # Strict doc formulas: averages by factual stage time T.
    lambda_avg = lambda_sum / t_fact
    s_avg = s_sum / t_fact
    s_avg_norm = abs(s_avg)
    gamma = 1.0 - s_avg_norm

    n_dop_180 = _fixed211_n_dop_x180(self)
    n_real = max(0.0, float(getattr(report, 'crashes', 0) or 0))
    n_dop = _fixed211_n_dop_stage(self, stage_no, t_fact)
    # Strict doc formulas for all stages: βавар = 1 - Nreal/Ndop(stage).
    n_avar = 1.0 - (float(n_real) / float(n_dop))

    v_avg_norm = float(_fixed200_normative_speed_value(self, stage_no))
    v_ratio = float(lambda_avg) / max(1e-6, v_avg_norm)
    t_slezh = float(v_ratio) * float(gamma) * float(n_avar)

    report.v_avg = float(lambda_avg)
    report.v_avg_norm = float(v_avg_norm)
    report.v_ratio = float(v_ratio)
    report.success_gamma = float(gamma)
    report.entropy_h = float(s_avg_norm)
    report.entropy_h_raw = float(s_avg)
    report.entropy_h_doc = float(s_avg_norm)
    report.crash_coeff_n_avar = float(n_avar)
    report.crash_limit_doc = float(n_dop)
    report.crash_limit_doc_180 = float(n_dop_180)
    report.y_lim_per_sec = float(_fixed200_stage_y_lim_per_sec(self, stage_no))
    report.n_real_doc = float(n_real)
    report.reduced_tempo_tr = float(t_slezh)
    report.t_slezh = float(t_slezh)
    report.avg_tracking_error = float(s_avg_norm)
    report.avg_tracking_error_raw = float(s_avg)
    report.avg_tracking_error_effective = float(s_avg_norm)
    report.y_sigma_x = float(getattr(report, '_fixed203_y_sigma_x', 0.0) or 0.0)
    report.y_sigma_y = float(getattr(report, '_fixed203_y_sigma_y', 0.0) or 0.0)
    report.y_sigma_z = float(getattr(report, '_fixed203_y_sigma_z', 0.0) or 0.0)
    stage = self.stage_defs[int(stage_no)]
    goal_xy = max(1e-6, float(getattr(self.cfg, 'target_half_cm', 3.0) or 3.0))
    crash_xy = max(goal_xy + 1e-6, goal_xy + float(getattr(self.cfg, 'work_extension_cm', 15.0) or 15.0))
    goal_z = max(1e-6, float(getattr(self.cfg, 'target_roll_deg', 5.0) or 5.0))
    crash_z = max(goal_z + 1e-6, float(getattr(self.cfg, 'work_roll_deg', 90.0) or 90.0))
    goal_combined = float(
        ((goal_xy if stage.get('x') else 0.0) ** 2
         + (goal_xy if stage.get('y') else 0.0) ** 2
         + (goal_z if stage.get('z') else 0.0) ** 2) ** 0.5
    )
    crash_combined = float(
        ((crash_xy if stage.get('x') else 0.0) ** 2
         + (crash_xy if stage.get('y') else 0.0) ** 2
         + (crash_z if stage.get('z') else 0.0) ** 2) ** 0.5
    )
    current_combined = float((x_avg * x_avg + y_avg * y_avg + z_avg * z_avg) ** 0.5)
    report.tracking_error_target = float(goal_combined)
    report.tracking_error_crash = float(crash_combined)
    report.tracking_error_current_avg = float(current_combined)
    report.calculation_version = _FIXED209_METHOD_A_CALC_VERSION
    report.runtime_rule_note = (
        'FIXED211(slezh_final): step=0.5s; lambda_avg=Sum(lambda_i*step)/Tfact; '
        'gamma=1-Sum(S_i*step)/Tfact; '
        'NdopX=T*NdopX180/180, NdopXY=T*NdopX180/120, NdopXYZ=T*NdopX180/90; '
        'beta_avar=1-(Nreal/Ndop_stage); t=lambda_avg*gamma*beta_avar.'
    )
    return report


def _fixed209_build_method_a_payload(self, session: SessionInfo, result: dict) -> dict:
    payload = _fixed204_build_method_a_payload(self, session, result)
    summary = payload.get('summary', {}) if isinstance(payload.get('summary', {}), dict) else {}
    summary['calculation_version'] = _FIXED209_METHOD_A_CALC_VERSION
    payload['summary'] = summary
    return payload


