def _fixed218_style_research_tabs(self):
    tabs = getattr(self, 'research_tabs', None)
    if tabs is None:
        return
    try:
        style = ttk.Style(self.root)
        try:
            if 'clam' in style.theme_names():
                style.theme_use('clam')
        except Exception:
            pass
        scale = max(0.9, min(1.5, float(self.root.winfo_screenwidth()) / 1920.0))
        font_size = max(10, int(11 * scale))
        pad_x = max(12, int(14 * scale))
        pad_y = max(5, int(6 * scale))

        style.configure(
            'ResearchUnified.TNotebook',
            background=BG_COLOR,
            borderwidth=0,
            tabmargins=(0, 6, 8, 0),
        )
        style.configure(
            'ResearchUnified.TNotebook.Tab',
            background=PANEL_COLOR,
            foreground=TITLE_COLOR,
            borderwidth=1,
            relief='flat',
            lightcolor=PANEL_COLOR,
            darkcolor=PANEL_COLOR,
            bordercolor='#938b73',
            padding=(pad_x, pad_y),
            font=('Segoe UI', font_size, 'bold'),
        )
        style.map(
            'ResearchUnified.TNotebook.Tab',
            background=[('selected', BG_COLOR), ('active', BG_COLOR)],
            foreground=[('selected', TITLE_COLOR), ('active', TITLE_COLOR)],
            lightcolor=[('selected', BG_COLOR), ('active', BG_COLOR)],
            darkcolor=[('selected', BG_COLOR), ('active', BG_COLOR)],
            bordercolor=[('selected', '#7e765f'), ('active', '#7e765f')],
            # Selected tab: slightly raised, same width as inactive tabs.
            padding=[('selected', (pad_x, max(1, pad_y + 1), pad_x, max(1, pad_y - 1))), ('!selected', (pad_x, pad_y, pad_x, pad_y))],
            expand=[('selected', (0, 2, 0, 0)), ('!selected', (0, 0, 0, 0))],
        )
        tabs.configure(style='ResearchUnified.TNotebook')
    except Exception:
        pass


