def _fixed218_apply_menu_layout(self):
    if callable(_fixed218_prev_apply_menu_layout):
        _fixed218_prev_apply_menu_layout(self)
    try:
        root_w = max(int(self.root.winfo_width() or 0), 1100)
        root_h = max(int(self.root.winfo_height() or 0), 760)
        scale = max(0.80, min(min(root_w / BASE_W, root_h / BASE_H), 1.10))
        main_font = max(11, int(13 * scale))
        result_font = max(10, int(11 * scale))
        control_font = max(9, int(11 * scale))

        for code in TEST_ORDER:
            card = getattr(self, 'menu_cards', {}).get(code)
            btn = getattr(self, 'menu_buttons', {}).get(code)
            result_btn = getattr(self, 'menu_result_buttons', {}).get(code)
            if card is None or btn is None or result_btn is None:
                continue

            btn.configure(
                font=('Segoe UI', main_font, 'bold'),
                wraplength=0,
                justify='center',
                anchor='center',
                height=4,
                padx=8,
                pady=6,
            )
            result_btn.configure(
                font=('Segoe UI', result_font, 'bold'),
                wraplength=0,
                justify='center',
                anchor='center',
                height=2,
                padx=8,
                pady=4,
            )

        control_frame = getattr(self, 'menu_btn_frame', None)
        controls = [
            getattr(self, 'settings_btn', None),
            getattr(self, 'all_results_btn', None),
            getattr(self, 'continue_btn', None),
            getattr(self, 'restart_btn', None),
            getattr(self, 'exit_btn', None),
        ]
        controls = [b for b in controls if b is not None and b.winfo_exists()]
        if control_frame is not None and control_frame.winfo_exists() and controls:
            for idx, btn in enumerate(controls):
                btn.grid_configure(sticky='ew', padx=(0 if idx == 0 else 6, 6 if idx < len(controls) - 1 else 0))
                btn.configure(
                    font=('Segoe UI', control_font, 'bold'),
                    width=1,
                    wraplength=0,
                    justify='center',
                    anchor='center',
                    padx=6,
                    pady=max(3, int(control_font * 0.35)),
                )
    except Exception:
        pass


StartPageApp.apply_menu_layout = _fixed218_apply_menu_layout

_fixed218_prev_apply_researcher_layout_2 = getattr(StartPageApp, 'apply_researcher_layout', None)


def _fixed218_apply_researcher_layout_2(self):
    if callable(_fixed218_prev_apply_researcher_layout_2):
        _fixed218_prev_apply_researcher_layout_2(self)
    try:
        row_buttons = [
            getattr(self, 'research_default_btn', None),
            getattr(self, 'research_all_results_btn', None),
            getattr(self, 'research_next_btn', None),
            getattr(self, 'research_exit_btn', None),
        ]
        row_buttons = [b for b in row_buttons if b is not None and b.winfo_exists()]
        if row_buttons:
            frame = getattr(self, 'research_actions_top', None)
            root_w = max(int(self.root.winfo_width() or 0), 1100)
            root_h = max(int(self.root.winfo_height() or 0), 760)
            scale = max(0.80, min(min(root_w / BASE_W, root_h / BASE_H), 1.10))
            frame_w = max(int(frame.winfo_width() or 0), int(root_w * 0.42)) if frame is not None else int(root_w * 0.42)
            slot_w = max(120, int((frame_w - 12) / max(1, len(row_buttons))))
            fsz = max(9, int(11 * scale))
            for i, btn in enumerate(row_buttons):
                btn.grid_configure(sticky='ew', padx=(0 if i == 0 else 6, 6 if i < len(row_buttons) - 1 else 0))
                btn.configure(
                    font=('Segoe UI', fsz, 'bold'),
                    wraplength=0,
                    justify='center',
                    anchor='center',
                    width=1,
                    padx=6,
                    pady=max(3, int(fsz * 0.35)),
                )
    except Exception:
        pass


StartPageApp.apply_researcher_layout = _fixed218_apply_researcher_layout_2


# ====== FIXED220: config schema versioning + auto-reset of legacy config files ======
_FIXED220_CONFIG_SCHEMA_VERSION = 'fixed221_config_schema_2026_04_26_v2'
_FIXED220_CONFIG_VERSION_FILE = 'config_schema_version.txt'
_FIXED220_CONFIG_FILES = (
    ('method_a_config.json', MethodAConfig),
    ('method_b_config.json', MethodBConfig),
    ('method_c_config.json', MethodCConfig),
    ('method_d_config.json', MethodDConfig),
)


def _fixed220_write_default_config(path: Path, cls):
    obj = cls()
    payload = asdict(obj)
    path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding='utf-8')


def _fixed220_prepare_config_schema(base_dir: Path):
    try:
        base_dir = Path(base_dir)
        marker_path = base_dir / _FIXED220_CONFIG_VERSION_FILE
        current = ''
        if marker_path.exists():
            try:
                current = marker_path.read_text(encoding='utf-8').strip()
            except Exception:
                current = ''

        if current == _FIXED220_CONFIG_SCHEMA_VERSION:
            return

        ts = datetime.now().strftime('%Y%m%d_%H%M%S')
        backup_dir = base_dir / 'data' / 'config_backup' / ts
        backup_created = False

        for filename, cls in _FIXED220_CONFIG_FILES:
            cfg_path = base_dir / filename
            if cfg_path.exists():
                if not backup_created:
                    backup_dir.mkdir(parents=True, exist_ok=True)
                    backup_created = True
                shutil.copy2(str(cfg_path), str(backup_dir / filename))
            _fixed220_write_default_config(cfg_path, cls)

        marker_path.write_text(_FIXED220_CONFIG_SCHEMA_VERSION, encoding='utf-8')
    except Exception:
        # Do not block app startup if migration cannot be completed.
        pass


_fixed220_prev_run_app = _run_app


def _run_app():
    _fixed220_prepare_config_schema(_runtime_app_dir())
    _fixed220_prev_run_app()


if __name__ == '__main__':
    _run_app()
